INSERT INTO `answers` VALUES
(1,'1.1.01-001','Nicht auf dem eigenen Recht bestehen','Not insisting on your rights','روی حق خودت پافشاری نکن','<p>زیرا رانندگی تدافعی همچنین به معنای صرف نظر کردن از حق تقدم خود در صورت لزوم به نفع ایمنی عمومی جاده است</p>',0,'Nicht auf dem eigenen Recht bestehen',1,1,''),
(2,'1.1.01-001','Mit Fehlern anderer rechnen','Allowing for other people\'s mistakes','انتظار اشتباه دیگران را داشته باش<div><br></div>','<p>عدم اطمینان و قضاوت نادرست از سوی سایر کاربران جاده قطعاً امکان‌پذیر است. با رانندگی با دوراندیشی می‌توان از تصادفات جلوگیری کرد.</p>',0,'Mit Fehlern anderer rechnen',1,1,''),
(3,'1.1.01-001','Vorsorglich an jeder Kreuzung anhalten','Stopping as a precaution at every crossroads','برای احتیاط در هر تقاطع توقف کنید','<p>توقف در هر تقاطع، جریان ترافیک را مختل می‌کند و همچنین ممکن است منجر به سبقت‌های خطرناک توسط رانندگان پشت سر شود. این امر ایمنی جاده را افزایش نمی‌دهد.</p>',0,'Vorsorglich an jeder Kreuzung anhalten',1,0,''),
(4,'1.1.01-002','Unerwartet starkes Bremsen','Unexpectedly heavy braking','ترمزگیری شدید و غیرمنتظره','<p>همیشه باید فرض کنید که راننده پشت سر شما واکنش کندی دارد. اگر به طور غیرمنتظره‌ای ترمز شدید بگیرید، ممکن است آنها نتوانند به سرعت کافی ترمز کنند.</p>',0,'Unerwartet starkes Bremsen',1,1,''),
(5,'1.1.01-002','Unaufmerksamkeit','Inattentiveness','بی توجهی','<p>تمرکز کامل، توجه مداوم و واکنش سریع در ترافیک جاده‌ای بسیار مهم هستند. اگر لحظه‌ای بی‌توجه باشید (مثلاً هنگام تغییر موج رادیو)، این امر بر زمان واکنش شما تأثیر می‌گذارد زیرا شما لحظه‌ای قادر به مشاهده ترافیک پیش رو نیستید</p>',0,'Unaufmerksamkeit',1,1,''),
(6,'1.1.01-002','Zu dichtes Auffahren','Driving too close behind the vehicle in front','رانندگی با فاصله خیلی کم از وسیله نقلیه جلویی','<p>رانندگی با پیش‌بینی به معنای حفظ فاصله ایمن است، زیرا رفتار رانندگی وسیله نقلیه جلویی غیرقابل پیش‌بینی است. ترمز ناگهانی توسط راننده دیگر در صورت عدم رعایت فاصله ایمن می‌تواند به سرعت منجر به برخورد از عقب شود. به یاد داشته باشید: هر چه سرعت بیشتر باشد، فاصله باید بیشتر باشد!</p>',0,'Zu dichtes Auffahren',1,1,''),
(7,'1.1.01-101','- bremst unerwartet','- could brake unexpectedly','ترمز غیر منتظره','<p>راننده ممکن است با منطقه آشنا نباشد و از gps استفاده کند یا مسیرها را دنبال کند. در صورت عدم توجه به جاده، این امر می‌تواند منجر به ترمز ناگهانی شود. بنابراین، باید فاصله ایمن رعایت شود.</p>',0,'- bremst unerwartet',1,1,''),
(8,'1.1.01-101','- betätigt den Blinker vor dem Abbiegen zu spät','- may switch on the direction indicators too late before turning','قبل از پیچیدن با تاخیر راهنما بزند','<p>این هم یک سناریوی محتمل است که می‌توان آن را به عدم آگاهی راننده نسبت داد.</p>',0,'- betätigt den Blinker vor dem Abbiegen zu spät',1,1,''),
(9,'1.1.01-101','- hält unerwartet an, um nach dem Weg zu fragen','- could stop unexpectedly to ask the way','به طور غیر منتظره ای برای پرسیدن آدرس توقف کند','<p>بنابراین با احتیاط رانندگی کنید و فاصله کافی را حفظ کنید.</p>',0,'- hält unerwartet an, um nach dem Weg zu fragen',1,1,''),
(10,'1.1.01-102','Abwürgen des Motors','Stalling the engine in dense traffic','از کار افتادن موتور خودرو','<p>با رانندگی دقیق و تمرین کافی می‌توان به راحتی از این امر جلوگیری کرد</p>',0,'Abwürgen des Motors',1,1,''),
(11,'1.1.01-102','Langsamfahren ohne triftigen Grund','Vehicles proceeding too slowly for no good reason','رانندگی آهسته بدون دلیل موجه','<p>این امر جریان ترافیک را مختل می‌کند، سایر کاربران جاده را به تأخیر می‌اندازد و یک مانع قابل اجتناب است. البته، تراکتورها یا کامیون‌های کندرو نیز می‌توانند گاهی اوقات مانع باشند. با این حال، آنها قادر به رانندگی سریع‌تر نیستند</p>',0,'Langsamfahren ohne triftigen Grund',1,1,''),
(12,'1.1.01-102','Liegenbleiben wegen Kraftstoffmangels','Motor vehicles breaking down because they have run out of fuel','توقف در جا به علق کمبود سوخت','<p>سطح سوخت را می‌توان از روی نشانگر سوخت خواند. اگر چراغ سوخت کم روشن شود، قاعده کلی این است: شما هنوز می‌توانید تقریباً ۵۰ کیلومتر با این باک سوخت رانندگی کنید. با این حال، هرگز نباید این مقدار را به حداکثر برسانید، زیرا می‌تواند به موتور آسیب برساند. بنابراین: به موقع سوخت‌گیری کنید و از دردسر خود را نجات دهید</p>',0,'Liegenbleiben wegen Kraftstoffmangels',1,1,''),
(13,'1.1.01-103','Weil der Verkehrsfluss behindert wird','Because it obstructs the flow of traffic','زیرا جریان ترافیک را مختل می کند','<p>این می‌تواند باعث ایجاد ترافیک شود و شما می‌توانید به یک مانع ترافیکی برای سایر رانندگان تبدیل شوید.</p>',0,'Weil der Verkehrsfluss behindert wird',1,1,''),
(14,'1.1.01-103','Weil die Gefahr von Auffahrunfällen erhöht wird','Because it increases the danger of rear-end collisions','خطر تصادفات از عقب افزایش می یابد','<p>اگر راننده‌ی پشت سر با سرعت توصیه‌شده حرکت کند و خیلی دیر متوجه شود که وسیله‌ی نقلیه‌ی جلویی به آن پایبند نیست، ممکن است دیگر نتواند به موقع ترمز کند.</p>',0,'Weil die Gefahr von Auffahrunfällen erhöht wird',1,1,''),
(15,'1.1.01-103','Weil Nachfolgende zu gefährlichem Überholen verleitet werden','Because it encourages vehicle drivers behind to overtake dangerously','زیرا خودروهای پشت سر به سبقت خطرناک وسوسه می شوند','<p>به خصوص در جاده‌های تک بانده مانند جاده‌های روستایی، رانندگی خیلی آهسته عامل خطرناکی برای جریان ترافیک است. سایر رانندگان، برای رعایت محدودیت سرعت، ممکن است احساس کنند که مجبور به سبقت گرفتن هستند، احتمالاً حتی در مناطقی با دید کم یا پیچ‌ها، و در نتیجه ایمنی شما و همچنین سایر کاربران جاده را به خطر می‌اندازند.</p>',0,'Weil Nachfolgende zu gefährlichem Überholen verleitet werden',1,1,''),
(16,'1.1.01-107','Schwere Augenlider','Heavy eyelids','پلک های سنگین','<p>اگر پلک‌هایتان سنگین شد، حتماً باید استراحت کنید یا اجازه دهید شخص دیگری رانندگی کند. واکنش سریع برای جلوگیری از خطر خواب کوتاه (میکرو اسلیپ) بسیار مهم است</p>',0,'Schwere Augenlider',1,1,''),
(17,'1.1.01-107','Häufiges Gähnen','Frequent yawning','خمیازه های مکرر','<p>خمیازه کشیدن مکرر نشانه خستگی است. بنابراین، باید استراحت طولانی‌تری داشته باشید یا راننده را عوض کنید.</p>',0,'Häufiges Gähnen',1,1,''),
(18,'1.1.01-107','Verkürzte Reaktionszeit','Quicker reaction time','کاهش زمان واکنش\n(یعنی سریعتر واکنش نشان میدهید)','<p>زمان واکنش کوتاه‌تر نشان دهنده توجه و هوشیاری بالا است، که نقطه مقابل خستگی است.</p>',0,'Verkürzte Reaktionszeit',1,0,''),
(19,'1.1.01-108','Sekundenschlaf','Microsleep','خواب های کوتاه','<p>خواب کوتاه به خواب رفتن غیرارادی اشاره دارد که می‌تواند چند ثانیه طول بکشد. اگر خواب کوتاه هنگام رانندگی رخ دهد، می‌تواند تهدید کننده زندگی باشد</p>',0,'Sekundenschlaf',1,1,''),
(20,'1.1.01-108','Konzentrationsmangel','Lack of concentration','عدم تمرکز ','<p>هر چه خسته‌تر باشید، تمرکزتان کمتر می‌شود. تمرکز بالا برای رانندگی ایمن ضروری است.</p>',0,'Konzentrationsmangel',1,1,''),
(21,'1.1.01-108','Fahrfehler','Driving mistakes','اشتباهات رانندگی','<p>وقتی خسته هستید، احتمال اشتباهات رانندگی شما بیشتر از زمانی است که به خوبی استراحت کرده و تمرکز دارید. برای جلوگیری از این اتفاق، باید استراحت کنید.</p>',0,'Fahrfehler',1,1,''),
(22,'1.1.01-109','Unverzüglich eine Pause einlegen','Take a break straightaway','فوراً استراحت کنید.','<p>برای بازیابی تمرکز و هوشیاری در ترافیک، باید با اولین نشانه خستگی استراحت کرد.</p>',0,'Unverzüglich eine Pause einlegen',1,1,''),
(23,'1.1.01-109','Sich an frischer Luft bewegen','Get out of the car and move around in the fresh air','در هوای تازه ورزش کنید','<p>ورزش و اکسیژن با خستگی مقابله می‌کنند</p>',0,'Sich an frischer Luft bewegen',1,1,''),
(24,'1.1.01-109','Anregende Musik hören','Listen to stimulating music','به موسیقی مهیج گوش دهید','<p>موسیقی نشاط‌آور وقتی بدن خسته است، فشار بیشتری به آن وارد می‌کند. به جای آن، باید برای استراحت برنامه‌ریزی کنید و پاهایتان را بکشید</p>',0,'Anregende Musik hören',1,0,''),
(25,'1.1.01-110','Nachlassende Aufmerksamkeit','Decreases alertness','از دست دادن توجه','<p>خستگی بر توجه فرد تأثیر منفی می‌گذارد و به طور بالقوه منجر به کندتر شدن زمان واکنش می‌شود. بنابراین، ضروری است که به محض مشاهده خستگی، هنگام رانندگی استراحت کنید.</p>',0,'Nachlassende Aufmerksamkeit',1,1,''),
(26,'1.1.01-110','Eingeschränkte Wahrnehmung','Limits awareness','آگاهی را محدود می کند','<p>خستگی، دریافت، انتقال و پردازش محرک‌های حسی را مختل می‌کند. در نتیجه، ادراک نیز کاهش می‌یابد</p>',0,'Eingeschränkte Wahrnehmung',1,1,''),
(27,'1.1.01-110','Verzögerte Reaktionen','Delays reactions','واکنش های با تاخیر','<p>وقتی خسته هستید، زمان واکنش شما افزایش می‌یابد. این می‌تواند منجر به موقعیت‌های خطرناکی در ترافیک شود.</p>',0,'Verzögerte Reaktionen',1,1,''),
(28,'1.1.01-112','Ablenkung','Distraction','انحراف','<div dir=\"rtl\">تحت هیچ شرایطی نباید حواس راننده از سبک رانندگی متمرکز و فعال پرت شود.</div>',0,'Ablenkung',1,1,''),
(29,'1.1.01-112','Unaufmerksamkeit','Inattention','بی توجهی','<div dir=\"rtl\">بی توجهی زمان واکنش را به تاخیر می اندازد، این می تواند منجر به خروج شما از جاده شود. استفاده از تلفن همراه از مهمترین رفتارهای بی توجه در هنگام رانندگی است. بنابراین بهتر است آن را سایلنت نگه دارید و&nbsp; کنار بگذارید تا نتواند مزاحم شما شود.</div>',0,'Unaufmerksamkeit',1,1,''),
(30,'1.1.01-112','Müdigkeit','Tiredness','خستگی','<div dir=\'rtl\'>اگر خسته هستید، حتما باید استراحت کنید یا در صورت امکان، راننده را عوض کنید.</div>',0,'Müdigkeit',1,1,''),
(31,'1.1.02-005','Sie laufen auf den Zebrastreifen, ohne auf den Verkehr zu achten','They will run onto the zebra crossing without paying attention to traffic','آنها بدون توجه به ترافیک وارد خط عابر پیاده می شوند','<div dir=\"rtl\">اگر خط عابر پیاده در معرض دید است، عموماً باید به عابران پیاده توجه بیشتری شود، به ویژه اگر کودکان در نزدیکی آن باشند. نمی توان از کودکان انتظار داشت که در جاده با احتیاط رفتار کنند.</div>',0,'Sie laufen auf den Zebrastreifen, ohne auf den Verkehr zu achten',1,1,''),
(32,'1.1.02-005','Sie kehren ohne erkennbaren Grund auf dem Zebrastreifen um und laufen zurück','They will turn around on the zebra crossing for no apparent reason and run back','آنها بدون هیچ دلیل مشخصی روی خط عابرپیاده می چرخند و به عقب برمی گردند','<div dir=\'rtl\'>پیش بینی رفتار کودکان ممکن است دشوار باشد. آنها همچنین درک متفاوتی از خطر نسبت به بزرگسالان دارند.</div>',0,'Sie kehren ohne erkennbaren Grund auf dem Zebrastreifen um und laufen zurück',1,1,''),
(33,'1.1.02-005','Sie schätzen Geschwindigkeit und Entfernung herannahender Fahrzeuge immer richtig ein und warten am Fahrbahnrand','They will wait at the curb because they always correctly judge the speed and distance of approaching vehicles','آنها همیشه سرعت و مسافت وسایل نقلیه نزدیک را به درستی ارزیابی می کنند و در کنار جاده منتظر می مانند','<div dir=\'rtl\'>این را نمی توان حتی برای بزرگسالانی که تجربه در ترافیک جاده ای دارند، فرض کرد. بنابراین نمی توان این رفتار را از کودکانی که تمرکز ادراکی آنها روی چیزهایی غیر از رفتار انطباقی و توجه در ترافیک است، انتظار داشت.</div>',0,'Sie schätzen Geschwindigkeit und Entfernung herannahender Fahrzeuge immer richtig ein und warten am Fahrbahnrand',1,0,''),
(34,'1.1.02-022','- schon losrennen, wenn die Ampel in meiner Fahrtrichtung von Grün auf Gelb umschaltet','- will already start running when the traffic lights in my driving direction change from green to amber','- وقتی چراغ راهنمایی در جهت من از سبز به زرد تغییر کرد، شروع به دویدن کنند','<div dir=\'rtl\'>بچه ها به تدریج یاد می گیرند که چگونه در ترافیک درست رفتار کنند. آنها محیط اطراف خود را متفاوت از بزرگسالان درک می کنند و هنوز در ارزیابی موقعیت های خطرناک خوب نیستند.</div>',0,'- schon losrennen, wenn die Ampel in meiner Fahrtrichtung von Grün auf Gelb umschaltet',1,1,''),
(35,'1.1.02-022','- auch bei Rot loslaufen, weil es ihnen zu lange dauert','- will also start running when the light is red because they cannot wait since it\'s taking them too long','- حتی زمانی که چراغ قرمز است شروع به دویدن میکنند. زیرا این برای انها زیاد طول می کشد','<div dir=\'rtl\'>کودکان اغلب نمی توانند به درستی خطر اعمال و موقعیت خود را ارزیابی کنند. بنابراین، به عنوان یک راننده، باید انتظار داشته باشید که کودکان از خیابان عبور کنند، حتی اگر چراغ راهنمایی هنوز برای آنها قرمز است، زیرا ممکن است برای صبر کردن بیش از حد بی تاب باشند.</div>',0,'- auch bei Rot loslaufen, weil es ihnen zu lange dauert',1,1,''),
(36,'1.1.02-022','- sich gegenseitig auf die Fahrbahn schubsen','- will push each other onto the roadway','- یکدیگر را به جاده هل دهند','<div dir=\"rtl\">کودکان تنها در سن 8 سالگی قادر به درک و ارزیابی موقعیت های خطرناک هستند. با این حال، در هر سنی، می توان فرض کرد که در طول بازی یکی از عابرین به خیابان هل داده می شود. بنابراین موارد زیر صدق می کند: با دقت و آینده نگری رانندگی کنید.</div>',0,'- sich gegenseitig auf die Fahrbahn schubsen',1,1,''),
(37,'1.1.02-027','Dass sie auf der Fahrbahn stehen bleiben','They may stop on the road','که در جاده توقف می کنند','<div dir=\'rtl\'>اگر افراد مسن کمک راه رفتن دارند به این دلیل است که راه رفتن برایشان مشکل است. بنابراین ممکن است آنها در جاده توقف کنند تا استراحتی کوتاه داشته باشند.</div>',0,'Dass sie auf der Fahrbahn stehen bleiben',1,1,''),
(38,'1.1.02-027','Dass sie auf der Fahrbahn umkehren','They may turn round and go back','که در جاده می چرخند','<div dir=\'rtl\'>به طور کلی، عابران پیاده به دلایل مختلفی می توانند انگیزه ای برای چرخش ناگهانی در هنگام عبور از جاده داشته باشند. شما باید همیشه برای این کار آماده باشید.</div>',0,'Dass sie auf der Fahrbahn umkehren',1,1,''),
(39,'1.1.02-027','Dass sie die Fahrbahn langsam überqueren','They will cross the road slowly','که آهسته از جاده عبور می کنند','<div dir=\'rtl\'>حتی بسیار محتمل است که افراد مسن که به کمک پیاده روی نیز نیاز دارند از جاده به آرامی عبور کنند و نسبت به سایر عابران پیاده زمان بیشتری را صرف کنند.</div>',0,'Dass sie die Fahrbahn langsam überqueren',1,1,''),
(40,'1.1.02-028','Ich fahre so lange hinterher, bis ich überholen kann','I follow behind the wheelchair until I can overtake it','تا زمانی که بتوانم سبقت بگیرم پشت او حرکت می کنم','<div dir=\"rtl\">§ 3 (2a) StVO بیان می کند که رانندگان باید به طور ویژه با افراد نیازمند، کودکان و افراد مسن رفتار کنند. بنابراین، تا زمانی که بتوانید با خیال راحت از آنها سبقت بگیرید، باید پشت سر ویلچر رانندگی کنید.</div>',0,'Ich fahre so lange hinterher, bis ich überholen kann',1,1,''),
(41,'1.1.02-028','Ich überhole mit großem Seitenabstand, weil ich mit Ausweichbewegungen rechnen muss','I overtake it, leaving plenty of room on the side because the wheelchair may swing out','من با فاصله کناری زیاد سبقت می گیرم چون باید منتظر حرکات انحرافی باشم','<div dir=\"rtl\">اگر امکان سبقت بدون خطر وجود داشته باشد، سبقت گرفتن با فاصله جانبی کافی تا ویلچر مجاز است.</div>',0,'Ich überhole mit großem Seitenabstand, weil ich mit Ausweichbewegungen rechnen muss',1,1,''),
(42,'1.1.02-028','Ich mache die Person durch Hupen darauf aufmerksam, dass sie sich falsch verhält','I honk the horn to indicate that the person is not behaving correctly','من به شخص با بوق زدن هشدار می دهم که&nbsp; نادرست رفتار می کند','<div dir=\"rtl\">اگر چه برای&nbsp; ویلچر رفتن در پیاده رو منطقی تر است، اما این به شما اجازه بوق زدن نمی دهد. فرد ویلچری ممکن است نتواند به طور مستقل وارد پیاده رو شود. در این صورت بوق زدن غیرقانونی خواهد بود.</div>',0,'Ich mache die Person durch Hupen darauf aufmerksam, dass sie sich falsch verhält',1,0,''),
(43,'1.1.02-029','Ich halte und schalte die Warnblinkanlage ein','I stop and switch on the hazard warning lights','می ایستم و چراغ خطر را روشن می کنم','<div dir=\'rtl\'>با روشن کردن چراغ‌های هشدار خطر، به سایر کاربران جاده هشدار می‌دهید که هوشیاری بیشتری لازم است. سپس به کاربر ویلچر کمک می کنید تا بر مانع غلبه کند.</div>',0,'Ich halte und schalte die Warnblinkanlage ein',1,1,''),
(44,'1.1.02-029','Ich steige aus und helfe der Person im Rollstuhl','I get out of the car and help the person in the wheelchair','پیاده می شوم و به فردی که روی ویلچر نشسته است کمک می کنم','<div dir=\'rtl\'>طبق §3 (2a) StVO، شما باید \"(...) با کودکان، افراد نیازمند به کمک و افراد مسن تر، به ویژه با کاهش سرعت رانندگی خود و آمادگی برای ترمز، به گونه ای رفتار کنید که خطر این کاربران جاده را منتفی کند.\" کاربر ویلچری که بدون کمک نمی تواند وارد پیاده رو شود، فردی نیازمند است که به کمک شما نیاز دارد.</div>',0,'Ich steige aus und helfe der Person im Rollstuhl',1,1,''),
(45,'1.1.02-029','Ich hupe und fahre um die Person herum','I honk the horn and drive around the person','بوق می زنم و از کنارش رد میشوم','<div dir=\"rtl\">بوق زدن و عبور از کنار فرد ویلچر، فرد ویلچری را از موقعیت خطرناک خارج نمی کند و هیچ کمکی نمی کند.</div>',0,'Ich hupe und fahre um die Person herum',1,0,''),
(46,'1.1.02-032','Dem Mann','The man','مرد','<div dir=\"rtl\">مرد چوب سفیدی را حمل می کند و بازوبند زرد رنگی با سه نقطه سیاه می بندد. این نشان می دهد که مرد کم بینا یا نابینا است.</div>',0,'Dem Mann',1,1,''),
(47,'1.1.02-032','Dem Kind','The child','کودک','<div dir=\'rtl\'>کودک هیچ نشانه قابل مشاهده ای از اختلال بینایی را نشان نمی دهد.</div>',0,'Dem Kind',1,0,''),
(48,'1.1.02-032','Der Frau','The woman','زن','<div dir=\'rtl\'>زن یک عصای سفید، یک سگ راهنما یا یک بازوبند زرد با سه نقطه سیاه حمل نمی کند. بنابراین او هیچ نشانه ای از اختلال بینایی قابل مشاهده خارجی ندارد.</div>',0,'Der Frau',1,0,''),
(49,'1.1.02-039-M','Kinder beobachten','watch out for children','نگاه کردن به بچه ها','<div dir=\'rtl\'>بچه ها نزدیک کنار جاده هستند. به همین دلیل باید سرعت خود را کاهش دهید تا در صورت برخورد به جاده بتوانید به موقع ترمز کنید.</div>',0,'Kinder beobachten',1,1,''),
(50,'1.1.02-039-M','Bremsbereit sein','be ready to brake','آماده ترمز بودن','<div dir=\'rtl\'>ممکن است هر لحظه بچه ها به خیابان بیایند. به همین دلیل باید آماده ترمزگیری باشید.</div>',0,'Bremsbereit sein',1,1,''),
(51,'1.1.02-039-M','Mit unveränderter Geschwindigkeit weiterfahren','continue driving at the same speed','با همان سرعت به رانندگی ادامه دادن','<div dir=\'rtl\'>ادامه دادن به رانندگی با همان سرعت، اگر بچه ها ناگهان به جاده بیفتند، در معرض خطر بزرگی قرار می گیرد.</div>',0,'Mit unveränderter Geschwindigkeit weiterfahren',1,0,''),
(52,'1.1.02-041-M','Die Kinder verlassen die Fahrbahn nicht rechtzeitig','the children will not get off the road in time','بچه ها به موقع جاده را ترک نمی کنند','<div dir=\'rtl\'>به نظر می رسد که بچه ها در حال ترک جاده هستند. با این حال، ممکن است یک موقعیت غیرقابل پیش بینی رخ دهد که شما را ملزم به ترمز کند. به عنوان مثال، توپ می تواند به خیابان بغلتد. با سرعت کم به رانندگی ادامه دهید و آماده ترمز شوید.</div>',0,'Die Kinder verlassen die Fahrbahn nicht rechtzeitig',1,1,''),
(53,'1.1.02-041-M','Einzelne Kinder kehren wieder um','some children will turn around again','تک تک کودکان به عقب برمی گردند','<div dir=\"rtl\">کودکان نمی توانند موقعیت های خطرناک را به خوبی بزرگسالان ارزیابی کنند. بنابراین ممکن است یکی از بچه ها ناگهان بچرخد و دوباره به خیابان&nbsp; برگردد.</div>',0,'Einzelne Kinder kehren wieder um',1,1,''),
(54,'1.1.02-041-M','Alle Kinder warten auf dem Gehweg','all children will wait on the pavement','همه بچه ها در پیاده رو منتظر میمانند','<div dir=\'rtl\'>انتظار در پیاده رو رفتاری مناسب با ترافیک خواهد بود. با این حال، این را نمی توان در مورد کودکان فرض کرد. بنابراین، در اینجا باید بسیار آهسته رانندگی کنید و آماده ترمز باشید.</div>',0,'Alle Kinder warten auf dem Gehweg',1,0,''),
(55,'1.1.02-042-M','Auf Schrittgeschwindigkeit abbremsen','slow to walking pace','ترمز کردن تا رسیدن به سرعت پیاده روی','<div dir=\'rtl\'>سرعت رانندگی خود را به سرعت پیاده روی کاهش دهید تا ایمنی کودکان به خطر نیفتد.</div>',0,'Auf Schrittgeschwindigkeit abbremsen',1,1,''),
(56,'1.1.02-042-M','Bremsbereit bleiben','remain ready to brake','آماده ترمز باشید','<div dir=\"rtl\">بچه ها می توانستند به خیابان بیایند. در این صورت باید برای ترمز آماده باشید.</div>',0,'Bremsbereit bleiben',1,1,''),
(57,'1.1.02-042-M','Unvermindert weiterfahren','continue driving at same speed','بدون کاهش سرعت&nbsp; به رانندگی ادامه دهید','<div dir=\'rtl\'>شما باید به گونه ای رفتار کنید که با شیوه رانندگی خود خطری برای کودکان نداشته باشید.</div>',0,'Unvermindert weiterfahren',1,0,''),
(58,'1.1.02-043-M','Sofort auf Schrittgeschwindigkeit abbremsen','slow to walking pace immediately','فوراً سرعت خود را کاهش دهید و به سرعت پیاده روی برسید','<div dir=\"rtl\">یک توپ در خیابان وجود دارد. این نشان می دهد که کودکان در نزدیکی بازی می کنند. بنابراین باید با سرعت پیاده روی برانید&nbsp; تا خطری برای کودکان ایجاد نشود.</div>',0,'Sofort auf Schrittgeschwindigkeit abbremsen',1,1,''),
(59,'1.1.02-043-M','Bremsbereit bleiben','remain ready to brake','آماده ترمز باشید','<div dir=\'rtl\'>به گفته StVO، شما باید به گونه ای با کودکان رفتار کنید که آنها را به خطر نیندازید، به خصوص با کاهش سرعت رانندگی و آمادگی برای ترمز.</div>',0,'Bremsbereit bleiben',1,1,''),
(60,'1.1.02-043-M','Mit unverminderter Geschwindigkeit vorbeifahren','drive past at the same speed','با سرعتی بدون کاهش از آن عبور کنید','<div dir=\'rtl\'>شما باید در ترافیک طوری رفتار کنید که خطری برای کسی نداشته باشید. در این مورد، این بدان معناست که: آماده ترمز کردن باشید و با سرعت پیاده روی رانندگی کنید، زیرا کودکان ممکن است به خیابان بیایند.</div>',0,'Mit unverminderter Geschwindigkeit vorbeifahren',1,0,''),
(61,'1.1.02-108-B','- nur mit Schrittgeschwindigkeit vorbeifahren','- pass at walking speed only','- فقط با سرعت پیاده روی از کنارش بگذریم','',0,'- nur mit Schrittgeschwindigkeit vorbeifahren',1,1,''),
(62,'1.1.02-108-B','- nur vorbeifahren, wenn eine Gefährdung von Fahrgästen ausgeschlossen ist','- pass only if you are sure that passengers are not endangered','- فقط در صورتی که خطری برای مسافران وجود نداشته باشد از کنار آن عبور کنیم','',0,'- nur vorbeifahren, wenn eine Gefährdung von Fahrgästen ausgeschlossen ist',1,1,''),
(63,'1.1.02-108-B','- in keinem Fall vorbeifahren','- not pass under any circumstances','- تحت هیچ شرایطی رانندگی نکنید','',0,'- in keinem Fall vorbeifahren',1,0,''),
(64,'1.1.02-110-B','Auf beiden Fahrstreifen darf höchstens mit Schrittgeschwindigkeit an dem Bus vorbeigefahren werden','','در هر دو خط عبور، حداکثر با سرعت قدم زدن می‌توان از اتوبوس عبور کرد.','',0,'Auf beiden Fahrstreifen darf höchstens mit Schrittgeschwindigkeit an dem Bus vorbeigefahren werden',1,1,''),
(65,'1.1.02-110-B','Auf beiden Fahrstreifen muss angehalten werden, wenn sonst Fahrgäste gefährdet würden','','در هر دو خط عبور باید توقف کرد، اگر در غیر این صورت مسافران به خطر بیفتند.','',0,'Auf beiden Fahrstreifen muss angehalten werden, wenn sonst Fahrgäste gefährdet würden',1,1,''),
(66,'1.1.02-110-B','Die Fahrzeuge auf dem linken Fahrstreifen dürfen ohne besondere Vorsicht an dem Bus vorbeifahren','','وسایل نقلیه در خط عبور سمت چپ می‌توانند بدون احتیاط ویژه از اتوبوس عبور کنند.','',0,'Die Fahrzeuge auf dem linken Fahrstreifen dürfen ohne besondere Vorsicht an dem Bus vorbeifahren',1,0,''),
(67,'1.1.02-116','- dürfen nicht gefährdet werden','- may not be endangered','- نباید در خطر باشد','<div dir=\'rtl\'>باید طوری رفتار کنید که سوار و پیاده شدن مسافران در خطر نباشند. این به معنای کاهش سرعت و آمادگی برای ترمز است.</div>',0,'- dürfen nicht gefährdet werden',1,1,''),
(68,'1.1.02-116','- dürfen nicht behindert werden','- may not be impeded','- نباید سد مسیر بشوند','<div dir=\'rtl\'>باید طوری رفتار کنید که سوار و پیاده شدن مسافران در خطر نباشند. این به معنای کاهش سرعت و آمادگی برای ترمز است.</div>',0,'- dürfen nicht behindert werden',1,1,''),
(69,'1.1.02-116','- dürfen mit der Hupe gewarnt werden','- may be warned using the horn','- ممکن است با بوق هشدار داده شود','<div dir=\'rtl\'>هشدار دادن به مسافران با بوق ممنوع است. شما نمی توانید مانع آنها شوید.</div>',0,'- dürfen mit der Hupe gewarnt werden',1,0,''),
(70,'1.1.03-001','An Baustellen','Near construction sites','در محل‌های ساخت و ساز','<div dir=\'rtl\'>زیرا در اینجا مصالح ساختمانی زیادی حمل می‌شود، می‌تواند به سرعت منجر به آلودگی سطح جاده شود. به ویژه به دلیل شرایط آب و هوایی مانند باران و باد، مصالح ساختمانی می‌تواند در جاده پخش شود و در نتیجه به یک خطر لغزنده برای راننده تبدیل شود.</div>',0,'An Baustellen',1,1,''),
(71,'1.1.03-001','An Einmündungen von Feldwegen','At junctions with farm tracks','در محل تلاقی با جاده‌های خاکی/فرعی','<div dir=\'rtl\'>جاده‌های خاکی اغلب آسفالت نشده‌اند، بلکه از شن یا ماسه تشکیل شده‌اند. این مواد می‌توانند توسط لاستیک وسایل نقلیه به سطح جاده در ورودی و خروجی جاده خاکی منتقل شوند و در نتیجه نیز به دلیل تأثیرات آب و هوایی، خطر لغزش بالقوه‌ای را ایجاد کنند.</div>',0,'An Einmündungen von Feldwegen',1,1,''),
(72,'1.1.03-001','An innerstädtischen Kreuzungen','At innercity crossroads','در تقاطع‌های درون‌شهری','<div dir=\'rtl\'>از آنجایی که اینها آسفالت شده و معمولاً پرتردد هستند، در اینجا به طور معمول می‌توان انتظار یک سطح جاده غیرلغزنده و تمیز را داشت.</div>',0,'An innerstädtischen Kreuzungen',1,0,''),
(73,'1.1.03-003','Auf Brücken','On bridges','روی پل‌ها','<div dir=\'rtl\'>در زیر پل‌ها، زمین به عنوان یک ذخیره‌کننده گرما وجود ندارد. علاوه بر این، باد باعث خنک شدن بیشتر و سریع‌تر سطح جاده‌ای می‌شود که در اثر تردد گرم شده است.</div>',0,'Auf Brücken',1,1,''),
(74,'1.1.03-003','Auf Strecken, die durch Wald führen','On stretches of road running through forest','در مسیرهایی که از میان جنگل می‌گذرند','<div dir=\'rtl\'>در جنگل، تابش نور خورشید توسط درختان محدود می‌شود. به همین دلیل، جاده نمی‌تواند به اندازه‌ای که در جاده‌های باز اتفاق می‌افتد، توسط گرمای خورشید گرم شده و یخ ذوب شود. علاوه بر این، جاده‌های جنگلی اغلب کمتر از بزرگراه‌ها مورد استفاده قرار می‌گیرند.</div>',0,'Auf Strecken, die durch Wald führen',1,1,''),
(75,'1.1.03-003','Auf stark befahrenen Strecken','On frequently used stretches of road','در مسیرهای پرتردد','<div dir=\'rtl\'>در جاده‌های پرتردد، به دلیل انتشار زیاد گازهای خروجی، گرمای بیشتری به جاده‌ها منتقل می‌شود. بنابراین، یخ کمتر به راحتی تشکیل می‌شود یا باقی می‌ماند. با این حال، حتی در جاده‌های پرتردد نیز باید صبح‌ها احتیاط بیشتری کرد، زیرا شب‌ها تردد کمتری وجود دارد و سطح زمین خنک می‌شود.</div>',0,'Auf stark befahrenen Strecken',1,0,''),
(76,'1.1.03-102-B','Weil die Fahrbahnoberfläche uneben und unterschiedlich griffig ist','The road surface is uneven and road grip varies','زیرا سطح جاده ناهموار و دارای اصطحکاک متفاوتی است','<div dir=\"rtl\">به این ترتیب لاستیک‌ها&nbsp;<span style=\"background-color: rgba(102, 126, 234, 0.1);\">اصطحکاک</span>&nbsp;کمتری دارند و مسافت ترمز طولانی‌تر می‌شود.</div>',0,'Weil die Fahrbahnoberfläche uneben und unterschiedlich griffig ist',1,1,''),
(77,'1.1.03-102-B','Weil eine Straßenbahn entgegenkommen könnte','A tram might come from the opposite direction','زیرا ممکن است یک تراموا از روبرو بیاید','<div dir=\'rtl\'>در صورت بروز این وضعیت، باید با سرعتی رانندگی کنید که بتوانید فاصله خود را با تراموا به اندازه کافی تخمین بزنید.</div>',0,'Weil eine Straßenbahn entgegenkommen könnte',1,1,''),
(78,'1.1.03-102-B','Weil das Fahren auf den Schienen gefährlich ist','Driving on the tracks is dangerous','زیرا رانندگی روی ریل‌ها خطرناک است','<div dir=\"rtl\">ممکن است یک تراموا از پشت یا جلو به سمت شما بیاید. در این صورت، باید یک راه فرار در نظر داشته باشید که هیچ شرکت‌کننده دیگری در ترافیک به خطر نیفتد. این تنها از طریق رانندگی پیش‌بینانه امکان‌پذیر است. علاوه بر این، ریل‌ها می‌توانند لغزنده باشند و&nbsp;<span style=\"background-color: rgba(102, 126, 234, 0.1);\">اصطحکاک</span>&nbsp;لاستیک‌ها به زمین را کاهش دهند.</div>',0,'Weil das Fahren auf den Schienen gefährlich ist',1,1,''),
(79,'1.1.03-104','Beschleunigen','Accelerating','شتاب گرفتن','<div dir=\'rtl\'>در یک سطح یخ‌زده، باید تلاش کرد تا خطر لغزش را تا حد امکان پایین نگه داشت. بنابراین، در جاده‌های یخ‌زده باید با احتیاط بسیار زیاد و سرعت کم رانندگی کرد.</div>',0,'Beschleunigen',1,1,''),
(80,'1.1.03-104','Bremsen','Braking','ترمز کردن','<div dir=\'rtl\'>تا حد امکان ترمز نکنید، زیرا در غیر این صورت به راحتی ممکن است دچار لغزش شوید. در عوض، اجازه دهید خودرو به آرامی حرکت خود را از دست بدهد و متوقف شود.</div>',0,'Bremsen',1,1,''),
(81,'1.1.03-104','Lenkbewegungen','Steering wheel movements','حرکات فرمان','<div dir=\'rtl\'>حتی کوچکترین حرکت کنترل‌نشده فرمان می‌تواند در یک جاده یخ‌زده منجر به تصادف شود. بنابراین، در شرایط لغزنده باید با دقت بسیار رانندگی کنید و از حرکات ناگهانی یا عجولانه فرمان خودداری کنید.</div>',0,'Lenkbewegungen',1,1,''),
(82,'1.1.03-105','Bei ganz langsamer Fahrt bremsen','By carefully applying the brakes at very low speed','در سرعت بسیار پایین ترمز کنید','<div dir=\'rtl\'>آزمایش ترمز در سرعت بسیار پایین برای ارزیابی وضعیت جاده در هنگام یخبندان مهم است. در این صورت، مسافت توقف نسبتاً کوتاه است و خطر لغزش حداقل است. بنابراین، چنین آزمایشی توصیه می شود تا بتوانید پس از آن، رفتار رانندگی خود را بهتر کنترل کنید. به این ترتیب می توان از به خطر افتادن سایر کاربران جاده نیز جلوگیری کرد.</div>',0,'Bei ganz langsamer Fahrt bremsen',1,1,''),
(83,'1.1.03-105','Lenkung ruckartig hin- und herbewegen','By jerking the steering wheel to the left and right','فرمان را ناگهانی به این سو و آن سو حرکت دهید','<div dir=\'rtl\'>در شرایط خاص جاده (مانند یخ، شن ریزه)، باید از حرکات ناگهانی فرمان خودداری کرد، زیرا در غیر این صورت خطر لغزش وجود دارد.</div>',0,'Lenkung ruckartig hin- und herbewegen',1,0,''),
(84,'1.1.03-105','Kräftig Gas geben','By rapid acceleration','محکم گاز دهید','<div dir=\'rtl\'>محکم گاز دادن خطر لغزش را در سطوح جاده یخ زده افزایش می دهد، زیرا لاستیک ها می توانند به سرعت چسبندگی خود را از دست بدهند. بنابراین، در جاده یخ زده باید آهسته رانندگی کرد.</div>',0,'Kräftig Gas geben',1,0,''),
(85,'1.1.03-108-B','Weil die Fahrbahn glatt ist','Because the roadway is slippery','زیرا سطح جاده لغزنده است','<div dir=\'rtl\'>به دلیل برف و یخ‌زدگی، در اینجا حتماً باید آهسته و با احتیاط رانندگی کرد.</div>',0,'Weil die Fahrbahn glatt ist',1,1,''),
(86,'1.1.03-108-B','Weil die Sicht durch die Kurve behindert ist','Because the view is obscured by the bend','زیرا دید به دلیل پیچ محدود شده است','<div dir=\'rtl\'>به دلیل پیچ، مشخص نیست که جاده چگونه ادامه می‌یابد. این موضوع در ترکیب با شرایط آب و هوایی و خودروی پارک شده باید شما را وادار کند که بسیار آهسته و با احتیاط رانندگی کنید.</div>',0,'Weil die Sicht durch die Kurve behindert ist',1,1,''),
(87,'1.1.03-108-B','Weil die Fahrbahn durch den falsch parkenden Pkw verengt ist','Because the roadway is made narrower by the wrongly parked car','زیرا سطح جاده به دلیل پارک نادرست خودروی سواری باریک شده است','<div dir=\'rtl\'>پارک کردن در پیچ‌ها ممنوع است. خودروی سواری به این ترتیب دید شما را نسبت به پیچ و ترافیک احتمالی روبرو که از قبل محدود بوده، بیشتر مختل می‌کند. بنابراین، باید با نهایت احتیاط و آهسته به پیچ نزدیک شوید تا در صورت وجود ترافیک روبرو، بتوانید سریع و ایمن واکنش نشان دهید.</div>',0,'Weil die Fahrbahn durch den falsch parkenden Pkw verengt ist',1,1,''),
(88,'1.1.03-109','An Flussläufen','Near rivers','در کنار رودخانه‌ها','<div dir=\'rtl\'>مه زمانی تشکیل می‌شود که هوای اشباع شده از بخار آب خنک شود. بنابراین، در کنار رودخانه‌ها باید انتظار توده‌های مه را داشت.</div>',0,'An Flussläufen',1,1,''),
(89,'1.1.03-109','In Moorgebieten','In marshy areas','در مناطق باتلاقی','<div dir=\'rtl\'>باتلاق‌های مرطوب به دلیل رطوبت بالای خود، تشکیل مه را تسهیل می‌کنند.</div>',0,'In Moorgebieten',1,1,''),
(90,'1.1.03-109','An Seen','Near lakes','در کنار دریاچه‌ها','<div dir=\'rtl\'>به طور کلی، آب‌ها تشکیل مه را تسهیل می‌کنند. بنابراین، مه در کنار دریاچه‌ها نیز تشکیل می‌شود و می‌تواند دید راننده را مختل کند.</div>',0,'An Seen',1,1,''),
(91,'1.1.03-110','Geschwindigkeit rechtzeitig den Sichtverhältnissen anpassen','Adapt your speed in time to visibility conditions','سرعت را به موقع با شرایط دید تطبیق دهید','<div dir=\'rtl\'>در بند ۱ ماده ۳ قانون راهنمایی و رانندگی (StVO) تعریف شده است که راننده وسیله نقلیه فقط باید با سرعتی حرکت کند که بتواند وسیله نقلیه خود را همیشه کنترل کند. او باید سرعت خود را به ویژه با شرایط دید و آب و هوا تطبیق دهد. از آنجایی که دید به دلیل مه مختل می‌شود، فقط باید با سرعتی رانندگی کرد که بتوان در هر زمان با ایمنی توقف کرد.</div>',0,'Geschwindigkeit rechtzeitig den Sichtverhältnissen anpassen',1,1,''),
(92,'1.1.03-110','Abstand zum vorausfahrenden Fahrzeug vergrößern','Increase the distance from the vehicle in front','فاصله با وسیله نقلیه جلویی را افزایش دهید','<div dir=\'rtl\'>در مه، سطح جاده مرطوب است. این باعث افزایش مسافت ترمزگیری وسیله نقلیه می‌شود و علاوه بر این، دید به وسیله نقلیه جلویی محدود است. بر این اساس، باید فاصله با وسیله نقلیه جلویی افزایش یابد تا خطر تصادف از پشت به حداقل برسد.</div>',0,'Abstand zum vorausfahrenden Fahrzeug vergrößern',1,1,''),
(93,'1.1.03-110','Dicht aufschließen, um sich an den Schlussleuchten des vorausfahrenden Fahrzeugs zu orientieren','Drive up close to the vehicle in front so you can use its rear lights as an orientation point','نزدیک بچسبید تا با چراغ‌های عقب وسیله نقلیه جلویی خود را جهت‌یابی کنید','<div dir=\'rtl\'>نزدیک رانندگی کردن (فاصله کم گرفتن) باعث تصادفات از پشت می‌شود. به ویژه در ترکیب با یک سطح جاده مرطوب، این می‌تواند فاجعه‌بار باشد. بنابراین، فاصله ایمنی در مه باید بیشتر افزایش یابد تا در صورت توقف ناگهانی وسیله نقلیه جلویی، بتوان با ایمنی و به آرامی ترمز کرد.</div>',0,'Dicht aufschließen, um sich an den Schlussleuchten des vorausfahrenden Fahrzeugs zu orientieren',1,0,''),
(94,'1.1.03-114-M','Weil der Straßenverlauf unübersichtlich ist','Because it is not clear which direction the road will take','زیرا مسیر جاده دید کافی ندارد','<div dir=\'rtl\'>انتهای پیچ و ترافیک روبرو در اینجا قابل مشاهده نیستند. بنابراین، باید به آرامی و با احتیاط به پیچ نزدیک شوید.</div>',0,'Weil der Straßenverlauf unübersichtlich ist',1,1,''),
(95,'1.1.03-114-M','Weil die Fahrbahnoberfläche ungleichmäßig ist','Because the road surface is uneven','زیرا سطح جاده ناهموار است','<div dir=\'rtl\'>به دلیل سطح ناهموار جاده، لاستیک‌ها چسبندگی کمتری دارند. باید این را در رانندگی خود در نظر بگیرید.</div>',0,'Weil die Fahrbahnoberfläche ungleichmäßig ist',1,1,''),
(96,'1.1.03-114-M','Weil der Gegenverkehr die Kurve schneiden könnte','Because oncoming traffic could cut the corner','زیرا ترافیک روبرو ممکن است پیچ را ببرد','<div dir=\'rtl\'>ترافیک روبرو در اینجا قابل مشاهده نیست و این امکان وجود دارد که پیچ را ببرد. به همین دلیل باید در اینجا توجه ویژه‌ای داشته باشید.</div>',0,'Weil der Gegenverkehr die Kurve schneiden könnte',1,1,''),
(97,'1.1.04-103-B','Zum rechten Fahrbahnrand schauen','Look to the right-hand edge of the roadway','به لبه سمت راست جاده نگاه کنید','<div dir=\'rtl\'>اگر نور وسایل نقلیه روبرو شما را خیره می‌کند، نگاه کردن به لبه سمت راست جاده مفید است. به این ترتیب، شما همچنان دیدی به ترافیک پیش رو خواهید داشت و کمتر توسط چراغ‌های جلوی وسایل نقلیه روبرو آشفته می‌شوید.</div>',0,'Zum rechten Fahrbahnrand schauen',1,1,''),
(98,'1.1.04-103-B','Geschwindigkeit notfalls vermindern','If necessary, reduce your speed','در صورت لزوم، سرعت را کاهش دهید','<div dir=\'rtl\'>اگر خیرگی، رانندگی ایمن شما را محدود می‌کند، باید آهسته‌تر برانید و به لبه سمت راست جاده نگاه کنید.</div>',0,'Geschwindigkeit notfalls vermindern',1,1,''),
(99,'1.1.04-103-B','Beschleunigen, um schneller aus dem Lichtkegel herauszukommen','Accelerate to get out of the beam of light more quickly','شتاب بگیرید تا سریع‌تر از مخروط نور خارج شوید','<div dir=\'rtl\'>این بسیار خطرناک خواهد بود، زیرا میدان دید شما از قبل توسط چراغ‌های خیره‌کننده محدود شده است.</div>',0,'Beschleunigen, um schneller aus dem Lichtkegel herauszukommen',1,0,''),
(100,'1.1.04-107','Dass Ihr Fahrzeug von anderen nicht rechtzeitig gesehen wird','That your vehicle will not be seen in time','اینکه وسیله نقلیه شما به موقع توسط دیگران دیده نشود','<div dir=\'rtl\'>محیط اطراف به شدت با چراغ‌های رنگارنگ روشن شده است. به همین دلیل، رانندگان دیگر ممکن است به دلیل سطح بالای نور، نتوانند وسیله نقلیه شما را به خوبی از محیط تاریک اطراف تشخیص دهند و احتمالاً شما را به موقع نبینند.</div>',0,'Dass Ihr Fahrzeug von anderen nicht rechtzeitig gesehen wird',1,1,''),
(101,'1.1.04-107','Dass Sie entgegenkommende Fahrzeuge erst spät erkennen','That you only detect oncoming vehicles after it is too late','اینکه شما وسایل نقلیه روبرو را دیر تشخیص دهید','<div dir=\'rtl\'>به دلیل وجود تابلوهای نئون رنگارنگ زیاد، تشخیص وسایل نقلیه دیگر از محیط اطراف برای شما دشوارتر می‌شود. بنابراین ممکن است وسایل نقلیه روبرو را دیرتر تشخیص دهید.</div>',0,'Dass Sie entgegenkommende Fahrzeuge erst spät erkennen',1,1,''),
(102,'1.1.04-107','Dass sich Ampeln von den bunten Lichtreklamen kaum abheben','That the traffic lights are hardly distinct from the coloured signs','اینکه چراغ‌های راهنمایی و رانندگی به سختی از تابلوهای نئون رنگارنگ متمایز شوند','<div dir=\'rtl\'>چراغ‌های راهنمایی و رانندگی شبیه به نورهای رنگارنگ محیط اطراف هستند. آنها به شدت از محیط متمایز نمی‌شوند و بنابراین ممکن است دیرتر تشخیص داده شوند.</div>',0,'Dass sich Ampeln von den bunten Lichtreklamen kaum abheben',1,1,''),
(103,'1.1.05-001','An Straßenkreuzungen und -einmündungen','At crossroads and junctions','در تقاطع‌ها و ورودی‌های خیابان','<div dir=\'rtl\'>در تقاطع‌ها و ورودی‌ها، راننده دید محدودی به وضعیت ترافیک دارد. وسایل نقلیه احتمالی که در حال نزدیک شدن هستند ممکن است دیرتر دیده شوند. رانندگی سریع باعث طولانی‌تر شدن مسیر واکنش و طولانی شدن مسافت ترمز برای توقف می‌شود. این می‌تواند منجر به تصادف شود.</div>',0,'An Straßenkreuzungen und -einmündungen',1,1,''),
(104,'1.1.05-001','An Fußgängerüberwegen','At pedestrian crossings','در گذرگاه‌های عابر پیاده','<div dir=\'rtl\'>عابران پیاده‌ای که ناگهان وارد مسیر حرکت می‌شوند، تنها زمان واکنش بسیار کوتاه و مسافت ترمز بسیار کمی را امکان‌پذیر می‌سازند. در صورت رانندگی با سرعت زیاد، مسیر واکنش طولانی‌تر و مسافت ترمز برای توقف بیش از حد طولانی می‌شود تا عبور ایمن عابران پیاده تضمین شود. بنابراین، به محض اینکه یک گذرگاه عابر پیاده در دید قرار گرفت، سرعت رانندگی باید با توجه به احتمال عبور عابران تنظیم شود.</div>',0,'An Fußgängerüberwegen',1,1,''),
(105,'1.1.05-001','In Kurven','On bends','در پیچ‌ها','<div dir=\'rtl\'>به دلیل نیروی گریز از مرکز، خودرو در پیچ به سمت لبه پیچ رانده می‌شود. با افزایش سرعت خودرو، نیروی گریز از مرکز به سمت «بیرون» تقویت می‌شود و می‌تواند منجر به «خارج شدن از پیچ» شود.</div>',0,'In Kurven',1,1,''),
(106,'1.1.05-002','In unübersichtlichen Kurven','At blind corners','در پیچ‌های با دید محدود','<div dir=\'rtl\'>در اینجا فقط بخش کوچکی از مسیر رانندگی قابل مشاهده است. به همین دلیل، رانندگی پیش‌بینانه امکان‌پذیر نیست و موانع پس از پیچ قابل مشاهده نیستند. همچنین، ترافیک مقابل اغلب به دلیل پیچ قابل ارزیابی کافی نیست. علاوه بر این، در صورت رانندگی با سرعت زیاد، وسیله نقلیه ممکن است «از پیچ خارج شود». بنابراین، سرعت رانندگی باید با میزان دید جاده تنظیم شود.</div>',0,'In unübersichtlichen Kurven',1,1,''),
(107,'1.1.05-002','An Fahrbahnverengungen','At road narrowings','در محل‌های تنگ شدن جاده','<div dir=\'rtl\'>اگر جاده بیش از حد باریک باشد، در نقاط تنگ ممکن است عبور از کنار ترافیک مقابل مشکل‌ساز شود. بنابراین، باید آهسته رانندگی کرد تا در صورت لزوم بتوان ترمز کرد یا کمی به سمت راست منحرف شد، بدون اینکه خطر تصادف وجود داشته باشد.</div>',0,'An Fahrbahnverengungen',1,1,''),
(108,'1.1.05-002','An Bahnübergängen','At level crossings','در گذرگاه‌های ریلی (تقاطع راه‌آهن)','<div dir=\'rtl\'>برای عبور ایمن از گذرگاه ریلی، رانندگی پیش‌بینانه و آهسته ضروری است. تنها با این روش می‌توانید تخمین بزنید که یک وسیله نقلیه ریلی در حال نزدیک شدن چقدر فاصله دارد و به علائم راهنمایی و رانندگی توجه کنید.</div>',0,'An Bahnübergängen',1,1,''),
(109,'1.1.05-003','Vor der Kurve Geschwindigkeit vermindern','Reduce speed before reaching the bend','قبل از پیچ سرعت را کاهش دهید','<div dir=\'rtl\'>به دلیل نیروی گریز از مرکز، خودرو در پیچ به سمت لبه جاده رانده می‌شود. این اثر با سرعت بالا تشدید می‌گردد. بنابراین، برای جلوگیری از «خارج شدن از پیچ» و ورود به لاین مقابل، باید با سرعت کم وارد پیچ شد.</div>',0,'Vor der Kurve Geschwindigkeit vermindern',1,1,''),
(110,'1.1.05-003','Erst beim Übergang in die Gerade wieder beschleunigen','Only accelerate again when the road straightens out','فقط هنگام ورود به مسیر مستقیم دوباره شتاب بگیرید','<div dir=\'rtl\'>شتاب گرفتن در پیچ می‌تواند خطر لغزش را افزایش دهد. بنابراین، تنها زمانی باید دوباره گاز داد که خودرو به انتهای پیچ رسیده باشد.</div>',0,'Erst beim Übergang in die Gerade wieder beschleunigen',1,1,''),
(111,'1.1.05-003','Erst im Scheitelpunkt der Kurve Geschwindigkeit vermindern','Reduce speed only when you reach the centre of the bend','فقط در اوج پیچ سرعت را کاهش دهید','<div dir=\'rtl\'>اوج پیچ خطرناک‌ترین لحظه است، زیرا در این نقطه خطر لغزش خودرو در بالاترین حد خود قرار دارد. بنابراین، باید با احتیاط و سرعت کم وارد پیچ شد.</div>',0,'Erst im Scheitelpunkt der Kurve Geschwindigkeit vermindern',1,0,''),
(112,'1.1.06-002','Ja, weil der Lastzug die Sicht auf wichtige Verkehrszeichen verdecken kann','Yes, because the truck and trailer can obscure the view of important traffic signs','بله، زیرا کامیون می‌تواند دید را نسبت به علائم راهنمایی و رانندگی مهم مسدود کند.','<div dir=\'rtl\'>به دلیل ارتفاع زیاد وسیله نقلیه سنگین (کامیون)، دید نسبت به تقاطع محدود است. علائم راهنمایی و رانندگی نسبتاً کوچک در مقایسه با کامیون، می‌توانند به راحتی با سبقت گرفتن از کامیون نادیده گرفته شوند. بنابراین، باید از مانور سبقت خودداری کرد.</div>',0,'Ja, weil der Lastzug die Sicht auf wichtige Verkehrszeichen verdecken kann',1,1,''),
(113,'1.1.06-002','Ja, weil der Lastzug die Sicht auf den Querverkehr verdeckt','Yes, because the truck and trailer can obscure the view of the crossing traffic','بله، زیرا کامیون دید را نسبت به ترافیک عرضی مسدود می‌کند.','<div dir=\'rtl\'>یک کامیون همچنین می‌تواند دید را نسبت به ترافیک در یک تقاطع مسدود کند. ترافیک عرضی که ممکن است بخواهد به خیابان شما بپیچد، بدین ترتیب دیده نمی‌شود و ممکن است تصادف رخ دهد.</div>',0,'Ja, weil der Lastzug die Sicht auf den Querverkehr verdeckt',1,1,''),
(114,'1.1.06-002','Nein, weil Lastzüge meist langsam fahren','No, because trucks and trailers mostly drive at low speed','خیر، زیرا کامیون‌ها معمولاً آهسته حرکت می‌کنند.','<div dir=\'rtl\'>به طور کلی نمی‌توان فرض کرد که کامیون‌ها آهسته حرکت می‌کنند. همچنین نباید از وسایل نقلیه دیگر قبل از تقاطع‌ها سبقت گرفت، زیرا این کار بی‌احتیاطی است و ایمنی ترافیک جاده‌ای را به خطر می‌اندازد.</div>',0,'Nein, weil Lastzüge meist langsam fahren',1,0,''),
(115,'1.1.06-104','- plötzlich beschleunigt','- suddenly accelerates','- ناگهان شتاب می‌گیرد','<div dir=\'rtl\'>در این صورت، مسیر سبقت طولانی‌تر می‌شود. سبقت‌گیرنده نمی‌تواند چنین رفتاری را پیش‌بینی کند، اما این کار می‌تواند منجر به یک وضعیت خطرناک (مثلاً به دلیل ترافیک مقابل) شود. طبق آیین‌نامه راهنمایی و رانندگی، افزایش سرعت هنگام سبقت گرفتن ممنوع است.</div>',0,'- plötzlich beschleunigt',1,1,''),
(116,'1.1.06-104','- zum Überholen ausschert','- swerves out to overtake','- برای سبقت گرفتن از مسیر خارج می‌شود','<div dir=\'rtl\'>در این صورت ممکن است سبقت‌گیرنده در نقطه کور خودروی جلویی قرار داشته باشد و خودروی جلویی بدون دیدن وسیله نقلیه در حال نزدیک شدن، از مسیر خارج شود.</div>',0,'- zum Überholen ausschert',1,1,''),
(117,'1.1.06-104','- seine Geschwindigkeit stark verringert','- reduces his speed considerably','- سرعت خود را به شدت کاهش می‌دهد','<div dir=\'rtl\'>اگر وسیله نقلیه‌ای که از آن سبقت گرفته می‌شود، سرعت خود را به شدت کاهش دهد، مسیر سبقت به طور قابل توجهی کوتاه‌تر می‌شود. سبقت‌گیرنده می‌تواند زودتر به خط عبور سمت راست بازگردد و برای مدت طولانی در خط مقابل قرار نمی‌گیرد. در نتیجه، کسی به خطر نمی‌افتد.</div>',0,'- seine Geschwindigkeit stark verringert',1,0,''),
(118,'1.1.06-105','Wenn der Eingeholte plötzlich beschleunigt','When the road user being overtaken suddenly accelerates','اگر وسیله نقلیه سبقت‌شونده ناگهان شتاب بگیرد','<div dir=\'rtl\'>در این صورت، فرآیند سبقت گرفتن به طور قابل توجهی طولانی‌تر می‌شود. مسافت مورد نیاز افزایش می‌یابد. بنابراین بهتر است فرآیند سبقت گرفتن را متوقف کرد.</div>',0,'Wenn der Eingeholte plötzlich beschleunigt',1,1,''),
(119,'1.1.06-105','Wenn durch unerwarteten Gegenverkehr Gefahr entsteht','When there is danger from unexpected oncoming traffic','اگر به دلیل ترافیک غیرمنتظره از روبرو خطر ایجاد شود','<div dir=\'rtl\'>یک وسیله نقلیه که ناگهان ظاهر می‌شود می‌تواند زمان برنامه‌ریزی شده برای سبقت گرفتن را به طور قابل توجهی کاهش دهد. مسافت موجود نیز کوتاه‌تر می‌شود. بنابراین بهتر است فرآیند سبقت گرفتن را متوقف کرده و در صورت لزوم، در زمان مناسب دوباره برای سبقت گرفتن اقدام کرد.</div>',0,'Wenn durch unerwarteten Gegenverkehr Gefahr entsteht',1,1,''),
(120,'1.1.06-105','Wenn der Eingeholte seine Geschwindigkeit stark verringert','When the road user being overtaken considerably reduces his speed','اگر وسیله نقلیه سبقت‌شونده سرعت خود را به شدت کاهش دهد','<div dir=\'rtl\'>اگر وسیله نقلیه سبقت‌شونده سرعت خود را کاهش دهد، این کار فرآیند سبقت گرفتن را تسریع می‌کند. وسیله نقلیه سبقت‌گیرنده می‌تواند سریع‌تر به جلوی وسیله نقلیه سبقت‌شونده بازگردد. این امر سبقت گرفتن ایمن را تسهیل می‌کند.</div>',0,'Wenn der Eingeholte seine Geschwindigkeit stark verringert',1,0,''),
(121,'1.1.06-106','Wenn Sie nicht wesentlich schneller fahren können als der zu Überholende','If you are unable to drive considerably faster than the road user being overtaken','اگر نمی‌توانید به طور قابل توجهی سریع‌تر از وسیله نقلیه مورد سبقت حرکت کنید','<div dir=\'rtl\'>اگر قدرت موتور وسیله نقلیه خود را بیش از حد تخمین بزنید، این می‌تواند در فرآیند سبقت عواقب بسیار خطرناکی داشته باشد. به این ترتیب، فرآیند سبقت ممکن است بیشتر از آنچه در ابتدا تخمین زده شده بود طول بکشد و در نتیجه، مسافت مورد نیاز در زمان برنامه‌ریزی شده طی نشود. این امر باعث می‌شود سبقت گرفتن بسیار خطرناک شود. ممکن است وسیله نقلیه‌ای در مسیر مقابل ظاهر شود و خطر تصادف به وجود آید.</div>',0,'Wenn Sie nicht wesentlich schneller fahren können als der zu Überholende',1,1,''),
(122,'1.1.06-106','Wenn Sie nicht die gesamte Überholstrecke überblicken','If you do not have a clear view of the road ahead','اگر نمی‌توانید کل مسیر سبقت را ببینید','<div dir=\'rtl\'>اگر کل مسیر قابل مشاهده نباشد، نمی‌توان تخمین زد که چه چیزی در مسیر مقابل قرار دارد (یا آیا مانعی در مسیر خودتان وجود دارد). بنابراین، سبقت گرفتن در این وضعیت خطرناک است و باید صبر کرد تا دید کافی به جاده برای سبقت گرفتن فراهم شود.</div>',0,'Wenn Sie nicht die gesamte Überholstrecke überblicken',1,1,''),
(123,'1.1.06-106','Wenn die Verkehrslage unklar ist','If the traffic situation is not clear','اگر وضعیت ترافیک نامشخص باشد','<div dir=\'rtl\'>بنابراین، ارزیابی رفتار رانندگان دیگر امکان‌پذیر نیست. طبق قانون راهنمایی و رانندگی (StVO)، وضعیت ترافیک باید واضح باشد تا بتوان مانور سبقت را آغاز کرد.</div>',0,'Wenn die Verkehrslage unklar ist',1,1,''),
(124,'1.1.07-001','- seine Geschwindigkeit stark vermindern','- reduce speed drastically','- سرعت خود را به شدت کاهش دهد','<div dir=\'rtl\'>به خصوص زمانی که یک کامیون بخواهد وارد یک خیابان باریک شود، سرعت خود را به شدت کاهش خواهد داد، زیرا شعاع گردش بزرگتری نسبت به یک خودروی سواری دارد. بر این اساس، او باید با احتیاط بسیار در پیچ حرکت کند.</div>',0,'- seine Geschwindigkeit stark vermindern',1,1,''),
(125,'1.1.07-001','- vor dem Abbiegen nach links ausscheren','- swing out to the left before turning','- قبل از گردش به راست، به سمت چپ منحرف شود','<div dir=\'rtl\'>از آنجایی که کامیون شعاع گردش بزرگتری نسبت به خودروی سواری دارد، برای راننده آن، به خصوص در پیچ‌های بسیار تنگ، لازم است که برای عبور از آنها به سمت بیرون منحرف شود.</div>',0,'- vor dem Abbiegen nach links ausscheren',1,1,''),
(126,'1.1.07-001','- sich besonders weit rechts einordnen','- move well over to the right','- به خصوص در سمت راست قرار گیرد','<div dir=\'rtl\'>اگر کامیون در سمت راست قرار گیرد، پیچ را قطع خواهد کرد (نمی‌تواند بپیچد). به دلیل طول کامیون، لازم است که برای گردش به راست، به سمت چپ منحرف شود.</div>',0,'- sich besonders weit rechts einordnen',1,0,''),
(127,'1.1.07-002','Kreuzende oder einmündende Straßen können bevorrechtigt sein, obwohl sie schmal und weniger gut ausgebaut sind','Intersecting roads may have priority even though they are narrow and less well developed','جاده‌های متقاطع یا ورودی ممکن است حق تقدم داشته باشند، حتی اگر باریک و کمتر توسعه‌یافته باشند','<div dir=\'rtl\'>ترافیک یا توسط یک افسر پلیس، چراغ راهنمایی، علائم راهنمایی و رانندگی یا قانون اساسی «راست به چپ» تنظیم می‌شود. نحوه ساخت و ساز جاده در این مورد مهم نیست. کاملاً این امکان وجود دارد که یک جاده پهن و خوب ساخته شده، توسط علائم راهنمایی و رانندگی به یک جاده فرعی تبدیل شود.</div>',0,'Kreuzende oder einmündende Straßen können bevorrechtigt sein, obwohl sie schmal und weniger gut ausgebaut sind',1,1,''),
(128,'1.1.07-002','Die breitere Straße ist immer bevorrechtigt','A better developed road always has priority','جاده پهن‌تر همیشه حق تقدم دارد','<div dir=\'rtl\'>عرض جاده اطلاعاتی در مورد قوانین راهنمایی و رانندگی نمی‌دهد. در ترافیک، مقررات حق تقدم باید به ترتیب زیر رعایت شوند: ۱. یک افسر پلیس (در صورت وقوع تصادف یا خرابی چراغ راهنمایی)، ۲. چراغ‌های راهنمایی، ۳. سایر علائم راهنمایی و رانندگی، ۴. قانون اساسی «راست به چپ».</div>',0,'Die breitere Straße ist immer bevorrechtigt',1,0,''),
(129,'1.1.07-002','An allen Kreuzungen und Einmündungen gilt ausnahmslos die Regel „rechts vor links“','The rule \\\"right before left\\\" applies without exception at all crossroads and junctions','در تمام تقاطع‌ها و محل‌های اتصال جاده‌ها، بدون استثنا قانون «راست به چپ» اعمال می‌شود','<div dir=\'rtl\'>قانون «راست به چپ» تنها زمانی اعمال می‌شود که هیچ علامت راهنمایی و رانندگی، چراغ راهنمایی یا پلیسی برای تنظیم ترافیک وجود نداشته باشد.</div>',0,'An allen Kreuzungen und Einmündungen gilt ausnahmslos die Regel „rechts vor links“',1,0,''),
(130,'1.1.07-006-B','Weil beim Bremsen erhöhte Rutschgefahr besteht','Because there is an increased danger of skidding when braking','زیرا هنگام ترمزگیری خطر لغزش افزایش می‌یابد','<div dir=\'rtl\'>به دلیل وجود برگ‌ها در کنار جاده، این خطر وجود دارد که لاستیک‌ها، به خصوص هنگام ترمزگیری، به خوبی به زمین نچسبند. وسیله نقلیه ممکن است دچار لغزش شود. بنابراین، باید در اینجا با دقت و آهسته‌تر رانندگی کنید.</div>',0,'Weil beim Bremsen erhöhte Rutschgefahr besteht',1,1,''),
(131,'1.1.07-006-B','Weil ein Fahrzeug von rechts kommen könnte','Because a vehicle could come from the right','زیرا ممکن است وسیله نقلیه‌ای از سمت راست بیاید','<div dir=\'rtl\'>وجود یک جاده در سمت راست خود را از روی تابلوی راهنمایی و رانندگی می‌بینید. با این حال، این جاده کاملاً با برگ پوشیده شده است که تشخیص آن را دشوارتر می‌کند. این احتمال وجود دارد که خودرویی از این مسیر بیاید و شما طبق قانون اصلی «حق تقدم با راست» باید به آن حق تقدم بدهید. از آنجایی که به دلیل برگ‌ها برای هر دوی شما خطر لغزش وجود دارد، باید با احتیاط ویژه به وضعیت ترافیک نزدیک شوید.</div>',0,'Weil ein Fahrzeug von rechts kommen könnte',1,1,''),
(132,'1.1.07-006-B','Weil das von links kommende Auto Vorfahrt hat','Because the car coming from the left has priority','زیرا خودرویی که از سمت چپ می‌آید حق تقدم دارد','<div dir=\'rtl\'>در اینجا قانون اصلی «حق تقدم با راست» اعمال می‌شود. شما در سمت راست این خودرو هستید و بنابراین حق تقدم دارید.</div>',0,'Weil das von links kommende Auto Vorfahrt hat',1,0,''),
(133,'1.1.07-009','- ausgelassen auf die Fahrbahn stürmen','- rush onto the road without thinking','- با هیجان به سمت خیابان هجوم ببرند','<div dir=\'rtl\'>کودکان در ترافیک جاده‌ای به ویژه آسیب‌پذیر هستند. آن‌ها اغلب بی‌صبر هستند و هنگام بازی کردن محیط اطراف خود را فراموش می‌کنند. پس از یک روز پرمشغله در مدرسه، ممکن است کودکان پرانرژی و نیازمند حرکت باشند و توجهی به ترافیک جاده‌ای نداشته باشند.</div>',0,'- ausgelassen auf die Fahrbahn stürmen',1,1,''),
(134,'1.1.07-009','- mit ihren Fahrrädern unvorsichtig auf die Fahrbahn fahren','- ride their bicycles onto the road without paying attention','- با دوچرخه‌های خود بی‌احتیاطی وارد خیابان شوند','<div dir=\'rtl\'>کودکان اغلب نمی‌توانند موقعیت‌های خطرناک را به درستی ارزیابی کنند. علاوه بر این، آن‌ها معمولاً در دوچرخه‌سواری به اندازه بزرگسالان ایمن نیستند. در اینجا نهایت احتیاط و هوشیاری لازم است.</div>',0,'- mit ihren Fahrrädern unvorsichtig auf die Fahrbahn fahren',1,1,''),
(135,'1.1.07-009','- sich immer verkehrsgerecht verhalten','- always conduct themselves properly on the road','- همیشه مطابق با قوانین راهنمایی و رانندگی رفتار کنند','<div dir=\'rtl\'>کودکان همیشه مطابق با قوانین راهنمایی و رانندگی رفتار نمی‌کنند. اغلب آن‌ها محیط اطراف خود را فراموش می‌کنند یا نمی‌توانند خطرات را به درستی ارزیابی کنند.</div>',0,'- sich immer verkehrsgerecht verhalten',1,0,''),
(136,'1.1.07-010','Auf liegen gebliebene Fahrzeuge','To vehicles which have broken down','به وسایل نقلیه خراب شده','<div dir=\'rtl\'>به این ترتیب، ترافیک پشت سر می‌تواند از آن مطلع شود و به آرامی و با احتیاط از محل خرابی عبور کند، بدون اینکه کسی را به خطر بیندازد.</div>',0,'Auf liegen gebliebene Fahrzeuge',1,1,''),
(137,'1.1.07-010','Auf Schulbusse, bei denen Kinder ein- oder aussteigen','To school buses with children boarding or alighting','به اتوبوس‌های مدرسه، که کودکان در حال سوار یا پیاده شدن هستند.','<div dir=\'rtl\'>در اینجا باید توجه ویژه‌ای مبذول شود، زیرا به عنوان مثال، کودکان ممکن است بدون نگاه کردن به خیابان بدوند.</div>',0,'Auf Schulbusse, bei denen Kinder ein- oder aussteigen',1,1,''),
(138,'1.1.07-010','Auf einen Stau','To a traffic congestion','به یک راهبندان','<div dir=\'rtl\'>برای آگاه کردن وسایل نقلیه پشت سر از انتهای راهبندان، توصیه می‌شود چراغ هشداردهنده را روشن کنید. به این ترتیب می‌توان سرعت را زودتر کاهش داد و از تصادفات زنجیره‌ای جلوگیری کرد.</div>',0,'Auf einen Stau',1,1,''),
(139,'1.1.07-011','- wird beim Abbiegen weit nach links ausschwenken','- will swing far out to the left when turning','- هنگام پیچیدن به شدت به چپ منحرف خواهد شد.','<div dir=\'rtl\'>یک کمباین توسط محور عقب هدایت می‌شود. قسمت جلویی آن بسیار عریض است. بنابراین، لازم است هنگام پیچیدن به چپ منحرف شود تا به چیزی که در سمت راست قرار دارد برخورد نکند.</div>',0,'- wird beim Abbiegen weit nach links ausschwenken',1,1,''),
(140,'1.1.07-011','- wird vor dem Abbiegen sehr langsam werden','- will slow down drastically before turning','- قبل از پیچیدن بسیار آهسته خواهد شد.','<div dir=\'rtl\'>یک کمباین دارای مرکز ثقل بسیار بالایی است. به همین دلیل، در پیچ‌ها با سرعت بالا به سرعت تمایل به واژگونی دارد. بنابراین، راننده باید قبل از پیچ‌ها سرعت را به شدت کاهش دهد.</div>',0,'- wird vor dem Abbiegen sehr langsam werden',1,1,''),
(141,'1.1.07-011','- kann wegen der Hinterradlenkung nicht ausschwenken','- cannot swing out due to rear-wheel steering','- به دلیل فرمان‌پذیری چرخ‌های عقب نمی‌تواند منحرف شود.','<div dir=\'rtl\'>دقیقاً به دلیل فرمان‌پذیری چرخ‌های عقب، قسمت عقب به طور خاصی به شدت منحرف می‌شود.</div>',0,'- kann wegen der Hinterradlenkung nicht ausschwenken',1,0,''),
(142,'1.1.07-013','Vor allem beim Bremsen oder beim Abbiegen können Teile der Ladung herunterfallen','Particularly when braking or turning, parts of the load can fall off','به خصوص هنگام ترمز کردن یا پیچیدن، ممکن است قسمت‌هایی از بار به پایین بیفتد.','<div dir=\'rtl\'>طبق ماده ۲۳ آیین‌نامه راهنمایی و رانندگی (StVO)، راننده وسیله نقلیه موتوری باید بار خود را طوری مهار کند که او و سایر کاربران جاده را به خطر نیندازد. با این حال، نمی‌توان به طور خودکار این را فرض کرد، زیرا ممکن است مهار بار، به عنوان مثال، در حین رانندگی به طور ناخواسته شل شود. به خصوص بارهای شل مانند کاه را نمی‌توان به طور کامل مهار کرد و بنابراین ممکن است تکه‌های کاه از سطح بار به پرواز درآیند.</div>',0,'Vor allem beim Bremsen oder beim Abbiegen können Teile der Ladung herunterfallen',1,1,''),
(143,'1.1.07-013','Die Blinker können verdeckt sein, so dass schlecht zu erkennen ist, wenn der Zug abbiegen will','The indicators may be concealed, making it difficult to see when the combination of vehicles wishes to turn off','راهنماها ممکن است پوشیده باشند، به طوری که تشخیص اینکه مجموعه خودرو و تریلر چه زمانی می‌خواهد بپیچد، دشوار است.','<div dir=\'rtl\'>بنابراین باید با فاصله کافی رانندگی کرد تا از ترمزهای ناگهانی شدید یا تصادفات از پشت جلوگیری شود.</div>',0,'Die Blinker können verdeckt sein, so dass schlecht zu erkennen ist, wenn der Zug abbiegen will',1,1,''),
(144,'1.1.07-013','Der Zug hat wegen der Beladung einen besonders kurzen Bremsweg','The braking distance of the combination of vehicles is particularly short because of its load','مجموعه خودرو و تریلر به دلیل بار، مسافت ترمز بسیار کوتاهی دارد.','<div dir=\'rtl\'>برعکس این موضوع صحیح است. به دلیل بار سنگین، وزن بیشتری باید ترمز شود و مسافت ترمز طولانی‌تر می‌شود.</div>',0,'Der Zug hat wegen der Beladung einen besonders kurzen Bremsweg',1,0,''),
(145,'1.1.07-015-M','Geschwindigkeit vermindern','Reduce speed','سرعت را کاهش دهید','<div dir=\'rtl\'>تراکتور با دید محدود از ورودی به خیابان خارج می‌شود. بنابراین: پا را از روی گاز بردارید و آماده ترمز باشید.</div>',0,'Geschwindigkeit vermindern',1,1,''),
(146,'1.1.07-015-M','Bremsbereit sein','Be ready to brake','آماده ترمز باشید','<div dir=\'rtl\'>راننده تراکتور دید کافی به خیابان ندارد و بنابراین هنگام خروج نمی‌تواند شما را ببیند. به همین دلیل باید آماده ترمز باشید.</div>',0,'Bremsbereit sein',1,1,''),
(147,'1.1.07-015-M','Unverändert weiterfahren','Continue driving as before','بدون تغییر به رانندگی ادامه دهید','<div dir=\'rtl\'>راننده تراکتور احتمالاً شما را دیر می‌بیند، زیرا دید او محدود است. ادامه رانندگی بدون تغییر ممکن است مانع خروج او شود یا در بدترین حالت منجر به تصادف گردد.</div>',0,'Unverändert weiterfahren',1,0,''),
(148,'1.1.07-101','Beim Abbiegen kann das Anbaugerät ausschwenken','The mounted implement can swing out when the tractor turns off','هنگام گردش، تجهیزات متصل می‌تواند به بیرون منحرف شود.','<div dir=\'rtl\'>بسته به نوع تجهیزات متصل، آن از محور عقب تراکتور (ماشین کشنده کشاورزی) بیرون می‌زند. به همین دلیل، هنگام گردش به بیرون منحرف می‌شود. باید به این نکته توجه کرد.</div>',0,'Beim Abbiegen kann das Anbaugerät ausschwenken',1,1,''),
(149,'1.1.07-101','Die hintere Beleuchtung kann stark verschmutzt oder verdeckt sein, so dass eingeschaltete Blinkleuchten schlecht oder gar nicht zu sehen sind','The rear lights may be heavily soiled or concealed, making direction signals difficult or impossible to see when they are on','چراغ‌های عقب ممکن است به شدت کثیف یا پوشیده شده باشند، به طوری که چراغ‌های راهنمای روشن شده به سختی یا اصلاً دیده نشوند.','<div dir=\'rtl\'>چراغ‌های راهنما در مقایسه با اندازه تجهیزات متصل معمولاً بسیار کوچک هستند. آنها ممکن است علاوه بر این، در حین کار توسط گرد و غبار یا کثیفی‌های بلند شده، آلوده شوند. بنابراین، شما به عنوان راننده مستقیماً پشت یک وسیله نقلیه کشاورزی، همیشه باید آماده باشید که آن \"ناگهان\" گردش کند.</div>',0,'Die hintere Beleuchtung kann stark verschmutzt oder verdeckt sein, so dass eingeschaltete Blinkleuchten schlecht oder gar nicht zu sehen sind',1,1,''),
(150,'1.1.07-101','Zugmaschinen können wegen ihrer niedrigen Geschwindigkeit immer gefahrlos überholt werden','Farm tractors can always be overtaken safely due to their low speed','ماشین‌های کشنده به دلیل سرعت پایینشان همیشه می‌توانند بدون خطر سبقت گرفته شوند.','<div dir=\'rtl\'>خطر در مورد وسایل نقلیه کشاورزی در سرعت نیست، بلکه در این است که آنها هنگام گردش می‌توانند به بیرون منحرف شوند یا به دلیل کثیفی، چراغ‌ها و سیستم راهنما به وضوح قابل تشخیص نیستند.</div>',0,'Zugmaschinen können wegen ihrer niedrigen Geschwindigkeit immer gefahrlos überholt werden',1,0,''),
(151,'1.1.07-103-M','Dort kann ein Fahrzeug liegen geblieben sein','A vehicle may be stationary there','ممکن است آنجا یک وسیله نقلیه متوقف شده باشد.','<div dir=\'rtl\'>ممکن است پشت برآمدگی یک وسیله نقلیه وجود داشته باشد که دچار نقص فنی شده است.</div>',0,'Dort kann ein Fahrzeug liegen geblieben sein',1,1,''),
(152,'1.1.07-103-M','Es kann ein Fahrzeug entgegenkommen, das meinen Fahrstreifen mitbenutzt','There may be an oncoming vehicle on my side of the road','ممکن است یک وسیله نقلیه از روبرو بیاید که از خط عبور من نیز استفاده می‌کند.','<div dir=\'rtl\'>ترافیک روبرو ممکن است از خط عبور شما نیز استفاده کند.</div>',0,'Es kann ein Fahrzeug entgegenkommen, das meinen Fahrstreifen mitbenutzt',1,1,''),
(153,'1.1.07-103-M','Auf meinem Fahrstreifen kann sich ein langsam fahrendes Fahrzeug befinden','There may be a slow moving vehicle on my side of the road','ممکن است در خط عبور من یک وسیله نقلیه با سرعت کم وجود داشته باشد.','<div dir=\'rtl\'>ممکن است پشت برآمدگی در مسیر شما یک وسیله نقلیه با سرعت کم وجود داشته باشد.</div>',0,'Auf meinem Fahrstreifen kann sich ein langsam fahrendes Fahrzeug befinden',1,1,''),
(154,'1.1.07-107-B','Auf eine unebene und verschmutzte Fahrbahn','An uneven and dirty roadway','برای یک جاده ناهموار و آلوده','<div dir=\'rtl\'>شما در مقابل یک منطقه ساخت و ساز قرار دارید. این امکان وجود دارد که مصالح ساختمانی روی جاده ریخته شده باشند و اکنون جاده کثیف و لغزنده باشد. همچنین ممکن است جاده ناهموار باشد زیرا در حال کار یا بازسازی است.</div>',0,'Auf eine unebene und verschmutzte Fahrbahn',1,1,''),
(155,'1.1.07-107-B','Auf Arbeiter und Baugeräte auf der Fahrbahn','Workers and construction equipment on the roadway','برای کارگران و ماشین‌آلات ساختمانی در جاده','<div dir=\'rtl\'>بسیار محتمل است که کارگران و تجهیزات ساختمانی در محل ساخت و ساز حضور داشته باشند. به همین دلیل، باید در اینجا با احتیاط و توجه ویژه رانندگی کنید تا کسی را به خطر نیندازید.</div>',0,'Auf Arbeiter und Baugeräte auf der Fahrbahn',1,1,''),
(156,'1.1.07-107-B','Auf einen durch Polizei geregelten Verkehrsablauf','Police regulating traffic','برای جریان ترافیکی که توسط پلیس کنترل می‌شود','<div dir=\'rtl\'>از آنجایی که منطقه ساخت و ساز یک وضعیت استثنایی مانند تصادف یا خرابی چراغ راهنمایی نیست، نمی‌توان انتظار داشت که پلیس ترافیک را تنظیم کند. در اینجا باید از علائم راهنمایی و رانندگی موجود پیروی کنید.</div>',0,'Auf einen durch Polizei geregelten Verkehrsablauf',1,0,''),
(157,'1.1.07-111','- sich vergewissern, dass kein Verkehrsteilnehmer rechts neben Ihnen ist, der geradeaus weiter will','','- اطمینان حاصل کنید که هیچ کاربر ترافیکی در سمت راست شما نیست که می‌خواهد مستقیم ادامه دهد.','<div dir=\'rtl\'>چنین فردی می‌تواند مثلاً یک دوچرخه‌سوار باشد. در این حالت، کنترل تنها با آینه عقب کافی نیست (نقطه کور). یک \"نگاه روی شانه\" اضافی لازم است تا اطمینان حاصل شود که کسی در سمت راست شما نیست.</div>',0,'- sich vergewissern, dass kein Verkehrsteilnehmer rechts neben Ihnen ist, der geradeaus weiter will',1,1,''),
(158,'1.1.07-111','- nur im Spiegel beobachten, ob ein Radfahrer hinter Ihnen ist','','- فقط در آینه مشاهده کنید که آیا یک دوچرخه‌سوار پشت سر شماست.','<div dir=\'rtl\'>هنگام گردش به راست باید آنقدر صبر کرد تا زمانی که هیچ کاربر ترافیکی در سمت راست شما نباشد.</div>',0,'- nur im Spiegel beobachten, ob ein Radfahrer hinter Ihnen ist',1,0,''),
(159,'1.1.07-111','- sich ganz auf den Abbiegevorgang konzentrieren, weil Radfahrer ohnehin warten müssen','','- کاملاً روی فرآیند گردش تمرکز کنید، زیرا دوچرخه‌سواران به هر حال باید منتظر بمانند.','<div dir=\'rtl\'>کاربران ترافیکی در سمت راست شما هنگام عبور از تقاطع حق تقدم دارند. بنابراین شما باید آنقدر برای گردش به راست صبر کنید تا زمانی که هیچ کاربر ترافیکی در سمت راست شما نباشد.</div>',0,'- sich ganz auf den Abbiegevorgang konzentrieren, weil Radfahrer ohnehin warten müssen',1,0,''),
(160,'1.1.07-113','Wild überquert unerwartet die Fahrbahn','Wild animals unexpectedly crossing the roadway','حیوانات وحشی به طور غیرمنتظره از عرض جاده عبور می‌کنند','<div dir=\'rtl\'>جاده جدید ممکن است مسیری را قطع کند که حیوانات وحشی برای ده‌ها یا صدها سال از آن استفاده می‌کرده‌اند. حیوانات هنوز با وضعیت جدید سازگار نشده‌اند و بنابراین ممکن است ناگهان و غیرمنتظره از عرض جاده عبور کنند.</div>',0,'Wild überquert unerwartet die Fahrbahn',1,1,''),
(161,'1.1.07-113','Mit einem Hindernis durch einen Wildunfall','An obstruction caused by an accident involving a wild animal','با یک مانع ناشی از تصادف با حیوانات وحشی','<div dir=\'rtl\'>یک وسیله نقلیه یا یک حیوان زخمی یا مرده ناشی از تصادف با حیوانات وحشی ممکن است روی جاده افتاده باشد.</div>',0,'Mit einem Hindernis durch einen Wildunfall',1,1,''),
(162,'1.1.07-113','Auf neu angelegten Straßen sind Wildunfälle nicht zu erwarten','There is no reason to expect accidents involving wild animals on new roads','در جاده‌های تازه احداث شده، تصادفات با حیوانات وحشی قابل انتظار نیستند','<div dir=\'rtl\'>اگر جاده تازه احداث شده از میان جنگل‌ها یا مناطق باز و غیرمسکونی ساخته شود، باید انتظار عبور حیوانات وحشی را داشت.</div>',0,'Auf neu angelegten Straßen sind Wildunfälle nicht zu erwarten',1,0,''),
(163,'1.1.07-117','Während der Abenddämmerung','At dusk','هنگام غروب','<div dir=\'rtl\'>حیوانات وحشی بسته به گونه‌شان، هنگام غروب در راه استراحتگاه خود یا در جستجوی غذا هستند. بنابراین، انتظار می‌رود که عبور حیوانات وحشی در این زمان از روز از جاده صورت گیرد.</div>',0,'Während der Abenddämmerung',1,1,''),
(164,'1.1.07-117','Im Morgengrauen','At dawn','هنگام طلوع صبح','<div dir=\"rtl\">همچنین اوایل صبح، حیوانات وحشی اغلب در جستجوی غذا هستند. بنابراین، انتظار می‌رود که حیوانات وحشی از جاده عبور کنند. بنابراین، باید در هنگام طلوع صبح، حاشیه جاده به خوبی مشاهده شود.</div>',0,'Im Morgengrauen',1,1,''),
(165,'1.1.07-117','In der Mittagszeit','At noon','در ظهر','<div dir=\'rtl\'>صبح و عصر بیشترین میزان حضور حیوانات وحشی است. بنابراین، در ظهر به نسبت کمتر می‌توان انتظار عبور حیوانات وحشی را داشت. با این حال، حتی در این زمان از روز نیز ممکن است حیوانات وحشی از جاده عبور کنند. بنابراین، در هر زمان از شبانه‌روز هنگام عبور از مناطق جنگلی، رانندگی با دقت و هوشیاری مناسب است.</div>',0,'In der Mittagszeit',1,0,''),
(166,'1.1.07-118','Mit Fahrbahnverschmutzungen','Soiled roadways','با آلودگی‌های سطح جاده','<div dir=\'rtl\'>در مناطق روستایی، تراکتورهای زیادی با ماشین‌آلات خود برای کارهای کشاورزی در جاده‌ها تردد می‌کنند. اغلب اوقات، خاک و کثیفی از مزارع به جاده کشیده می‌شود، بدون اینکه راننده متوجه آن شود. بنابراین، در اینجا باید انتظار آلودگی‌های سطح جاده را داشته باشید.</div>',0,'Mit Fahrbahnverschmutzungen',1,1,''),
(167,'1.1.07-118','Mit langsamen landwirtschaftlichen Fahrzeugen','Slow farm vehicles','با وسایل نقلیه کشاورزی کندرو','<div dir=\'rtl\'>وسایل نقلیه کشاورزی برای کارهای مزرعه استفاده می‌شوند. بسیاری از آنها حداکثر سرعت کمی (۲۵ تا ۴۰ کیلومتر در ساعت) دارند. بنابراین، در مناطق روستایی باید انتظار وسایل نقلیه کشاورزی کندرو را داشته باشید.</div>',0,'Mit langsamen landwirtschaftlichen Fahrzeugen',1,1,''),
(168,'1.1.07-118','Mit überbreiten landwirtschaftlichen Fahrzeugen','Excessively wide farm vehicles','با وسایل نقلیه کشاورزی عریض','<div dir=\'rtl\'>وسایل نقلیه کشاورزی برای کارهای مزرعه استفاده می‌شوند. بسیاری از ابزارهای کاری آنها عرض زیادی دارند تا بتوانند تا حد امکان سطح بزرگی را یکباره پردازش کنند. بنابراین، در این مناطق باید انتظار وسایل نقلیه کشاورزی عریض را داشته باشید.</div>',0,'Mit überbreiten landwirtschaftlichen Fahrzeugen',1,1,''),
(169,'1.1.07-119','Die Zugmaschine kann ein breiteres, schlecht erkennbares Arbeitsgerät mitführen','The tractor can carry large work equipment which is difficult to see','تراکتور ممکن است یک ابزار کار عریض‌تر و با دید کم را حمل کند.','<div dir=\'rtl\'>اغلب تراکتورهای کشاورزی (ماشین‌های کشنده کشاورزی) یک ابزار کار برای شخم زدن مزارع به خود وصل کرده‌اند. این ابزارهای کار اغلب بسیار عریض هستند و به خوبی روشن نیستند. علاوه بر این، ممکن است چراغ‌ها به دلیل کثیفی و گرد و غبار از مزرعه به سختی قابل تشخیص باشند.</div>',0,'Die Zugmaschine kann ein breiteres, schlecht erkennbares Arbeitsgerät mitführen',1,1,''),
(170,'1.1.07-119','Die Breite der Zugmaschine ist trotz der eingeschalteten Beleuchtung nicht immer erkennbar','Despite the headlights being switched on, it is not always possible to discern the width of the tractor','عرض تراکتور با وجود چراغ‌های روشن همیشه قابل تشخیص نیست.','<div dir=\'rtl\'>بیشتر تراکتورها (ماشین‌های کشنده کشاورزی) دارای یک محور عقب بسیار عریض هستند. به دلیل چراغ‌های کثیف، این عرض در گرگ و میش همیشه قابل تشخیص نیست.</div>',0,'Die Breite der Zugmaschine ist trotz der eingeschalteten Beleuchtung nicht immer erkennbar',1,1,''),
(171,'1.1.07-119','Die Zugmaschine kann 2 breitere Anhänger mitführen','2 wide trailers can be attached to the tractor','تراکتور ممکن است 2 تریلر عریض‌تر را حمل کند.','<div dir=\'rtl\'>تراکتورها (ماشین‌های کشنده کشاورزی) مجاز به کشیدن 2 تریلر هستند. اینها معمولاً عریض‌تر و بزرگ‌تر از خود تراکتور هستند. در گرگ و میش، آنها گاهی اوقات به سختی قابل تشخیص هستند.</div>',0,'Die Zugmaschine kann 2 breitere Anhänger mitführen',1,1,''),
(172,'1.1.07-120','Auch am Tage in gut beleuchteten Tunneln mit Abblendlicht fahren','Drive with dipped headlights also during the day even in well lit tunnels','حتی در روز در تونل‌های با نورپردازی خوب با نور پایین رانندگی کنید','<div dir=\'rtl\'>در یک تونل، شرایط دید ایجاب می‌کند که نور پایین را روشن کنید.</div>',0,'Auch am Tage in gut beleuchteten Tunneln mit Abblendlicht fahren',1,1,''),
(173,'1.1.07-120','Sonnenbrille abnehmen','Take off your sunglasses','عینک آفتابی را بردارید','<div dir=\'rtl\'>با وجود نورپردازی، تونل‌ها هرگز آنقدر روشن نیستند که به عینک آفتابی نیاز داشته باشید. برای اینکه بتوانید در تونل به خوبی ببینید، باید عینک آفتابی خود را بردارید.</div>',0,'Sonnenbrille abnehmen',1,1,''),
(174,'1.1.07-120','Nebelscheinwerfer einschalten','Switch fog headlamps on','چراغ‌های مه‌شکن را روشن کنید','<div dir=\'rtl\'>در تونل مه ایجاد نمی‌شود، بنابراین در اینجا نباید چراغ‌های مه‌شکن را روشن کرد.</div>',0,'Nebelscheinwerfer einschalten',1,0,''),
(175,'1.1.07-121','Warnblinklicht einschalten','Switch hazard warning lights on','چراغ‌های هشداردهنده (فلاشر) را روشن کنید','<div dir=\'rtl\'>به این ترتیب، وسایل نقلیه پشت سر شما می‌توانند به موقع هشدار داده شوند. می‌توان سرعت را زودتر کاهش داد و از تصادفات از پشت، که اغلب در انتهای ترافیک رخ می‌دهند، جلوگیری کرد.</div>',0,'Warnblinklicht einschalten',1,1,''),
(176,'1.1.07-121','Bei Stillstand mit ca. 5 m Sicherheitsabstand zum Vordermann anhalten','When traffic comes to a standstill, keep a safety distance of approximately 5 m to the car ahead','هنگام توقف کامل، با فاصله ایمنی حدود 5 متر از خودروی جلویی توقف کنید','<div dir=\'rtl\'>برای اینکه در مواقع اضطراری هنوز فرصت واکنش داشته باشید، باید 5 متر فضا بین خود و خودروی جلویی بگذارید.</div>',0,'Bei Stillstand mit ca. 5 m Sicherheitsabstand zum Vordermann anhalten',1,1,''),
(177,'1.1.07-121','Fahrzeug sichern und umgehend verlassen','Secure and leave vehicle immediately','خودرو را ایمن کرده و فوراً آن را ترک کنید','<div dir=\'rtl\'>ترافیک ممکن است هر لحظه برطرف شود. ایمن کردن خودرو و ترک فوری آن، رفتاری در شرایط اضطراری است.</div>',0,'Fahrzeug sichern und umgehend verlassen',1,0,''),
(178,'1.1.07-122','Beleuchtungsreflexionen durch den Gegenverkehr','Reflections of light from oncoming traffic','بازتاب نور چراغ‌های خودروهای روبرو','<div dir=\'rtl\'>نور چراغ‌های خودروهای روبرو می‌تواند شما را خیره کند یا در رنگ بدنه خودروهای دیگر منعکس شود.</div>',0,'Beleuchtungsreflexionen durch den Gegenverkehr',1,1,''),
(179,'1.1.07-122','Tunnellänge','Length of the tunnel','طول تونل','<div dir=\'rtl\'>اگر تونل بسیار طولانی باشد، می‌تواند تأثیر منفی بر تمرکز داشته باشد، زیرا ادراک به منظره عادت می‌کند و نیاز به تمرکز فعال کمتری وجود دارد.</div>',0,'Tunnellänge',1,1,''),
(180,'1.1.07-122','Gute Fahrbahnmarkierung','Good road markings','خط‌کشی خوب جاده','<div dir=\'rtl\'>خط‌کشی خوب جاده برای راننده مفید است.</div>',0,'Gute Fahrbahnmarkierung',1,0,''),
(181,'1.1.07-125','Auch am Tage im gut beleuchteten Tunnel mit Abblendlicht fahren','Drive with dipped headlights also by day even in a well lit tunnel','حتی در روز در تونل‌های با نور کافی نیز با نور پایین رانندگی کنید.','<div dir=\'rtl\'>مطابق با بند ۱ ماده ۱۷ قانون راهنمایی و رانندگی (StVO)، ما باید چراغ‌های روشنایی مقرر را در صورت لزوم دید روشن کنیم. در تونل، با وجود نورپردازی گاهی خوب، همیشه لازم است که چراغ‌های پایین (Abblendlicht) را روشن کنید.</div>',0,'Auch am Tage im gut beleuchteten Tunnel mit Abblendlicht fahren',1,1,''),
(182,'1.1.07-125','Nicht wenden','Do not make a U-turn','دور نزنید.','<div dir=\'rtl\'>در تونل باید از هرگونه خطری که می‌تواند باعث تصادف شود، اجتناب کرد. این شامل دور زدن نیز می‌شود.</div>',0,'Nicht wenden',1,1,''),
(183,'1.1.07-125','Anweisungen und Informationen des Tunnelpersonals Folge leisten','Follow instructions and information from the tunnel personnel','به دستورالعمل‌ها و اطلاعات پرسنل تونل عمل کنید.','<div dir=\'rtl\'>پرسنل تونل در موارد خاص یا اضطراری مداخله می‌کنند. بنابراین، باید به گفته‌های آن‌ها عمل کرد تا کسی در موقعیت خطرناک قرار نگیرد.</div>',0,'Anweisungen und Informationen des Tunnelpersonals Folge leisten',1,1,''),
(184,'1.1.09-004','Durch Übermüdung','Fatigue','به دلیل خستگی مفرط','<div dir=\'rtl\'>خستگی پشت فرمان می‌تواند منجر به اختلال در رانندگی ایمن خودرو شود، زیرا در این حالت توجه و توانایی تمرکز کاهش می‌یابد. بنابراین، همیشه باید خودرو را در حالت استراحت کافی رانندگی کرد.</div>',0,'Durch Übermüdung',1,1,''),
(185,'1.1.09-004','Durch Alkohol und andere berauschende Mittel','Alcohol and other intoxicants','به دلیل الکل و سایر مواد مخدر','<div dir=\'rtl\'>الکل و سایر مواد مخدر منجر به کاهش توانایی واکنش و ارزیابی نادرست موقعیت‌ها می‌شوند. بنابراین، آنها توانایی رانندگی را مختل می‌کنند و نباید قبل از شروع رانندگی مصرف شوند.</div>',0,'Durch Alkohol und andere berauschende Mittel',1,1,''),
(186,'1.1.09-004','Durch bestimmte Medikamente','Certain medicines','به دلیل داروهای خاص','<div dir=\'rtl\'>برخی داروها در بروشور خود اشاره می‌کنند که توانایی رانندگی ممکن است مختل شود. بنابراین، اگر چنین دارویی مصرف کرده‌اید، بهتر است از رانندگی خودداری کنید.</div>',0,'Durch bestimmte Medikamente',1,1,''),
(187,'1.1.09-006','10 Stunden','10 hours','۱۰ ساعت','<div dir=\'rtl\'>پس از یک ساعت، غلظت الکل در خون هنوز آنقدر بالاست که می‌تواند به طور قابل توجهی بر رفتار رانندگی تأثیر بگذارد. در این حالت، شما احتمالاً هنوز حدود ۰.۹ پرومیل الکل در خون خود دارید.</div>',0,'10 Stunden',1,1,''),
(188,'1.1.09-006','5 Stunden','5 hours','۵ ساعت','<div dir=\'rtl\'>پس از پنج ساعت، هنوز مقدار زیادی الکل باقیمانده در خون وجود دارد. از آنجایی که این می‌تواند به طور قابل توجهی توانایی رانندگی را محدود کند، نباید پس از ۵ ساعت دوباره پشت فرمان نشست.</div>',0,'5 Stunden',1,0,''),
(189,'1.1.09-006','1 Stunde','1 hour','۱ ساعت','<div dir=\'rtl\'>پس از یک ساعت، غلظت الکل در خون هنوز آنقدر بالاست که می‌تواند به طور قابل توجهی بر رفتار رانندگی تأثیر بگذارد. در این حالت، شما احتمالاً هنوز حدود ۰.۹ پرومیل الکل در خون خود دارید.</div>',0,'1 Stunde',1,0,''),
(190,'1.1.09-008','Zu verzögerter Reaktion','Delayed reactions','به تأخیر در واکنش','<div dir=\'rtl\'>حتی مقادیر کم الکل به شدت توانایی واکنش را محدود می‌کند، اگرچه فرد خود را سرحال احساس می‌کند. حتی غلظت پایین الکل در خون منجر به افزایش زمان واکنش می‌شود. واکنش‌ها نادرست می‌شوند. رانندگان تحت تأثیر الکل دیگر قادر به مدیریت موقعیت‌های غیرمنتظره نیستند.</div>',0,'Zu verzögerter Reaktion',1,1,''),
(191,'1.1.09-008','Zu riskanter Fahrweise','Reckless driving','به رانندگی پرخطر','<div dir=\'rtl\'>به‌ویژه مقادیر کم الکل باعث افزایش فعالیت حرکتی می‌شود، در حالی که همزمان عملکردهای بازدارنده و کنترلی کاهش می‌یابند.</div>',0,'Zu riskanter Fahrweise',1,1,''),
(192,'1.1.09-008','Zu einem Nachlassen der Hör- und Sehleistung','Impairment of hearing and vision','به کاهش عملکرد شنوایی و بینایی','<div dir=\'rtl\'>حتی با مقادیر کم الکل، عملکرد بینایی به طرق مختلف مختل می‌شود. یک کاربر ترافیک از طریق دستگاه بینایی 90% اطلاعات مهم برای ترافیک را دریافت می‌کند. بنابراین، اختلالات دستگاه بینایی تأثیرات بسیار منفی دارند. علائم معمول اختلال بینایی ناشی از الکل عبارتند از دوبینی (کاهش درک فضایی)، دید تونلی (محدودیت میدان دید)، و تأخیر در تطابق با نور و تاریکی.</div>',0,'Zu einem Nachlassen der Hör- und Sehleistung',1,1,''),
(193,'1.1.09-015','Ungleichmäßig, zeitlich nicht abschätzbar','Unevenly over an indeterminate period','به‌طور نامنظم، غیرقابل پیش‌بینی از نظر زمانی','<div dir=\'rtl\'>ماده فعال مست‌کننده حشیش (THC) به‌طور نامنظم و غیرقابل پیش‌بینی از نظر زمانی در بدن تجزیه می‌شود، زیرا در بافت چربی ذخیره می‌گردد.</div>',0,'Ungleichmäßig, zeitlich nicht abschätzbar',1,1,''),
(194,'1.1.09-015','Gleichmäßig, 0,1 Promille je Stunde','Evenly, 0.1 per mille per hour','به‌طور منظم، ۰.۱ پرومیل در هر ساعت','<div dir=\'rtl\'>مقدار پرومیل فقط امکان اظهارنظر در مورد میزان الکل در خون را فراهم می‌کند. این مقدار، میزان THC در بدن را اندازه‌گیری نمی‌کند.</div>',0,'Gleichmäßig, 0,1 Promille je Stunde',1,0,''),
(195,'1.1.09-015','Gleichmäßig, 0,1 Gramm je Stunde','Evenly, 0.1 gram per hour','به‌طور منظم، ۰.۱ گرم در هر ساعت','<div dir=\'rtl\'>مقدار پرومیل فقط امکان اظهارنظر در مورد میزان الکل در خون را فراهم می‌کند. این مقدار، میزان THC در بدن را اندازه‌گیری نمی‌کند.</div>',0,'Gleichmäßig, 0,1 Gramm je Stunde',1,0,''),
(196,'1.1.09-017','Entzug der Fahrerlaubnis oder Fahrverbot','Confiscation of driving licence or driving ban','ابطال گواهینامه رانندگی یا ممنوعیت رانندگی','<div dir=\'rtl\'>طبق قانون، دادگاه می‌تواند فرد متخلف را برای یک تا سه ماه از رانندگی وسایل نقلیه موتوری در ترافیک منع کند (رجوع شود به ماده ۲۵ بند ۱ قانون ترافیک جاده‌ای StVG). علاوه بر این، گواهینامه رانندگی می‌تواند ابطال شود اگر کسی مرتکب عمل غیرقانونی طبق ماده ۶۹ قانون مجازات آلمان (StGB) شود. رانندگی وسیله نقلیه تحت تأثیر مواد مخدر نیز شامل این مورد می‌شود.</div>',0,'Entzug der Fahrerlaubnis oder Fahrverbot',1,1,''),
(197,'1.1.09-017','Geld- und/oder Freiheitsstrafe','Fine and/or imprisonment','جریمه نقدی و/یا حبس','<div dir=\'rtl\'>ماده ۲۴ الف قانون ترافیک جاده‌ای (StVG) مقرر می‌دارد که رانندگی وسایل نقلیه موتوری تحت تأثیر مواد مخدر یک تخلف اداری محسوب می‌شود که می‌تواند با جریمه نقدی تا سه هزار یورو مجازات شود. قانون مجازات آلمان (StGB) در این زمینه حتی فراتر می‌رود. در اینجا، ماده ۳۱۵c بند ۱ تصریح می‌کند که هر کس در ترافیک جاده‌ای وسیله نقلیه‌ای را رانندگی کند، در حالی که به دلیل مصرف نوشیدنی‌های الکلی یا سایر مواد مخدر قادر به رانندگی ایمن وسیله نقلیه نباشد و در نتیجه جان یا سلامت شخص دیگری یا اموال با ارزش قابل توجه دیگران را به خطر اندازد، به حبس تا پنج سال یا جریمه نقدی محکوم می‌شود.</div>',0,'Geld- und/oder Freiheitsstrafe',1,1,''),
(198,'1.1.09-017','Anordnung einer medizinisch-psychologischen Untersuchung','Compulsory medical/psychological examination','دستور انجام معاینه پزشکی-روانشناختی','<div dir=\'rtl\'>یکی از پیامدهای رایج زمانی که راننده‌ای تحت تأثیر مواد مخدر پشت فرمان دستگیر می‌شود، MPU (معاینه پزشکی-روانشناختی) است. در این صورت، اداره گواهینامه رانندگی می‌تواند دستور دهد که یک گزارش یا گواهی از یک پزشک متخصص یا پزشک دولتی، یک گزارش از یک مرکز ارزیابی صلاحیت رانندگی رسمی تأیید شده یا از یک کارشناس یا بازرس رسمی تأیید شده برای ترافیک وسایل نقلیه موتوری در یک بازه زمانی معقول تهیه شود.</div>',0,'Anordnung einer medizinisch-psychologischen Untersuchung',1,1,''),
(199,'1.1.09-018','Rausch mit gefährlichen Sinnestäuschungen und Herabsetzung des Reaktionsvermögens','Intoxication with dangerous hallucination and reduced reaction capability','مستی همراه با توهمات حسی خطرناک و کاهش توانایی واکنش','<div dir=\'rtl\'>در حالت مسمومیت حاد، اختلالات فکری اغلب رخ می‌دهد. توانایی تمرکز و توجه می‌تواند کاهش یابد، همچنین عملکرد حافظه کوتاه‌مدت. مصرف‌کننده راحت‌تر حواسش پرت می‌شود و بر محرک‌های فرعی تمرکز می‌کند. توهمات و خطاهای ادراکی می‌توانند نتیجه آن باشند.</div>',0,'Rausch mit gefährlichen Sinnestäuschungen und Herabsetzung des Reaktionsvermögens',1,1,''),
(200,'1.1.09-018','Rausch mit Verwirrtheitszuständen und Depressionen','Intoxication with confusion and depression','مستی همراه با حالات سردرگمی و افسردگی','<div dir=\'rtl\'>حشیش در حالت مسمومیت حاد اغلب تأثیری تغییردهنده بر هوشیاری دارد. این تأثیر می‌تواند مثبت یا منفی باشد. تمایلات به اضطراب یا افسردگی می‌توانند با مصرف حشیش تشدید شوند. همچنین، عدم جهت‌یابی و لحظاتی از سردرگمی نیز می‌تواند از عواقب آن باشد.</div>',0,'Rausch mit Verwirrtheitszuständen und Depressionen',1,1,''),
(201,'1.1.09-018','Verbesserte Zeiteinschätzung','Improved judgement of time','بهبود در تخمین زمان','<div dir=\'rtl\'>برای تخمین دقیق زمان، ادراکی بدون ابهام و واضح ضروری است. اما دقیقاً همین ادراک در حالت مسمومیت با حشیش تحریف می‌شود.</div>',0,'Verbesserte Zeiteinschätzung',1,0,''),
(202,'1.1.09-019','Das Gefahrenbewusstsein kann abnehmen','Diminished awareness of danger','آگاهی از خطر می‌تواند کاهش یابد','<div dir=\'rtl\'>حشیش آگاهی را تغییر می‌دهد. اغلب اوقات یک اثر سرخوش‌کننده و آرامش‌بخش مشاهده می‌شود. بنابراین، موقعیت‌های خطرناک بالقوه ممکن است کمتر خطرناک ارزیابی شوند، که می‌تواند عواقب پرخطر گسترده‌ای به همراه داشته باشد.</div>',0,'Das Gefahrenbewusstsein kann abnehmen',1,1,''),
(203,'1.1.09-019','Fehler bei der Verarbeitung von Informationen können zunehmen','Increased likelihood of mistakes in assimilating information','خطاها در پردازش اطلاعات می‌توانند افزایش یابند','<div dir=\'rtl\'>یکی از عواقب مصرف حشیش می‌تواند افکار ناگهانی و شکاف‌های حافظه باشد. در نتیجه، پردازش اطلاعات و ادراکات حسی محدود می‌شود.</div>',0,'Fehler bei der Verarbeitung von Informationen können zunehmen',1,1,''),
(204,'1.1.09-019','Fehleinschätzungen von Geschwindigkeit und Entfernung können eintreten','Misjudgement of speed and distance','اشتباه در تخمین سرعت و فاصله می‌تواند رخ دهد','<div dir=\'rtl\'>به دلیل تغییر در ادراک حسی هنگام مصرف حشیش، تخمین مسافت‌ها و سرعت می‌تواند تحریف شود. این امر به ویژه در ترافیک جاده‌ای می‌تواند عواقب خطرناک گسترده‌ای داشته باشد.</div>',0,'Fehleinschätzungen von Geschwindigkeit und Entfernung können eintreten',1,1,''),
(205,'1.1.09-021','Für alle Kraftfahrer unter 21 Jahren','All drivers under 21','برای تمام رانندگان زیر ۲۱ سال','<div dir=\'rtl\'>هر راننده زیر ۲۱ سال باید ۰.۰ پرومیل (میزان الکل در خون) داشته باشد. در اینجا ممنوعیت مطلق الکل حاکم است.</div>',0,'Für alle Kraftfahrer unter 21 Jahren',1,1,''),
(206,'1.1.09-021','Für alle Kraftfahrer in der Probezeit','All drivers during their probation period','برای تمام رانندگان در دوره آزمایشی','<div dir=\'rtl\'>تمام رانندگانی که در دوره آزمایشی هستند، تحت ممنوعیت مطلق الکل قرار دارند. این به معنای ۰.۰ پرومیل هنگام شروع رانندگی است.</div>',0,'Für alle Kraftfahrer in der Probezeit',1,1,''),
(207,'1.1.09-021','Für alle Kraftfahrer','All drivers','برای تمام رانندگان','<div dir=\'rtl\'>تمام رانندگانی که در دوره آزمایشی هستند، تحت ممنوعیت مطلق الکل قرار دارند. این به معنای ۰.۰ پرومیل هنگام شروع رانندگی است.</div>',0,'Für alle Kraftfahrer',1,0,''),
(208,'1.1.09-022','Nein, in keinem Fall','No, definitely not','خیر، در هیچ صورتی','<div dir=\'rtl\'>در طول دوره آزمایشی، هیچ محدودیت ۰.۵ پرومیل وجود ندارد. یک راننده در این مدت نباید هنگام رانندگی هیچ‌گونه الکلی در خون خود داشته باشد.</div>',0,'Nein, in keinem Fall',1,1,''),
(209,'1.1.09-022','Ja, bis 0,5 Promille ohne alkoholbedingte Fahrauffälligkeit','Yes, up to a blood alcohol level of 50 milligrams if they have not committed any alcohol related traffic violation','بله، تا ۰.۵ پرومیل بدون علائم رانندگی ناشی از الکل','<div dir=\'rtl\'>محدودیت ۰.۵ پرومیل تنها پس از دوره آزمایشی اعمال می‌شود.</div>',0,'Ja, bis 0,5 Promille ohne alkoholbedingte Fahrauffälligkeit',1,0,''),
(210,'1.1.09-022','Ja, bis 0,3 Promille ohne alkoholbedingte Fahrauffälligkeit','Yes, up to a blood alcohol level of 30 milligrams if they have not committed any alcohol related traffic violation','بله، تا ۰.۳ پرومیل بدون علائم رانندگی ناشی از الکل','<div dir=\'rtl\'>محدودیت ۰.۵ پرومیل تنها پس از دوره آزمایشی اعمال می‌شود.</div>',0,'Ja, bis 0,3 Promille ohne alkoholbedingte Fahrauffälligkeit',1,0,''),
(211,'1.2.01-001','- mit Fehlverhalten anderer rechnen','','- انتظار رفتار اشتباه از دیگران را داشته باشید','<div dir=\'rtl\'>هیچ انسانی بی‌عیب نیست. بنابراین، نباید بی‌جهت بر حق خود پافشاری کرد، اگر با این کار بتوان از دردسر و موقعیت‌های خطرناک جلوگیری کرد.</div>',0,'- mit Fehlverhalten anderer rechnen',1,1,''),
(212,'1.2.01-001','- vorausschauend fahren','','- با دید باز رانندگی کنید','<div dir=\'rtl\'>رانندگی پیش‌بینانه به معنای رانندگی متمرکز، حفظ فاصله، مشاهده دقیق وضعیت ترافیک و واکنش مناسب است.</div>',0,'- vorausschauend fahren',1,1,''),
(213,'1.2.01-001','- in jedem Fall auf Ihrem Vorfahrtrecht bestehen','','- در هر صورت بر حق تقدم خود اصرار ورزید','<div dir=\'rtl\'>مهم‌تر این است که با دید باز رانندگی کنید و به سایر کاربران جاده توجه داشته باشید. اگر حق تقدم از کسی گرفته شود، ممکن است به این دلیل باشد که راننده دیگر او را ندیده است. در این صورت، بهتر است حق تقدم را واگذار کنید تا از یک تصادف احتمالی جلوگیری شود.</div>',0,'- in jedem Fall auf Ihrem Vorfahrtrecht bestehen',1,0,''),
(214,'1.2.02-101-B','Zum Halten und Parken','For stopping and parking','برای توقف و پارک','<div dir=\'rtl\'>طبق بخش 12 پاراگراف 4 StVO، می توانید در شانه توسعه یافته یک جاده روستایی توقف کرده و پارک کنید.</div>',0,'Zum Halten und Parken',1,1,''),
(215,'1.2.02-101-B','Zum Befahren mit langsamen Fahrzeugen','For driving a slow-moving vehicle','برای رانندگی با وسایل نقلیه کند','<div dir=\'rtl\'>وسایل نقلیه کند، مانند تراکتورها، می توانند از این شانه برای رانندگی در جاده های کشور استفاده کنند تا مانع دیگر ترافیک نشوند.</div>',0,'Zum Befahren mit langsamen Fahrzeugen',1,1,''),
(216,'1.2.02-101-B','Zum Überholen','For overtaking','برای سبقت گرفتن','<div dir=\'rtl\'>شما مجاز به سبقت گرفتن در سمت راست نیستید. همچنین یک خط ثابت در اینجا نشان داده شده است، که همچنین به طور کلی سبقت را ممنوع می کند.</div>',0,'Zum Überholen',1,0,''),
(217,'1.2.03-001','Mitführen eines ungebremsten Anhängers','Towing a trailer not fitted with brakes','یدک‌کشی تریلر بدون ترمز','<div dir=\'rtl\'>یک تریلر بدون ترمز تنها با ترمز کردن خودروی کشنده می‌تواند متوقف شود. این بدان معناست که خودروی کشنده باید جرم بیشتری را علاوه بر وزن خود متوقف کند و بنابراین برای انجام این کار به مسافت بیشتری نیاز دارد.</div>',0,'Mitführen eines ungebremsten Anhängers',1,1,''),
(218,'1.2.03-001','Nasse oder glatte Fahrbahnen','A wet or slippery roadway','جاده‌های خیس یا لغزنده','<div dir=\'rtl\'>جاده‌های خیس یا لغزنده مقاومت اصطکاکی را کاهش داده و در نتیجه مسافت توقف را افزایش می‌دهند. این امر در شرایط یخبندان به وضوح مشهود است.</div>',0,'Nasse oder glatte Fahrbahnen',1,1,''),
(219,'1.2.03-001','Fahren auf Gefällstrecken','Driving down slopes','رانندگی در سراشیبی','<div dir=\'rtl\'>هنگام رانندگی در سربالایی، مسافت توقف کاهش می‌یابد زیرا خودرو باید در خلاف جهت شیب کار کند. در سراشیبی دقیقاً برعکس است و با همان نیروی ترمز، مسافت توقف افزایش می‌یابد.</div>',0,'Fahren auf Gefällstrecken',1,1,''),
(220,'1.2.03-002','- Bereifung','- tyres','- لاستیک','<div dir=\'rtl\'>فاصله ترمز به وضعیت لاستیک ها بستگی دارد. کیفیت تایر به سن، ابعاد، پروفیل و فشار تایر بستگی دارد. اگر یک یا چند عامل کمبود داشته باشد، فاصله ترمز طولانی تر خواهد بود.</div>',0,'- Bereifung',1,1,''),
(221,'1.2.03-002','- Bremsanlage','- braking system','- سیستم ترمز','<div dir=\'rtl\'>انواع مختلفی از سیستم های ترمز وجود دارد. بسته به کیفیت سیستم ترمز، فاصله ترمز کوتاه یا افزایش می یابد.</div>',0,'- Bremsanlage',1,1,''),
(222,'1.2.03-002','- Fahrbahnoberfläche','- road surface','- سطح جاده','<div dir=\'rtl\'>بسته به شرایط سطح جاده، چسبندگی لاستیک خودرو بیشتر یا کمتر است. به عنوان مثال، یخ سیاه چسبندگی لاستیک را در جاده کاهش می دهد و در نتیجه فاصله ترمز را افزایش می دهد.</div>',0,'- Fahrbahnoberfläche',1,1,''),
(223,'1.2.03-101','50','50','50','',0,'50',2,1,'km/h'),
(224,'1.2.03-102','4','4','4','',0,'4',2,1,'times as long'),
(225,'1.2.03-103','Sicht- und Wetterverhältnisse','Visibility and weather conditions','دید و شرایط آب و هوایی','<div dir=\'rtl\'>سرعت باید متناسب با دید و شرایط آب و هوایی تنظیم شود. به عنوان مثال، مه، باران شدید و بارش برف می تواند دید را به حدی مختل کند که برای اینکه خطری برای خود و سایر کاربران جاده ایجاد نکنید، باید بسیار کندتر از حد لازم رانندگی کنید.</div>',0,'Sicht- und Wetterverhältnisse',1,1,''),
(226,'1.2.03-103','Fahrbahnzustand und Verkehrsverhältnisse','The condition of the road and traffic conditions','شرایط جاده و شرایط ترافیک','<div dir=\'rtl\'>نمونه هایی از وضعیت نامناسب جاده ها شامل چاله ها، بسترهای شن (خطر لغزش)، جاده های لغزنده و خاک است. در اینجا باید آهسته تر رانندگی کنید و فاصله کافی را رعایت کنید. علاوه بر این، سرعت باید با شرایط ترافیکی تنظیم شود. هنگامی که حجم ترافیک افزایش می یابد، خطر توقف ترافیک یا ترافیک افزایش می یابد. در اینجا سرعت باید با حجم ترافیک تطبیق داده شود.</div>',0,'Fahrbahnzustand und Verkehrsverhältnisse',1,1,''),
(227,'1.2.03-103','Persönliche Fähigkeiten','Personal driving ability','مهارت های شخصی','<div dir=\'rtl\'>رانندگان تازه کار به طور خاص نمی توانند موقعیت های خطرناک را به همان اندازه ای که رانندگان وسایل نقلیه آموزش دیده می توانند ارزیابی کنند. سالها تجربه رانندگی لازم است تا بتوانید موقعیت های مختلف ترافیکی را ارزیابی کنید و بر اساس آن واکنش نشان دهید. مخصوصاً هنگام رانندگی با سرعت نامحدود یا در مانورهای سبقت‌انگیز گیج‌کننده، باید در مورد ریسک کردن محتاط باشید.</div>',0,'Persönliche Fähigkeiten',1,1,''),
(228,'1.2.03-104','<img src=\'%IMG_ETC%/div10mult3.png\' alt=\'div10mult3.png\' />','<img src=\'%IMG_ETC%/div10mult3.png\' alt=\'div10mult3.png\' />','(سرعت بر حسب کیلومتر تقسیم بر ۱۰) ضربدر ۳','',1,'<img src=\'%IMG_ETC%/div10mult3.png\' alt=\'div10mult3.png\' />',1,1,''),
(229,'1.2.03-104','<img src=\'%IMG_ETC%/div10mult5.png\' alt=\'div10mult5.png\' />','<img src=\'%IMG_ETC%/div10mult5.png\' alt=\'div10mult5.png\' />','<div>(سرعت بر حسب کیلومتر تقسیم بر ۱۰) ضرب در ۵</div>','',1,'<img src=\'%IMG_ETC%/div10mult5.png\' alt=\'div10mult5.png\' />',1,0,''),
(230,'1.2.03-104','<img src=\'%IMG_ETC%/div100.png\' alt=\'div100.png\' />','<img src=\'%IMG_ETC%/div100.png\' alt=\'div100.png\' />','(سرعت بر حسب کیلومتر تقسیم بر ۱۰) ضرب در( سرعت بر حسب کیلومتر تقسیم بر ۱۰)','',1,'<img src=\'%IMG_ETC%/div100.png\' alt=\'div100.png\' />',1,0,''),
(231,'1.2.03-105','<img src=\'%IMG_ETC%/div100.png\' alt=\'div100.png\' />','<img src=\'%IMG_ETC%/div100.png\' alt=\'div100.png\' />','<img src=\'%IMG_ETC%\\/div100.png\' alt=\'div100.png\' \\/>','',1,'<img src=\'%IMG_ETC%/div100.png\' alt=\'div100.png\' />',1,1,''),
(232,'1.2.03-105','<img src=\'%IMG_ETC%/div10mult5.png\' alt=\'div10mult5.png\' />','<img src=\'%IMG_ETC%/div10mult5.png\' alt=\'div10mult5.png\' />','<img src=\'%IMG_ETC%\\/div10mult5.png\' alt=\'div10mult5.png\' \\/>','',1,'<img src=\'%IMG_ETC%/div10mult5.png\' alt=\'div10mult5.png\' />',1,0,''),
(233,'1.2.03-105','<img src=\'%IMG_ETC%/div10mult3.png\' alt=\'div10mult3.png\' />','<img src=\'%IMG_ETC%/div10mult3.png\' alt=\'div10mult3.png\' />','<img src=\'%IMG_ETC%\\/div10mult3.png\' alt=\'div10mult3.png\' \\/>','',1,'<img src=\'%IMG_ETC%/div10mult3.png\' alt=\'div10mult3.png\' />',1,0,''),
(234,'1.2.03-106','36 m','36 m','36 متر','<div dir=\'rtl\'>این را می توان با استفاده از قانون کلی برای ترمز معمولی به شرح زیر محاسبه کرد: (سرعت بر حسب کیلومتر در ساعت: 10) x (سرعت بر حسب کیلومتر در ساعت: 10) بنابراین در 30 کیلومتر در ساعت فاصله ترمز برابر است: (30 کیلومتر در ساعت: 10) x (30 کیلومتر در ساعت: 10) = 9 متر در ساعت: فاصله 6 کیلومتر در ساعت: 6 کیلومتر در ساعت: 10) x (60 کیلومتر در ساعت : 10) = 36 متر در اینجا می توانید ببینید: فاصله ترمز با دو برابر سرعت چهار برابر می شود!</div>',0,'36 m',1,1,''),
(235,'1.2.03-106','27 m','27 m','27 متر','<div dir=\'rtl\'>این پاسخ صحیح نیست.</div>',0,'27 m',1,0,''),
(236,'1.2.03-106','18 m','18 m','18 متر','<div dir=\'rtl\'>این مسافت ترمز در صورت ترمز اضطراری خواهد بود.</div>',0,'18 m',1,0,''),
(237,'1.2.04-101','Von den Sichtverhältnissen','Visibility conditions','به شرایط دید','<div dir=\'rtl\'>در صورت دید ضعیف، فاصله ایمنی باید افزایش یابد، زیرا دیگر نمی‌توان تشخیص داد که چه اتفاقی در جلوی خودروی جلویی می‌افتد.</div>',0,'Von den Sichtverhältnissen',1,1,''),
(238,'1.2.04-101','Von der Geschwindigkeit','Speed','به سرعت','<div dir=\'rtl\'>با افزایش سرعت، مسافت واکنش، مسافت ترمز و مسافت توقف نیز افزایش می‌یابند. برای جبران این امر، فاصله نیز باید افزایش یابد.</div>',0,'Von der Geschwindigkeit',1,1,''),
(239,'1.2.04-101','Von der Fahrbahnbeschaffenheit','State of the road surface','به وضعیت سطح جاده','<div dir=\'rtl\'>هرچه وضعیت سطح جاده (یعنی شرایط جاده) بدتر باشد، مسافت ترمز و مسافت توقف طولانی‌تر می‌شوند. بنابراین، در این حالت نیز باید فاصله ایمنی افزایش یابد.</div>',0,'Von der Fahrbahnbeschaffenheit',1,1,''),
(240,'1.2.05-101','Wo die Verkehrslage unklar ist','When the traffic situation is not clear','جایی که وضعیت ترافیک نامشخص است','<div dir=\'rtl\'>به طور کلی: در صورت لزوم، تنها زمانی سبقت بگیرید که وضعیت ترافیک به طور کامل قابل مشاهده و ارزیابی باشد. در وضعیت‌های ترافیکی نامشخص، سبقت‌گیری ایمن تضمین نمی‌شود.</div>',0,'Wo die Verkehrslage unklar ist',1,1,''),
(241,'1.2.05-101','Wo der Gegenverkehr behindert werden könnte','Where oncoming traffic could be obstructed','جایی که ممکن است مانع ترافیک مقابل شود','<div dir=\'rtl\'>عملیات سبقت باید به گونه‌ای انجام شود که نه ترافیک مقابل و نه خودروی سبقت‌گرفته‌شده مجبور به ترمز کردن نشوند. بنابراین، سرعت خودروی جلویی، سرعت ترافیک مقابل و فاصله تا ترافیک مقابل باید در مانور سبقت در نظر گرفته شود.</div>',0,'Wo der Gegenverkehr behindert werden könnte',1,1,''),
(242,'1.2.05-101','In allen Einbahnstraßen','In all one-way streets','در تمام خیابان‌های یک‌طرفه','<div dir=\'rtl\'>خیابان‌های یک‌طرفه می‌توانند دو لاین نیز داشته باشند. به طور کلی، سبقت گرفتن در اینجا ممنوع نیست، با این حال باید هوشیاری بیشتری داشت.</div>',0,'In allen Einbahnstraßen',1,0,''),
(243,'1.2.05-103','Dass eine Gefährdung des nachfolgenden Verkehrs ausgeschlossen ist','There is no danger to the traffic behind','اینکه هیچ خطری برای ترافیک پشت سر وجود نداشته باشد.','<div dir=\'rtl\'>اگر این تضمین نشود، پس نباید سبقت گرفت.</div>',0,'Dass eine Gefährdung des nachfolgenden Verkehrs ausgeschlossen ist',1,1,''),
(244,'1.2.05-103','Dass der Gegenverkehr nicht gefährdet wird','Oncoming traffic is not endangered','اینکه ترافیک روبرو به خطر نیفتد.','<div dir=\'rtl\'>ترافیک روبرو هنگام سبقت گرفتن نباید مختل شود. اگر فاصله با آن، مثلاً به دلیل شرایط ترافیکی نامشخص، قابل تخمین نباشد، در این صورت باید از سبقت گرفتن خودداری کرد.</div>',0,'Dass der Gegenverkehr nicht gefährdet wird',1,1,''),
(245,'1.2.05-103','Dass der Vorausfahrende rechts blinkt','The vehicle in front indicates right','اینکه خودروی جلویی راهنمای راست بزند.','<div dir=\'rtl\'>اگر خودروی جلویی راهنمای راست بزند، این به معنای آن است که او می‌خواهد به راست بپیچد، یا می‌خواهد به خودروی پشت سر علامت دهد که مسیر برای سبقت گرفتن آزاد است. اما این یک پیش‌نیاز برای خارج شدن از مسیر جهت سبقت گرفتن نیست.</div>',0,'Dass der Vorausfahrende rechts blinkt',1,0,''),
(246,'1.2.05-104','Ohne den Überholten zu behindern, so bald wie möglich wieder nach rechts einordnen','Move over to the right as soon as possible without inconveniencing the vehicle you have overtaken','بدون ایجاد مزاحمت برای خودروی سبقت‌گرفته‌شده، در اسرع وقت دوباره به سمت راست برگردید.','<div dir=\'rtl\'>هنگام سبقت گرفتن باید اطمینان حاصل شود که هیچ خطری برای خودروی سبقت‌گرفته‌شده وجود ندارد. علاوه بر این، سبقت‌گیرنده باید پس از اتمام سبقت، در اسرع وقت دوباره به سمت راست برگردد.</div>',0,'Ohne den Überholten zu behindern, so bald wie möglich wieder nach rechts einordnen',1,1,''),
(247,'1.2.05-104','Das Wiedereinordnen rechtzeitig und deutlich anzeigen','Signal your intention to draw in clearly and in good time','بازگشت به مسیر را به موقع و به وضوح اعلام کنید.','<div dir=\'rtl\'>طبق آیین‌نامه راهنمایی و رانندگی، عملیات سبقت باید به موقع و به وضوح از قبل با استفاده از چراغ راهنما اعلام شود تا سایر کاربران جاده بتوانند خود را با آن تطبیق دهند.</div>',0,'Das Wiedereinordnen rechtzeitig und deutlich anzeigen',1,1,''),
(248,'1.2.05-104','Dicht vor dem Überholten wieder auf die rechte Fahrbahnseite wechseln','Move over to the right-hand side of the roadway right in front of the vehicle you have overtaken','درست جلوی خودروی سبقت‌گرفته‌شده دوباره به سمت راست جاده برگردید.','<div dir=\'rtl\'>قبل، حین و بعد از عملیات سبقت باید فاصله ایمنی رعایت شود. بنابراین، هنگام بازگشت به مسیر نیز باید اطمینان حاصل شود که همیشه فضای کافی در پشت خودروی سبقت‌گرفته‌شده وجود دارد.</div>',0,'Dicht vor dem Überholten wieder auf die rechte Fahrbahnseite wechseln',1,0,''),
(249,'1.2.05-105','Die Geschwindigkeit des Überholenden muss wesentlich höher sein','The speed of the overtaking vehicle must be appreciably higher','سرعت خودروی سبقت‌گیرنده باید به طور قابل توجهی بیشتر باشد.','<div dir=\'rtl\'>سرعت خودروی سبقت‌گیرنده باید به طور قابل توجهی بیشتر باشد، زیرا در غیر این صورت، فرآیند سبقت طولانی شده و می‌تواند منجر به موقعیت‌های خطرناک در مسیر حرکت وسایل نقلیه روبرو یا هنگام بازگشت به لاین شود.</div>',0,'Die Geschwindigkeit des Überholenden muss wesentlich höher sein',1,1,''),
(250,'1.2.05-105','Die zulässige Höchstgeschwindigkeit darf nicht überschritten werden','The permissible top speed must not be exceeded','حداکثر سرعت مجاز نباید تجاوز شود.','<div dir=\'rtl\'>حداکثر سرعت مجاز در هیچ شرایطی، حتی هنگام سبقت گرفتن، نباید تجاوز شود.</div>',0,'Die zulässige Höchstgeschwindigkeit darf nicht überschritten werden',1,1,''),
(251,'1.2.05-105','Wer überholt wird, darf seine Geschwindigkeit nicht erhöhen','The person being overtaken must not increase his speed','کسی که از او سبقت گرفته می‌شود، نباید سرعت خود را افزایش دهد.','<div dir=\'rtl\'>اگر خودرویی که از آن سبقت گرفته می‌شود، سرعت خود را در طول فرآیند سبقت افزایش دهد، خطر غیرقابل پیش‌بینی برای خودروی سبقت‌گیرنده ایجاد می‌شود، زیرا او باید بیشتر از حد برنامه‌ریزی شده در مسیر مقابل بماند و ممکن است دید کافی برای سبقت ایمن دیگر وجود نداشته باشد.</div>',0,'Wer überholt wird, darf seine Geschwindigkeit nicht erhöhen',1,1,''),
(252,'1.2.05-106','Möglichst weit rechts fahren','If possible, drive on the far right','تا حد امکان در سمت راست رانندگی کنید','<div dir=\'rtl\'>هنگامی که از شما سبقت گرفته می‌شود، باید تمام تلاش خود را بکنید تا عملیات سبقت‌گیری به خطر نیفتد. این شامل رانندگی تا حد امکان در سمت راست به عنوان وسیله نقلیه‌ای است که از آن سبقت گرفته می‌شود.</div>',0,'Möglichst weit rechts fahren',1,1,''),
(253,'1.2.05-106','Geschwindigkeit nicht erhöhen','Not increase your speed','سرعت را افزایش ندهید','<div dir=\'rtl\'>هنگامی که از شما سبقت گرفته می‌شود، باید تمام تلاش خود را بکنید تا عملیات سبقت‌گیری به خطر نیفتد. بر این اساس، سرعت نباید افزایش یابد، زیرا در غیر این صورت سبقت‌گیرنده ممکن است در خط مقابل یا هنگام بازگشت به خط خود دچار مشکل شود.</div>',0,'Geschwindigkeit nicht erhöhen',1,1,''),
(254,'1.2.05-106','Geschwindigkeit erhöhen','Increase your speed','سرعت را افزایش دهید','<div dir=\'rtl\'>هنگامی که از شما سبقت گرفته می‌شود، باید تمام تلاش خود را بکنید تا عملیات سبقت‌گیری به خطر نیفتد. بر این اساس، سرعت نباید افزایش یابد، زیرا در غیر این صورت سبقت‌گیرنده ممکن است در خط مقابل یا هنگام بازگشت به خط خود دچار مشکل شود.</div>',0,'Geschwindigkeit erhöhen',1,0,''),
(255,'1.2.05-107','Rechts','On the right','از سمت راست','<div dir=\'rtl\'>از تراموایی که در وسط خط حرکت می‌کند، همیشه باید از سمت راست سبقت گرفت. سبقت گرفتن از سمت چپ به این معنی است که شما باید وارد خط مقابل شوید. به دلیل طول تراموا، این کار بسیار خطرناک است.</div>',0,'Rechts',1,1,''),
(256,'1.2.05-107','Links','On the left','از سمت چپ','<div dir=\'rtl\'>حتی اگر وسایل نقلیه در سمت راست مسیر را مسدود کرده باشند، نباید از تراموا از سمت چپ سبقت گرفت. در این صورت باید صبر کرد تا ترافیک باز شود.</div>',0,'Links',1,0,''),
(257,'1.2.05-107','Links nur dann, wenn rechts andere Fahrzeuge die Fahrbahn versperren','On the left only if other vehicles are blocking the roadway on the right','از سمت چپ فقط در صورتی که وسایل نقلیه دیگر در سمت راست مسیر را مسدود کرده باشند','<div dir=\'rtl\'>از تراموایی که در وسط خط حرکت می‌کند، همیشه باید از سمت راست سبقت گرفت. سبقت گرفتن از سمت چپ به این معنی است که شما باید وارد خط مقابل شوید. به دلیل طول تراموا، این کار بسیار خطرناک است.</div>',0,'Links nur dann, wenn rechts andere Fahrzeuge die Fahrbahn versperren',1,0,''),
(258,'1.2.05-108','In Einbahnstraßen','In one-way streets','در خیابان‌های یک‌طرفه','<div dir=\'rtl\'>خیابان‌های یک‌طرفه فقط از یک مسیر برای یک جهت تشکیل شده‌اند. در این حالت، می‌توان از تراموا از سمت چپ نیز سبقت گرفت.</div>',0,'In Einbahnstraßen',1,1,''),
(259,'1.2.05-108','Wenn die Schienen zu weit rechts liegen','When the rails run too far to the right','اگر ریل‌ها بیش از حد به سمت راست قرار گرفته باشند','<div dir=\'rtl\'>اگر ریل‌ها در مسیر حرکت بیش از حد به سمت راست قرار گرفته باشند، اغلب امکان سبقت گرفتن وجود ندارد. در این صورت، به طور استثنایی می‌توان از سمت چپ سبقت گرفت.</div>',0,'Wenn die Schienen zu weit rechts liegen',1,1,''),
(260,'1.2.05-108','Wenn die Fahrbahn (keine Einbahnstraße) rechts neben der Straßenbahn durch andere Fahrzeuge versperrt ist','When the roadway (not a one-way street) to the right of the tram is blocked by other vehicles','اگر مسیر (نه خیابان یک‌طرفه) در سمت راست تراموا توسط وسایل نقلیه دیگر مسدود شده باشد','<div dir=\'rtl\'>اگر ریل‌ها بیش از حد به سمت راست قرار گرفته باشند، آنگاه مجاز به سبقت گرفتن از تراموا از سمت چپ هستم. اگر در حاشیه سمت راست مسیر، وسایل نقلیه توقف کرده یا پارک شده باشند، ریل‌ها بیش از حد به سمت راست قرار نگرفته‌اند، بلکه فقط وسایل نقلیه مزاحم هستند. استثنای مجاز بودن سبقت از سمت چپ در این مورد اعمال نمی‌شود.</div>',0,'Wenn die Fahrbahn (keine Einbahnstraße) rechts neben der Straßenbahn durch andere Fahrzeuge versperrt ist',1,0,''),
(261,'1.2.05-109','Fahrräder','Bicycles','دوچرخه‌ها','<div dir=\'rtl\'>هنگام سبقت گرفتن از دوچرخه‌ها، همیشه باید انتظار حرکات ناگهانی یا مانورهای انحرافی غیرمنتظره را داشته باشید. به همین دلیل، همیشه باید با احتیاط ویژه و با فاصله جانبی بسیار زیاد (حداقل ۱.۵ تا ۲ متر) از این شرکت‌کنندگان در ترافیک عبور کنید.</div>',0,'Fahrräder',1,1,''),
(262,'1.2.05-109','Motorräder','Motorcycles','موتورسیکلت‌ها','<div dir=\'rtl\'>موتورسیکلت‌ها اگرچه به چابکی دوچرخه‌ها نیستند، اما ممکن است گاهی اوقات به طور غیرمنتظره تغییر مسیر دهند. بنابراین، هنگام سبقت گرفتن از موتورسیکلت‌ها نیز باید فاصله جانبی بسیار زیادی را رعایت کرد.</div>',0,'Motorräder',1,1,''),
(263,'1.2.05-109','Straßenbahnen','Trams','ترامواها','<div dir=\'rtl\'>ترامواها روی ریل حرکت می‌کنند که امکان انحراف ناگهانی یا حرکات غیرمنتظره را نمی‌دهد. بنابراین، نیازی به حفظ فاصله بسیار زیاد ندارید، زیرا نباید انتظار مانورهای غیرمنتظره را داشته باشید.</div>',0,'Straßenbahnen',1,0,''),
(264,'1.2.05-110','Vor dem Ausscheren zum Überholen oder zum Vorbeifahren','Before pulling out to overtake or to pass','قبل از انحراف برای سبقت گرفتن یا عبور کردن','<div dir=\'rtl\'>با راهنما زدن، به سایر کاربران جاده نشان می‌دهید که قصد دارید به راست یا چپ بپیچید. به همین ترتیب، هنگام انحراف برای سبقت گرفتن یا عبور کردن در یک جهت، باید راهنما بزنید.</div>',0,'Vor dem Ausscheren zum Überholen oder zum Vorbeifahren',1,1,''),
(265,'1.2.05-110','Vor dem Wiedereinordnen nach dem Überholen','Before pulling in again after overtaking','قبل از بازگشت به مسیر اصلی پس از سبقت گرفتن','<div dir=\'rtl\'>قبل از بازگشت به مسیر اصلی پس از سبقت گرفتن نیز باید راهنما بزنید، زیرا به خط اصلی حرکت خود بازمی‌گردید.</div>',0,'Vor dem Wiedereinordnen nach dem Überholen',1,1,''),
(266,'1.2.05-110','Beim Verlassen einer abknickenden Vorfahrtstraße in gerader Richtung','When proceeding straight ahead as you leave a priority road which bends sharply','هنگام ترک یک خیابان اصلی با حق تقدم خمیده به صورت مستقیم','<div dir=\'rtl\'>با علامت راهنما، قصد خود را برای حرکت در جهتی غیر از مستقیم به سایر کاربران جاده اطلاع می‌دهید. بنابراین، هنگام حرکت مستقیم نباید راهنما بزنید. این کار می‌تواند سایر کاربران جاده را گیج کند.</div>',0,'Beim Verlassen einer abknickenden Vorfahrtstraße in gerader Richtung',1,0,''),
(267,'1.2.06-001','Das Fahrzeug, auf dessen Seite die Baustelle ist','The vehicle on the side of the roadway where the roadworks are','وسیله نقلیه‌ای که کارگاه ساختمانی در سمت آن قرار دارد','<div dir=\'rtl\'>همیشه کسی باید توقف کند و به ترافیک روبرو اجازه عبور دهد که موانع در سمت او قرار دارند. این اصل در مورد کارگاه‌های ساختمانی نیز صدق می‌کند.</div>',0,'Das Fahrzeug, auf dessen Seite die Baustelle ist',1,1,''),
(268,'1.2.06-001','Das Fahrzeug auf der freien Fahrbahnhälfte','The vehicle on the unobstructed side of the roadway','وسیله نقلیه در نیمه آزاد خط عبور','<div dir=\'rtl\'>وسیله نقلیه در نیمه آزاد خط عبور نیازی به توقف ندارد. می‌تواند عبور کند، زیرا مانع در خط عبور مقابل قرار دارد.</div>',0,'Das Fahrzeug auf der freien Fahrbahnhälfte',1,0,''),
(269,'1.2.06-001','Immer das kleinere Fahrzeug','Always the smaller vehicle','همیشه وسیله نقلیه کوچکتر','<div dir=\'rtl\'>نسبت اندازه وسایل نقلیه نقشی ندارد. در ترافیک جاده‌ای، هدف نشان دادن این نیست که چه کسی قوی‌تر است. حتی اگر یک کامیون ۱۲ تنی پشت یک کارگاه ساختمانی ایستاده باشد، ابتدا باید به یک خودروی کوچک روبرو اجازه عبور دهد، قبل از اینکه خودش بتواند از کارگاه ساختمانی عبور کند.</div>',0,'Immer das kleinere Fahrzeug',1,0,''),
(270,'1.2.07-001','Fahrstreifenwechsel rechtzeitig ankündigen','You must signal your intention to change lanes in time','تغییر خط رانندگی را به موقع اعلام کنید','<div dir=\'rtl\'>برای اطلاع‌رسانی به موقع به سایر کاربران جاده در مورد قصد خود، باید تغییر خط رانندگی را به موقع اعلام کنید (با استفاده از راهنما). این کار به سایر کاربران جاده امکان می‌دهد تا خود را آماده کنند.</div>',0,'Fahrstreifenwechsel rechtzeitig ankündigen',1,1,''),
(271,'1.2.07-001','Auf den nachfolgenden Verkehr achten','You must pay attention to the traffic following behind','به ترافیک پشت سر خود توجه کنید','<div dir=\'rtl\'>شما همیشه باید به ترافیک پشت سر خود نیز توجه کنید تا مانع هیچ وسیله نقلیه‌ای نشوید یا تصادفی ایجاد نکنید. در اینجا باید در نظر داشت که راننده پشت سر شما ممکن است هنوز متوجه نشده باشد که شما قصد تغییر خط رانندگی را دارید.</div>',0,'Auf den nachfolgenden Verkehr achten',1,1,''),
(272,'1.2.07-001','Vor dem Fahrstreifenwechsel immer stark abbremsen','You must always brake heavily before changing lanes','همیشه قبل از تغییر خط رانندگی به شدت ترمز کنید','<div dir=\'rtl\'>با ترمز شدید، مانع ترافیک پشت سر خود می‌شوید و آن را به خطر می‌اندازید.</div>',0,'Vor dem Fahrstreifenwechsel immer stark abbremsen',1,0,''),
(273,'1.2.07-104','Fahrstreifenbegrenzung nicht überfahren','','از خطوط محدودکننده مسیر عبور نکنید','<div dir=\'rtl\'>به طور کلی، عبور از خطوط محدودکننده مسیر مجاز نیست.</div>',0,'Fahrstreifenbegrenzung nicht überfahren',1,1,''),
(274,'1.2.07-104','Nicht wenden','','دور نزنید','<div dir=\'rtl\'>دور زدن در تونل ممنوع است.</div>',0,'Nicht wenden',1,1,''),
(275,'1.2.07-104','Zum Überholen Fahrstreifenbegrenzung überfahren','','برای سبقت گرفتن از خطوط محدودکننده مسیر عبور کنید','<div dir=\'rtl\'>از خطوط محدودکننده مسیر نباید عبور کرد. آنها به دلایل موجه، به ویژه در تونل، سبقت گرفتن را ممنوع می‌کنند.</div>',0,'Zum Überholen Fahrstreifenbegrenzung überfahren',1,0,''),
(276,'1.2.09-101','Zu schnelles Fahren','Driving too fast','رانندگی با سرعت زیاد','<div dir=\'rtl\'>رانندگی با سرعت زیاد می‌تواند منجر به این شود که در حین گردش دچار لغزش شوم و در نتیجه خطر ورود به مسیر دیگر را داشته باشم. بدین ترتیب، من خطری برای سایر شرکت‌کنندگان در ترافیک ایجاد می‌کنم. بنابراین، عمل گردش همیشه باید به آرامی و با مشاهده ترافیک باقی‌مانده انجام شود.</div>',0,'Zu schnelles Fahren',1,1,''),
(277,'1.2.09-101','Fahrstreifenwechsel während des Abbiegens','Changing lanes while performing the turn','تغییر مسیر (لاین) در حین گردش','<div dir=\'rtl\'>مسیر باید از مدتی قبل از شروع واقعی گردش تغییر داده شود. تغییر مسیر در حین گردش مجاز نیست، زیرا نمی‌توان همزمان به ترافیک پشت سر در هنگام تغییر مسیر و همچنین به سایر شرکت‌کنندگان در ترافیک هنگام گردش توجه کرد. بدین ترتیب، به سرعت اشتباهات و در نتیجه تصادفات رخ می‌دهند. بنابراین، منطقی است که ابتدا مسیر را تغییر دهید و سپس گردش کنید.</div>',0,'Fahrstreifenwechsel während des Abbiegens',1,1,''),
(278,'1.2.09-101','Genaues Einhalten des Fahrstreifens','Keeping exactly to your lane','رعایت دقیق مسیر (لاین)','<div dir=\'rtl\'>رعایت دقیق مسیر منجر به این می‌شود که هیچ مسیر دیگری در حین گردش قطع نشود. بدین ترتیب، عملکرد خود شخص بی‌خطر است. با این حال، مهم است که با دید باز رانندگی کرده و جریان ترافیک را به طور مداوم مشاهده کنید.</div>',0,'Genaues Einhalten des Fahrstreifens',1,0,''),
(279,'1.2.09-103-B','Der gelbe Pkw','The yellow car','خودروی سواری زرد','<div dir=\'rtl\'>خودروی سواری زرد طبق مقررات از سمت راست مانع عبور کرده تا سپس به چپ بپیچد.</div>',0,'Der gelbe Pkw',1,1,''),
(280,'1.2.09-103-B','Der Lkw','The truck','کامیون','<div dir=\'rtl\'>کامیون در لاین سمت راست قرار گرفته است. او باید در لاین سمت چپ قرار می‌گرفت تا بتواند به چپ بپیچد.</div>',0,'Der Lkw',1,0,''),
(281,'1.2.09-103-B','Der grüne Pkw','The green car','خودروی سواری سبز','<div dir=\'rtl\'>خودروی سواری سبز روی ریل‌ها ایستاده و به تابلوی راهنمایی و رانندگی که نشان می‌دهد باید از سمت راست مانع عبور کرد، توجه نکرده است.</div>',0,'Der grüne Pkw',1,0,''),
(282,'1.2.09-104-B','- rote Pkw','- the red car','- خودروی قرمز','<div dir=\'rtl\'>خودروی قرمز در لاین سمت راست قرار دارد. به این ترتیب، پس از گردش به چپ، گردش به راست بدون نیاز به تغییر لاین امکان‌پذیر است.</div>',0,'- rote Pkw',1,1,''),
(283,'1.2.09-104-B','- grüne Pkw','- the green car','- خودروی سبز','<div dir=\'rtl\'>اگر خود را پشت خودروی سبز قرار دهید، باید قبل از گردش به راست یک بار دیگر لاین را تغییر دهید، که در چنین مسافت کوتاهی و با وجود ترافیک می‌تواند خطرناک باشد.</div>',0,'- grüne Pkw',1,0,''),
(284,'1.2.09-104-B','- blaue Pkw','- the blue car','- خودروی آبی','<div dir=\'rtl\'>خودروی آبی بین دو لاین قرار گرفته است. این کار مجاز نیست و باعث سردرگمی سایر کاربران جاده می‌شود.</div>',0,'- blaue Pkw',1,0,''),
(285,'1.2.09-107-B','Das Motorrad','The motorcycle','موتورسیکلت','<div dir=\'rtl\'>هر تغییر جهت باید با راهنما زدن نشان داده شود، حتی اگر از خیابان اصلی خارج نشوید.</div>',0,'Das Motorrad',1,1,''),
(286,'1.2.09-107-B','Ich selbst','I myself','خودم','<div dir=\'rtl\'>شما که جهت حرکت خود را تغییر نمی‌دهید.</div>',0,'Ich selbst',1,0,''),
(287,'1.2.09-107-B','Keiner','No one','هیچ‌کس','<div dir=\'rtl\'>شما نیازی به نشان دادن تغییر جهت حرکت ندارید، زیرا مستقیم می‌رانید. اما موتورسوار باید راهنما بزند و نشان دهد که به چپ می‌پیچد.</div>',0,'Keiner',1,0,''),
(288,'1.2.09-109','Eine Mittelinsel darf nur überfahren werden, wenn dies aufgrund der Fahrzeuggröße unvermeidbar ist','You can only drive over a central island if this is unavoidable because of your vehicle\'s size','عبور از جزیره مرکزی تنها زمانی مجاز است که به دلیل ابعاد خودرو اجتناب‌ناپذیر باشد','<div dir=\'rtl\'>همانطور که در بالا توضیح داده شد، طبق بند ۲ از ماده ۹a قانون راهنمایی و رانندگی (StVO)، عبور از جزیره مرکزی تنها زمانی مجاز است که به دلیل ابعاد خودرو چاره دیگری نباشد.</div>',0,'Eine Mittelinsel darf nur überfahren werden, wenn dies aufgrund der Fahrzeuggröße unvermeidbar ist',1,1,''),
(289,'1.2.09-109','Im Kreisverkehr ist das Halten auf der Fahrbahn verboten','You are not allowed to stop on the roadway in a roundabout','توقف در مسیر حرکت در داخل میدان ممنوع است','<div dir=\'rtl\'>همانطور که در بالا توضیح داده شد، طبق بند ۱ از ماده ۹a قانون راهنمایی و رانندگی (StVO)، توقف در مسیر حرکت ممنوع است، اگر در یک میدان (فلکه) باشید.</div>',0,'Im Kreisverkehr ist das Halten auf der Fahrbahn verboten',1,1,''),
(290,'1.2.09-109','Das Verlassen des Kreises muss durch Blinken angezeigt werden','You must indicate to leave the roundabout','خروج از میدان باید با استفاده از چراغ راهنما نشان داده شود','<div dir=\'rtl\'>خروج از میدان (فلکه) از نظر قانون راهنمایی و رانندگی (StVO) معادل پیچیدن به راست است. بنابراین، تمام قوانین مربوط به پیچیدن باید رعایت شود. همانطور که در بالا توضیح داده شد، طبق بند ۱ از ماده ۹ قانون راهنمایی و رانندگی (StVO)، در این حالت باید از چراغ‌های راهنما استفاده شود.</div>',0,'Das Verlassen des Kreises muss durch Blinken angezeigt werden',1,1,''),
(291,'1.2.09-113-M','Ich selbst','Me','خودم','<div dir=\'rtl\'>زیرا شما به سمت چپ می‌پیچید، باید تغییر جهت حرکت خود را نشان دهید.</div>',0,'Ich selbst',1,1,''),
(292,'1.2.09-113-M','<span class=\"mutterfrage\">Der rote Pkw</span>','<span class=\\\"mutterfrage\\\">The red car</span>','<span class=\"mutterfrage\">خودروی قرمز</span>','<div dir=\'rtl\'>خودروی قرمز باید قبل از پیچیدن به چپ، راهنما بزند.</div>',0,'<span class=\"mutterfrage\">Der rote Pkw</span>',1,1,''),
(293,'1.2.09-113-M','<span class=\"mutterfrage\">Das Motorrad</span>','<span class=\\\"mutterfrage\\\">The motorbike</span>','<span class=\"mutterfrage\">موتورسیکلت</span>','<div dir=\'rtl\'>موتورسوار باید قبل از پیچیدن به راست، راهنما بزند.</div>',0,'<span class=\"mutterfrage\">Das Motorrad</span>',1,1,''),
(294,'1.2.09-117','Vor dem Abbiegen in eine Einmündung oder in ein Grundstück','Before turning into a junction or a property lot','قبل از پیچیدن به یک تقاطع یا به یک ملک','<div dir=\'rtl\'>اگر می‌خواهید به یک تقاطع یا به یک ملک بپیچید، باید آن را با راهنما زدن نشان دهید.</div>',0,'Vor dem Abbiegen in eine Einmündung oder in ein Grundstück',1,1,''),
(295,'1.2.09-117','Wenn ich dem Verlauf einer abknickenden Vorfahrtstraße folgen will','If I want to continue following a priority road that changes direction','اگر می‌خواهم مسیر یک خیابان با حق تقدم خمیده را دنبال کنم','<div dir=\'rtl\'>حتی اگر در یک خیابان با حق تقدم هستید، باید تغییر جهت حرکت را نشان دهید، اگر این خیابان خمیده باشد.</div>',0,'Wenn ich dem Verlauf einer abknickenden Vorfahrtstraße folgen will',1,1,''),
(296,'1.2.09-117','Wenn ich eine abknickende Vorfahrtstraße in gerader Richtung verlassen will','If I want to continue straight on, thereby leaving a priority road that changes direction','اگر می‌خواهم یک خیابان با حق تقدم خمیده را در جهت مستقیم ترک کنم','<div dir=\'rtl\'>اگر مستقیم رانندگی می‌کنید، جهت حرکت را تغییر نمی‌دهید و بنابراین نیازی به نشان دادن آن ندارید.</div>',0,'Wenn ich eine abknickende Vorfahrtstraße in gerader Richtung verlassen will',1,0,''),
(297,'1.2.10-005','Wer über einen abgesenkten Bordstein in eine Straße einfährt, ist wartepflichtig','Whoever turns into a road over a sunken kerbstone must wait','کسی که از روی یک جدول پایین‌آورده شده وارد خیابان می‌شود، موظف به رعایت حق تقدم است.','<div dir=\'rtl\'>در اینجا همان قوانینی اعمال می‌شود که هنگام خروج از یک خروجی. بر این اساس، باید حق تقدم به سایر کاربران ترافیک داده شود.</div>',0,'Wer über einen abgesenkten Bordstein in eine Straße einfährt, ist wartepflichtig',1,1,''),
(298,'1.2.10-005','Die Regel „rechts vor links“','The rule \\\"right before left\\\"','قانون «راست به چپ»','<div dir=\'rtl\'>حتی یک خودروی سواری که از سمت چپ می‌آید نیز حق تقدم دارد، زیرا در اینجا قانون «راست به چپ» اعمال نمی‌شود. باید به سایر کاربران ترافیک حق تقدم داده شود.</div>',0,'Die Regel „rechts vor links“',1,0,''),
(299,'1.2.10-005','Der abgesenkte Bordstein ist für die Wartepflicht ohne Bedeutung','The sunken kerbstone is of no relevance for the obligation to wait','جدول پایین‌آورده شده برای رعایت حق تقدم بی‌اهمیت است.','<div dir=\'rtl\'>برعکس این موضوع صحیح است. جدول پایین‌آورده شده نشان‌دهنده لزوم رعایت حق تقدم است. بر این اساس، سایر کاربران ترافیک مجازند قبل از شما حرکت کنند.</div>',0,'Der abgesenkte Bordstein ist für die Wartepflicht ohne Bedeutung',1,0,''),
(300,'1.2.10-101','Rückwärtigen Verkehr beobachten','Check for traffic from behind','ترافیک پشت سر را مشاهده کنید','<div dir=\'rtl\'>همانطور که در بالا توضیح داده شد، هنگام حرکت از کنار جاده نباید هیچ کس به خطر بیفتد. برای اطمینان از این امر، باید سایر شرکت‌کنندگان در ترافیک و وضعیت ترافیک به دقت مشاهده شوند. برای این منظور باید از آینه‌های داخلی و خارجی خودرو استفاده شود.</div>',0,'Rückwärtigen Verkehr beobachten',1,1,''),
(301,'1.2.10-101','Blinken','Switch on your direction indicator','راهنما زدن','<div dir=\'rtl\'>تا سایر شرکت‌کنندگان در ترافیک قصد شما را برای ورود به خیابان متوجه شوند، باید از راهنما (چراغ نشانگر جهت) استفاده شود.</div>',0,'Blinken',1,1,''),
(302,'1.2.10-101','Blick in den Rückspiegel genügt','A look into the rear-view mirror is sufficient','نگاه کردن به آینه عقب کافی است','<div dir=\'rtl\'>همانطور که در بالا توضیح داده شد، برای حرکت باید از چراغ راهنما (چراغ چشمک‌زن) استفاده شود. بنابراین، تنها مشاهده سایر شرکت‌کنندگان در ترافیک کافی نیست.</div>',0,'Blick in den Rückspiegel genügt',1,0,''),
(303,'1.2.11-003','Kreuzungen','Crossroads','تقاطع‌ها','<div dir=\'rtl\'>تقاطع‌ها باید در ترافیک متوقف به طور کلی باز نگه داشته شوند، زیرا در غیر این صورت، ترافیک عرضی نیز مسدود شده و جریان ترافیک به طور غیرضروری مختل خواهد شد.</div>',0,'Kreuzungen',1,1,''),
(304,'1.2.11-003','Bahnübergänge','Level crossings','گذرگاه‌های ریلی','<div dir=\'rtl\'>از آنجایی که در ترافیک متوقف نمی‌توانید با اطمینان بگویید چه زمانی وسایل نقلیه جلوی شما دوباره حرکت کرده و گذرگاه ریلی را ترک می‌کنند، اگر در محدوده ریل متوقف شوید، خود را در معرض خطر بسیار زیادی قرار می‌دهید. اگر موانع بسته شوند، دیگر هیچ راهی برای خروج وسیله نقلیه خود از روی ریل‌ها نخواهید داشت. برخورد با قطار در حال نزدیک شدن اجتناب‌ناپذیر خواهد بود.</div>',0,'Bahnübergänge',1,1,''),
(305,'1.2.11-003','Grundstückseinfahrten','Driveways','ورودی‌های ملک','<div dir=\'rtl\'>هیچ الزام کلی برای باز نگه داشتن ورودی‌های ملک در ترافیک متوقف وجود ندارد. با این حال، اگر می‌بینید که کسی قصد ورود یا خروج از ملک را دارد، باز نگه داشتن ورودی ملک منطقی است.</div>',0,'Grundstückseinfahrten',1,0,''),
(306,'1.2.12-001','Auf Bahnübergängen','On level crossings','در گذرگاه‌های ریلی (تقاطع راه‌آهن)','<div dir=\'rtl\'>توقف در گذرگاه‌های ریلی مانع ترافیک ریلی می‌شود و بسیار خطرناک است.</div>',0,'Auf Bahnübergängen',1,1,''),
(307,'1.2.12-001','An engen und an unübersichtlichen Straßenstellen','On narrow sections of the road and at blind spots','در نقاط باریک و با دید محدود جاده','<div dir=\'rtl\'>نقاط باریک و با دید محدود جاده، مکان‌های بالقوه خطرناک برای تصادفات هستند. برای اینکه خطر تصادف بیشتر نشود، توقف در این نقاط ممنوع است.</div>',0,'An engen und an unübersichtlichen Straßenstellen',1,1,''),
(308,'1.2.12-001','Unmittelbar hinter Fußgängerüberwegen','Immediately behind pedestrian crossings','بلافاصله پشت گذرگاه‌های عابر پیاده','<div dir=\'rtl\'>بلافاصله پشت گذرگاه‌های عابر پیاده، دید به گذرگاه عابر پیاده مختل نمی‌شود. بنابراین، در اینجا نیز می‌توان توقف کرد.</div>',0,'Unmittelbar hinter Fußgängerüberwegen',1,0,''),
(309,'1.2.12-002','Am Fahrbahnrand, wenn hierdurch die Benutzung gekennzeichneter Parkflächen verhindert wird','At the edge of the roadway if this would prevent others from using designated parking areas','در کنار جاده، اگر این کار مانع استفاده از فضاهای پارک مشخص شده شود','<div dir=\'rtl\'>پارک کردن وسایل نقلیه به گونه‌ای که مانع استفاده از فضاهای پارک مشخص شده شود، مجاز نیست (بند ۱۲، بخش ۳، جمله ۲ StVO).</div>',0,'Am Fahrbahnrand, wenn hierdurch die Benutzung gekennzeichneter Parkflächen verhindert wird',1,1,''),
(310,'1.2.12-002','Auf Vorfahrtstraßen außerhalb geschlossener Ortschaften','On priority roads outside built-up areas','در خیابان‌های حق تقدم خارج از مناطق مسکونی','<div dir=\'rtl\'>پارک کردن در خیابان‌های حق تقدم داخل مناطق مسکونی مجاز است. در اینجا حداکثر سرعت وسایل نقلیه به ۵۰ کیلومتر در ساعت محدود شده است. برای استفاده بهتر از فضای محدود در یک منطقه مسکونی، می‌توان در کنار جاده پارک کرد، مشروط بر اینکه فضای پارک با تابلوی ممنوعیت پارک مشخص نشده باشد.</div>',0,'Auf Vorfahrtstraßen außerhalb geschlossener Ortschaften',1,1,''),
(311,'1.2.12-002','Auf Vorfahrtstraßen innerhalb geschlossener Ortschaften','On priority roads within built-up areas','در خیابان‌های حق تقدم داخل مناطق مسکونی','<div dir=\'rtl\'>پارک کردن در خیابان‌های حق تقدم داخل مناطق مسکونی مجاز است. در اینجا حداکثر سرعت وسایل نقلیه به ۵۰ کیلومتر در ساعت محدود شده است. برای استفاده بهتر از فضای محدود در یک منطقه مسکونی، می‌توان در کنار جاده پارک کرد، مشروط بر اینکه فضای پارک با تابلوی ممنوعیت پارک مشخص نشده باشد.</div>',0,'Auf Vorfahrtstraßen innerhalb geschlossener Ortschaften',1,0,''),
(312,'1.2.12-103','Auf der Fahrbahn, wenn rechts ein geeigneter Seitenstreifen vorhanden ist','On the roadway, if there is a sufficiently wide hard shoulder on the right','در مسیر حرکت (جاده)، اگر در سمت راست یک شانه راه مناسب وجود داشته باشد','<div dir=\'rtl\'>توقف در مسیرهای رانندگی که دارای شانه راه مناسب هستند ممنوع است، زیرا در غیر این صورت ترافیک بعدی به طور غیرضروری مختل می‌شود. رانندگان پشت سر ممکن است با توقف در مسیر رانندگی غافلگیر شوند و مجبور به ترمز ناگهانی یا حتی تغییر مسیر برای جلوگیری از برخورد شوند. این می‌تواند منجر به موقعیت‌های ترافیکی خطرناک شود، مثلاً زمانی که ترافیک از روبرو می‌آید. شانه‌های راه به گونه‌ای طراحی شده‌اند که وسایل نقلیه بتوانند با خیال راحت در آنجا توقف کنند، بدون اینکه جریان ترافیک در مسیر رانندگی را مختل کنند. بنابراین، اگر یک شانه راه وجود دارد و فضای کافی را فراهم می‌کند، باید در آنجا توقف کرد و به هیچ وجه در خود مسیر رانندگی نباید توقف کرد.</div>',0,'Auf der Fahrbahn, wenn rechts ein geeigneter Seitenstreifen vorhanden ist',1,1,''),
(313,'1.2.12-103','Auf markierten Fahrstreifen mit Richtungspfeilen','Between lane dividers when direction arrows are marked on the roadway','در خطوط رانندگی علامت‌گذاری شده با فلش‌های جهت‌نما','<div dir=\'rtl\'>توقف در خطوط رانندگی که با فلش‌های جهت‌نما علامت‌گذاری شده‌اند مجاز نیست، زیرا در غیر این صورت تقسیم‌بندی و هدایت به موقع ترافیک دیگر امکان‌پذیر نخواهد بود. علاوه بر این، استفاده صحیح و مثلاً گردش به راست در یک خط گردش به راست برای ترافیک بعدی غیرممکن می‌شود. بنابراین، توقف در خطوط رانندگی علامت‌گذاری شده با فلش‌های جهت‌نما ممنوع است. تنها از این طریق می‌توان ایمنی ترافیک و جریان منظم ترافیک را مطابق با علائم و نشانه‌های راه حفظ کرد. ضمناً، پارک کردن در چنین خطوط رانندگی علامت‌گذاری شده نیز ممنوع است.</div>',0,'Auf markierten Fahrstreifen mit Richtungspfeilen',1,1,''),
(314,'1.2.12-103','An Taxenständen','At taxi ranks','در ایستگاه‌های تاکسی','<div dir=\'rtl\'>توقف در ایستگاه‌های تاکسی به دلایل متعددی ممنوع است: اولاً، ایستگاه‌های تاکسی برای فراهم کردن مکانی مرکزی برای رانندگان تاکسی طراحی شده‌اند تا بتوانند در آنجا منتظر مسافران باشند. در اینجا باید فضای موجود تحت هر شرایطی آزاد نگه داشته شود تا مسافران بتوانند در هر زمان با خیال راحت و بدون مانع سوار شوند و راننده مجبور نباشد با پارک کردن در ردیف دوم، ترافیک را مختل کند. ثانیاً، ایستگاه‌های تاکسی اغلب در مکان‌های قابل مشاهده و نزدیک به تقاطع‌های ترافیکی قرار دارند تا به مسافران امکان یافتن سریع تاکسی را بدهند. اگر وسایل نقلیه دیگر در این مکان‌ها توقف کنند، جریان ترافیک ممکن است مختل شود و موقعیت‌های بالقوه خطرناکی ایجاد شود.</div>',0,'An Taxenständen',1,1,''),
(315,'1.2.12-104','Auf Fußgängerüberwegen sowie bis zu 5 m davor','On pedestrian crossings and up to 5 m before pedestrian crossings','روی خط‌کشی عابر پیاده و تا ۵ متر قبل از آن','<div dir=\'rtl\'>این کار برای اطمینان از این است که مسیر تعیین شده برای عبور از خیابان همیشه آزاد بماند و از طرف دیگر، عابران پیاده در محل عبور برای رانندگان وسایل نقلیه در حال نزدیک شدن به موقع قابل تشخیص باشند.</div>',0,'Auf Fußgängerüberwegen sowie bis zu 5 m davor',1,1,''),
(316,'1.2.12-104','Unmittelbar hinter Fußgängerüberwegen','Immediately behind pedestrian crossings','بلافاصله پشت خط‌کشی عابر پیاده','<div dir=\'rtl\'>پشت خط‌کشی عابر پیاده نیازی به حفظ میدان دید نیست، بنابراین توقف در اینجا ممنوع نیست.</div>',0,'Unmittelbar hinter Fußgängerüberwegen',1,0,''),
(317,'1.2.12-104','Über Schachtdeckeln','Over manholes and other road covers','روی درپوش‌های منهول','<div dir=\'rtl\'>پارک کردن روی درپوش‌های منهول برای اطمینان از دسترسی آزاد ممنوع است. اما توقف کوتاه مدت (Halten) در اینجا ممنوع نیست.</div>',0,'Über Schachtdeckeln',1,0,''),
(318,'1.2.12-105','Am Fahrbahnrand, wenn hierdurch die Benutzung gekennzeichneter Parkflächen verhindert wird','At the edge of the roadway if this would prevent others from using designated parking areas','در کنار جاده، اگر این کار مانع استفاده از فضاهای پارک مشخص شده شود','<div dir=\'rtl\'>در نهایت، فضاهای پارک مشخص شده برای استفاده در نظر گرفته شده‌اند. از یک طرف، وسایل نقلیه موجود در آنجا از خارج شدن از پارک منع می‌شوند و از طرف دیگر، رانندگانی که می‌خواهند در آنجا پارک کنند، از ورود منع می‌شوند.</div>',0,'Am Fahrbahnrand, wenn hierdurch die Benutzung gekennzeichneter Parkflächen verhindert wird',1,1,''),
(319,'1.2.12-105','Vor Bordsteinabsenkungen','Before sunken kerbstones','جلوی رمپ‌های جدول کنار خیابان','<div dir=\'rtl\'>پارک کردن جلوی رمپ‌های جدول کنار خیابان ممنوع است، زیرا این‌ها معمولاً نشان‌دهنده یک ورودی و خروجی هستند.</div>',0,'Vor Bordsteinabsenkungen',1,1,''),
(320,'1.2.12-105','Unmittelbar hinter Fußgängerüberwegen','Immediately behind pedestrian crossings','بلافاصله پشت خط‌کشی عابر پیاده','<div dir=\'rtl\'>پارک کردن بلافاصله پشت خط‌کشی عابر پیاده مجاز است. اما جلوی خط‌کشی عابر پیاده باید حداقل ۵ متر فاصله رعایت شود.</div>',0,'Unmittelbar hinter Fußgängerüberwegen',1,0,''),
(321,'1.2.12-106','In Einbahnstraßen','In one-way streets','در خیابان‌های یک‌طرفه','<div dir=\'rtl\'>در خیابان‌های یک‌طرفه، پارک کردن در سمت چپ و در جهت حرکت مجاز است، زیرا در این خیابان‌ها ترافیک مقابل مورد انتظار نیست و فضای ترافیکی آن مسدود نمی‌شود.</div>',0,'In Einbahnstraßen',1,1,''),
(322,'1.2.12-106','Wo Schienen auf der rechten Seite verlegt sind','Where there are rails on the right-hand side','در جایی که ریل‌ها در سمت راست قرار گرفته‌اند','<div dir=\'rtl\'>اگر ریل‌ها در سمت راست قرار داشته باشند، پارک کردن در آنجا امکان‌پذیر نیست. بنابراین، در این حالت می‌توان در سمت چپ پارک کرد.</div>',0,'Wo Schienen auf der rechten Seite verlegt sind',1,1,''),
(323,'1.2.12-106','Wo rechts das Parken verboten ist','Where parking is prohibited on the right','در جایی که پارک کردن در سمت راست ممنوع است','<div dir=\'rtl\'>این مورد مجوزی برای پارک کردن در سمت چپ و در جهت حرکت نمی‌دهد.</div>',0,'Wo rechts das Parken verboten ist',1,0,''),
(324,'1.2.12-107','Wer länger als drei Minuten hält','Anyone who stops for more than 3 minutes','کسی که بیش از سه دقیقه توقف می‌کند','<div dir=\'rtl\'>در کمتر از سه دقیقه، به آن «توقف» گفته می‌شود.</div>',0,'Wer länger als drei Minuten hält',1,1,''),
(325,'1.2.12-107','Wer sein Fahrzeug verlässt','Anyone who leaves his vehicle','کسی که وسیله نقلیه خود را ترک می‌کند','<div dir=\'rtl\'>در این صورت فرض می‌شود که مالک وسیله نقلیه قصد پارک کردن دارد.</div>',0,'Wer sein Fahrzeug verlässt',1,1,''),
(326,'1.2.12-107','Wer vor einer geschlossenen Bahnschranke länger als drei Minuten wartet','Anyone who waits longer than 3 minutes at a closed level crossing barrier','کسی که بیش از سه دقیقه جلوی یک مانع بسته راه‌آهن منتظر می‌ماند','<div dir=\'rtl\'>راننده به دلیل مانع بسته راه‌آهن مجبور به توقف می‌شود.</div>',0,'Wer vor einer geschlossenen Bahnschranke länger als drei Minuten wartet',1,0,''),
(327,'1.2.12-108','5','5','۵','',0,'5',2,1,'m'),
(328,'1.2.12-110','50','50','50','',0,'50',2,1,'m'),
(329,'1.2.12-111','5','5','5','',0,'5',2,1,'m'),
(330,'1.2.12-112','15','15','15','',0,'15',2,1,'m in each case'),
(331,'1.2.12-113','3','3','۳','',0,'3',2,1,'minutes'),
(332,'1.2.12-123-M','Links von der Fahrbahnbegrenzung darf nicht gehalten werden','It is not permitted to stop to the left of the boundary line of the carriageway','توقف در سمت چپ خط محدودکننده مسیر مجاز نیست','<div dir=\'rtl\'>در سمت چپ خط محدودکننده مسیر مجاز به توقف نیستید، زیرا این خط مربوط به مسیر حرکت است. اما در اینجا می‌توانید در شانه راه توقف کنید.</div>',0,'Links von der Fahrbahnbegrenzung darf nicht gehalten werden',1,1,''),
(333,'1.2.12-123-M','Langsame Fahrzeuge müssen möglichst auf dem Seitenstreifen fahren','Slower moving vehicles must use the hard shoulder if possible','وسایل نقلیه کندرو باید تا حد امکان در شانه راه حرکت کنند','<div dir=\'rtl\'>برای اینکه تا حد امکان مانع سایر وسایل نقلیه نشوند، وسایل نقلیه کندرو باید در شانه راه حرکت کنند.</div>',0,'Langsame Fahrzeuge müssen möglichst auf dem Seitenstreifen fahren',1,1,''),
(334,'1.2.12-123-M','Die Fahrbahnbegrenzung darf in keinem Fall überfahren werden','Driving across the boundary line of the carriageway is prohibited at all times','خط محدودکننده مسیر در هیچ صورتی نباید عبور شود','<div dir=\'rtl\'>خط محدودکننده مسیر می‌تواند توسط وسایل نقلیه کندرو که برای تسهیل حرکت سایر کاربران جاده به شانه راه تغییر مسیر می‌دهند، عبور شود.</div>',0,'Die Fahrbahnbegrenzung darf in keinem Fall überfahren werden',1,0,''),
(335,'1.2.16-101','Als Warnsignal','As a warning signal','به عنوان سیگنال هشدار','<div dir=\'rtl\'>در صورت لزوم، بوق را می‌توان در هر مکانی به عنوان سیگنال هشدار استفاده کرد.</div>',0,'Als Warnsignal',1,1,''),
(336,'1.2.16-101','Als Überholsignal','As an overtaking signal','به عنوان سیگنال سبقت','<div dir=\'rtl\'>با این حال، این فقط در خارج از شهر معتبر است، زیرا در داخل مناطق مسکونی، این کار باعث ایجاد آلودگی صوتی برای ساکنان و عابران پیاده می‌شود.</div>',0,'Als Überholsignal',1,1,''),
(337,'1.2.16-101','Als Rufzeichen','As a calling signal','به عنوان علامت صدا زدن','<div dir=\'rtl\'>بوق منحصراً به عنوان سیگنال هشدار در نظر گرفته شده است.</div>',0,'Als Rufzeichen',1,0,''),
(338,'1.2.16-102','Als Warnsignal','As a warning signal','به عنوان علامت هشدار','<div dir=\'rtl\'>با بوق می‌توان (و باید) به یک موقعیت خطرناک اشاره کرد تا سایر کاربران جاده را هشدار داد. به همین دلیل، مهم است که رادیو را خیلی بلند نکنید، زیرا در غیر این صورت ممکن است به سرعت علائم هشدار دیگران را نشنوید.</div>',0,'Als Warnsignal',1,1,''),
(339,'1.2.16-102','Als Überholsignal','As an overtaking signal','به عنوان علامت سبقت','<div dir=\'rtl\'>بوق فقط در خارج از شهر به عنوان علامت سبقت مجاز است.</div>',0,'Als Überholsignal',1,0,''),
(340,'1.2.16-102','Als Rufzeichen','As a calling signal','به عنوان علامت صدا زدن','<div dir=\'rtl\'>بوق یک علامت هشدار است و نباید به عنوان علامت صدا زدن استفاده شود.</div>',0,'Als Rufzeichen',1,0,''),
(341,'1.2.16-103','Warnblinklicht einschalten','Switch on the hazard warning lights','چراغ‌های هشداردهنده (فلاشر) را روشن کنید','<div dir=\'rtl\'>در یک وضعیت نقص فنی، همیشه ابتدا باید چراغ‌های هشداردهنده (فلاشر) روشن شوند. این امر به ویژه در تونل بسیار مهم است، زیرا در اینجا تاریک‌تر و دید کمتر از فضای باز است.</div>',0,'Warnblinklicht einschalten',1,1,''),
(342,'1.2.16-103','Fahrzeug möglichst in einer Pannenbucht abstellen','If possible, park the vehicle in an emergency bay','خودرو را در صورت امکان در یک توقفگاه اضطراری پارک کنید','<div dir=\'rtl\'>این برای شما ایمن‌تر است و مانع ترافیک دیگر نمی‌شوید.</div>',0,'Fahrzeug möglichst in einer Pannenbucht abstellen',1,1,''),
(343,'1.2.16-103','Motor vorsorglich laufen lassen','Let the engine run by way of precaution','موتور را به عنوان احتیاط روشن نگه دارید','<div dir=\'rtl\'>در صورت نقص فنی، موتور باید در اسرع وقت خاموش شود.</div>',0,'Motor vorsorglich laufen lassen',1,0,''),
(344,'1.2.16-104','Warnblinklicht einschalten','Switch on the hazard warning lights','چراغ‌های هشداردهنده (فلاشر) را روشن کنید','<div dir=\'rtl\'>به این ترتیب، ترافیک پشت سر در اسرع وقت مطلع و هشدار داده می‌شود.</div>',0,'Warnblinklicht einschalten',1,1,''),
(345,'1.2.16-104','Wenden und den Tunnel verlassen','Make a U-turn and leave the tunnel','دور زدن و خروج از تونل','<div dir=\'rtl\'>دور زدن در تونل ممنوع است. این کار فقط باعث ایجاد بی‌نظمی در بین سایر رانندگان می‌شود.</div>',0,'Wenden und den Tunnel verlassen',1,0,''),
(346,'1.2.16-104','Am Stauende Motor abstellen und das Fahrzeug verlassen','At the end of the traffic jam, switch off the engine and leave the vehicle','در انتهای ترافیک موتور را خاموش کرده و خودرو را ترک کنید','<div dir=\'rtl\'>خاموش کردن موتور و ترک خودرو، قوانین رفتاری هستند که فقط در مواقع اضطراری باید رعایت شوند.</div>',0,'Am Stauende Motor abstellen und das Fahrzeug verlassen',1,0,''),
(347,'1.2.17-001','Sie müssen vorschriftsmäßig angebracht sein','It must be correctly installed','آنها باید مطابق مقررات نصب شده باشند','<div dir=\'rtl\'>باید اطمینان حاصل شود که تجهیزات روشنایی به درستی نصب شده و محکم بسته شده‌اند.</div>',0,'Sie müssen vorschriftsmäßig angebracht sein',1,1,''),
(348,'1.2.17-001','Sie müssen sauber sein','It must be clean','آنها باید تمیز باشند','<div dir=\'rtl\'>روشنایی کثیف، دید راننده را نسبت به جاده و ترافیک محدود می‌کند و همچنین مانع از دید کافی سایر کاربران جاده نسبت به خودرو می‌شود. همچنین، ممکن است در این صورت چراغ راهنما به اندازه کافی قابل تشخیص نباشد.</div>',0,'Sie müssen sauber sein',1,1,''),
(349,'1.2.17-001','Sie müssen funktionstüchtig sein','It must be in operating condition','آنها باید سالم و کارآمد باشند','<div dir=\'rtl\'>برای اینکه روشنایی به هدف خود برسد، باید کار کند. این امر برای داشتن دید کافی در تاریکی و دیده شدن به اندازه کافی توسط سایر کاربران جاده ضروری است.</div>',0,'Sie müssen funktionstüchtig sein',1,1,''),
(350,'1.2.19-002','Wenn rotes Blinklicht aufleuchtet','When a flashing red light comes on','هنگامی که چراغ چشمک‌زن قرمز روشن می‌شود','<div dir=\'rtl\'>اگر وظیفه انتظار با وجود چراغ چشمک‌زن قرمز یا علائم نوری زرد یا قرمز رعایت نشود، ممکن است یک وضعیت خطرناک ایجاد شود.</div>',0,'Wenn rotes Blinklicht aufleuchtet',1,1,''),
(351,'1.2.19-002','Wenn sich die Schranken senken','When the barriers are being lowered','هنگامی که موانع (راهبندها) پایین می‌آیند','<div dir=\'rtl\'>این نشان می‌دهد که به زودی یک وسیله نقلیه ریلی از مسیر عبور خواهد کرد.</div>',0,'Wenn sich die Schranken senken',1,1,''),
(352,'1.2.19-002','Wenn ein Bahnbediensteter eine weiß-rot-weiße Fahne schwenkt','When a railway employee is waving a white-red-white flag','هنگامی که یک کارمند راه‌آهن پرچم سفید-قرمز-سفید را تکان می‌دهد','<div dir=\'rtl\'>این یک پرچم هشدار یا سیگنال است و به شرکت‌کنندگان در ترافیک نشان می‌دهد که باید توقف کرده یا منتظر بمانند.</div>',0,'Wenn ein Bahnbediensteter eine weiß-rot-weiße Fahne schwenkt',1,1,''),
(353,'1.2.19-003','Vor dem Andreaskreuz warten','','قبل از صلیب آندریاس (علامت گذرگاه ریلی) منتظر بمانید','<div dir=\'rtl\'>چراغ چشمک‌زن قرمز به کاربران ترافیک هشدار می‌دهد که باید توقف کنند، زیرا به زودی یک وسیله نقلیه ریلی از مسیر عبور خواهد کرد.</div>',0,'Vor dem Andreaskreuz warten',1,1,''),
(354,'1.2.19-003','Weiterfahren, solange die Halbschranke noch geöffnet ist','','تا زمانی که نیم‌حصار هنوز باز است، به حرکت ادامه دهید','<div dir=\'rtl\'>نیم‌حصار ممکن است هر لحظه بسته شود. چراغ چشمک‌زن برای آماده‌سازی جهت بسته شدن نیم‌حصار است. از این (گذرگاه) دیگر نباید عبور کرد.</div>',0,'Weiterfahren, solange die Halbschranke noch geöffnet ist',1,0,''),
(355,'1.2.19-003','Den Bahnübergang überqueren, wenn kein Schienenfahrzeug in Sicht ist','','از گذرگاه ریلی عبور کنید، اگر هیچ وسیله نقلیه ریلی در دید نیست','<div dir=\'rtl\'>این (وسیله نقلیه ریلی) می‌تواند بسیار سریع نزدیک شود. به همین دلیل، اقدام چراغ چشمک‌زن قرمز وجود دارد. اگر این (چراغ) نمایش داده شود، باید منتظر ماند، حتی اگر هیچ وسیله نقلیه ریلی دیده نشود.</div>',0,'Den Bahnübergang überqueren, wenn kein Schienenfahrzeug in Sicht ist',1,0,''),
(356,'1.2.19-004','Sie müssen vor dem Bahnübergang warten','You must wait in front of the level crossing','شما باید قبل از گذرگاه راه‌آهن منتظر بمانید','<div dir=\'rtl\'>اگر یک کارمند راه‌آهن یک چراغ قرمز را تکان دهد، در هر صورت باید منتظر ماند.</div>',0,'Sie müssen vor dem Bahnübergang warten',1,1,''),
(357,'1.2.19-004','Sie dürfen die Gleise vorsichtig überqueren','You may cross the rails carefully','شما مجاز هستید با احتیاط از ریل‌ها عبور کنید','<div dir=\'rtl\'>چراغ قرمز این را نشان نمی‌دهد. باید توقف کرد یا منتظر ماند.</div>',0,'Sie dürfen die Gleise vorsichtig überqueren',1,0,''),
(358,'1.2.19-004','Die rote Leuchte hat für Sie keine Bedeutung','The red lamp is of no significance for you','چراغ قرمز برای شما هیچ معنایی ندارد','<div dir=\'rtl\'>چراغ قرمز به کاربر جاده‌ای (راننده) علامت می‌دهد: \"توقف!\".</div>',0,'Die rote Leuchte hat für Sie keine Bedeutung',1,0,''),
(359,'1.2.19-005','Mit mäßiger Geschwindigkeit heranfahren, Bahnstrecke beobachten','','با سرعت متوسط نزدیک شوید، مسیر ریلی را مشاهده کنید','<div dir=\'rtl\'>حمل و نقل ریلی حق تقدم دارد. سرعت متوسط برای مشاهده مسیر ریلی ضروری است، زیرا وسایل نقلیه ریلی اغلب با سرعت بسیار بالا حرکت می‌کنند و به این ترتیب می‌توان از تصادفات جلوگیری کرد. علاوه بر این، گذرگاه‌های ریلی اغلب ناهموار هستند.</div>',0,'Mit mäßiger Geschwindigkeit heranfahren, Bahnstrecke beobachten',1,1,''),
(360,'1.2.19-005','Vor dem Bahnübergang warten, wenn auf ihm wegen Stau angehalten werden müsste','','قبل از گذرگاه ریلی منتظر بمانید، اگر به دلیل ترافیک مجبور به توقف روی آن شوید','<div dir=\'rtl\'>این برای تضمین ایمنی خود ضروری است. اگر در ترافیک روی ریل‌ها متوقف شوید و یک وسیله نقلیه ریلی نزدیک شود، هیچ راه فراری وجود نخواهد داشت.</div>',0,'Vor dem Bahnübergang warten, wenn auf ihm wegen Stau angehalten werden müsste',1,1,''),
(361,'1.2.19-005','Mit unverminderter Geschwindigkeit weiterfahren, weil in solchen Fällen der Straßenverkehr immer Vorrang hat','','با سرعت بدون کاهش ادامه دهید، زیرا در چنین مواردی ترافیک جاده‌ای همیشه حق تقدم دارد','<div dir=\'rtl\'>حمل و نقل ریلی حق تقدم دارد و نه ترافیک جاده‌ای.</div>',0,'Mit unverminderter Geschwindigkeit weiterfahren, weil in solchen Fällen der Straßenverkehr immer Vorrang hat',1,0,''),
(362,'1.2.19-008','An Bahnübergänge nur mit mäßiger Geschwindigkeit heranfahren','Approach level crossings at moderate speed only','فقط با سرعت متوسط به گذرگاه‌های ریلی نزدیک شوید','<div dir=\'rtl\'>وسایل نقلیه ریلی حق تقدم دارند و بنابراین در صورت لزوم باید ترمز کنید، اگر یکی از آنها از ریل جلوی شما عبور کند.</div>',0,'An Bahnübergänge nur mit mäßiger Geschwindigkeit heranfahren',1,1,''),
(363,'1.2.19-008','Schienenfahrzeuge haben an allen Bahnübergängen Vorrang','Rail vehicles have precedence at all level crossings','وسایل نقلیه ریلی در تمام گذرگاه‌های ریلی حق تقدم دارند','<div dir=\'rtl\'>صرف نظر از اینکه یک تقاطع ریلی در یک منطقه صنعتی یا در مکان دیگری باید عبور شود، وسایل نقلیه ریلی همیشه نسبت به سایر شرکت‌کنندگان در ترافیک حق تقدم دارند.</div>',0,'Schienenfahrzeuge haben an allen Bahnübergängen Vorrang',1,1,''),
(364,'1.2.19-008','Kraftfahrzeuge haben an Bahnübergängen ohne Andreaskreuz Vorrang','Motor vehicles have precedence at level crossings without St. Andrew\'s Cross','وسایل نقلیه موتوری در گذرگاه‌های ریلی بدون علامت صلیب آندریاس (Andreaskreuz) حق تقدم دارند','<div dir=\'rtl\'>در گذرگاه‌های ریلی، وسایل نقلیه ریلی همیشه حق تقدم دارند.</div>',0,'Kraftfahrzeuge haben an Bahnübergängen ohne Andreaskreuz Vorrang',1,0,''),
(365,'1.2.19-101','Mit mäßiger Geschwindigkeit heranfahren und beobachten, ob sich ein Schienenfahrzeug nähert','Proceed at moderate speed and check to see if a rail vehicle is approaching','با سرعت متوسط نزدیک شوید و مشاهده کنید که آیا وسیله نقلیه ریلی نزدیک می‌شود یا خیر','<div dir=\'rtl\'>بند ۱ ماده ۱۹ قانون راهنمایی و رانندگی (StVO) مقرر می‌دارد: \"وسایل نقلیه ریلی حق تقدم دارند (...) در گذرگاه‌های ریلی که از روی مسیرهای پیاده‌رو، کشاورزی، جنگلی یا دوچرخه‌سواری عبور می‌کنند (...). ترافیک جاده‌ای فقط با سرعت متوسط می‌تواند به چنین گذرگاه‌های ریلی نزدیک شود.\" به این ترتیب عبور ایمن از ریل‌ها تضمین می‌شود و در صورت لزوم، زمان کافی برای ترمز کردن وجود دارد، اگر وسیله نقلیه ریلی نزدیک شود.</div>',0,'Mit mäßiger Geschwindigkeit heranfahren und beobachten, ob sich ein Schienenfahrzeug nähert',1,1,''),
(366,'1.2.19-101','Horchen, ob sich durch Pfeifen oder Läuten ein Schienenfahrzeug ankündigt','Listen out in case a rail vehicle signals its approach by whistling or ringing a bell','گوش دهید که آیا وسیله نقلیه ریلی با سوت یا زنگ اعلام حضور می‌کند یا خیر','<div dir=\'rtl\'>از آنجایی که دید به مسیر ریلی به دلیل درختان محدود است، باید توجه ویژه‌ای به سیگنال‌های صوتی داشت. لوکوموتیورانان هنگام نزدیک شدن با وسیله نقلیه ریلی به گذرگاه، علائم زنگ، بوق یا سوت می‌دهند. همین امر در تاریکی، بارش برف یا باران شدید نیز صدق می‌کند.</div>',0,'Horchen, ob sich durch Pfeifen oder Läuten ein Schienenfahrzeug ankündigt',1,1,''),
(367,'1.2.19-101','Ohne weiteres durchfahren, da Schienenfahrzeuge hier wartepflichtig sind','Proceed without taking any special precautions since rail vehicles are required to wait here','بدون هیچ مشکلی عبور کنید، زیرا وسایل نقلیه ریلی در اینجا موظف به توقف هستند','<div dir=\'rtl\'>وسایل نقلیه ریلی حق تقدم نسبت به وسایل نقلیه موتوری دارند، حتی در مناطق جنگلی.</div>',0,'Ohne weiteres durchfahren, da Schienenfahrzeuge hier wartepflichtig sind',1,0,''),
(368,'1.2.19-102','Vor dem Andreaskreuz warten, Straßeneinmündungen freilassen','Wait before the St. Andrew\'s Cross without obstructing junctions','قبل از صلیب آندریاس (Andreaskreuz) منتظر بمانید، ورودی‌های خیابان را باز بگذارید','<div dir=\'rtl\'>اگر ورودی‌های قبل از گذرگاه ریلی باز نگه داشته نشوند، ترافیک عرضی بی‌مورد مختل خواهد شد.</div>',0,'Vor dem Andreaskreuz warten, Straßeneinmündungen freilassen',1,1,''),
(369,'1.2.19-102','Bei Dunkelheit möglichst auf Standlicht schalten','If possible, switch on the side lights when it is dark','در تاریکی، در صورت امکان به چراغ کوچک (Standlicht) تغییر دهید','<div dir=\'rtl\'>هنگام انتظار در مقابل گذرگاه ریلی بسته، چراغ‌های جلوی شما نباید کسی را خیره کنند. به همین دلیل، منطقی است که به چراغ کوچک تغییر دهید. همچنین برای کاهش بار روی باتری خودرو در هنگام خاموش بودن موتور.</div>',0,'Bei Dunkelheit möglichst auf Standlicht schalten',1,1,''),
(370,'1.2.19-102','Verkehrsraum ausnutzen, dicht vor der Schranke warten','Use the road area and wait directly in front of the barrier','از فضای ترافیک استفاده کنید، درست جلوی مانع منتظر بمانید','<div dir=\'rtl\'>برای اینکه ترافیک عرضی احتمالی را بی‌مورد مختل نکنید، باید ورودی‌ها را باز نگه دارید و تا جلوی مانع پیش نروید.</div>',0,'Verkehrsraum ausnutzen, dicht vor der Schranke warten',1,0,''),
(371,'1.2.19-104','Wenn das rote Blinklicht erloschen ist','When the flashing red light goes out','هنگامی که چراغ چشمک‌زن قرمز خاموش شده باشد','<div dir=\'rtl\'>این نشانه عبور ایمن از گذرگاه ریلی است.</div>',0,'Wenn das rote Blinklicht erloschen ist',1,1,''),
(372,'1.2.19-104','Sofort nach Durchfahrt des Zuges, auch wenn das rote Blinklicht noch leuchtet','Immediately after the train has passed, even if the flashing red light is still on','بلافاصله پس از عبور قطار، حتی اگر چراغ چشمک‌زن قرمز هنوز روشن باشد','<div dir=\'rtl\'>فقط زمانی که این چراغ خاموش شود، می‌توان از گذرگاه عبور کرد.</div>',0,'Sofort nach Durchfahrt des Zuges, auch wenn das rote Blinklicht noch leuchtet',1,0,''),
(373,'1.2.19-104','Sobald der Gegenverkehr anfährt, auch wenn das rote Blinklicht noch leuchtet','As soon as the oncoming traffic sets off, even if the flashing red light is still on','به محض اینکه ترافیک مقابل شروع به حرکت کند، حتی اگر چراغ چشمک‌زن قرمز هنوز روشن باشد','<div dir=\'rtl\'>ترافیک مقابل تضمینی برای رفتار صحیح در ترافیک جاده‌ای نیست. اگر آنها خیلی زود حرکت کنند، خود را در معرض خطری قرار می‌دهند که با انتظار مناسب قابل اجتناب است.</div>',0,'Sobald der Gegenverkehr anfährt, auch wenn das rote Blinklicht noch leuchtet',1,0,''),
(374,'1.2.19-105','Vor dem Andreaskreuz','In front of the St. Andrew\'s Cross','قبل از صلیب آندریاس','<div dir=\'rtl\'>در ترافیک متوقف، تضمینی وجود ندارد که عبور از گذرگاه ریلی به صورت روان امکان‌پذیر باشد. برای جلوگیری از خطر توقف روی ریل‌ها به دلیل ترافیک متوقف، باید قبل از صلیب آندریاس منتظر بمانید تا زمانی که بتوانید بدون مانع از ریل‌ها عبور کنید.</div>',0,'Vor dem Andreaskreuz',1,1,''),
(375,'1.2.19-105','Unmittelbar vor den Schienen','Just before the rails','بلافاصله قبل از ریل‌ها','<div dir=\'rtl\'>باید طوری توقف کرد که بتوانید هنوز چراغ سیگنال روی صلیب آندریاس را ببینید و راهبندها هنوز بتوانند پایین بیایند. بنابراین، باید از فاصله قابل توجهی قبل از ریل‌ها متوقف شوید.</div>',0,'Unmittelbar vor den Schienen',1,0,''),
(376,'1.2.19-105','In Höhe der Schranke','Level with the barrier','در ارتفاع راهبند','<div dir=\'rtl\'>در صورتی که راهبند پایین بیاید، ممکن است خودرو آسیب ببیند. فاصله ایمنی کافی از وسیله نقلیه ریلی در حال نزدیک شدن فقط در ارتفاع صلیب آندریاس فراهم است.</div>',0,'In Höhe der Schranke',1,0,''),
(377,'1.2.19-107','Vor dem Andreaskreuz','In front of the St. Andrew\'s Cross','قبل از صلیب آندریاس (Andreaskreuz)','<div dir=\'rtl\'>صرف‌نظر از اینکه گذرگاه ریلی خارج از شهر یا داخل شهر باشد - اگر راهبند و صلیب آندریاس وجود دارد، باید قبل از صلیب آندریاس منتظر ماند.</div>',0,'Vor dem Andreaskreuz',1,1,''),
(378,'1.2.19-107','Vor der letzten Bake','Before the last beacon','قبل از آخرین تابلوی نشانگر (Bake)','<div dir=\'rtl\'>آخرین تابلوی نشانگر (Bake) هنوز قبل از صلیب آندریاس قرار دارد. اما شما مجازید تا صلیب آندریاس جلو بروید و فقط در آنجا باید منتظر بمانید.</div>',0,'Vor der letzten Bake',1,0,''),
(379,'1.2.19-107','Vor der ersten Bake','Before the first beacon','قبل از اولین تابلوی نشانگر (Bake)','<div dir=\'rtl\'>آخرین تابلوی نشانگر (Bake) هنوز قبل از صلیب آندریاس قرار دارد. اما شما مجازید تا صلیب آندریاس جلو بروید و فقط در آنجا باید منتظر بمانید.</div>',0,'Vor der ersten Bake',1,0,''),
(380,'1.2.19-109','Hinweis auf vorhandene elektrische Oberleitungen','Indication of existing overhead electrical wires','نشانه‌ای از وجود خطوط برق هوایی','<div dir=\'rtl\'>علامت صاعقه که در مرکز صلیب آندریاس قرار دارد، به وجود خطوط برق هوایی بالای ریل‌های قطار اشاره می‌کند. این هشدار به ویژه برای رانندگان وسایل نقلیه کشاورزی یا جنگلداری اهمیت زیادی دارد، زیرا اغلب بار آن‌ها بسیار بلند است.</div>',0,'Hinweis auf vorhandene elektrische Oberleitungen',1,1,''),
(381,'1.2.19-109','Der Schienenverkehr hat immer Vorrang','Rail traffic always has priority','حمل و نقل ریلی همیشه حق تقدم دارد','<div dir=\'rtl\'>همیشه باید به قطارها حق تقدم داد.</div>',0,'Der Schienenverkehr hat immer Vorrang',1,1,''),
(382,'1.2.19-109','Es ist immer zu warten, wenn sich ein Schienenfahrzeug nähert','You must always wait when a rail vehicle is approaching','همیشه باید در صورت نزدیک شدن وسیله نقلیه ریلی منتظر ماند','<div dir=\'rtl\'>صلیب آندریاس به یک گذرگاه ریلی اشاره دارد. همیشه باید به قطارها حق تقدم داد.</div>',0,'Es ist immer zu warten, wenn sich ein Schienenfahrzeug nähert',1,1,''),
(383,'1.2.19-110','An der Haltlinie','At the stop line','در خط توقف','<div dir=\'rtl\'>در بند ۳ ماده ۴۱ قانون راهنمایی و رانندگی (StVO)، علامت ۲۹۴ (۲ خط توقف) بیان می‌کند: \"علاوه بر دستورات توقف و انتظار که توسط علامت ۲۰۶ (تابلوی ایست)، توسط افسران پلیس یا توسط چراغ‌های راهنمایی (در این مورد چراغ قرمز) داده می‌شوند، این علامت دستور می‌دهد: \"اینجا توقف کنید!\" همین امر در مورد گذرگاه‌های ریلی برای کسی که باید منتظر بماند نیز صدق می‌کند.\" بنابراین، باید در خط توقف، قبل از چراغ راهنمایی قرمز رنگ روشن، منتظر ماند تا زمانی که چراغ تغییر کند.</div>',0,'An der Haltlinie',1,1,''),
(384,'1.2.19-110','Wenn keine Haltlinie vorhanden ist, vor dem Lichtzeichen','In front of the light signal, if there is no stop line','اگر خط توقف وجود ندارد، قبل از چراغ راهنمایی','<div dir=\'rtl\'>عبور از چراغ راهنمایی قرمز رنگ روشن ممنوع است.</div>',0,'Wenn keine Haltlinie vorhanden ist, vor dem Lichtzeichen',1,1,''),
(385,'1.2.19-110','Ich kann nach Beobachten des Verkehrs bis zum Bahnübergang vorfahren','I can drive up to the level crossing after watching out for other traffic','من می‌توانم پس از مشاهده ترافیک تا گذرگاه ریلی جلو بروم','<div dir=\'rtl\'>این کار باعث ایجاد مانع برای وسایل نقلیه ای می‌شود که از سمت راست می‌آیند و در نتیجه منجر به کندی ترافیک می‌شود. علاوه بر این، عبور از چراغ راهنمایی قرمز رنگ روشن ممنوع است.</div>',0,'Ich kann nach Beobachten des Verkehrs bis zum Bahnübergang vorfahren',1,0,''),
(386,'1.2.20-004','Linienbussen','Regular buses','اتوبوس‌های خطی','<div dir=\'rtl\'>یک اتوبوس خطی هنگام حرکت از یک ایستگاه مشخص شده، بر ترافیک جاری اولویت دارد، زیرا باید زمان‌های تعیین شده در برنامه زمانی رعایت شود. این امر در صورت تأخیرهای مداوم به دلیل زمان انتظار، دیگر امکان‌پذیر نخواهد بود.</div>',0,'Linienbussen',1,1,''),
(387,'1.2.20-004','Schulbussen','School buses','اتوبوس‌های مدرسه','<div dir=\'rtl\'>یک اتوبوس مدرسه هنگام حرکت از یک ایستگاه مشخص شده، بر ترافیک جاری اولویت دارد.</div>',0,'Schulbussen',1,1,''),
(388,'1.2.20-004','Taxen','Taxis','تاکسی‌ها','<div dir=\'rtl\'>تاکسی‌ها زمان‌های ورود مشخصی ندارند، بنابراین بر ترافیک جاری اولویتی نیز ندارند.</div>',0,'Taxen',1,0,''),
(389,'1.2.22-101','1','1','1','',0,'1',2,1,'m'),
(390,'1.2.22-102','Mit roter Leuchte und rotem Rückstrahler','By a red light and red rear reflector','با چراغ قرمز و بازتابنده قرمز','<div dir=\'rtl\'>اینگونه می‌توان اطمینان حاصل کرد که طول اضافی توسط سایر کاربران جاده به موقع تشخیص داده شود و فاصله ایمنی بر این اساس تنظیم گردد.</div>',0,'Mit roter Leuchte und rotem Rückstrahler',1,1,''),
(391,'1.2.22-102','Mit orangefarbener Warntafel','By an orange warning plate','با تابلوی هشدار نارنجی‌رنگ','<div dir=\'rtl\'>یک تابلوی هشدار زرد رنگ به هیچ وجه الزامات علامت‌گذاری محموله بیرون‌زده در تاریکی را برآورده نمی‌کند، زیرا از فاصله کافی قابل تشخیص نیست. علاوه بر این، تابلوهای هشدار نارنجی‌رنگ معمولاً برای نشان دادن حمل و نقل کالاهای خطرناک استفاده می‌شوند.</div>',0,'Mit orangefarbener Warntafel',1,0,''),
(392,'1.2.22-102','Durch Einschalten der Nebelschlussleuchte','By switching the fog tail lamp on','با روشن کردن چراغ مه‌شکن عقب','<div dir=\'rtl\'>این یک وسیله مناسب برای علامت‌گذاری محموله بیرون‌زده نیست. این چراغ مستقیماً روی خودرو نصب شده و هیچ نشانه‌ای از محموله بیرون‌زده نمی‌دهد. روشن کردن چراغ مه‌شکن عقب خطر اضافی ایجاد می‌کند، زیرا سایر کاربران جاده به شدت خیره می‌شوند. این امر تشخیص به موقع محموله بیرون‌زده از عقب را دشوارتر می‌کند.</div>',0,'Durch Einschalten der Nebelschlussleuchte',1,0,''),
(393,'1.2.22-104','Überbeanspruchung der Bremsen','The brakes may be overstrained','فشار بیش از حد به ترمزها','<div dir=\'rtl\'>ترمزها برای وزن کلی مجاز طراحی شده‌اند. اگر وسیله نقلیه بیش از حد سنگین باشد، ممکن است در اثر گرم شدن بیش از حد ترمزها آسیب ببیند.</div>',0,'Überbeanspruchung der Bremsen',1,1,''),
(394,'1.2.22-104','Verschlechterung des Lenkverhaltens','Steering may become worse','بدتر شدن فرمان‌پذیری','<div dir=\'rtl\'>سیستم فرمان نیز برای وزن کلی مجاز طراحی شده است. اگر وسیله نقلیه بیش از حد سنگین باشد، فرمان دادن به آن نیز دشوارتر می‌شود.</div>',0,'Verschlechterung des Lenkverhaltens',1,1,''),
(395,'1.2.22-104','Schäden an tragenden Fahrzeugteilen','There may be too much strain on the load-bearing parts of the vehicle','آسیب به قطعات باربر وسیله نقلیه','<div dir=\'rtl\'>اگر وسیله نقلیه بیش از حد بار داشته باشد، حتی دست‌اندازهای بزرگ‌تر یا نیروی گریز از مرکز بیشتر در پیچ‌ها به دلیل اضافه‌بار، برای ایجاد آسیب، مثلاً به لاستیک‌ها، کافی است.</div>',0,'Schäden an tragenden Fahrzeugteilen',1,1,''),
(396,'1.2.22-106','- Gefahrguttransport','- dangerous goods','- حمل و نقل کالاهای خطرناک','<div dir=\'rtl\'>کامیون‌هایی که کالاهای خطرناک را حمل می‌کنند، باید با دو تابلوی مستطیلی، عمودی نصب شده و نارنجی رنگ در عقب وسیله نقلیه مشخص شوند.</div>',0,'- Gefahrguttransport',1,1,''),
(397,'1.2.22-106','- Viehtransport','- cattle','- حمل و نقل دام','<div dir=\'rtl\'>تابلوهای هشداردهنده نارنجی رنگ نشان‌دهنده حمل و نقل کالاهای خطرناک هستند، نه حمل و نقل دام.</div>',0,'- Viehtransport',1,0,''),
(398,'1.2.22-106','- Transport leicht verderblicher Lebensmittel','- easily perishable food','- حمل و نقل مواد غذایی فاسدشدنی','<div dir=\'rtl\'>تابلوهای هشداردهنده نارنجی رنگ نشان‌دهنده حمل و نقل کالاهای خطرناک هستند. در صورت حمل و نقل مواد غذایی فاسدشدنی، نیازی به علامت‌گذاری خاصی روی کامیون نیست.</div>',0,'- Transport leicht verderblicher Lebensmittel',1,0,''),
(399,'1.2.23-001','Der Fahrer','The driver','راننده','<div dir=\'rtl\'>راننده باید قبل از شروع رانندگی اطمینان حاصل کند که وسیله نقلیه در وضعیت ایمن رانندگی قرار دارد. او همچنین مستقیماً با وسیله نقلیه در تماس است و بنابراین قادر است نقص‌ها را بلافاصله تشخیص داده و واکنش نشان دهد.</div>',0,'Der Fahrer',1,1,''),
(400,'1.2.23-001','Der Halter','The owner','صاحب وسیله نقلیه','<div dir=\'rtl\'>صاحب وسیله نقلیه نیز مسئولیت دارد. او باید اطمینان حاصل کند که وسیله نقلیه قبل از تحویل به راننده دیگر، برای رانندگی مناسب و ایمن برای استفاده در ترافیک جاده‌ای است.</div>',0,'Der Halter',1,1,''),
(401,'1.2.23-001','Die Haftpflichtversicherung','The motor liability insurance company','بیمه مسئولیت مدنی','<div dir=\'rtl\'>بیمه مسئولیت مدنی تنها زمانی مسئول است که خساراتی با وسیله نقلیه ایجاد شود. این بیمه مسئول وضعیت ایمن رانندگی وسیله نقلیه نیست.</div>',0,'Die Haftpflichtversicherung',1,0,''),
(402,'1.2.23-002','Das Fahrzeug auf kürzestem Weg aus dem Verkehr ziehen','Take the vehicle out of the traffic as quickly as possible','وسیله نقلیه را در کوتاه‌ترین مسیر ممکن از ترافیک خارج کنید.','<div dir=\'rtl\'>استفاده از وسیله نقلیه‌ای که دیگر ایمن نیست، خطر قابل توجه و مهم‌تر از آن، غیرقابل پیش‌بینی برای شما و سایر کاربران جاده ایجاد می‌کند.</div>',0,'Das Fahrzeug auf kürzestem Weg aus dem Verkehr ziehen',1,1,''),
(403,'1.2.23-002','Erst nach Beseitigung des Schadens weiterfahren','Continue only when the damage has been repaired','فقط پس از رفع نقص، به رانندگی ادامه دهید.','<div dir=\'rtl\'>فقط در این صورت است که وسیله نقلیه دوباره ایمن خواهد بود.</div>',0,'Erst nach Beseitigung des Schadens weiterfahren',1,1,''),
(404,'1.2.23-002','Bis zur nächsten Vertragswerkstatt weiterfahren','Proceed to the next authorised dealer','تا نزدیک‌ترین نمایندگی مجاز به رانندگی ادامه دهید.','<div dir=\'rtl\'>ادامه رانندگی تا نزدیک‌ترین نمایندگی مجاز می‌تواند خطرات قابل توجهی برای همه شرکت‌کنندگان در ترافیک داشته باشد و بنابراین ممنوع است.</div>',0,'Bis zur nächsten Vertragswerkstatt weiterfahren',1,0,''),
(405,'1.2.23-003','Abgefahrene Reifen','Worn tyres','لاستیک‌های فرسوده','<div dir=\'rtl\'>لاستیک‌های فرسوده می‌توانند ایمنی ترافیک جاده‌ای را به خطر بیندازند. زیرا آن‌ها اغلب علت لیز خوردن وسیله نقلیه هستند. به این ترتیب، خطر تصادف افزایش می‌یابد.</div>',0,'Abgefahrene Reifen',1,1,''),
(406,'1.2.23-003','Defekte Schlussleuchten','Defective rear lamps','چراغ‌های عقب معیوب','<div dir=\'rtl\'>اگر یک چراغ عقب معیوب باشد، ممکن است وسایل نقلیه پشت سر شما را به موقع تشخیص ندهند. این می‌تواند به عنوان مثال، منجر به تصادفات از پشت شود.</div>',0,'Defekte Schlussleuchten',1,1,''),
(407,'1.2.23-003','Unzureichende Bremswirkung','Insufficient braking effect','عملکرد ترمز ناکافی','<div dir=\'rtl\'>اگر ترمزها فرسوده باشند، مسافت ترمزگیری طولانی‌تر می‌شود. به این ترتیب، تصادفات می‌توانند تسهیل شوند.</div>',0,'Unzureichende Bremswirkung',1,1,''),
(408,'1.2.26-005','- überholt werden','- overtake','- سبقت گرفته شود','<div dir=\'rtl\'>قبل و روی گذرگاه عابر پیاده نباید سبقت گرفته شود. به این ترتیب ممکن است عابران پیاده‌ای که می‌خواهند از خیابان عبور کنند، نادیده گرفته شوند.</div>',0,'- überholt werden',1,1,''),
(409,'1.2.26-005','- gehalten werden','- stop','- توقف (کوتاه) شود','<div dir=\'rtl\'>قبل و روی گذرگاه عابر پیاده نباید توقف (کوتاه) شود. این کار از یک سو جریان ترافیک و از سوی دیگر عبور عابران پیاده از خیابان را مختل می‌کند.</div>',0,'- gehalten werden',1,1,''),
(410,'1.2.26-005','- geparkt werden','- park','- پارک شود','<div dir=\'rtl\'>قبل و روی گذرگاه عابر پیاده پارک ممنوع است. عابران پیاده‌ای که می‌خواهند از خیابان عبور کنند، ممکن است توسط یک وسیله نقلیه پارک شده پنهان شوند.</div>',0,'- geparkt werden',1,1,''),
(411,'1.2.34-103','Unfallstelle absichern','Make the scene of the accident safe','ایمن‌سازی محل حادثه','<div dir=\'rtl\'>ایمن‌سازی محل حادثه به معنای قرار دادن مثلث هشدار، روشن کردن چراغ‌های هشداردهنده (فلاشر) برای قابل مشاهده کردن محل خطر (و در صورت امکان پاکسازی محل حادثه) است تا خطر تصادف بعدی کاهش یابد.</div>',0,'Unfallstelle absichern',1,1,''),
(412,'1.2.34-103','Zur nächsten Telefonzelle fahren und Rettungsdienst alarmieren','Drive to the next telephone box and call the rescue service','به نزدیک‌ترین باجه تلفن رانندگی کرده و خدمات اورژانس را خبر کنید','<div dir=\'rtl\'>خدمات اورژانس تنها پس از ایمن‌سازی محل حادثه و ارائه کمک‌های اولیه باید خبر شوند.</div>',0,'Zur nächsten Telefonzelle fahren und Rettungsdienst alarmieren',1,0,''),
(413,'1.2.34-103','Prüfen, wie schwer die Verletzungen sind','Check the seriousness of the injuries','بررسی میزان جراحات','<div dir=\'rtl\'>کمک‌های اولیه باید در مرحله دوم، پس از ایمن‌سازی محل حادثه، ارائه شوند.</div>',0,'Prüfen, wie schwer die Verletzungen sind',1,0,''),
(414,'1.2.34-106','Über Autobahnraststätten','From the autobahn service areas','از طریق استراحتگاه‌های اتوبان','<div dir=\'rtl\'>در مواقع اضطراری، باید به ستون‌های تماس اضطراری مراجعه کرد. اما اگر موضوع کمک در خرابی خودرو باشد، پیاده‌روی در اتوبان تا نزدیک‌ترین ستون تماس اضطراری خطرناک‌تر است. در این صورت، اگر تلفن همراه در دسترس نیست، توصیه می‌شود به نزدیک‌ترین استراحتگاه مراجعه کنید.</div>',0,'Über Autobahnraststätten',1,1,''),
(415,'1.2.34-106','Über Notrufsäulen','Use an emergency call box','از طریق ستون‌های تماس اضطراری','<div dir=\'rtl\'>ستون‌های تماس اضطراری در کنار اتوبان با فاصله ۲ کیلومتر از یکدیگر قرار دارند. فلش‌های سیاه کوچک روی تیرهای راهنما نشان می‌دهند که برای رسیدن به نزدیک‌ترین ستون باید به کدام سمت رفت. به محض بالا بردن درب ستون تماس اضطراری، اداره راهداری پاسخ می‌دهد. برای راهنمایی آن‌ها، باید شماره حک شده روی ستون و/یا کیلومتر محل خرابی (هر ۵۰۰ متر در کنار اتوبان تابلوهای آبی با اطلاعات کیلومتر وجود دارد) را اعلام کنید.</div>',0,'Über Notrufsäulen',1,1,''),
(416,'1.2.34-106','Über die Telefonnummern 112 oder 110','Dial 112 or 110','از طریق شماره تلفن‌های ۱۱۲ یا ۱۱۰','<div dir=\'rtl\'>شماره‌های اضطراری رسمی در آلمان، «۱۱۰» برای پلیس و «۱۱۲» برای آتش‌نشانی و اورژانس پزشکی هستند. با این حال، این شماره‌ها فقط در مواقع اضطراری واقعی باید گرفته شوند، نه در صورت خرابی خودرو.</div>',0,'Über die Telefonnummern 112 oder 110',1,1,''),
(417,'1.2.34-109','Warnblinklicht einschalten','Switch on the hazard warning lights','چراغ‌های هشداردهنده (فلاشر) را روشن کنید','<div dir=\'rtl\'>این اولین گام مهم برای جلب توجه سایر کاربران جاده به تصادف و در نتیجه نشان دادن نیاز به احتیاط بیشتر است.</div>',0,'Warnblinklicht einschalten',1,1,''),
(418,'1.2.34-109','Notdienste über Notrufstation informieren','Inform emergency services via the SOS-telephone','خدمات اضطراری را از طریق ایستگاه تماس اضطراری مطلع کنید','<div dir=\'rtl\'>فقط از این طریق می‌توان در اسرع وقت کمک برای مجروحان و پاکسازی محل حادثه را فراهم کرد.</div>',0,'Notdienste über Notrufstation informieren',1,1,''),
(419,'1.2.34-109','Fahrzeug nicht verlassen','Do not leave your vehicle','خودرو را ترک نکنید','<div dir=\'rtl\'>در صورت لزوم، باید کمک‌های اولیه را ارائه دهید و خدمات اضطراری را از طریق ایستگاه تماس اضطراری مطلع کنید.</div>',0,'Fahrzeug nicht verlassen',1,0,''),
(420,'1.2.36-001','Die Zeichen des Polizeibeamten','The police officer\'s signals','علائم افسر پلیس','<div dir=\'rtl\'>قوانین کنترل ترافیک به این ترتیب الزامی است: ۱. دستورات افسران پلیس، ۲. چراغ‌های راهنمایی، ۳. علائم راهنمایی و رانندگی، ۴. قانون اساسی «حق تقدم از راست»</div>',0,'Die Zeichen des Polizeibeamten',1,1,''),
(421,'1.2.36-001','Die Lichtzeichen der Ampeln','The traffic light signals','علائم نوری چراغ‌های راهنمایی','<div dir=\'rtl\'>اگر افسر پلیسی در چهارراه حضور نداشت، باید از این علائم پیروی می‌کردید.</div>',0,'Die Lichtzeichen der Ampeln',1,0,''),
(422,'1.2.36-001','Die vorfahrtregelnden Verkehrszeichen','The traffic signs governing priority','علائم راهنمایی و رانندگی تعیین‌کننده حق تقدم','<div dir=\'rtl\'>قوانین حق تقدم تنها زمانی اعمال می‌شوند که هیچ افسر پلیس یا علامت راهنمایی و رانندگی ترافیک را کنترل نکند.</div>',0,'Die vorfahrtregelnden Verkehrszeichen',1,0,''),
(423,'1.2.36-003','Ihnen ist Folge zu leisten','They must be obeyed','باید از آنها پیروی کرد','<div dir=\'rtl\'>باید از دستورات پلیس پیروی کرد.</div>',0,'Ihnen ist Folge zu leisten',1,1,''),
(424,'1.2.36-003','Ihnen ist nur Folge zu leisten, wenn sie mit den aufgestellten Verkehrszeichen übereinstimmen','They must be obeyed only if they tally with the traffic signs installed','فقط در صورتی باید از آنها پیروی کرد که با علائم راهنمایی و رانندگی نصب شده مطابقت داشته باشند','<div dir=\'rtl\'>دستورات یک افسر پلیس، مقررات ترافیکی تعیین شده توسط علائم راهنمایی و رانندگی را لغو می‌کند.</div>',0,'Ihnen ist nur Folge zu leisten, wenn sie mit den aufgestellten Verkehrszeichen übereinstimmen',1,0,''),
(425,'1.2.36-003','Sie entbinden von der eigenen Sorgfaltspflicht','They release you from your own duty to take care','آنها شما را از وظیفه مراقبت شخصی معاف می‌کنند','<div dir=\'rtl\'>دستورات افسر پلیس شما را از وظیفه مراقبت شخصی‌تان معاف نمی‌کند.</div>',0,'Sie entbinden von der eigenen Sorgfaltspflicht',1,0,''),
(426,'1.2.36-004-B','Der gelbe Pkw muss die Kreuzung räumen','The yellow car must leave the crossroads','خودروی سواری زرد باید تقاطع را ترک کند.','<div dir=\'rtl\'>اگر افسر پلیس یک دست خود را بالا ببرد، به این معنی است که راننده‌ای که در تقاطع قرار دارد باید آن را ترک کند.</div>',0,'Der gelbe Pkw muss die Kreuzung räumen',1,1,''),
(427,'1.2.36-004-B','Ich muss mich auf die Weiterfahrt vorbereiten','I must get ready to proceed','من باید برای ادامه حرکت آماده شوم.','<div dir=\'rtl\'>ادامه حرکت تنها زمانی مجاز است که پلیس دیگر به صورت عرضی (عمود بر مسیر حرکت شما) نایستاده باشد، بلکه به صورت جانبی (موازی با مسیر حرکت شما) قرار گرفته باشد. یک دست بالا رفته به شما علامت می‌دهد که برای ادامه حرکت آماده شوید.</div>',0,'Ich muss mich auf die Weiterfahrt vorbereiten',1,1,''),
(428,'1.2.36-004-B','Ich darf schon jetzt abbiegen','I can turn now','من همین الان می‌توانم بپیچم.','<div dir=\'rtl\'>شما تنها زمانی مجاز به پیچیدن هستید که پلیس به صورت جانبی (موازی با شما) ایستاده باشد و هر دو دست خود را به دو طرف باز کرده باشد.</div>',0,'Ich darf schon jetzt abbiegen',1,0,''),
(429,'1.2.36-005-B','Vor der Kreuzung warten','','قبل از تقاطع منتظر بمانید','<div dir=\'rtl\'>پلیس به صورت عرضی نسبت به شما ایستاده و هر دو بازویش را به طرفین باز کرده است. این به این معنی است که ترافیک عرضی می‌تواند عبور کند و شما باید منتظر بمانید.</div>',0,'Vor der Kreuzung warten',1,1,''),
(430,'1.2.36-005-B','Ohne zu halten abbiegen','','بدون توقف بپیچید','<div dir=\'rtl\'>موقعیت افسر پلیس به شما علامت می‌دهد که منتظر بمانید.</div>',0,'Ohne zu halten abbiegen',1,0,''),
(431,'1.2.36-007','Nur für Sie','To you only','فقط برای شما','<div dir=\'rtl\'>دستورالعمل روی تابلوی راهنمایی یک خودروی گشت پلیس یا برای وسیله نقلیه بلافاصله جلوتر یا برای وسیله نقلیه بلافاصله پشت سر معتبر است. از آنجایی که نوشته در آینه عقب قابل تشخیص است و شما مستقیماً جلوی خودروی پلیس رانندگی می‌کنید، منظور از این درخواست شما هستید.</div>',0,'Nur für Sie',1,1,''),
(432,'1.2.36-007','Für alle nachfolgenden Fahrzeuge','To all following vehicles','برای تمام وسایل نقلیه پشت سر','<div dir=\'rtl\'>اگر منظور وسایل نقلیه پشت سر بودند، شما نمی‌توانستید نوشته‌ای در آینه عقب ببینید. این توسط افسران پلیس قابل تنظیم است.</div>',0,'Für alle nachfolgenden Fahrzeuge',1,0,''),
(433,'1.2.36-007','Für alle Fahrzeuge, die sich auf der Straße befinden','To all vehicles on the road','برای تمام وسایل نقلیه‌ای که در جاده هستند','<div dir=\'rtl\'>یک دستورالعمل روی نوشته نورانی یک خودروی گشت پلیس همیشه فقط برای راننده‌ای که مستقیماً جلوتر حرکت می‌کند یا وسیله نقلیه‌ای که مستقیماً پشت سر خودروی گشت قرار دارد، معتبر است.</div>',0,'Für alle Fahrzeuge, die sich auf der Straße befinden',1,0,''),
(434,'1.2.36-101-B','Die Kreuzung darf überquert werden','The crossroads may be crossed','عبور از تقاطع مجاز است','<div dir=\'rtl\'>افسر پلیس با هر دو دست باز به پهلو به شما ایستاده است. این به شما علامت می‌دهد که می‌توانید از تقاطع عبور کنید.</div>',0,'Die Kreuzung darf überquert werden',1,1,''),
(435,'1.2.36-101-B','Vor dem Einfahren in die Kreuzung muss auf weitere Zeichen des Polizeibeamten gewartet werden','You must wait for further signals from the police officer before the crossroads may be entered','قبل از ورود به تقاطع باید منتظر علائم بعدی افسر پلیس ماند','<div dir=\'rtl\'>این حالت زمانی است که افسر پلیس یک دست خود را بالا ببرد.</div>',0,'Vor dem Einfahren in die Kreuzung muss auf weitere Zeichen des Polizeibeamten gewartet werden',1,0,''),
(436,'1.2.36-101-B','Abbiegen ist nicht zulässig','Turning off is prohibited','پیچیدن مجاز نیست','<div dir=\'rtl\'>شما مجاز به عبور از تقاطع و در نتیجه پیچیدن هستید، اگر افسر پلیس در این وضعیت رو به شما ایستاده باشد.</div>',0,'Abbiegen ist nicht zulässig',1,0,''),
(437,'1.2.37-002-B','Der grüne Pkw muss warten','The green car must wait','خودروی سبز باید منتظر بماند','<div dir=\'rtl\'>خودروی سبز جلوی چراغ قرمز ایستاده است و بنابراین باید منتظر بماند.</div>',0,'Der grüne Pkw muss warten',1,1,''),
(438,'1.2.37-002-B','Ich darf unter Beachtung der Verkehrszeichen abbiegen','I may turn observing the traffic signs','من می‌توانم با رعایت علائم راهنمایی و رانندگی بپیچم','<div dir=\'rtl\'>چراغ راهنمایی به شما مربوط نمی‌شود، زیرا شما می‌خواهید قبل از آن بپیچید. با این حال، در اینجا باید قبل از پیچیدن به تابلوی «حق تقدم را واگذار کنید» توجه کنید.</div>',0,'Ich darf unter Beachtung der Verkehrszeichen abbiegen',1,1,''),
(439,'1.2.37-002-B','Ich darf erst abbiegen, wenn die Ampel „Grün“ zeigt','I may only turn when the lights show \\\"green\\\"','من فقط زمانی می‌توانم بپیچم که چراغ راهنمایی «سبز» شود','<div dir=\'rtl\'>از آنجایی که خیابانی که می‌خواهید به آن بپیچید قبل از چراغ راهنمایی قرار دارد، نیازی نیست منتظر بمانید تا چراغ سبز شود تا بپیچید.</div>',0,'Ich darf erst abbiegen, wenn die Ampel „Grün“ zeigt',1,0,''),
(440,'1.2.37-007','Rechtsabbiegen aus dem rechten Fahrstreifen nach vorherigem Anhalten, sofern niemand behindert oder gefährdet wird','','گردش به راست از خط عبور سمت راست پس از توقف قبلی، مشروط بر اینکه کسی مانع یا در معرض خطر قرار نگیرد.','<div dir=\'rtl\'>این مطابق با ماده ۳۷ قانون راهنمایی و رانندگی (StVO) است.</div>',0,'Rechtsabbiegen aus dem rechten Fahrstreifen nach vorherigem Anhalten, sofern niemand behindert oder gefährdet wird',1,1,''),
(441,'1.2.37-007','Rechtsabbiegen ohne anzuhalten','','گردش به راست بدون توقف','<div dir=\'rtl\'>این در صورتی بود که پیکان سبز در نور چراغ راهنمایی ظاهر می‌شد. یک تابلوی راهنمایی و رانندگی جداگانه به این معنی است که ابتدا باید توقف کرد و سپس در صورت آزاد بودن مسیر، گردش کرد.</div>',0,'Rechtsabbiegen ohne anzuhalten',1,0,''),
(442,'1.2.37-007','Rechtsabbiegen, nur wenn die Ampel „Grün“ zeigt','','گردش به راست، فقط زمانی که چراغ راهنمایی «سبز» را نشان می‌دهد.','<div dir=\'rtl\'>پیکان سبز کنار چراغ قرمز راهنمایی، اجازه ادامه حرکت را تحت شرایط ذکر شده در بالا حتی در چراغ قرمز نیز می‌دهد. نیازی به انتظار برای چراغ سبز نیست، اگر این شرایط رعایت شوند.</div>',0,'Rechtsabbiegen, nur wenn die Ampel „Grün“ zeigt',1,0,''),
(443,'1.2.37-009','An der Haltlinie','At the stop line','در خط توقف','<div dir=\'rtl\'>اگر هیچ شرکت‌کننده ترافیکی مزاحم نشود، آنگاه راننده‌ای که در خط عبور سمت راست قرار دارد، پس از توقف می‌تواند به راست بپیچد.</div>',0,'An der Haltlinie',1,1,''),
(444,'1.2.37-009','Wenn keine Haltlinie vorhanden ist, vor der Kreuzung oder Einmündung','Before the crossing or junction if there is no stop line','اگر خط توقف وجود نداشته باشد، قبل از تقاطع یا ورودی','<div dir=\'rtl\'>بدین ترتیب می‌توان ترافیک را مشاهده کرد و در صورت باز بودن مسیر به راست پیچید. این تابلو نشان می‌دهد که قبل از اینکه اجازه گردش به راست داده شود، باید توقف کرد.</div>',0,'Wenn keine Haltlinie vorhanden ist, vor der Kreuzung oder Einmündung',1,1,''),
(445,'1.2.37-009','Es muss nicht angehalten werden','There is no need to stop','نیازی به توقف نیست','<div dir=\'rtl\'>این در صورتی بود که پیکان سبز در خود چراغ راهنمایی ادغام شده بود و چراغ قرمز روشن نبود. یک تابلوی راهنمایی و رانندگی جداگانه با پیکان سبز به این معنی است که قبل از گردش باید توقف کرد.</div>',0,'Es muss nicht angehalten werden',1,0,''),
(446,'1.2.37-010-M','Die Kreuzung ohne anzuhalten überqueren','Pass through the crossing without stopping','چهارراه را بدون توقف عبور کنید','<div dir=\'rtl\'>چراغ راهنمایی برای شما سبز است. به همین دلیل می‌توانید بدون توقف از چهارراه عبور کنید.</div>',0,'Die Kreuzung ohne anzuhalten überqueren',1,1,''),
(447,'1.2.37-010-M','An der Sichtlinie anhalten','Stop on the line of sight','در خط دید توقف کنید','<div dir=\'rtl\'>اگر چراغ راهنمایی روشن نبود، ابتدا باید در خط توقف کنار تابلوی ایست توقف می‌کردید و سپس تا خط دید به داخل چهارراه پیش می‌رفتید.</div>',0,'An der Sichtlinie anhalten',1,0,''),
(448,'1.2.37-010-M','An der Haltlinie anhalten','Stop on the stop line','در خط توقف توقف کنید','<div dir=\'rtl\'>اگر چراغ راهنمایی روشن نبود، ابتدا باید در خط توقف کنار تابلوی ایست توقف می‌کردید و سپس تا خط دید به داخل چهارراه پیش می‌رفتید.</div>',0,'An der Haltlinie anhalten',1,0,''),
(449,'1.2.37-101','Sie müssen warten','You must wait','شما باید صبر کنید','<div dir=\'rtl\'>چراغ راهنمایی سبز است. اما هیچ پیکان سبزی ظاهر نمی‌شود که حق تقدم را نسبت به سایر شرکت‌کنندگان در ترافیک بدهد. اگر چراغ راهنمایی \"سبز\" باشد، می‌توان از خط توقف عبور کرد. اما باید در نقطه پیچیدن صبر کرد تا تراموا عبور کند، قبل از اینکه بپیچید.</div>',0,'Sie müssen warten',1,1,''),
(450,'1.2.37-101','Die Straßenbahn muss warten','The tram must wait','تراموا باید صبر کند','<div dir=\'rtl\'>راننده خودرو باید صبر کند، تراموا حق تقدم دارد.</div>',0,'Die Straßenbahn muss warten',1,0,''),
(451,'1.2.37-101','Gegenseitige Verständigung, weil keine Regel besteht','You must come to an agreement since there are no rules for this','توافق متقابل، زیرا هیچ قانونی وجود ندارد','<div dir=\'rtl\'>یک قانون وجود دارد. تراموا بر خودرو حق تقدم دارد.</div>',0,'Gegenseitige Verständigung, weil keine Regel besteht',1,0,''),
(452,'1.2.37-102-B','Geradeaus','Straight ahead','مستقیم','<div dir=\'rtl\'>از آنجایی که در سمت چپ شما یک خط ممتد وجود دارد، دیگر اجازه ندارید به خط گردش به چپ تغییر مسیر دهید.</div>',0,'Geradeaus',1,1,''),
(453,'1.2.37-102-B','Nach rechts','To the right','به راست','<div dir=\'rtl\'>فلش‌های روی خط رانندگی شما به سمت مستقیم و راست اشاره می‌کنند. شما فقط مجاز به رانندگی در این دو جهت هستید و به دلیل خط ممتد، دیگر اجازه ندارید به خط گردش به چپ تغییر مسیر دهید.</div>',0,'Nach rechts',1,1,''),
(454,'1.2.37-102-B','Nach links, sobald die Ampel dafür „Grün“ zeigt','To the left when the traffic lights are \\\"green\\\"','به چپ، به محض اینکه چراغ راهنمایی سبز شود','<div dir=\'rtl\'>به دلیل خط ممتد، دیگر اجازه ندارید خط رانندگی را تغییر دهید.</div>',0,'Nach links, sobald die Ampel dafür „Grün“ zeigt',1,0,''),
(455,'1.2.38-002','Woher kommt das Einsatzfahrzeug?','','وسیله نقلیه اضطراری از کجا می‌آید؟','<div dir=\'rtl\'>اگر صدای آژیر اضطراری را می‌شنوید، باید مطمئن شوید که وسیله نقلیه از کدام جهت می‌آید و به کجا می‌رود. تنها از این طریق می‌توانید به موقع واکنش نشان دهید تا مانع عبور آن نشوید.</div>',0,'Woher kommt das Einsatzfahrzeug?',1,1,''),
(456,'1.2.38-002','Könnte das Einsatzfahrzeug durch mich behindert werden?','','آیا ممکن است وسیله نقلیه اضطراری توسط من مسدود شود؟','<div dir=\'rtl\'>اگر وسیله نقلیه‌ای با آژیر اضطراری را می‌بینید که به سمت شما می‌آید، باید اطمینان حاصل کنید که مانع آن نمی‌شوید. بر این اساس، باید بررسی کنید که آیا می‌تواند بدون مشکل از کنار شما عبور کند. اگر اینطور نیست، باید برای وسیله نقلیه جا باز کنید تا بتواند بدون مانع به راه خود ادامه دهد.</div>',0,'Könnte das Einsatzfahrzeug durch mich behindert werden?',1,1,''),
(457,'1.2.38-002','Darf das Fahrzeug das Einsatzhorn überhaupt benutzen?','','آیا این وسیله نقلیه اصلاً مجاز به استفاده از آژیر اضطراری است؟','<div dir=\'rtl\'>اینکه آیا وسیله نقلیه مجاز به استفاده از آژیر اضطراری است یا خیر، توسط قانون و مدیریت عملیات تعیین می‌شود. شما نیازی نیست در مورد آن نگران باشید.</div>',0,'Darf das Fahrzeug das Einsatzhorn überhaupt benutzen?',1,0,''),
(458,'1.2.38-003','Vor Gefahren an einer Arbeits- oder Unfallstelle','For dangers at roadworks or the scene of an accident','در مورد خطرات در یک محل کار یا محل حادثه','<div dir=\'rtl\'>چراغ چشمک‌زن زرد روی یک وسیله نقلیه در مورد یک خطر هشدار می‌دهد. این چراغ می‌تواند ثابت یا از طریق وسایل نقلیه استفاده شود. مجاز است برای هشدار در مورد محل‌های کار یا محل‌های حادثه استفاده شود.</div>',0,'Vor Gefahren an einer Arbeits- oder Unfallstelle',1,1,''),
(459,'1.2.38-003','Vor einem Fahrzeug mit ungewöhnlicher Breite','For an exceptionally wide vehicle','در مورد یک وسیله نقلیه با عرض غیرمعمول','<div dir=\'rtl\'>استفاده از آن برای هشدار در مورد وسایل نقلیه با عرض یا طول غیرمعمول امکان‌پذیر است. زیرا این وسایل نقلیه معمولاً در حفظ محدوده‌های مسیر دشواری بیشتری دارند. همچنین خطر انحراف زیاد این وسایل نقلیه در پیچ‌ها وجود دارد. بنابراین، چراغ چشمک‌زن زرد در اینجا استفاده می‌شود تا سایر کاربران جاده هشدار داده شوند.</div>',0,'Vor einem Fahrzeug mit ungewöhnlicher Breite',1,1,''),
(460,'1.2.38-003','Vor einem langsam fahrenden Großraumtransport','For a large transport proceeding at low speed','در مورد یک حمل و نقل بزرگ با حرکت آهسته','<div dir=\'rtl\'>یک چراغ چشمک‌زن زرد می‌تواند در مورد وسایل نقلیه با بار غیرمعمول پهن یا بلند هشدار دهد. این اغلب در مورد حمل و نقل‌های بزرگ اتفاق می‌افتد.</div>',0,'Vor einem langsam fahrenden Großraumtransport',1,1,''),
(461,'1.2.38-101','An einer Unfallstelle wird vor Gefahren gewarnt','Warning of an accident or other dangers','در محل حادثه نسبت به خطرات هشدار داده می‌شود.','<div dir=\'rtl\'>چراغ آبی که بدون آژیر روشن می‌شود، صرفاً یک عملکرد هشداردهنده دارد. به عنوان مثال، برای هشدار دادن در مورد خطر در محل‌های حادثه استفاده می‌شود. به این ترتیب، سایر کاربران جاده از دور می‌دانند که باید با احتیاط از این نقطه عبور کنند.</div>',0,'An einer Unfallstelle wird vor Gefahren gewarnt',1,1,''),
(462,'1.2.38-101','Es wird vor einer Einsatzstelle der Feuerwehr gewarnt','Warning of fire-brigade in action','در مورد محل عملیات آتش‌نشانی هشدار داده می‌شود.','<div dir=\'rtl\'>چراغ چشمک‌زن آبی می‌تواند در عملیات آتش‌نشانی برای هشدار دادن به سایر کاربران جاده استفاده شود.</div>',0,'Es wird vor einer Einsatzstelle der Feuerwehr gewarnt',1,1,''),
(463,'1.2.38-101','Ein Abschleppwagen fährt zu einem Einsatz','A breakdown vehicle is on duty and on its way to its destination','یک یدک‌کش در حال حرکت به سمت محل عملیات است.','<div dir=\'rtl\'>یدک‌کش‌ها هنگام حرکت به سمت محل عملیات از چراغ‌های چشمک‌زن آبی استفاده نمی‌کنند.</div>',0,'Ein Abschleppwagen fährt zu einem Einsatz',1,0,''),
(464,'1.2.38-102','Das Fahrzeug befindet sich auf einer Einsatzfahrt. Sie sollten ihm Platz machen','The vehicle is on duty. You should give way','این وسیله نقلیه در حال انجام ماموریت اضطراری است. شما باید راه را برای آن باز کنید.','<div dir=\'rtl\'>حتی بدون آژیر (هورن مارتین)، اما با چراغ چشمک‌زن آبی روشن، وسیله نقلیه می‌تواند در حال انجام ماموریت باشد. در این صورت، اگرچه وسیله نقلیه اضطراری حق تقدم ندارد، اما شما باید راه را برای آن باز کنید.</div>',0,'Das Fahrzeug befindet sich auf einer Einsatzfahrt. Sie sollten ihm Platz machen',1,1,''),
(465,'1.2.38-102','Ankündigung eines geschlossenen Verbandes','Advance warning of a closed convoy','اعلام حضور یک کاروان سازمان‌یافته','<div dir=\'rtl\'>برای همراهی یک کاروان سازمان‌یافته، چراغ چشمک‌زن آبی روشن می‌شود.</div>',0,'Ankündigung eines geschlossenen Verbandes',1,1,''),
(466,'1.2.38-102','Ohne Einsatzhorn hat das blaue Blinklicht keine Bedeutung','Without a siren, a flashing blue light does not mean anything','بدون آژیر، چراغ چشمک‌زن آبی معنایی ندارد.','<div dir=\'rtl\'>چراغ چشمک‌زن آبی حتی بدون آژیر نیز معنا دارد. آژیر ممکن است به دلایل تاکتیکی یا برای به حداقل رساندن آلودگی صوتی در شب خاموش باشد.</div>',0,'Ohne Einsatzhorn hat das blaue Blinklicht keine Bedeutung',1,0,''),
(467,'1.3.01-001','An Straßenkreuzungen und -einmündungen','At crossroads and junctions','در چهارراه‌ها و تقاطع‌ها','<div dir=\'rtl\'>قانون «حق تقدم با راست» اصولاً در تمام چهارراه‌ها و تقاطع‌هایی اعمال می‌شود که در آن‌ها هیچ علامت راهنمایی و رانندگی (تابلو یا چراغ راهنمایی) نصب نشده باشد و حق تقدم توسط افسران پلیس تنظیم نشده باشد.</div>',0,'An Straßenkreuzungen und -einmündungen',1,1,''),
(468,'1.3.01-001','An Grundstücksausfahrten','At driveways','در خروجی‌های ملک/پارکینگ','<div dir=\'rtl\'>در خروجی‌های ملک، قانون «حق تقدم با راست» اعمال نمی‌شود. در اینجا، کسی که از ملک وارد خیابان می‌شود باید آنقدر صبر کند تا تمام وسایل نقلیه دیگر عبور کنند و خیابان دوباره آزاد شود. سپس نوبت اوست.</div>',0,'An Grundstücksausfahrten',1,0,''),
(469,'1.3.01-001','Am Ende eines verkehrsberuhigten Bereiches','At the end of a traffic calmed area','در انتهای یک منطقه آرام‌سازی ترافیک','<div dir=\'rtl\'>شرکت‌کنندگان در ترافیک که از منطقه آرام‌سازی ترافیک خارج می‌شوند، مسئولیت مراقبت ویژه‌ای دارند. به همین دلیل، قانون «حق تقدم با راست» در چنین مکانی برای آن‌ها اعمال نمی‌شود. آن‌ها معمولاً باید حق تقدم تمام شرکت‌کنندگان دیگر در ترافیک را رعایت کنند.</div>',0,'Am Ende eines verkehrsberuhigten Bereiches',1,0,''),
(470,'1.3.01-002','An Straßenkreuzungen und -einmündungen','At crossroads and junctions','در چهارراه‌ها و تقاطع‌ها','<div dir=\'rtl\'>اگر هیچ علامت راهنمایی و رانندگی، چراغ راهنمایی یا پلیسی ترافیک را تنظیم نکند، به طور کلی قانون «حق تقدم با راست» اعمال می‌شود.</div>',0,'An Straßenkreuzungen und -einmündungen',1,1,''),
(471,'1.3.01-002','An Einmündungen mit abgesenktem Bordstein','At junctions with sunken kerbstone','در تقاطع‌هایی با جدول پایین‌آمده','<div dir=\'rtl\'>تقاطع‌هایی با جدول پایین‌آمده، خیابان‌های هم‌تراز محسوب نمی‌شوند. معمولاً این‌ها ورودی یا خروجی به املاک خصوصی هستند. بنابراین، قانون «حق تقدم با راست» در اینجا اعمال نمی‌شود.</div>',0,'An Einmündungen mit abgesenktem Bordstein',1,0,''),
(472,'1.3.01-002','Wo Feld- oder Waldwege in eine andere Straße münden','At junctions of farm tracks or forest tracks with other roads','جایی که جاده‌های خاکی یا جنگلی به خیابان دیگری منتهی می‌شوند','<div dir=\'rtl\'>جاده‌های خاکی و جنگلی معمولاً خیابان‌های آسفالت‌شده نیستند، بلکه بیشتر جاده‌های شنی هستند که نمی‌توان با سرعت در آن‌ها رانندگی کرد. واژه «راه» (Weg) خود نشان می‌دهد که این‌ها خیابان‌های هم‌تراز نیستند. بر این اساس، قانون «حق تقدم با راست» در اینجا اعمال نمی‌شود.</div>',0,'Wo Feld- oder Waldwege in eine andere Straße münden',1,0,''),
(473,'1.3.01-003','Warten, beobachten und sich gegebenenfalls mit anderen verständigen','Wait, observe and come to an agreement with others, if necessary','صبر کردن، مشاهده کردن و در صورت لزوم با دیگران ارتباط برقرار کردن','<div dir=\'rtl\'>از آنجایی که شما نمی‌توانید وضعیت حق تقدم را تشخیص دهید و بنابراین ممکن است حق تقدم سایر شرکت‌کنندگان در ترافیک را نادیده بگیرید، در چنین حالتی صحیح است که صبر کنید، مشاهده کنید و در صورت لزوم با دیگران ارتباط برقرار کنید.</div>',0,'Warten, beobachten und sich gegebenenfalls mit anderen verständigen',1,1,''),
(474,'1.3.01-003','Nach der Regel „rechts vor links“ fahren','Proceed according to the rule \\\"right before left\\\"','بر اساس قانون «راست به چپ» رانندگی کردن','<div dir=\'rtl\'>اگر از وضعیت حق تقدم مطمئن نیستید، نمی‌توانید به سادگی یک قانون حق تقدم را انتخاب کنید، زیرا ممکن است با مقررات واقعی حاکم در تقاطع مغایرت داشته باشد. سعی کنید با سایر شرکت‌کنندگان در ترافیک تماس بگیرید و در صورت لزوم حق تقدم را به آنها بدهید.</div>',0,'Nach der Regel „rechts vor links“ fahren',1,0,''),
(475,'1.3.01-003','Als Geradeausfahrer immer durchfahren','Always proceed when driving straight ahead','به عنوان راننده مستقیم‌رو همیشه عبور کردن','<div dir=\'rtl\'>شما به عنوان راننده مستقیم‌رو تنها زمانی می‌توانید از تقاطع عبور کنید که مشخص شود نیازی به دادن حق تقدم به هیچ شرکت‌کننده دیگری در ترافیک ندارید.</div>',0,'Als Geradeausfahrer immer durchfahren',1,0,''),
(476,'1.3.01-016-M','Ich muss <span class=\"mutterfrage\">den blauen Lkw</span> durchfahren lassen','I have to allow the <span class=\\\"mutterfrage\\\">blue truck</span> to pass through','من باید اجازه دهم <span class=\"mutterfrage\">کامیون آبی</span> عبور کند','',0,'Ich muss <span class=\"mutterfrage\">den blauen Lkw</span> durchfahren lassen',1,1,''),
(477,'1.3.01-016-M','Ich muss <span class=\"mutterfrage\">den Traktor</span> abbiegen lassen','I have to allow the <span class=\\\"mutterfrage\\\">tractor</span> to turn','من باید اجازه دهم <span class=\"mutterfrage\">تراکتور</span> بپیچد','',0,'Ich muss <span class=\"mutterfrage\">den Traktor</span> abbiegen lassen',1,1,''),
(478,'1.3.01-016-M','<span class=\"mutterfrage\">Der blaue Lkw</span> muss mich durchfahren lassen','The <span class=\\\"mutterfrage\\\">blue truck</span> has to allow me to pass through','<span class=\"mutterfrage\">کامیون آبی</span> باید اجازه دهد من عبور کنم','',0,'<span class=\"mutterfrage\">Der blaue Lkw</span> muss mich durchfahren lassen',1,0,''),
(479,'1.3.01-017-M','Ich muss <span class=\"mutterfrage\">das Motorrad</span> durchfahren lassen','I have to allow the <span class=\\\"mutterfrage\\\">motorcycle</span> to pass through','من باید اجازه دهم <span class=\"mutterfrage\">موتورسیکلت</span> عبور کند','',0,'Ich muss <span class=\"mutterfrage\">das Motorrad</span> durchfahren lassen',1,1,''),
(480,'1.3.01-017-M','Ich fahre vor <span class=\"mutterfrage\">dem Bus</span>','I take priority before <span class=\\\"mutterfrage\\\">the bus</span>','من قبل از <span class=\"mutterfrage\">اتوبوس</span> حرکت می‌کنم','',0,'Ich fahre vor <span class=\"mutterfrage\">dem Bus</span>',1,1,''),
(481,'1.3.01-017-M','Ich muss <span class=\"mutterfrage\">den Bus</span> durchfahren lassen','I have to allow <span class=\\\"mutterfrage\\\">the bus</span> to pass through','من باید اجازه دهم <span class=\"mutterfrage\">اتوبوس</span> عبور کند','',0,'Ich muss <span class=\"mutterfrage\">den Bus</span> durchfahren lassen',1,0,''),
(482,'1.3.01-018-M','Ich muss <span class=\"mutterfrage\">das Motorrad</span> durchfahren lassen','I have to allow <span class=\\\"mutterfrage\\\">the motorcycle</span> to pass through','من باید به <span class=\"mutterfrage\">موتورسیکلت</span> اجازه عبور بدهم.','',0,'Ich muss <span class=\"mutterfrage\">das Motorrad</span> durchfahren lassen',1,1,''),
(483,'1.3.01-018-M','Ich fahre vor dem <span class=\"mutterfrage\">Bus</span>','I take priority before the <span class=\\\"mutterfrage\\\">bus</span>','من قبل از <span class=\"mutterfrage\">اتوبوس</span> عبور می‌کنم.','',0,'Ich fahre vor dem <span class=\"mutterfrage\">Bus</span>',1,1,''),
(484,'1.3.01-018-M','Ich muss <span class=\"mutterfrage\">den Bus</span> durchfahren lassen','I have to allow the <span class=\\\"mutterfrage\\\">bus</span> to pass through','من باید به <span class=\"mutterfrage\">اتوبوس</span> اجازه عبور بدهم.','',0,'Ich muss <span class=\"mutterfrage\">den Bus</span> durchfahren lassen',1,0,''),
(485,'1.3.01-021-M','- erst nach dem <span class=\"mutterfrage\">Motorrad</span> abbiegen','- only turn after the <span class=\\\"mutterfrage\\\">motorcycle</span>','- فقط بعد از <span class=\"mutterfrage\">موتورسیکلت</span> بپیچم','',0,'- erst nach dem <span class=\"mutterfrage\">Motorrad</span> abbiegen',1,1,''),
(486,'1.3.01-021-M','- vor dem <span class=\"mutterfrage\">gelben Pkw</span> abbiegen','- turn before the <span class=\\\"mutterfrage\\\">yellow car</span>','- قبل از <span class=\"mutterfrage\">خودروی سواری زرد</span> بپیچم','',0,'- vor dem <span class=\"mutterfrage\">gelben Pkw</span> abbiegen',1,1,''),
(487,'1.3.01-021-M','- als Erster abbiegen','- be the first to make my turn','- به عنوان نفر اول بپیچم','<div dir=\'rtl\'>شما مجاز به گردش هستید، به محض اینکه موتورسوار عبور کرده و مسیر آزاد باشد.</div>',0,'- als Erster abbiegen',1,0,''),
(488,'1.3.01-035-M','Ich lasse den <span class=\"mutterfrage\">grünen Pkw</span> durchfahren','I give way to the <span class=\\\"mutterfrage\\\">green car</span>','من اجازه می‌دهم <span class=\"mutterfrage\">خودروی سبز</span> عبور کند','',0,'Ich lasse den <span class=\"mutterfrage\">grünen Pkw</span> durchfahren',1,1,''),
(489,'1.3.01-035-M','Ich biege vor dem <span class=\"mutterfrage\">grünen Pkw</span> links ab','I turn left before the <span class=\\\"mutterfrage\\\">green car</span>','من قبل از <span class=\"mutterfrage\">خودروی سبز</span> به چپ می‌پیچم','',0,'Ich biege vor dem <span class=\"mutterfrage\">grünen Pkw</span> links ab',1,0,''),
(490,'1.3.01-035-M','Ich muss den <span class=\"mutterfrage\">roten Pkw</span> vorbeilassen','I have to allow the <span class=\\\"mutterfrage\\\">red car</span> to pass','من باید به <span class=\"mutterfrage\">خودروی قرمز</span> راه بدهم','',0,'Ich muss den <span class=\"mutterfrage\">roten Pkw</span> vorbeilassen',1,0,''),
(491,'1.3.01-038-M','Ich muss das Motorrad durchfahren lassen','I have to give way to the motorcycle','من باید اجازه دهم موتورسیکلت عبور کند','<div dir=\'rtl\'>این تابلو راهنمایی و رانندگی به معنای «حق تقدم بدهید» است. علاوه بر این، یک خیابان اصلی با مسیر منحنی را نشان می‌دهد که موتورسوار در آن قرار دارد. بنابراین، شما باید اجازه دهید موتورسوار عبور کند.</div>',0,'Ich muss das Motorrad durchfahren lassen',1,1,''),
(492,'1.3.01-038-M','Ich muss den <span class=\"mutterfrage\">blauen Pkw</span> durchfahren lassen','I have to give way to the <span class=\\\"mutterfrage\\\">blue car</span>','من باید اجازه دهم <span class=\"mutterfrage\">خودروی آبی</span> عبور کند','',0,'Ich muss den <span class=\"mutterfrage\">blauen Pkw</span> durchfahren lassen',1,1,''),
(493,'1.3.01-038-M','Ich darf vor dem <span class=\"mutterfrage\">blauen Pkw</span> fahren','I may drive out before the <span class=\\\"mutterfrage\\\">blue car</span>','من می‌توانم قبل از <span class=\"mutterfrage\">خودروی آبی</span> رانندگی کنم','',0,'Ich darf vor dem <span class=\"mutterfrage\">blauen Pkw</span> fahren',1,0,''),
(494,'1.3.01-042-M','Ich muss die Straßenbahn durchfahren lassen','I have to allow the tram to pass through','من باید اجازه دهم تراموا عبور کند.','<div dir=\'rtl\'>به دلیل تابلوی «حق تقدم را واگذار کنید»، شما باید حق تقدم را به تراموا بدهید.</div>',0,'Ich muss die Straßenbahn durchfahren lassen',1,1,''),
(495,'1.3.01-042-M','Ich muss das <span class=\"mutterfrage\">Motorrad</span> durchfahren lassen','I have to allow the <span class=\\\"mutterfrage\\\">motorcycle</span> to pass through','من باید اجازه دهم <span class=\"mutterfrage\">موتورسیکلت</span> عبور کند.','',0,'Ich muss das <span class=\"mutterfrage\">Motorrad</span> durchfahren lassen',1,1,''),
(496,'1.3.01-042-M','Die Straßenbahn muss mich vorher abbiegen lassen','The tram must allow me to make the turn first','تراموا باید ابتدا به من اجازه گردش دهد.','<div dir=\'rtl\'>شما باید اجازه دهید تراموا عبور کند.</div>',0,'Die Straßenbahn muss mich vorher abbiegen lassen',1,0,''),
(497,'1.3.01-046-M','Ich darf durchfahren','I may drive through','من مجاز به عبور هستم','<div dir=\'rtl\'>شما در جاده اصلی قرار دارید و بنابراین مجاز هستید قبل از خودروی آبی عبور کنید. باید گردش خود را با راهنما زدن نشان دهید.</div>',0,'Ich darf durchfahren',1,1,''),
(498,'1.3.01-046-M','Ich muss <span class=\"mutterfrage\">den blauen Pkw</span> durchfahren lassen','I have to allow <span class=\\\"mutterfrage\\\">the blue car</span> to pass through','من باید اجازه دهم <span class=\"mutterfrage\">خودروی آبی</span> عبور کند','',0,'Ich muss <span class=\"mutterfrage\">den blauen Pkw</span> durchfahren lassen',1,0,''),
(499,'1.3.01-048-M','Ich lasse <span class=\"mutterfrage\">den blauen Pkw</span> abbiegen','I allow <span class=\\\"mutterfrage\\\">the blue car</span> to turn','من اجازه می‌دهم <span class=\"mutterfrage\">خودروی آبی</span> بپیچد','',0,'Ich lasse <span class=\"mutterfrage\">den blauen Pkw</span> abbiegen',1,1,''),
(500,'1.3.01-048-M','Ich fahre als Erster','I am the first to proceed','من اول حرکت می‌کنم','<div dir=\'rtl\'>شما باید ابتدا اجازه دهید خودروی آبی بپیچد، قبل از اینکه حرکت کنید.</div>',0,'Ich fahre als Erster',1,0,''),
(501,'1.3.01-048-M','Ich lasse das Motorrad vor mir abbiegen','I allow the motorcycle to turn before me','من اجازه می‌دهم موتورسیکلت جلوی من بپیچد','<div dir=\'rtl\'>موتورسوار باید به شما اجازه عبور دهد، قبل از اینکه بپیچد، زیرا او جهت حرکت خود را تغییر می‌دهد و شما به عنوان راننده مستقیم‌رو حق تقدم دارید.</div>',0,'Ich lasse das Motorrad vor mir abbiegen',1,0,''),
(502,'1.3.01-049-M','Ich darf als Erster fahren','I may be the first to proceed','من می‌توانم اول حرکت کنم.','<div dir=\'rtl\'>شما در خیابان اصلی هستید و به همین دلیل می‌توانید اول حرکت کنید.</div>',0,'Ich darf als Erster fahren',1,1,''),
(503,'1.3.01-049-M','Ich muss <span class=\"mutterfrage\">den roten Pkw</span> vorlassen','I have to give way to the <span class=\\\"mutterfrage\\\">red car</span>','من باید به <span class=\"mutterfrage\">خودروی قرمز</span> اجازه عبور دهم.','',0,'Ich muss <span class=\"mutterfrage\">den roten Pkw</span> vorlassen',1,0,''),
(504,'1.3.01-049-M','Ich muss die Straßenbahn vorlassen','I have to give way to the tram','من باید به تراموا اجازه عبور دهم.','<div dir=\'rtl\'>در این مورد، برای راننده تراموا نیز همان قوانین سایر شرکت‌کنندگان در ترافیک اعمال می‌شود. از آنجایی که شما در خیابان اصلی هستید، حق تقدم دارید.</div>',0,'Ich muss die Straßenbahn vorlassen',1,0,''),
(505,'1.3.01-050-M','Ich darf durchfahren','I may drive through','من اجازه دارم عبور کنم','<div dir=\'rtl\'>شما در جاده اصلی قرار دارید و بنابراین اجازه دارید عبور کنید.</div>',0,'Ich darf durchfahren',1,1,''),
(506,'1.3.01-050-M','Ich muss <span class=\"mutterfrage\">dem blauen Pkw</span> Vorfahrt gewähren','I have to allow right of way to <span class=\\\"mutterfrage\\\">the blue car</span>','من باید <span class=\"mutterfrage\">به خودروی آبی</span> حق تقدم بدهم','',0,'Ich muss <span class=\"mutterfrage\">dem blauen Pkw</span> Vorfahrt gewähren',1,0,''),
(507,'1.3.01-050-M','Ich muss <span class=\"mutterfrage\">dem grünen Pkw</span> Vorfahrt gewähren','I have to allow right of way to <span class=\\\"mutterfrage\\\">the green car</span>','من باید <span class=\"mutterfrage\">به خودروی سبز</span> حق تقدم بدهم','',0,'Ich muss <span class=\"mutterfrage\">dem grünen Pkw</span> Vorfahrt gewähren',1,0,''),
(508,'1.4.40-001','Geschwindigkeit vermindern','Reduce speed','سرعت را کاهش دهید','<div dir=\'rtl\'>برای اینکه بتوانید به وسیله نقلیه‌ای که احتمالاً از سمت راست می‌آید حق تقدم بدهید، باید سرعت خود را کاهش دهید تا در صورت لزوم بتوانید توقف کنید.</div>',0,'Geschwindigkeit vermindern',1,1,''),
(509,'1.4.40-001','Bremsbereit sein','Be ready to brake','آماده ترمز باشید','<div dir=\'rtl\'>برای اینکه بتوانید به وسیله نقلیه‌ای که احتمالاً از سمت راست می‌آید حق تقدم بدهید، باید همیشه آماده ترمز باشید.</div>',0,'Bremsbereit sein',1,1,''),
(510,'1.4.40-001','Nur den von rechts kommenden Verkehr beobachten','Observe the traffic coming from the right only','فقط ترافیک ورودی از سمت راست را مشاهده کنید','<div dir=\'rtl\'>البته که باید به ترافیک ورودی از سمت راست توجه کنید. اما این به هیچ وجه به این معنی نیست که می‌توانید از بقیه وضعیت ترافیک غافل شوید.</div>',0,'Nur den von rechts kommenden Verkehr beobachten',1,0,''),
(511,'1.4.40-004','Dem Gegenverkehr Vorrang einräumen','','به ترافیک روبرو حق تقدم بدهید','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی در مورد باریک شدن مسیر در سمت راست هشدار می‌دهد. از آنجایی که کسی که مانع را در مقابل خود دارد باید منتظر بماند، در این حالت وظیفه شماست که به ترافیک روبرو حق تقدم بدهید.</div>',0,'Dem Gegenverkehr Vorrang einräumen',1,1,''),
(512,'1.4.40-004','Bei zwei Fahrstreifen für eine Richtung das Reißverschlussverfahren anwenden','','در صورت وجود دو خط عبور در یک جهت، از روش زیپ (ادغام متناوب) استفاده کنید','<div dir=\'rtl\'>اگر یکی از چندین خط عبور که در یک جهت حرکت می‌کنند به پایان برسد یا توسط مانعی مسدود شود، همیشه باید در چنین مکانی از روش زیپ (ادغام متناوب) استفاده شود. بدین ترتیب ترافیک می‌تواند به حرکت خود ادامه دهد و از ایجاد ترافیک غیرضروری در خط عبوری که به پایان می‌رسد جلوگیری می‌شود.</div>',0,'Bei zwei Fahrstreifen für eine Richtung das Reißverschlussverfahren anwenden',1,1,''),
(513,'1.4.40-004','Wenn Sie bei zwei Fahrstreifen für eine Richtung auf dem linken fahren, haben Sie absoluten Vorrang','','اگر در صورت وجود دو خط عبور در یک جهت، در خط چپ رانندگی می‌کنید، حق تقدم مطلق دارید','<div dir=\'rtl\'>اگر یکی از دو خط عبور در یک جهت به پایان برسد، هرگز حق تقدم مطلق در اینجا اعمال نمی‌شود، بلکه به طور کلی باید از روش زیپ (ادغام متناوب) استفاده شود.</div>',0,'Wenn Sie bei zwei Fahrstreifen für eine Richtung auf dem linken fahren, haben Sie absoluten Vorrang',1,0,''),
(514,'1.4.40-005','Mit Gegenverkehr','','با ترافیک روبرو','<div dir=\'rtl\'>این تابلو را معمولاً زمانی می‌بینید که مثلاً وارد یک خیابان یک‌طرفه می‌شوید که موقتاً برای هر دو جهت حرکت باز شده است، یا زمانی که یک سمت جاده موقتاً ترافیک سمت دیگر را به عهده می‌گیرد (مثلاً به دلیل یک کارگاه ساختمانی). در این صورت، باید انتظار ترافیک روبرو را داشته باشید.</div>',0,'Mit Gegenverkehr',1,1,''),
(515,'1.4.40-005','Mit Blendung durch den Gegenverkehr bei Nacht','','با خیرگی ناشی از ترافیک روبرو در شب','<div dir=\'rtl\'>از آنجایی که در این حالت باید انتظار ترافیک روبرو را داشته باشید، ممکن است در تاریکی نیز توسط آن خیره شوید.</div>',0,'Mit Blendung durch den Gegenverkehr bei Nacht',1,1,''),
(516,'1.4.40-005','Mit Vorrang des Gegenverkehrs','','با حق تقدم ترافیک روبرو','<div dir=\'rtl\'>تابلویی که حق تقدم را به ترافیک روبرو می‌دهد، یک پیکان قرمز و یک پیکان سیاه را نشان می‌دهد. این تابلو معمولاً در پل‌های باریک و تنگ‌شدگی‌های جاده یافت می‌شود. راننده‌ای که در جهت پیکان قرمز حرکت می‌کند، باید منتظر بماند. راننده‌ای که در جهت پیکان سیاه حرکت می‌کند، حق تقدم دارد.</div>',0,'Mit Vorrang des Gegenverkehrs',1,0,''),
(517,'1.4.40-006','Höchste Aufmerksamkeit','Greatest alertness','حداکثر توجه','<div dir=\'rtl\'>در چنین مناطقی باید با حداکثر توجه رانندگی کرد، زیرا ممکن است ناگهان کودکان در مسیر رانندگی ظاهر شوند.</div>',0,'Höchste Aufmerksamkeit',1,1,''),
(518,'1.4.40-006','Bremsbereitschaft','Readiness to brake','آمادگی برای ترمز','<div dir=\'rtl\'>از آنجایی که احتمال دارد کودکان ناگهان وارد مسیر رانندگی شوند، شما باید همیشه آماده ترمز باشید.</div>',0,'Bremsbereitschaft',1,1,''),
(519,'1.4.40-006','Geschwindigkeit vermindern','Reduction in speed','کاهش سرعت','<div dir=\'rtl\'>شما باید در اینجا تا حد امکان آهسته رانندگی کنید تا در صورت نیاز به ترمز، مسافت ترمزگیری تا حد ممکن کوتاه باشد و کسی به خطر نیفتد.</div>',0,'Geschwindigkeit vermindern',1,1,''),
(520,'1.4.40-101','Zwischen 150 m und 250 m','Between 150 m and 250 m','بین ۱۵۰ متر و ۲۵۰ متر','<div dir=\'rtl\'>تابلویی که در این فاصله نصب شده باشد، به راننده با سرعت‌های معمول خارج از شهر زمان کافی نمی‌دهد تا سرعت خود را کاهش دهد یا در صورت لزوم حتی توقف کند.</div>',0,'Zwischen 150 m und 250 m',1,1,''),
(521,'1.4.40-101','Zwischen 50 m und 150 m','Between 50 m and 150 m','بین ۵۰ متر و ۱۵۰ متر','<div dir=\'rtl\'>تابلویی که در این فاصله نصب شده باشد، به راننده با سرعت‌های معمول خارج از شهر زمان کافی نمی‌دهد تا سرعت خود را کاهش دهد یا در صورت لزوم حتی توقف کند.</div>',0,'Zwischen 50 m und 150 m',1,0,''),
(522,'1.4.40-101','Zwischen 250 m und 350 m','Between 250 m and 350 m','بین ۲۵۰ متر و ۳۵۰ متر','<div dir=\'rtl\'>تابلویی که در این فاصله نصب شده باشد، به راننده با سرعت‌های معمول خارج از شهر زمان کافی نمی‌دهد تا سرعت خود را کاهش دهد یا در صورت لزوم حتی توقف کند.</div>',0,'Zwischen 250 m und 350 m',1,0,''),
(523,'1.4.40-103','- auf der Fahrbahn Wintersport betrieben wird','- this road may be used for winter sports','- ورزش‌های زمستانی در سطح جاده انجام می‌شود','<div dir=\'rtl\'>این تابلوها نشان می‌دهند که در اینجا اسکی‌بازان از عرض جاده عبور می‌کنند.</div>',0,'- auf der Fahrbahn Wintersport betrieben wird',1,1,''),
(524,'1.4.40-103','- auf der Fahrbahn Schnee- oder Eisglätte herrscht','- there is packed snow or black ice on the roadway','- سطح جاده برفی یا یخبندان است','<div dir=\'rtl\'>از آنجایی که در اینجا ورزش‌های زمستانی انجام می‌شود، احتمالاً این منطقه پربرف است. بنابراین، می‌توانید انتظار داشته باشید که سطح جاده برفی، یخبندان و لغزنده باشد.</div>',0,'- auf der Fahrbahn Schnee- oder Eisglätte herrscht',1,1,''),
(525,'1.4.40-103','- Wintersport nur auf den Gehwegen stattfindet','- only the pavements are used for winter sports','- ورزش‌های زمستانی فقط در پیاده‌روها انجام می‌شود','<div dir=\'rtl\'>در اینجا هیچ نشانه‌ای برای این موضوع وجود ندارد.</div>',0,'- Wintersport nur auf den Gehwegen stattfindet',1,0,''),
(526,'1.4.40-105','Geschwindigkeit vermindern','Reduce your speed','سرعت را کاهش دهید','<div dir=\'rtl\'>در چنین مسیر جاده‌ای، کاهش سرعت ضروری است. این امر حتی در پیچ‌های ساده نیز صدق می‌کند تا از پرتاب شدن خودرو به بیرون از پیچ جلوگیری شود.</div>',0,'Geschwindigkeit vermindern',1,1,''),
(527,'1.4.40-105','Möglichst weit rechts fahren','Drive as far as possible over on the right-hand side','تا حد امکان در سمت راست برانید','<div dir=\'rtl\'>در چنین مکانی نیز باید تا حد امکان در سمت راست رانندگی کرد، زیرا به عنوان مثال، رانندگان مقابل ممکن است به دلیل سرعت زیاد پیچ را ببرند یا وسایل نقلیه بزرگ برای عبور از پیچ دوتایی مجبور باشند از بخشی از خط شما استفاده کنند.</div>',0,'Möglichst weit rechts fahren',1,1,''),
(528,'1.4.40-105','Gleich nach der Rechtskurve kräftig beschleunigen','Accelerate strongly immediately after the right bend','بلافاصله پس از پیچ راست، به شدت شتاب بگیرید','<div dir=\'rtl\'>اگر بلافاصله پس از پیچ راست دوباره گاز دهید، با سرعت بیشتری به سمت پیچ چپ حرکت خواهید کرد. این بسیار خطرناک است، زیرا در بدترین حالت، خودرو برای عبور از پیچ بعدی بیش از حد سریع خواهد بود.</div>',0,'Gleich nach der Rechtskurve kräftig beschleunigen',1,0,''),
(529,'1.4.40-106','Ein Gefälle von 800 m Länge','A downhill slope 800 m in length','یک سراشیبی به طول ۸۰۰ متر','<div dir=\'rtl\'>در این علامت راهنمایی و رانندگی، یک سراشیبی به طول ۸۰۰ متر نشان داده شده است. اینکه این یک سراشیبی است، از این طریق قابل تشخیص است که شیب در علامت راهنمایی و رانندگی به صورت مورب از بالا سمت چپ به پایین سمت راست می‌افتد. اگر یک سربالایی باشد، شیب از پایین سمت چپ به بالا سمت راست متمایل است. از آنجایی که در سمت چپ و راست عدد «۸۰۰ متر» فلش‌هایی قرار گرفته‌اند، این به معنای «به طول ۸۰۰ متر» است.</div>',0,'Ein Gefälle von 800 m Länge',1,1,''),
(530,'1.4.40-106','Eine Steigung in 800 m Entfernung','An uphill slope 800 m in length','یک سربالایی در فاصله ۸۰۰ متری','<div dir=\'rtl\'>این در صورتی بود که تابلوی پایینی از دو تابلوی راهنمایی و رانندگی فقط عبارت «۸۰۰ متر» را بدون فلش نشان می‌داد و در تابلوی بالایی شیب به سمت «بالا» متمایل بود.</div>',0,'Eine Steigung in 800 m Entfernung',1,0,''),
(531,'1.4.40-106','Ein Gefälle in 800 m Entfernung','The beginning of a downhill slope 800 m ahead','یک سراشیبی در فاصله ۸۰۰ متری','<div dir=\'rtl\'>این در صورتی بود که تابلوی پایینی از دو تابلوی راهنمایی و رانندگی فقط عبارت «۸۰۰ متر» را بدون فلش نشان می‌داد.</div>',0,'Ein Gefälle in 800 m Entfernung',1,0,''),
(532,'1.4.40-108','Geschwindigkeit verringern','Reduce your speed','سرعت را کاهش دهید','<div dir=\'rtl\'>با کاهش سرعت می‌توانید از جاده ناهموار با ایمنی بیشتر و خطر کمتر برای خود، وسیله نقلیه‌تان و سایر کاربران جاده عبور کنید.</div>',0,'Geschwindigkeit verringern',1,1,''),
(533,'1.4.40-108','Geschwindigkeit erhöhen','Increase your speed','سرعت را افزایش دهید','<div dir=\'rtl\'>با رانندگی سریع‌تر، خطر موقعیت‌های خطرناک افزایش می‌یابد. ممکن است کنترل خودرو را از دست بدهید، خودرو دچار شکستگی محور یا فنر شود یا بار حمل شده در اثر ضربه‌های شدید آسیب ببیند.</div>',0,'Geschwindigkeit erhöhen',1,0,''),
(534,'1.4.40-108','Durch schnelle Lenkbewegungen den Unebenheiten ausweichen','Avoid the uneven patches by making sudden steering wheel movements','با حرکات سریع فرمان از ناهمواری‌ها دوری کنید','<div dir=\'rtl\'>حرکات سریع فرمان در این نوع سطح، خطر از دست دادن کنترل خودرو را افزایش می‌دهد.</div>',0,'Durch schnelle Lenkbewegungen den Unebenheiten ausweichen',1,0,''),
(535,'1.4.40-109','Das Fahrzeug könnte schleudern und den Gegenverkehr gefährden','The vehicle could go into a skid and endanger oncoming traffic','ممکن است خودرو سر بخورد و ترافیک مقابل را به خطر اندازد.','<div dir=\'rtl\'>بنابراین، کاهش سرعت کاملاً ضروری است.</div>',0,'Das Fahrzeug könnte schleudern und den Gegenverkehr gefährden',1,1,''),
(536,'1.4.40-109','Das Fahrzeug könnte einen Achs- oder Federbruch erleiden','The vehicle could suffer a broken axle or spring fracture','ممکن است خودرو دچار شکستگی محور یا فنر شود.','<div dir=\'rtl\'>حرکات شدید بالا و پایین خودرو در سرعت بالا و سطح جاده ناهموار، فشار زیادی به محور و فنر وارد می‌کند. در صورت استفاده بیش از حد، ممکن است اینها بشکنند. در اینجا نیز کاهش سرعت به جلوگیری از آسیب به خودرو کمک می‌کند.</div>',0,'Das Fahrzeug könnte einen Achs- oder Federbruch erleiden',1,1,''),
(537,'1.4.40-109','Die Ladung könnte beschädigt werden','The load could be damaged','ممکن است بار آسیب ببیند.','<div dir=\'rtl\'>حتی بار به خوبی مهار شده نیز ممکن است در اثر حرکات شدید بالا و پایین در خودرو به اطراف پرتاب شده و آسیب ببیند.</div>',0,'Die Ladung könnte beschädigt werden',1,1,''),
(538,'1.4.40-112','Vor Schleudergefahr bei verschmutzter Fahrbahn','Danger of skidding when the roadway is dirty','خطر لغزش در صورت کثیف بودن سطح جاده','<div dir=\'rtl\'>یک سطح جاده کثیف خطر لغزش را افزایش می‌دهد.</div>',0,'Vor Schleudergefahr bei verschmutzter Fahrbahn',1,1,''),
(539,'1.4.40-112','Vor Schleudergefahr bei nasser Fahrbahn','Danger of skidding when the roadway is wet','خطر لغزش در صورت خیس بودن سطح جاده','<div dir=\'rtl\'>بنابراین، سرعت و سبک رانندگی باید با وضعیت خطرناک تطبیق داده شود تا از لغزش جلوگیری شود.</div>',0,'Vor Schleudergefahr bei nasser Fahrbahn',1,1,''),
(540,'1.4.40-112','Vor alkoholisierten Autofahrern','Drivers under the influence of alcohol','در مورد رانندگان مست','<div dir=\'rtl\'>این تابلو به رانندگان مست اشاره نمی‌کند.</div>',0,'Vor alkoholisierten Autofahrern',1,0,''),
(541,'1.4.40-114','Geschwindigkeit verringern','Reduce your speed','سرعت را کاهش دهید','<div dir=\'rtl\'>جاده باریک شده ممکن است فقط فضای کافی برای عبور یک وسیله نقلیه را فراهم کند. بنابراین، توصیه می‌شود سرعت را کاهش داده و با آمادگی برای ترمز گرفتن به محل خطر نزدیک شوید.</div>',0,'Geschwindigkeit verringern',1,1,''),
(542,'1.4.40-114','Nicht mehr überholen','Refrain from overtaking','دیگر سبقت نگیرید','<div dir=\'rtl\'>با وجود این تابلوی راهنمایی و رانندگی نباید سبقت گرفت، زیرا جاده به طور قابل توجهی باریک می‌شود.</div>',0,'Nicht mehr überholen',1,1,''),
(543,'1.4.40-114','Vor Erreichen der Verengung immer anhalten','Always stop before the road narrows','همیشه قبل از رسیدن به محل باریک شدن توقف کنید','<div dir=\'rtl\'>لزومی ندارد که حتماً قبل از باریک شدن جاده توقف کنید. این کار باعث کندی بی‌مورد ترافیک می‌شود. با این حال، به مقررات ترافیکی در خود نقطه باریک شده توجه کنید.</div>',0,'Vor Erreichen der Verengung immer anhalten',1,0,''),
(544,'1.4.40-115','Mit einer verengten Fahrbahn in etwa 50 m Entfernung','The roadway narrowing approximately 50 m ahead','با یک مسیر باریک شده در فاصله تقریباً ۵۰ متری','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی به یک مسیر باریک شده در فاصله تقریباً ۵۰ متری اشاره دارد.</div>',0,'Mit einer verengten Fahrbahn in etwa 50 m Entfernung',1,1,''),
(545,'1.4.40-115','Mit einer verengten Fahrbahn von 50 m Länge','The roadway narrowing for 50 m','با یک مسیر باریک شده به طول ۵۰ متر','<div dir=\'rtl\'>تابلوی راهنمایی و رانندگی برای «مسیر باریک شده به طول ۵۰ متر» باید روی تابلوی فرعی دو فلش سیاه رنگ و رو به بالا داشته باشد.</div>',0,'Mit einer verengten Fahrbahn von 50 m Länge',1,0,''),
(546,'1.4.40-115','Mit einer Ausweichstelle in 50 m Entfernung','A road widening 50 m ahead','با یک محل انحراف (فرعی) در فاصله ۵۰ متری','<div dir=\'rtl\'>هیچ تابلوی راهنمایی و رانندگی رسمی برای یک محل انحراف (فرعی) وجود ندارد. فقط یک تابلوی راهنمایی و رانندگی برای یک توقفگاه اضطراری و خرابی خودرو وجود دارد.</div>',0,'Mit einer Ausweichstelle in 50 m Entfernung',1,0,''),
(547,'1.4.40-116','Mit Verkehr von Baustellenfahrzeugen','Traffic from road construction vehicles','با تردد وسایل نقلیه ساختمانی','<div dir=\'rtl\'>احتمال دارد که وسایل نقلیه ساختمانی در نزدیکی محل کارگاه ساختمانی حضور داشته باشند.</div>',0,'Mit Verkehr von Baustellenfahrzeugen',1,1,''),
(548,'1.4.40-116','Mit Arbeitern auf der Fahrbahn','Men at work on the roadway','با کارگران در سطح جاده','<div dir=\'rtl\'>در یک کارگاه ساختمانی می‌توان انتظار حضور کارگران ساختمانی را داشت. این کارگران ممکن است گاهی بسیار نزدیک به لبه جاده کار کنند. بنابراین، سرعت و سبک رانندگی باید با این وضعیت خطرناک تطبیق داده شود تا کارگران به خطر نیفتند.</div>',0,'Mit Arbeitern auf der Fahrbahn',1,1,''),
(549,'1.4.40-116','Mit Baumaterial auf der Fahrbahn','Construction materials on the roadway','با مصالح ساختمانی در سطح جاده','<div dir=\'rtl\'>این مصالح ممکن است از وسایل نقلیه ساختمانی سقوط کنند یا ناخواسته وارد سطح جاده شوند. در اینجا باید توجه بیشتری داشت.</div>',0,'Mit Baumaterial auf der Fahrbahn',1,1,''),
(550,'1.4.40-118','Mit einem Stau','Traffic congestion','با راهبندان','<div dir=\'rtl\'>این علامت خطر به یک نقطه احتمالی راهبندان اشاره دارد.</div>',0,'Mit einem Stau',1,1,''),
(551,'1.4.40-118','Mit plötzlichem Bremsen der Vorausfahrenden','The vehicles driving in front may suddenly brake','با ترمز ناگهانی خودروهای جلویی','<div dir=\'rtl\'>راننده خودروی جلویی ممکن است به دلیل ترافیک متوقف یا در حال ترمز، خود مجبور به ترمز ناگهانی شود، به خصوص اگر انتهای راهبندان در یک نقطه نامشخص یا در یک پیچ باشد. بنابراین، باید فاصله کافی حفظ شود و با دید باز رانندگی کرد.</div>',0,'Mit plötzlichem Bremsen der Vorausfahrenden',1,1,''),
(552,'1.4.40-118','Mit Erweiterung der Fahrbahn auf drei Fahrstreifen','The roadway widens into three lanes','با گسترش مسیر رانندگی به سه خط','<div dir=\'rtl\'>علامت راهنمایی و رانندگی که به گسترش مسیر رانندگی به سه خط اشاره دارد، آبی و مستطیل شکل است و سه فلش سفید در جهت حرکت را نشان می‌دهد.</div>',0,'Mit Erweiterung der Fahrbahn auf drei Fahrstreifen',1,0,''),
(553,'1.4.40-121','Auf eine Ampel','Traffic lights','به یک چراغ راهنمایی','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی به معنای «سیستم چراغ راهنمایی» است و به یک چراغ راهنمایی اشاره دارد.</div>',0,'Auf eine Ampel',1,1,''),
(554,'1.4.40-121','Auf eine Zollstelle','A customs post','به یک گمرک','<div dir=\'rtl\'>تابلوی راهنمایی و رانندگی برای گمرک، یک دایره با حاشیه قرمز و نوشته «Zoll/Douane» است.</div>',0,'Auf eine Zollstelle',1,0,''),
(555,'1.4.40-121','Auf einen Bahnübergang mit rotem Blinklicht','A level crossing with flashing red light','به یک گذرگاه ریلی با چراغ چشمک‌زن قرمز','<div dir=\'rtl\'>یک گذرگاه ریلی با تابلوی راهنمایی و رانندگی «صلیب آندریاس» همراه با چراغ چشمک‌زن مشخص می‌شود.</div>',0,'Auf einen Bahnübergang mit rotem Blinklicht',1,0,''),
(556,'1.4.40-127','Auf einen Bahnübergang in der nach rechts führenden Straße','A level crossing on the road turning right','به یک گذرگاه راه‌آهن در خیابانی که به سمت راست می‌رود','<div dir=\'rtl\'>علامت راهنمایی و رانندگی بالایی به یک گذرگاه راه‌آهن بدون مانع اشاره دارد. علامت تکمیلی \"در جهت نقطه خطر، به سمت راست\" نشان می‌دهد که گذرگاه راه‌آهن در خیابانی قرار دارد که به سمت راست می‌رود.</div>',0,'Auf einen Bahnübergang in der nach rechts führenden Straße',1,1,''),
(557,'1.4.40-127','Auf die Richtung, aus der ein Zug kommen kann','The direction from which a train could come','به جهتی که قطار ممکن است از آن بیاید','<div dir=\'rtl\'>هیچ علامت راهنمایی و رانندگی وجود ندارد که جهت حرکت یک وسیله نقلیه ریلی را نشان دهد. این کار منطقی هم نخواهد بود، زیرا ریل‌ها در هر دو جهت استفاده می‌شوند و در نتیجه جهت می‌تواند تغییر کند.</div>',0,'Auf die Richtung, aus der ein Zug kommen kann',1,0,''),
(558,'1.4.40-127','Auf eine Umleitung, die den Bahnübergang umgeht','A diversion avoiding the level crossing','به یک مسیر انحرافی که از گذرگاه راه‌آهن عبور نمی‌کند','<div dir=\'rtl\'>این علامت راهنمایی و رانندگی همچنین یک مسیر انحرافی را نشان نمی‌دهد که از گذرگاه راه‌آهن عبور نمی‌کند.</div>',0,'Auf eine Umleitung, die den Bahnübergang umgeht',1,0,''),
(559,'1.4.40-130','Auf einen Bahnübergang in etwa 160 m Entfernung','A level crossing approximately 160 m ahead','به یک گذرگاه راه‌آهن در فاصله تقریباً ۱۶۰ متری','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی یک نشانگر فاصله با دو نوار قرمز است. هر نوار نشان‌دهنده ۸۰ متر فاصله تا گذرگاه راه‌آهن است. در این حالت، فاصله ۱۶۰ متر است. اگر نوار از پایین سمت چپ به بالا سمت راست کشیده شده باشد، این نشانگر در سمت راست جاده قرار دارد و برعکس.</div>',0,'Auf einen Bahnübergang in etwa 160 m Entfernung',1,1,''),
(560,'1.4.40-130','Auf einen Bahnübergang in etwa 80 m Entfernung','A level crossing approximately 80 m ahead','به یک گذرگاه راه‌آهن در فاصله تقریباً ۸۰ متری','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی یک نشانگر فاصله با دو نوار قرمز است. هر نوار نشان‌دهنده ۸۰ متر فاصله تا گذرگاه راه‌آهن است. در این حالت، فاصله ۱۶۰ متر است. اگر نوار از پایین سمت چپ به بالا سمت راست کشیده شده باشد، این نشانگر در سمت راست جاده قرار دارد و برعکس.</div>',0,'Auf einen Bahnübergang in etwa 80 m Entfernung',1,0,''),
(561,'1.4.40-130','Auf einen Bahnübergang in etwa 240 m Entfernung','A level crossing approximately 240 m ahead','به یک گذرگاه راه‌آهن در فاصله تقریباً ۲۴۰ متری','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی یک نشانگر فاصله با دو نوار قرمز است. هر نوار نشان‌دهنده ۸۰ متر فاصله تا گذرگاه راه‌آهن است. در این حالت، فاصله ۱۶۰ متر است. اگر نوار از پایین سمت چپ به بالا سمت راست کشیده شده باشد، این نشانگر در سمت راست جاده قرار دارد و برعکس.</div>',0,'Auf einen Bahnübergang in etwa 240 m Entfernung',1,0,''),
(562,'1.4.40-131','Auf einen Bahnübergang in etwa 80 m Entfernung','A level crossing approximately 80 m ahead','به یک گذرگاه ریلی در فاصله تقریباً ۸۰ متری','<div dir=\'rtl\'>اگر گذرگاه ریلی در فاصله ۱۶۰ متری بود، نشانگر هشدار باید دو نوار قرمز می‌داشت. هر نوار نشان‌دهنده ۸۰ متر فاصله تا گذرگاه ریلی است. (۲ × ۸۰ متر = ۱۶۰ متر)</div>',0,'Auf einen Bahnübergang in etwa 80 m Entfernung',1,1,''),
(563,'1.4.40-131','Auf einen Bahnübergang in etwa 160 m Entfernung','A level crossing approximately 160 m ahead','به یک گذرگاه ریلی در فاصله تقریباً ۱۶۰ متری','<div dir=\'rtl\'>اگر گذرگاه ریلی در فاصله ۱۶۰ متری بود، نشانگر هشدار باید دو نوار قرمز می‌داشت. هر نوار نشان‌دهنده ۸۰ متر فاصله تا گذرگاه ریلی است. (۲ × ۸۰ متر = ۱۶۰ متر)</div>',0,'Auf einen Bahnübergang in etwa 160 m Entfernung',1,0,''),
(564,'1.4.40-131','Auf einen Bahnübergang in etwa 240 m Entfernung','A level crossing approximately 240 m ahead','به یک گذرگاه ریلی در فاصله تقریباً ۲۴۰ متری','<div dir=\'rtl\'>اگر گذرگاه ریلی در فاصله ۱۶۰ متری بود، نشانگر هشدار باید دو نوار قرمز می‌داشت. هر نوار نشان‌دهنده ۸۰ متر فاصله تا گذرگاه ریلی است. (۲ × ۸۰ متر = ۱۶۰ متر)</div>',0,'Auf einen Bahnübergang in etwa 240 m Entfernung',1,0,''),
(565,'1.4.41-001','Wenn ein Bahnbediensteter eine weiß-rot-weiße Fahne schwenkt','When a railway employee is waving a white-red-white flag','اگر یک کارمند راه‌آهن پرچم سفید-قرمز-سفید را تکان دهد','<div dir=\'rtl\'>اگر یک کارمند راه‌آهن پرچم سفید-قرمز-سفید را تکان دهد، به این معنی است که به زودی یک وسیله نقلیه ریلی از گذرگاه عبور خواهد کرد. بنابراین، در این وضعیت باید قبل از گذرگاه ریلی توقف کرد.</div>',0,'Wenn ein Bahnbediensteter eine weiß-rot-weiße Fahne schwenkt',1,1,''),
(566,'1.4.41-001','Wenn Sie den Übergang nicht überqueren können, ohne auf ihm anhalten zu müssen','When the level crossing cannot be crossed without having to stop on it','اگر نمی‌توانید از گذرگاه عبور کنید بدون اینکه مجبور شوید روی آن توقف کنید','<div dir=\'rtl\'>اگر پشت گذرگاه ریلی ترافیک متوقف شده است، حتماً باید قبل از آن منتظر بمانید تا بتوانید بدون خطر از آن عبور کنید. قطارها با سرعت بالا حرکت می‌کنند و به دلیل وزن خود، مسافت ترمز طولانی دارند. یک وسیله نقلیه که روی ریل قرار دارد می‌تواند باعث یک برخورد جدی شود.</div>',0,'Wenn Sie den Übergang nicht überqueren können, ohne auf ihm anhalten zu müssen',1,1,''),
(567,'1.4.41-001','Wenn sich ein Schienenfahrzeug nähert','When a rail vehicle is approaching','اگر یک وسیله نقلیه ریلی نزدیک می‌شود','<div dir=\'rtl\'>تخمین فاصله و سرعت وسیله نقلیه ریلی بسیار دشوار است. بنابراین، حتماً باید قبل از گذرگاه توقف کنید تا از خطر یک برخورد جدی جلوگیری شود.</div>',0,'Wenn sich ein Schienenfahrzeug nähert',1,1,''),
(568,'1.4.41-004','Sie müssen die Fahrtrichtungsänderung nach rechts anzeigen','You must indicate right','شما باید تغییر جهت حرکت به سمت راست را نشان دهید (راهنما بزنید).','<div dir=\'rtl\'>اگر تابلوی دستوری «فقط گردش به راست» در کنار جاده قرار دارد، فقط باید به سمت راست ادامه مسیر دهید. شما باید تغییر جهت حرکت را نشان دهید (راهنما بزنید).</div>',0,'Sie müssen die Fahrtrichtungsänderung nach rechts anzeigen',1,1,''),
(569,'1.4.41-004','Sie dürfen nur nach rechts weiterfahren','You may only proceed to the right','شما فقط مجاز به ادامه حرکت به سمت راست هستید.','<div dir=\'rtl\'>با دیدن این تابلوی راهنمایی و رانندگی، شما باید به سمت راست ادامه مسیر دهید.</div>',0,'Sie dürfen nur nach rechts weiterfahren',1,1,''),
(570,'1.4.41-004','Sie dürfen nicht nach rechts abbiegen','You may not turn right','شما مجاز به گردش به راست نیستید.','<div dir=\'rtl\'>در اینجا باید به سمت راست ادامه مسیر داده یا گردش کنید.</div>',0,'Sie dürfen nicht nach rechts abbiegen',1,0,''),
(571,'1.4.41-005','Sie müssen die Fahrtrichtungsänderung nach links anzeigen','','شما باید تغییر جهت حرکت به سمت چپ را نشان دهید (راهنما بزنید).','<div dir=\'rtl\'>تابلوی نشان داده شده در اینجا حکم می‌کند که باید قبل از آن در جهت فلش بپیچید. شما باید تغییر جهت حرکت به سمت چپ را نشان دهید (راهنما بزنید).</div>',0,'Sie müssen die Fahrtrichtungsänderung nach links anzeigen',1,1,''),
(572,'1.4.41-005','Sie dürfen nur nach links weiterfahren','','شما فقط مجاز به ادامه حرکت به سمت چپ هستید.','<div dir=\'rtl\'>اگر این تابلوی دستوری وجود داشته باشد، اجازه ادامه حرکت یا پیچیدن به هیچ جهت دیگری را ندارید.</div>',0,'Sie dürfen nur nach links weiterfahren',1,1,''),
(573,'1.4.41-005','Sie dürfen nicht nach links weiterfahren','','شما مجاز به ادامه حرکت به سمت چپ نیستید.','<div dir=\'rtl\'>اگر این تابلوی دستوری وجود داشته باشد، اجازه ادامه حرکت یا پیچیدن به هیچ جهت دیگری را ندارید.</div>',0,'Sie dürfen nicht nach links weiterfahren',1,0,''),
(574,'1.4.41-006','Geradeaus','Straight ahead','مستقیم','<div dir=\'rtl\'>شما مجاز به رانندگی مستقیم هستید.</div>',0,'Geradeaus',1,1,''),
(575,'1.4.41-006','Nach rechts','To the right','به راست','<div dir=\'rtl\'>زیرا فلش هم به سمت مستقیم و هم به سمت راست اشاره می‌کند، شما مجاز به رانندگی مستقیم یا گردش به راست هستید.</div>',0,'Nach rechts',1,1,''),
(576,'1.4.41-006','Nach links','To the left','به چپ','<div dir=\'rtl\'>روی تابلوی راهنمایی و رانندگی هیچ فلش به چپ نشان داده نشده است. بنابراین، مجاز به ادامه رانندگی به چپ نیستید.</div>',0,'Nach links',1,0,''),
(577,'1.4.41-007','Sie müssen an Verkehrsinseln rechts vorbeifahren','You must pass on the right of traffic islands','شما باید از سمت راست جزایر ترافیکی عبور کنید.','<div dir=\'rtl\'>پیکانی که از بالا سمت چپ به پایین سمت راست امتداد دارد، نشان می‌دهد که باید از سمت راست عبور کرد. اگر پیکان به سمت پایین چپ اشاره کند، باید از سمت چپ عبور کرد.</div>',0,'Sie müssen an Verkehrsinseln rechts vorbeifahren',1,1,''),
(578,'1.4.41-007','Sie sind verpflichtet, nach rechts abzubiegen','You are obliged to turn right','شما موظف هستید به راست بپیچید.','<div dir=\'rtl\'>باید از سمت راست عبور کرد. تابلوی دستوری با یک پیکان سفید افقی به سمت راست بر روی زمینه آبی، نشان‌دهنده پیچیدن به راست است.</div>',0,'Sie sind verpflichtet, nach rechts abzubiegen',1,0,''),
(579,'1.4.41-007','Sie dürfen vor diesem Zeichen nicht nach links abbiegen','You may not turn left in front of this sign','شما مجاز نیستید قبل از این تابلو به چپ بپیچید.','<div dir=\'rtl\'>پیچیدن به چپ (قبل از جزیره ترافیکی یا مانع) ممکن است در اینجا امکان‌پذیر باشد. این تابلو فقط شما را ملزم می‌کند که از سمت راست مانع یا جزیره ترافیکی عبور کنید.</div>',0,'Sie dürfen vor diesem Zeichen nicht nach links abbiegen',1,0,''),
(580,'1.4.41-008','Geschwindigkeit vermindern und bremsbereit bleiben','Reduce your speed and be ready to brake','سرعت را کاهش دهید و آماده ترمز گرفتن بمانید','<div dir=\'rtl\'>کودکان در ایستگاه اتوبوس احتمالاً منتظر اتوبوس هستند. رفتار کودکان قابل پیش‌بینی نیست. انتظار می‌رود که کودکان نسبت به ترافیک بی‌توجه باشند، زیرا آنها درک متفاوتی از خطر نسبت به بزرگسالان دارند. یک کودک ممکن است کودک دیگری را بدون فکر به داخل خیابان هل دهد، یا خودش به داخل آن بدود. در اینجا باید با هوشیاری بسیار بالا و آمادگی برای ترمز رانندگی کرد تا کسی به خطر نیفتد.</div>',0,'Geschwindigkeit vermindern und bremsbereit bleiben',1,1,''),
(581,'1.4.41-008','Eine Verminderung der Geschwindigkeit ist nur erforderlich, wenn dort ein Schulbus hält','A reduction in speed is only necessary when a school bus is stopping there','کاهش سرعت تنها زمانی لازم است که یک اتوبوس مدرسه در آنجا توقف کرده باشد','<div dir=\'rtl\'>به محض اینکه کودکان در دیدرس باشند، توجه بیشتری لازم است. آنها اغلب به صورت خودجوش و بدون فکر عمل می‌کنند. بنابراین، صرف نظر از اینکه یک اتوبوس مدرسه در آنجا ایستاده باشد یا نه، این قانون برقرار است: وقتی کودکان در دیدرس هستند - پا را از روی گاز بردارید.</div>',0,'Eine Verminderung der Geschwindigkeit ist nur erforderlich, wenn dort ein Schulbus hält',1,0,''),
(582,'1.4.41-008','Die Geschwindigkeit muss nicht vermindert werden, wenn ein Bus in einer Haltebucht hält','Speed must not be reduced when a bus stops at a stopping bay','سرعت نیازی به کاهش ندارد، اگر یک اتوبوس در یک توقفگاه مخصوص توقف کرده باشد','<div dir=\'rtl\'>شما باید سرعت را کاهش دهید و آماده ترمز باشید، به محض اینکه کودکان در دیدرس قرار گیرند.</div>',0,'Die Geschwindigkeit muss nicht vermindert werden, wenn ein Bus in einer Haltebucht hält',1,0,''),
(583,'1.4.41-010','Diese Fußgängerzone dürfen Sie mit einem Kraftfahrzeug nicht befahren','','شما مجاز به رانندگی با وسیله نقلیه موتوری در این منطقه عابر پیاده نیستید.','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی به منطقه‌ای اشاره دارد که منحصراً برای عابران پیاده در نظر گرفته شده است. بنابراین، نمی‌توان با وسیله نقلیه وارد آن شد.</div>',0,'Diese Fußgängerzone dürfen Sie mit einem Kraftfahrzeug nicht befahren',1,1,''),
(584,'1.4.41-010','In dieser Fußgängerzone dürfen Sie mit einem Kraftfahrzeug mit Schrittgeschwindigkeit fahren','','شما مجاز هستید با وسیله نقلیه موتوری و با سرعت پیاده‌روی در این منطقه عابر پیاده رانندگی کنید.','<div dir=\'rtl\'>رانندگی با وسیله نقلیه موتوری در این منطقه ممنوع است.</div>',0,'In dieser Fußgängerzone dürfen Sie mit einem Kraftfahrzeug mit Schrittgeschwindigkeit fahren',1,0,''),
(585,'1.4.41-010','Als Anlieger dürfen Sie in dieser Fußgängerzone mit Kraftfahrzeugen fahren','','به عنوان ساکن محلی، شما مجاز هستید با وسایل نقلیه موتوری در این منطقه عابر پیاده رانندگی کنید.','<div dir=\'rtl\'>ساکنان محلی تنها در صورتی مجاز به رانندگی در منطقه عابر پیاده هستند که با تابلوهای فرعی مربوطه اجازه داده شده باشد. از آنجایی که این تابلوها در اینجا وجود ندارند، در این مورد ممنوع است.</div>',0,'Als Anlieger dürfen Sie in dieser Fußgängerzone mit Kraftfahrzeugen fahren',1,0,''),
(586,'1.4.41-012','Mit Mofas','Motorized bicycle','با موتور گازی‌ها (موفا)','<div dir=\'rtl\'>نماد نشان‌داده‌شده در تابلوی ممنوعیت، عبور و مرور را منحصراً برای موتور گازی‌ها (موفا) ممنوع می‌کند. بنابراین، این ممنوعیت فقط مربوط به این وسایل نقلیه است و سایر وسایل نقلیه می‌توانند از اینجا عبور کنند.</div>',0,'Mit Mofas',1,1,''),
(587,'1.4.41-012','Mit Kleinkrafträdern','Small motorcycles','با موتورسیکلت‌های کوچک','<div dir=\'rtl\'>موتورسیکلت‌های سبک (Leichtkrafträder) به موتورسیکلت‌های کوچکی گفته می‌شود که حجم موتور آن‌ها بیش از ۵۰ سانتی‌متر مکعب و حداکثر ۱۲۵ سانتی‌متر مکعب است. اما این تابلوی راهنمایی و رانندگی عبور موتور گازی‌ها (موفا) را ممنوع می‌کند.</div>',0,'Mit Kleinkrafträdern',1,0,''),
(588,'1.4.41-012','Mit Leichtkrafträdern','Light motorcycles','با موتورسیکلت‌های سبک','<div dir=\'rtl\'>موتورسیکلت‌های سبک (Leichtkrafträder) به موتورسیکلت‌های کوچکی گفته می‌شود که حجم موتور آن‌ها بیش از ۵۰ سانتی‌متر مکعب و حداکثر ۱۲۵ سانتی‌متر مکعب است. اما این تابلوی راهنمایی و رانندگی عبور موتور گازی‌ها (موفا) را ممنوع می‌کند.</div>',0,'Mit Leichtkrafträdern',1,0,''),
(589,'1.4.41-013','Aus dieser Straße können Fahrzeuge kommen','','ممکن است وسایل نقلیه از این خیابان بیایند.','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی اغلب در انتهای دیگر یک خیابان یک‌طرفه قرار دارد.</div>',0,'Aus dieser Straße können Fahrzeuge kommen',1,1,''),
(590,'1.4.41-013','Sie dürfen nicht in diese Straße einfahren','','شما مجاز به ورود به این خیابان نیستید.','<div dir=\'rtl\'>ورود به این خیابان می‌تواند برای تمامی شرکت‌کنندگان در ترافیک بسیار خطرناک باشد، زیرا این تابلو اغلب نشان‌دهنده خیابان‌های یک‌طرفه از سمت دیگر است و می‌تواند باعث تصادف شود.</div>',0,'Sie dürfen nicht in diese Straße einfahren',1,1,''),
(591,'1.4.41-013','Sie dürfen in diese Straße einfahren','','شما مجاز به ورود به این خیابان هستید.','<div dir=\'rtl\'>ورود به این خیابان می‌تواند برای تمامی شرکت‌کنندگان در ترافیک بسیار خطرناک باشد، زیرا این تابلو اغلب نشان‌دهنده خیابان‌های یک‌طرفه از سمت دیگر است و می‌تواند باعث تصادف شود.</div>',0,'Sie dürfen in diese Straße einfahren',1,0,''),
(592,'1.4.41-015','Das Halten zum Be- oder Entladen sowie zum Ein- oder Aussteigen','Stopping for loading or unloading, for alighting or boarding vehicles','توقف برای بارگیری یا تخلیه بار و همچنین برای سوار یا پیاده شدن','<div dir=\'rtl\'>اما پارک کردن در اینجا ممنوع است.</div>',0,'Das Halten zum Be- oder Entladen sowie zum Ein- oder Aussteigen',1,1,''),
(593,'1.4.41-015','Das Halten bis zu 3 Minuten','Waiting up to 3 minutes','توقف تا ۳ دقیقه','<div dir=\'rtl\'>کسی که بیش از سه دقیقه توقف کند، پارک کرده است. این کار در این مورد مجاز نیست.</div>',0,'Das Halten bis zu 3 Minuten',1,1,''),
(594,'1.4.41-015','Das Parken, wenn eine Parkscheibe benutzt wird','Parking, provided a parking disc is used','پارک کردن، در صورتی که از دیسک پارک استفاده شود','<div dir=\'rtl\'>پارک کردن در اینجا به طور کلی مجاز نیست. این موضوع مستقل از این است که آیا از دیسک پارک استفاده می‌شود یا خیر.</div>',0,'Das Parken, wenn eine Parkscheibe benutzt wird',1,0,''),
(595,'1.4.41-016','Schwerbehinderte mit entsprechend nummeriertem Parkausweis dürfen hier parken','','افراد دارای معلولیت شدید با کارت پارک شماره‌دار مربوطه مجاز به پارک در اینجا هستند.','<div dir=\'rtl\'>با توجه به تابلوی تکمیلی که زیر تابلوی راهنمایی و رانندگی «ممنوعیت توقف محدود» نصب شده است، افراد دارای معلولیت با کارت پارک از این قانون مستثنی هستند. بنابراین، آنها مجازند برای مدت نامحدود در اینجا پارک کنند.</div>',0,'Schwerbehinderte mit entsprechend nummeriertem Parkausweis dürfen hier parken',1,1,''),
(596,'1.4.41-016','Das Halten zum Ein- oder Aussteigen für jeden','','توقف برای سوار یا پیاده کردن مسافر برای همه','<div dir=\'rtl\'>مانند هر ممنوعیت توقف محدودی که فقط پارک کردن را ممنوع می‌کند، در اینجا توقف برای سوار یا پیاده کردن مسافر مجاز است.</div>',0,'Das Halten zum Ein- oder Aussteigen für jeden',1,1,''),
(597,'1.4.41-016','Mit einem Parkschein aus einem Parkscheinautomaten darf hier jeder unbegrenzt parken','','با یک بلیط پارک از دستگاه پارکومتر، هر کسی مجاز است به صورت نامحدود در اینجا پارک کند.','<div dir=\'rtl\'>کارت پارکی که در تابلوی تکمیلی ذکر شده است، یک کارت شناسایی ویژه و شماره‌دار است که توسط اداره راهنمایی و رانندگی مربوطه صادر شده است. این کارت هیچ ارتباطی با یک بلیط پارک «عادی» ندارد.</div>',0,'Mit einem Parkschein aus einem Parkscheinautomaten darf hier jeder unbegrenzt parken',1,0,''),
(598,'1.4.41-102','Sie müssen dem Gegenverkehr Vorrang gewähren','','شما باید به ترافیک مقابل حق تقدم بدهید','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی به این معناست که من باید به ترافیک مقابل حق تقدم بدهم و خودم فقط پس از آن مجاز به عبور از محل هستم. پیکان قرمز همیشه به کسی اشاره دارد که باید منتظر بماند.</div>',0,'Sie müssen dem Gegenverkehr Vorrang gewähren',1,1,''),
(599,'1.4.41-102','Sie dürfen nicht abbiegen','','شما مجاز به گردش نیستید','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی گردش را ممنوع نمی‌کند. فقط از شما می‌خواهد که به ترافیک مقابل حق تقدم بدهید.</div>',0,'Sie dürfen nicht abbiegen',1,0,''),
(600,'1.4.41-102','Sie haben Vorrang vor dem Gegenverkehr','','شما نسبت به ترافیک مقابل حق تقدم دارید','<div dir=\'rtl\'>تابلوی «حق تقدم نسبت به ترافیک مقابل» یک پیکان قرمز و سفید در جهت مخالف روی یک مربع آبی است.</div>',0,'Sie haben Vorrang vor dem Gegenverkehr',1,0,''),
(601,'1.4.41-106','Nach links','To the left','به چپ','<div dir=\'rtl\'>شما مجازید در اینجا به چپ بپیچید.</div>',0,'Nach links',1,1,''),
(602,'1.4.41-106','Nach rechts','To the right','به راست','<div dir=\'rtl\'>شما مجازید در اینجا به راست بپیچید.</div>',0,'Nach rechts',1,1,''),
(603,'1.4.41-106','Geradeaus','Straight ahead','مستقیم','<div dir=\'rtl\'>جهت‌های رانندگی مجاز چپ و راست هستند. در اینجا مجاز به رانندگی مستقیم نیستید.</div>',0,'Geradeaus',1,0,''),
(604,'1.4.41-109','Ja, weil Kinder häufig über die Straße rennen, um den Bus noch zu erreichen','Yes, because children frequently run across the road to catch the bus','بله، زیرا کودکان اغلب برای رسیدن به اتوبوس، با عجله از خیابان عبور می‌کنند.','<div dir=\'rtl\'>کودکان در ترافیک به ویژه در معرض خطر هستند، زیرا آنها اغلب موقعیت‌های ترافیکی را اشتباه ارزیابی می‌کنند و هنوز درک کاملی از خطر ندارند. این درک تنها در طول رشد ایجاد می‌شود. بنابراین، ممکن است برای رسیدن به اتوبوس، بدون نگاه کردن به اطراف، ناگهان به خیابان بدوند. در اینجا، رانندگی با احتیاط و آهسته، بالاترین اولویت است تا کسی به خطر نیفتد!</div>',0,'Ja, weil Kinder häufig über die Straße rennen, um den Bus noch zu erreichen',1,1,''),
(605,'1.4.41-109','Ja, weil Kinder nicht immer auf kürzestem Weg die Fahrbahn überqueren','Yes, because children do not always take the shortest route to cross the roadway','بله، زیرا کودکان همیشه از کوتاه‌ترین مسیر از عرض خیابان عبور نمی‌کنند.','<div dir=\'rtl\'>اغلب کودکان بی‌صبر هستند و محیط اطراف خود را فراموش می‌کنند. ممکن است بدون احتیاط از خیابان عبور کنند، یا بدون دلیل مشخص از پیاده‌رو به خیابان بیایند. بنابراین، در این نقطه باید با دقت و آهسته رانندگی کنید و برای ترمز ناگهانی آماده باشید.</div>',0,'Ja, weil Kinder nicht immer auf kürzestem Weg die Fahrbahn überqueren',1,1,''),
(606,'1.4.41-109','Nein, weil an jeder Schulbushaltestelle Schülerlotsen den Verkehr sichern','No, because school crossing patrols regulate traffic at every school bus stop','خیر، زیرا در هر ایستگاه اتوبوس مدرسه، راهنمایان دانش‌آموزان (شولرلوتسن) ترافیک را ایمن می‌کنند.','<div dir=\'rtl\'>هر ایستگاه اتوبوس مدرسه توسط راهنمای دانش‌آموزان (شولرلوتسن) ایمن نمی‌شود. حتی اگر ایستگاه راهنمای دانش‌آموزان داشته باشد، باز هم باید بسیار محتاط باشید. حتی با وجود راهنمایان دانش‌آموزان، کودکان همیشه مطابق با وضعیت ترافیک رفتار نمی‌کنند.</div>',0,'Nein, weil an jeder Schulbushaltestelle Schülerlotsen den Verkehr sichern',1,0,''),
(607,'1.4.41-114','Wer Waren liefern muss','Persons delivering goods','کسی که باید کالا تحویل دهد','<div dir=\'rtl\'>خیابانی که اینگونه علامت‌گذاری شده است، فقط می‌تواند توسط وسایل نقلیه تحویل کالا استفاده شود، نه توسط سایر وسایل نقلیه. علاوه بر این، عابران پیاده نیز مجاز به استفاده از این مسیر هستند.</div>',0,'Wer Waren liefern muss',1,1,''),
(608,'1.4.41-114','Wer etwas einkaufen will','Shoppers','کسی که می‌خواهد چیزی بخرد','<div dir=\'rtl\'>خرید در یک مغازه فعالیت تحویل کالا محسوب نمی‌شود. پیاده می‌توان اینجا خرید کرد، اما خودرو برای این منظور نباید استفاده شود.</div>',0,'Wer etwas einkaufen will',1,0,''),
(609,'1.4.41-114','Wer jemanden besuchen will','Visitors','کسی که می‌خواهد به ملاقات کسی برود','<div dir=\'rtl\'>پیاده می‌توان از این مسیر برای ملاقات کسی استفاده کرد. اما با وسیله نقلیه مجاز به عبور از اینجا نیستید.</div>',0,'Wer jemanden besuchen will',1,0,''),
(610,'1.4.41-115','Linienbusse','Regular buses','اتوبوس‌های خط واحد','<div dir=\'rtl\'>فقط اتوبوس‌ها مجازند از این خط ویژه استفاده کنند.</div>',0,'Linienbusse',1,1,''),
(611,'1.4.41-115','Lkws','Trucks','کامیون‌ها','<div dir=\'rtl\'>استفاده از این خط ویژه برای کامیون‌ها مجاز نیست.</div>',0,'Lkws',1,0,''),
(612,'1.4.41-115','Pkws','Cars','خودروهای سواری','<div dir=\'rtl\'>خودروهای سواری مجاز به استفاده از این خط ویژه نیستند.</div>',0,'Pkws',1,0,''),
(613,'1.4.41-116','Bewohner','Residents','ساکنان','<div dir=\'rtl\'>ساکنان جزو افراد مرتبط با منطقه هستند و بنابراین مجاز به عبور از این تابلو می‌باشند.</div>',0,'Bewohner',1,1,''),
(614,'1.4.41-116','Besucher der Bewohner','People visiting residents','بازدیدکنندگان ساکنان','<div dir=\'rtl\'>ساکنان جزو افراد مرتبط با منطقه هستند و بنابراین مجاز به عبور از این تابلو می‌باشند.</div>',0,'Besucher der Bewohner',1,1,''),
(615,'1.4.41-116','Fahrzeuge im Durchgangsverkehr','Through-traffic','وسایل نقلیه عبوری','<div dir=\'rtl\'>عبور این وسایل نقلیه ممنوع است.</div>',0,'Fahrzeuge im Durchgangsverkehr',1,0,''),
(616,'1.4.41-118','Lkws','Trucks','کامیون‌ها','<div dir=\'rtl\'>این تابلو راهنمایی و رانندگی، تردد در جاده پشت آن را برای تمامی وسایل نقلیه موتوری چندمسیره ممنوع می‌کند. این تابلو نه تنها به خودروهای سواری (همانطور که روی تابلو نشان داده شده است) بلکه به سایر وسایل نقلیه مانند کامیون‌ها یا اتوبوس‌ها نیز مربوط می‌شود.</div>',0,'Lkws',1,1,''),
(617,'1.4.41-118','Pkws','Cars','خودروهای سواری','<div dir=\'rtl\'>خودروی سواری یک وسیله نقلیه موتوری چندمسیره است و بنابراین مجاز به عبور از جاده‌ای با این تابلو نیست.</div>',0,'Pkws',1,1,''),
(618,'1.4.41-118','Motorräder','Motorcycles','موتورسیکلت‌ها','<div dir=\'rtl\'>موتورسیکلت‌ها جزو وسایل نقلیه موتوری چندمسیره محسوب نمی‌شوند و بنابراین مجاز به تردد در جاده‌ای با این تابلو هستند.</div>',0,'Motorräder',1,0,''),
(619,'1.4.41-119','Fahrräder','Bicycles','دوچرخه‌ها','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی به معنای «ممنوعیت برای دوچرخه‌ها» است. این تابلو متعلق به گروه ممنوعیت‌های ترافیکی است.</div>',0,'Fahrräder',1,1,''),
(620,'1.4.41-119','Motorräder','Motorcycles','موتورسیکلت‌ها','<div dir=\'rtl\'>اگر این ممنوعیت ترافیکی برای موتورسیکلت‌ها اعمال می‌شد، باید نماد یک موتورسیکلت می‌بود.</div>',0,'Motorräder',1,0,''),
(621,'1.4.41-119','Pkws','Cars','خودروهای سواری','<div dir=\'rtl\'>اگر این ممنوعیت برای خودروهای سواری اعمال می‌شد، آنگاه نماد روی تابلو باید یک خودروی سواری را نشان می‌داد. این یک ممنوعیت ترافیکی برای وسایل نقلیه موتوری چندمسیره می‌بود و بنابراین کامیون‌ها و اتوبوس‌ها را نیز شامل می‌شد.</div>',0,'Pkws',1,0,''),
(622,'1.4.41-120','Motorräder','Motorcycles','موتورسیکلت‌ها','<div dir=\'rtl\'>انواع موتورسیکلت‌ها، حتی با سایدکار، موتورسیکلت‌های سبک و موپدها، مجاز به رانندگی در اینجا نیستند. با این حال، امکان هل دادن موتورسیکلت وجود دارد.</div>',0,'Motorräder',1,1,''),
(623,'1.4.41-120','Pkws','Cars','خودروهای سواری','<div dir=\'rtl\'>نماد ممنوعیت تردد برای خودروهای سواری، یک خودروی نمایش داده شده از جلو خواهد بود.</div>',0,'Pkws',1,0,''),
(624,'1.4.41-120','Lkws','Trucks','کامیون‌ها','<div dir=\'rtl\'>نماد ممنوعیت تردد برای کامیون‌ها، یک کامیون نمایش داده شده از کنار خواهد بود.</div>',0,'Lkws',1,0,''),
(625,'1.4.41-121','Auf das Verbot der Einfahrt in 100 m Entfernung','No entry 100 m ahead','به ممنوعیت ورود در فاصله ۱۰۰ متری','<div dir=\'rtl\'>این علامت راهنمایی و رانندگی به ممنوعیت ورود در فاصله ۱۰۰ متری اشاره دارد.</div>',0,'Auf das Verbot der Einfahrt in 100 m Entfernung',1,1,''),
(626,'1.4.41-121','Auf eine Einbahnstraße von 100 m Länge','A one-way street 100 m long','به یک خیابان یک‌طرفه به طول ۱۰۰ متر','<div dir=\'rtl\'>این علامت راهنمایی و رانندگی اغلب در انتهای یک خیابان یک‌طرفه قرار می‌گیرد تا از ورود اشتباه وسایل نقلیه به خیابان جلوگیری کند. علامت راهنمایی و رانندگی برای خیابان یک‌طرفه یک فلش سفید روی زمینه آبی است که روی آن نوشته شده است \"Einbahnstraße\" (خیابان یک‌طرفه).</div>',0,'Auf eine Einbahnstraße von 100 m Länge',1,0,''),
(627,'1.4.41-121','Auf eine Zollstelle in 100 m Entfernung','A customs post 100 m ahead','به یک گمرک در فاصله ۱۰۰ متری','<div dir=\'rtl\'>علامت راهنمایی و رانندگی برای گمرک یک دایره با حاشیه قرمز و نوشته Zoll/Douane (گمرک) است.</div>',0,'Auf eine Zollstelle in 100 m Entfernung',1,0,''),
(628,'1.4.41-124','- zulässigen Höchstgeschwindigkeit von 30 km/h','- a permitted maximum speed of 30 km/h','- حداکثر سرعت مجاز ۳۰ کیلومتر در ساعت','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی نشان‌دهنده آغاز منطقه‌ای با حداکثر سرعت مجاز ۳۰ کیلومتر در ساعت (منطقه سرعت ۳۰) است.</div>',0,'- zulässigen Höchstgeschwindigkeit von 30 km/h',1,1,''),
(629,'1.4.41-124','- vorgeschriebenen Mindestgeschwindigkeit von 30 km/h','- an obligatory minimum speed of 30 km/h','- حداقل سرعت اجباری ۳۰ کیلومتر در ساعت','<div dir=\'rtl\'>تابلوی راهنمایی و رانندگی «حداقل سرعت اجباری ۳۰ کیلومتر در ساعت» به صورت عدد ۳۰ با حروف سفید روی دایره آبی رنگ خواهد بود.</div>',0,'- vorgeschriebenen Mindestgeschwindigkeit von 30 km/h',1,0,''),
(630,'1.4.41-124','- Richtgeschwindigkeit von 30 km/h','- a recommended speed of 30 km/h','- سرعت توصیه شده ۳۰ کیلومتر در ساعت','<div dir=\'rtl\'>تابلوی راهنمایی و رانندگی برای «سرعت توصیه شده ۳۰ کیلومتر در ساعت» به صورت عدد ۳۰ با حروف سفید روی مربع آبی رنگ خواهد بود.</div>',0,'- Richtgeschwindigkeit von 30 km/h',1,0,''),
(631,'1.4.41-125','Auf regen Fußgängerverkehr besonders achten','You must specifically watch out for busy pedestrian traffic','به ترافیک زیاد عابران پیاده توجه ویژه داشته باشید','<div dir=\'rtl\'>در مناطق تجاری، انتظار می‌رود که عابران پیاده بدون توجه خاص به ترافیک، از یک سمت خیابان به سمت دیگر عبور کنند. بنابراین، در اینجا باید بسیار هوشیار باشید.</div>',0,'Auf regen Fußgängerverkehr besonders achten',1,1,''),
(632,'1.4.41-125','Höchstparkdauer beachten','You must pay attention to the allowed maximum parking time','به حداکثر زمان پارک توجه کنید','<div dir=\'rtl\'>تابلوی اضافی حداکثر زمان پارک ۲ ساعته را با استفاده از دیسک پارک (پارک‌دیسک) مجاز می‌داند. این زمان نباید تجاوز شود.</div>',0,'Höchstparkdauer beachten',1,1,''),
(633,'1.4.41-125','Mindestgeschwindigkeit von 20 km/h einhalten','You must observe a minimum speed of 20 km/h','حداقل سرعت ۲۰ کیلومتر بر ساعت را رعایت کنید','<div dir=\'rtl\'>بالاترین تابلوی راهنمایی و رانندگی به معنای «حداکثر سرعت مجاز در این منطقه ۲۰ کیلومتر بر ساعت» است. تابلوی راهنمایی و رانندگی برای حداقل سرعت، یک عدد سفید روی دایره آبی است.</div>',0,'Mindestgeschwindigkeit von 20 km/h einhalten',1,0,''),
(634,'1.4.41-126','- zulässigen Höchstgeschwindigkeit von 30 km/h','- a permitted maximum speed of 30 km/h','- حداکثر سرعت مجاز ۳۰ کیلومتر در ساعت','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی نشان‌دهنده پایان منطقه‌ای است که حداکثر سرعت مجاز در آن به ۳۰ کیلومتر در ساعت محدود شده است.</div>',0,'- zulässigen Höchstgeschwindigkeit von 30 km/h',1,1,''),
(635,'1.4.41-126','- vorgeschriebenen Mindestgeschwindigkeit von 30 km/h','- an obligatory minimum speed of 30 km/h','- حداقل سرعت اجباری ۳۰ کیلومتر در ساعت','<div dir=\'rtl\'>تابلوی راهنمایی و رانندگی برای حداقل سرعت اجباری ۳۰ کیلومتر در ساعت، یک عدد ۳۰ سفید روی پس‌زمینه آبی و گرد خواهد بود.</div>',0,'- vorgeschriebenen Mindestgeschwindigkeit von 30 km/h',1,0,''),
(636,'1.4.41-126','- Richtgeschwindigkeit von 30 km/h','- a recommended speed of 30 km/h','- سرعت توصیه شده ۳۰ کیلومتر در ساعت','<div dir=\'rtl\'>تابلوی راهنمایی و رانندگی برای سرعت توصیه شده ۳۰ کیلومتر در ساعت، یک عدد ۳۰ سفید روی یک تابلوی آبی و مربع خواهد بود.</div>',0,'- Richtgeschwindigkeit von 30 km/h',1,0,''),
(637,'1.4.41-127','Ja, wenn die Fahrbahn trocken ist','','بله، اگر سطح جاده خشک باشد','<div dir=\'rtl\'>تابلوی فرعی حداکثر سرعت مجاز را در هنگام خیس بودن جاده به ۶۰ کیلومتر بر ساعت محدود می‌کند. بنابراین، این سرعت در هنگام خیس بودن جاده نباید تجاوز شود.</div>',0,'Ja, wenn die Fahrbahn trocken ist',1,1,''),
(638,'1.4.41-127','Ja, wenn die Fahrbahn nass ist','','بله، اگر سطح جاده خیس باشد','<div dir=\'rtl\'>تابلوی فرعی حداکثر سرعت مجاز را در هنگام خیس بودن جاده به ۶۰ کیلومتر بر ساعت محدود می‌کند. بنابراین، این سرعت در هنگام خیس بودن جاده نباید تجاوز شود.</div>',0,'Ja, wenn die Fahrbahn nass ist',1,0,''),
(639,'1.4.41-129','Motorrad ohne Beiwagen','Motorcycle without sidecar','موتورسیکلت بدون سایدکار','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی حکم می‌کند که سبقت گرفتن از وسایل نقلیه موتوری چندمسیره و موتورسیکلت‌های دارای سایدکار ممنوع است. موتورسیکلت بدون سایدکار یک وسیله نقلیه موتوری تک‌مسیره است و بنابراین سبقت گرفتن از آن مجاز است.</div>',0,'Motorrad ohne Beiwagen',1,1,''),
(640,'1.4.41-129','Motorrad mit Beiwagen','Motorcycle with sidecar','موتورسیکلت با سایدکار','<div dir=\'rtl\'>اگرچه موتورسیکلت دارای سایدکار یک وسیله نقلیه موتوری دو مسیره نیست، اما به دلیل عرض خود مشمول این ممنوعیت می‌شود. بنابراین، سبقت گرفتن از موتورسیکلت‌های دارای سایدکار نیز مجاز نیست.</div>',0,'Motorrad mit Beiwagen',1,0,''),
(641,'1.4.41-129','Pkw','Car','خودروی سواری','<div dir=\'rtl\'>خودروهای سواری جزو گروه وسایل نقلیه موتوری چندمسیره محسوب می‌شوند و بنابراین سبقت گرفتن از آنها مجاز نیست.</div>',0,'Pkw',1,0,''),
(642,'1.4.41-130','Auf eine Überholverbotsstrecke von 3 km Länge','No overtaking for 3 km','به یک مسیر ممنوعیت سبقت به طول ۳ کیلومتر','<div dir=\'rtl\'>این علامت راهنمایی و رانندگی نشان‌دهنده ممنوعیت سبقت است. تابلوی فرعی (تکمیلی) به این معنی است که این ممنوعیت سبقت در مسیری به طول ۳ کیلومتر اعمال می‌شود.</div>',0,'Auf eine Überholverbotsstrecke von 3 km Länge',1,1,''),
(643,'1.4.41-130','Auf ein Überholverbot, das in 3 km Entfernung beginnt','Start of a no-overtaking area 3 km ahead','به ممنوعیت سبقت که در فاصله ۳ کیلومتری آغاز می‌شود','<div dir=\'rtl\'>دو فلش نشان می‌دهند که این ممنوعیت تا چه مدت (یا چه مسافتی) معتبر است. بدون این فلش‌ها، این یک نشانگر برای شروع ممنوعیت بود.</div>',0,'Auf ein Überholverbot, das in 3 km Entfernung beginnt',1,0,''),
(644,'1.4.41-130','Auf eine Fahrbahn mit zwei Fahrstreifen für eine Richtung von 3 km Länge','Roadway with two lanes in one direction for 3 km','به یک مسیر با دو خط عبور برای یک جهت به طول ۳ کیلومتر','<div dir=\'rtl\'>دو وسیله نقلیه کنار هم ممکن است به اشتباه به عنوان دو خط عبور برای یک مسیر تفسیر شوند. این اشتباه است. این علامت راهنمایی و رانندگی به ممنوعیت سبقت به طول ۳ کیلومتر اشاره دارد.</div>',0,'Auf eine Fahrbahn mit zwei Fahrstreifen für eine Richtung von 3 km Länge',1,0,''),
(645,'1.4.41-131','Auf ein Überholverbot, das in 200 m Entfernung beginnt','Start of a no-overtaking area 200 m ahead','به ممنوعیت سبقت که در فاصله ۲۰۰ متری آغاز می‌شود','<div dir=\'rtl\'>این علامت راهنمایی و رانندگی به ممنوعیت سبقت اشاره دارد که در ۲۰۰ متری آغاز می‌شود.</div>',0,'Auf ein Überholverbot, das in 200 m Entfernung beginnt',1,1,''),
(646,'1.4.41-131','Auf eine Überholverbotsstrecke von 200 m Länge','No overtaking for 200 m','به یک مسیر ممنوعیت سبقت به طول ۲۰۰ متر','<div dir=\'rtl\'>اگر این یک ممنوعیت سبقت به طول ۲۰۰ متر بود، آنگاه دو فلش سیاه رو به بالا روی تابلوی اضافی نصب می‌شد.</div>',0,'Auf eine Überholverbotsstrecke von 200 m Länge',1,0,''),
(647,'1.4.41-131','Auf ein Überholverbot, das nach 200 m endet','End of a no-overtaking area 200 m ahead','به ممنوعیت سبقت که پس از ۲۰۰ متر پایان می‌یابد','<div dir=\'rtl\'>تابلوی راهنمایی و رانندگی که نشان‌دهنده پایان ممنوعیت سبقت است، علامت ممنوعیت سبقت خط‌خورده است که کاملاً خاکستری با پس‌زمینه سفید است.</div>',0,'Auf ein Überholverbot, das nach 200 m endet',1,0,''),
(648,'1.4.41-132','Auf das Ende der Geschwindigkeitsbeschränkung','','به پایان محدودیت سرعت','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی به پایان محدودیت سرعت اشاره دارد. تابلوی راهنمایی و رانندگی که شروع محدودیت سرعت ۶۰ کیلومتر بر ساعت را اعلام می‌کند، یک تابلوی گرد با قاب قرمز و عدد ۶۰ سیاه در مرکز است. پس‌زمینه آن سفید است.</div>',0,'Auf das Ende der Geschwindigkeitsbeschränkung',1,1,''),
(649,'1.4.41-132','Auf ein Verbot, schneller als 60 km/h zu fahren','','به ممنوعیت رانندگی با سرعت بیش از ۶۰ کیلومتر بر ساعت','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی پایان یک مسیر با محدودیت سرعت را اعلام می‌کند.</div>',0,'Auf ein Verbot, schneller als 60 km/h zu fahren',1,0,''),
(650,'1.4.41-132','Auf den Anfang der Geschwindigkeitsbeschränkung','','به شروع محدودیت سرعت','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی به پایان محدودیت سرعت اشاره دارد. تابلوی راهنمایی و رانندگی که شروع محدودیت سرعت ۶۰ کیلومتر بر ساعت را اعلام می‌کند، یک تابلوی گرد با قاب قرمز و عدد ۶۰ سیاه در مرکز است. پس‌زمینه آن سفید است.</div>',0,'Auf den Anfang der Geschwindigkeitsbeschränkung',1,0,''),
(651,'1.4.41-133','Überholverbote','No overtaking','ممنوعیت‌های سبقت','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی تمامی ممنوعیت‌های مسیر را لغو می‌کند. این شامل ممنوعیت‌های سبقت که قبلاً اعمال شده‌اند، علاوه بر محدودیت‌های سرعت، می‌شود.</div>',0,'Überholverbote',1,1,''),
(652,'1.4.41-133','Geschwindigkeitsbeschränkungen','Speed restrictions','محدودیت‌های سرعت','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی پایان تمامی ممنوعیت‌های مسیر را نشان می‌دهد. این بدان معناست که محدودیت‌های سرعت که قبلاً اعمال شده‌اند، لغو می‌شوند.</div>',0,'Geschwindigkeitsbeschränkungen',1,1,''),
(653,'1.4.41-133','Parkverbote','No parking','ممنوعیت‌های پارک','<div dir=\'rtl\'>ممنوعیت‌های پارک جزو ممنوعیت‌های مسیر نیستند و بنابراین با این تابلو نیز لغو نمی‌شوند.</div>',0,'Parkverbote',1,0,''),
(654,'1.4.41-134','- das auf der Fahrbahn und auch auf dem Seitenstreifen gilt','- on the roadway and the hard shoulder','- که در مسیر حرکت و همچنین در شانه راه معتبر است','<div dir=\'rtl\'>این دقیقاً مطابق با تابلوهای راهنمایی و رانندگی است.</div>',0,'- das auf der Fahrbahn und auch auf dem Seitenstreifen gilt',1,1,''),
(655,'1.4.41-134','- das nur auf dem Seitenstreifen gilt','- on the hard shoulder only','- که فقط در شانه راه معتبر است','<div dir=\'rtl\'>تابلوی تکمیلی \"ممنوعیت توقف حتی در شانه راه\" ممنوعیت توقف را گسترش می‌دهد. آن را محدود نمی‌کند. محدودیت ممنوعیت توقف که فقط به شانه راه مربوط می‌شود، باید با تابلوی تکمیلی \"در شانه راه\" نشان داده شود.</div>',0,'- das nur auf dem Seitenstreifen gilt',1,0,''),
(656,'1.4.41-134','- das nur für Lkws gilt','- for trucks only','- که فقط برای کامیون‌ها معتبر است','<div dir=\'rtl\'>ممنوعیت توقف برای همه شرکت‌کنندگان در ترافیک و بنابراین برای کامیون‌ها نیز معتبر است.</div>',0,'- das nur für Lkws gilt',1,0,''),
(657,'1.4.41-135','Das Halten bis zu 3 Minuten','Stopping for up to 3 minutes','توقف تا ۳ دقیقه','<div dir=\'rtl\'>در این منطقه، توقف تا ۳ دقیقه مجاز است.</div>',0,'Das Halten bis zu 3 Minuten',1,1,''),
(658,'1.4.41-135','Das Halten zum Be- oder Entladen sowie zum Aus- oder Einsteigen','Stopping for loading or unloading as well as boarding or alighting','توقف برای بارگیری یا تخلیه بار و همچنین برای پیاده یا سوار شدن','<div dir=\'rtl\'>برای بارگیری و تخلیه یک وسیله نقلیه و همچنین برای سوار و پیاده شدن، توقف در این منطقه مجاز است.</div>',0,'Das Halten zum Be- oder Entladen sowie zum Aus- oder Einsteigen',1,1,''),
(659,'1.4.41-135','Das Parken, wenn eine Parkscheibe benutzt wird','Parking, provided a parking disc is used','پارک کردن، در صورتی که از دیسک پارک استفاده شود','<div dir=\'rtl\'>پارک کردن ممنوع است، مگر اینکه تابلوهای راهنمایی و رانندگی دیگر صراحتاً اجازه دهند. برای پارک کردن با دیسک پارک، این موضوع باید توسط یک تابلو راهنمایی و رانندگی مشخص شده باشد.</div>',0,'Das Parken, wenn eine Parkscheibe benutzt wird',1,0,''),
(660,'1.4.41-136','Eine Zone mit eingeschränktem Haltverbot','A no-waiting area','یک منطقه توقف ممنوع محدود','<div dir=\'rtl\'>پس از این تابلو راهنمایی و رانندگی، پارک کردن مجدداً مجاز است.</div>',0,'Eine Zone mit eingeschränktem Haltverbot',1,1,''),
(661,'1.4.41-136','Eine Zone mit absolutem Haltverbot','A no-stopping area','یک منطقه توقف مطلقاً ممنوع','<div dir=\'rtl\'>هیچ تابلوی راهنمایی و رانندگی وجود ندارد که کل مناطق توقف مطلقاً ممنوع را مشخص کند. تابلوهای راهنمایی و رانندگی که ممنوعیت توقف را نشان می‌دهند، یک دایره قرمز روی زمینه آبی با یک ضربدر قرمز و فلش‌های سفید را نشان می‌دهند که شروع، مسیر و پایان ممنوعیت توقف را مشخص می‌کنند.</div>',0,'Eine Zone mit absolutem Haltverbot',1,0,''),
(662,'1.4.41-136','Vorausgegangene Streckenverbote','All previous zonal prohibitions','ممنوعیت‌های مسیر قبلی','<div dir=\'rtl\'>با این تابلو فقط ممنوعیت توقف محدود لغو می‌شود. یک تابلوی راهنمایی و رانندگی که تمام ممنوعیت‌های مسیر را لغو می‌کند، سه خط مورب سیاه از پایین چپ به بالا راست را روی یک پس‌زمینه سفید و گرد نشان می‌دهد.</div>',0,'Vorausgegangene Streckenverbote',1,0,''),
(663,'1.4.41-140-B','Beim Verlassen des Kreisverkehrs','When you leave the roundabout','هنگام خروج از میدان','<div dir=\'rtl\'>جهت ورود به میدان به سمت راست مشخص شده است. به همین دلیل هنگام ورود به میدان نیازی به راهنما زدن نیست.</div>',0,'Beim Verlassen des Kreisverkehrs',1,1,''),
(664,'1.4.41-140-B','Beim Einfahren in den Kreisverkehr','When you enter the roundabout','هنگام ورود به میدان','<div dir=\'rtl\'>برای علامت دادن به سایر رانندگان مبنی بر خروج از میدان، باید هنگام خروج راهنما بزنید.</div>',0,'Beim Einfahren in den Kreisverkehr',1,0,''),
(665,'1.4.41-141','Die im Kreis befindlichen Fahrzeuge haben Vorfahrt','Vehicles in the roundabout have priority','وسایل نقلیه داخل میدان حق تقدم دارند.','<div dir=\'rtl\'>این دو علامت راهنمایی و رانندگی تعیین می‌کنند که وسایل نقلیه در میدان نسبت به سایر وسایل نقلیه‌ای که وارد میدان می‌شوند، حق تقدم دارند.</div>',0,'Die im Kreis befindlichen Fahrzeuge haben Vorfahrt',1,1,''),
(666,'1.4.41-141','Das Verlassen des Kreises muss durch Blinken angezeigt werden','You must indicate to leave the roundabout','خروج از میدان باید با راهنما زدن نشان داده شود.','<div dir=\'rtl\'>رانندگان باید خروج از میدان را با راهنما زدن نشان دهند.</div>',0,'Das Verlassen des Kreises muss durch Blinken angezeigt werden',1,1,''),
(667,'1.4.41-141','Beim Einfahren in den Kreis muss geblinkt werden','You must indicate when entering the roundabout','هنگام ورود به میدان باید راهنما زده شود.','<div dir=\'rtl\'>این علامت راهنمایی و رانندگی نشان می‌دهد که هنگام ورود به میدان باید به وسایل نقلیه داخل آن حق تقدم داد.</div>',0,'Beim Einfahren in den Kreis muss geblinkt werden',1,0,''),
(668,'1.4.41-142','Das Halten auf der Kreisfahrbahn ist verboten','','توقف در مسیر دایره‌ای (مسیر اصلی میدان) ممنوع است','<div dir=\'rtl\'>مفهوم «توقف کوتاه» (Halten) در ترافیک جاده‌ای به هر توقف خودرو اطلاق نمی‌شود، بلکه صرفاً به یک توقف داوطلبانه تا سه دقیقه اشاره دارد که راننده در خودرو یا در نزدیکی آن باقی می‌ماند. این می‌تواند مثلاً هنگام پیاده کردن مسافر یا خواندن نقشه خیابان باشد. چنین توقفی در مسیر دایره‌ای میدان در کوتاه‌ترین زمان منجر به انسدادهای قابل توجه و قابل اجتناب می‌شود و به همین دلیل ممنوع است. البته، اگر شرایط ترافیکی ایجاب کند (مثلاً در ترافیک سنگین)، همچنان می‌توانید در میدان متوقف شوید. در این صورت، این عمل «توقف کوتاه» (Halten) محسوب نمی‌شود، بلکه «انتظار» (Warten) است.</div>',0,'Das Halten auf der Kreisfahrbahn ist verboten',1,1,''),
(669,'1.4.41-142','Beim Einfahren in den Kreis ist zu blinken','','هنگام ورود به میدان باید راهنما زد','<div dir=\'rtl\'>راهنما زدن هنگام ورود به میدان اصولاً ممنوع است، زیرا می‌تواند به سرعت منجر به سوءتفاهم و در نتیجه تصادف شود.</div>',0,'Beim Einfahren in den Kreis ist zu blinken',1,0,''),
(670,'1.4.41-142','Es darf nur mit Schrittgeschwindigkeit gefahren werden','','فقط باید با سرعت پیاده‌روی رانندگی کرد','<div dir=\'rtl\'>اگرچه مسیر حرکت در میدان معمولاً نیازمند سرعتی کمتر از خیابان‌های مستقیم است، اما رانندگی با سرعت پیاده‌روی احتیاط بیش از حد محسوب می‌شود و منجر به ایجاد مانع غیرضروری برای سایر کاربران جاده خواهد شد. بنابراین، نه اجباری است و نه به طور کلی ضروری.</div>',0,'Es darf nur mit Schrittgeschwindigkeit gefahren werden',1,0,''),
(671,'1.4.42-001','- nur an der nächsten Kreuzung oder Einmündung','- only at the next crossroads or junction','- فقط در تقاطع یا ورودی بعدی','<div dir=\'rtl\'>طبق بند ۲ ماده ۴۲ آیین‌نامه راهنمایی و رانندگی (StVO)، این تابلوی راهنمایی و رانندگی به معنای «حق تقدم» در تقاطع یا ورودی بعدی است.</div>',0,'- nur an der nächsten Kreuzung oder Einmündung',1,1,''),
(672,'1.4.42-001','- an allen Kreuzungen und Einmündungen dieser Straße','- at all crossroads and junctions on this road','- در تمام تقاطع‌ها و ورودی‌های این خیابان','<div dir=\'rtl\'>اگر حق تقدم باید در تمام تقاطع‌ها و ورودی‌ها اعمال شود، این موضوع با تابلوی راهنمایی و رانندگی «خیابان دارای حق تقدم» (Vorfahrtsstraße) نشان داده می‌شود.</div>',0,'- an allen Kreuzungen und Einmündungen dieser Straße',1,0,''),
(673,'1.4.42-001','- bis zum Ortsende','- as far as the urban limit','- تا پایان محدوده شهری','<div dir=\'rtl\'>تابلوی راهنمایی و رانندگی که حق تقدم را تا پایان محدوده شهری اعطا کند، وجود ندارد.</div>',0,'- bis zum Ortsende',1,0,''),
(674,'1.4.42-005','Auf den Anfang einer Autobahn','The start of an autobahn','به ابتدای یک آزادراه','<div dir=\'rtl\'>تابلوی راهنمایی و رانندگی نشان داده شده به ابتدای یک آزادراه اشاره دارد.</div>',0,'Auf den Anfang einer Autobahn',1,1,''),
(675,'1.4.42-005','Auf das Ende der Autobahn','The end of an autobahn','به پایان آزادراه','<div dir=\'rtl\'>تابلوی راهنمایی و رانندگی برای پایان یک آزادراه، همین تابلو با یک خط مورب قرمز روی آن است.</div>',0,'Auf das Ende der Autobahn',1,0,''),
(676,'1.4.42-005','Auf den Anfang einer Kraftfahrstraße','The start of a clearway for motor vehicles only','به ابتدای یک جاده مخصوص وسایل نقلیه موتوری','<div dir=\'rtl\'>تابلوی راهنمایی و رانندگی برای ابتدای یک جاده مخصوص وسایل نقلیه موتوری، یک خودروی سواری سفید روی یک مربع آبی است.</div>',0,'Auf den Anfang einer Kraftfahrstraße',1,0,''),
(677,'1.4.42-101','Verkehrszeichen 1','','تابلوی راهنمایی و رانندگی ۱','<div dir=\'rtl\'>این تابلو به معنای: حق تقدم در برابر ترافیک روبرو است. این تابلو حق تقدم را در تقاطع‌ها تنظیم نمی‌کند، بلکه در نقاط باریک مانند پل‌های باریک تنظیم می‌کند.</div>',0,'Verkehrszeichen 1',1,1,''),
(678,'1.4.42-101','Verkehrszeichen 2','','تابلوی راهنمایی و رانندگی ۲','<div dir=\'rtl\'>این تابلو به معنای: حق تقدم در برابر ترافیک روبرو است. این تابلو حق تقدم را در تقاطع‌ها تنظیم نمی‌کند، بلکه در نقاط باریک مانند پل‌های باریک تنظیم می‌کند.</div>',0,'Verkehrszeichen 2',1,0,''),
(679,'1.4.42-101','Verkehrszeichen 3','','تابلوی راهنمایی و رانندگی ۳','<div dir=\'rtl\'>این تابلو به معنای: حق تقدم در برابر ترافیک روبرو است. این تابلو حق تقدم را در تقاطع‌ها تنظیم نمی‌کند، بلکه در نقاط باریک مانند پل‌های باریک تنظیم می‌کند.</div>',0,'Verkehrszeichen 3',1,0,''),
(680,'1.4.42-102','Verkehrszeichen 2','Traffic sign 2','تابلوی راهنمایی و رانندگی ۲','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی، جاده را به عنوان یک جاده فدرال (بوندس‌اشترسه) مشخص می‌کند.</div>',0,'Verkehrszeichen 2',1,1,''),
(681,'1.4.42-102','Verkehrszeichen 1','Traffic sign 1','تابلوی راهنمایی و رانندگی ۱','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی، جاده را به عنوان یک جاده فدرال (بوندس‌اشترسه) مشخص می‌کند.</div>',0,'Verkehrszeichen 1',1,0,''),
(682,'1.4.42-102','Verkehrszeichen 3','Traffic sign 3','تابلوی راهنمایی و رانندگی ۳','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی، جاده را به عنوان یک جاده فدرال (بوندس‌اشترسه) مشخص می‌کند.</div>',0,'Verkehrszeichen 3',1,0,''),
(683,'1.4.42-104','Halten am rechten Fahrbahnrand','Stopping on the right edge of the roadway','توقف در حاشیه سمت راست جاده','<div dir=\'rtl\'>خارج از شهر، در جاده‌های دارای حق تقدم، می‌توان در حاشیه جاده توقف کرد.</div>',0,'Halten am rechten Fahrbahnrand',1,1,''),
(684,'1.4.42-104','Parken auf dem Seitenstreifen','Parking on the hard shoulder','پارک کردن در شانه خاکی (حاشیه) جاده','<div dir=\'rtl\'>خارج از شهر، پارک کردن در شانه خاکی (حاشیه) جاده مجاز است، زیرا مانع ترافیک نمی‌شود.</div>',0,'Parken auf dem Seitenstreifen',1,1,''),
(685,'1.4.42-104','Parken auf der Fahrbahn','Parking on the roadway','پارک کردن روی سطح سواره‌رو (مسیر حرکت)','<div dir=\'rtl\'>پارک کردن روی سطح سواره‌رو (مسیر حرکت) مانع قابل توجهی برای ترافیک روان ایجاد می‌کند و به همین دلیل ممنوع است.</div>',0,'Parken auf der Fahrbahn',1,0,''),
(686,'1.4.42-106','Eine Vorfahrtstraße','','یک خیابان با حق تقدم','<div dir=\'rtl\'>این تابلو راهنمایی و رانندگی نشان‌دهنده پایان یک خیابان با حق تقدم است. بنابراین، پس از آن، مگر اینکه به نحو دیگری مشخص شده باشد، قانون ترافیکی «حق تقدم با راست» اعمال می‌شود.</div>',0,'Eine Vorfahrtstraße',1,1,''),
(687,'1.4.42-106','Ein Zonenhaltverbot','','ممنوعیت توقف در یک منطقه','<div dir=\'rtl\'>در اینجا یک خیابان با حق تقدم به پایان می‌رسد و نه ممنوعیت توقف در یک منطقه.</div>',0,'Ein Zonenhaltverbot',1,0,''),
(688,'1.4.42-106','Vorausgegangene Streckenverbote','','ممنوعیت‌های مسیر قبلی','<div dir=\'rtl\'>پایان ممنوعیت‌های مسیر قبلی با یک دایره خاکستری خط‌خورده نمادین می‌شود.</div>',0,'Vorausgegangene Streckenverbote',1,0,''),
(689,'1.4.42-107','Ihren Vorrang dürfen Sie nur dann nutzen, wenn die Engstelle frei ist','You may only take precedence when the narrowing is clear','شما فقط زمانی می‌توانید از حق تقدم خود استفاده کنید که مسیر باریک آزاد باشد','<div dir=\'rtl\'>ورود به مسیر باریک در صورتی که قبلاً توسط یک وسیله نقلیه روبرو مسدود شده باشد، منطقی نیست. این کار باعث ایجاد مانع یا خطر غیرضروری می‌شود.</div>',0,'Ihren Vorrang dürfen Sie nur dann nutzen, wenn die Engstelle frei ist',1,1,''),
(690,'1.4.42-107','Trotz Vorrang müssen Sie sich auf ein Anhalten einstellen','You must be ready to stop despite taking precedence','با وجود حق تقدم، باید آماده توقف باشید','<div dir=\'rtl\'>از آنجایی که در چنین مکان‌هایی اغلب وسایل نقلیه (با وجود حق تقدم ترافیک روبرو) وارد مسیر باریک می‌شوند، شما باید همیشه آماده توقف باشید.</div>',0,'Trotz Vorrang müssen Sie sich auf ein Anhalten einstellen',1,1,''),
(691,'1.4.42-107','Sie müssen dem Gegenverkehr Vorrang gewähren','You must give precedence to the oncoming traffic','شما باید به ترافیک روبرو حق تقدم بدهید','<div dir=\'rtl\'>حق تقدم ترافیک روبرو با یک تابلوی راهنمایی و رانندگی دیگر به شما نشان داده می‌شود. این تابلو یک دایره قرمز روی زمینه سفید است که در جهت حرکت شما یک پیکان قرمز و در جهت حرکت روبرو یک پیکان سیاه نشان می‌دهد.</div>',0,'Sie müssen dem Gegenverkehr Vorrang gewähren',1,0,''),
(692,'1.4.42-109','Bewohner mit entsprechend nummeriertem Parkausweis dürfen hier parken','Residents holding a parking licence with corresponding number may park here','ساکنینی که دارای مجوز پارک با شماره مربوطه هستند، مجاز به پارک در اینجا می‌باشند.','<div dir=\'rtl\'>مجوز پارک ممکن است توسط یک تابلوی تکمیلی محدود شود. این مورد در اینجا صدق می‌کند. در این صورت، فقط ساکنینی مجاز به پارک هستند که مجوز پارک با شماره مشخص شده را به وضوح در خودروی خود به نمایش بگذارند.</div>',0,'Bewohner mit entsprechend nummeriertem Parkausweis dürfen hier parken',1,1,''),
(693,'1.4.42-109','Alle Bewohner dürfen jeden dieser Parkplätze benutzen','All residents may use any of these parking spaces','همه ساکنین مجاز به استفاده از هر یک از این پارکینگ‌ها هستند.','<div dir=\'rtl\'>فقط ساکنینی که دارای شماره مجوز پارک مشخص شده در تابلوی تکمیلی هستند، مجاز به پارک در این منطقه می‌باشند.</div>',0,'Alle Bewohner dürfen jeden dieser Parkplätze benutzen',1,0,''),
(694,'1.4.42-109','Solange noch andere Parkplätze frei sind, darf jeder diesen Parkplatz benutzen','Everybody may use this parking space as long as other parking spaces are still free','تا زمانی که پارکینگ‌های دیگری خالی هستند، هر کسی مجاز به استفاده از این پارکینگ است.','<div dir=\'rtl\'>فقط ساکنینی که دارای شماره مجوز پارک مشخص شده در تابلوی تکمیلی هستند، مجاز به پارک در این منطقه می‌باشند. اگر فقط یک تابلوی راهنمایی و رانندگی با حرف \"P\" سفید بر روی پس‌زمینه آبی و مربع شکل نمایش داده شده باشد، در آن صورت هر کسی مجاز به پارک در اینجا است.</div>',0,'Solange noch andere Parkplätze frei sind, darf jeder diesen Parkplatz benutzen',1,0,''),
(695,'1.4.42-110','Ja, als Schwerbehinderter mit amtlichem Parkausweis','Yes, as a seriously disabled person with an official parking permit','بله، به عنوان فرد دارای معلولیت شدید با کارت پارک رسمی','<div dir=\'rtl\'>افراد دارای معلولیت شدید با کارت مربوطه مجاز به استفاده از این پارکینگ هستند. این پارکینگ تنها در صورتی قابل استفاده است که کارت پارک به وضوح در خودرو نمایش داده شود.</div>',0,'Ja, als Schwerbehinderter mit amtlichem Parkausweis',1,1,''),
(696,'1.4.42-110','Ja, als Begleitperson von Blinden mit amtlichem Parkausweis','Yes, as a person accompanying blind persons with an official parking permit','بله، به عنوان همراه افراد نابینا با کارت پارک رسمی','<div dir=\'rtl\'>افراد نابینا با کارت مربوطه مجاز به استفاده از این پارکینگ هستند. از آنجایی که افراد نابینا خودشان مجاز به رانندگی نیستند، این مقررات برای همراه آنها اعمال می‌شود. این پارکینگ تنها در صورتی قابل استفاده است که کارت پارک به وضوح در خودرو نمایش داده شود.</div>',0,'Ja, als Begleitperson von Blinden mit amtlichem Parkausweis',1,1,''),
(697,'1.4.42-110','Ja, für kurzfristige Einkäufe','Yes, briefly for shopping','بله، برای خریدهای کوتاه مدت','<div dir=\'rtl\'>استفاده از چنین پارکینگی برای خریدهای کوتاه مدت ممنوع است، زیرا ممکن است فرد مجاز به استفاده از آن محروم شود. یک علامت راهنمایی و رانندگی که به طور کلی پارک کردن را مجاز می‌داند، یک \"P\" سفید روی پس‌زمینه آبی و مربع شکل است. اگر فقط این علامت راهنمایی و رانندگی بدون تابلوی اضافی نصب شده باشد، هر کسی می‌تواند اینجا پارک کند.</div>',0,'Ja, für kurzfristige Einkäufe',1,0,''),
(698,'1.4.42-111','Die auf dem Parkschein angegebene Parkzeit darf nicht überschritten werden','The parking time indicated on the parking ticket may not be exceeded','زمان پارک مشخص شده روی بلیط پارک نباید تجاوز شود','<div dir=\'rtl\'>برای مدت زمان پارک، باید یک بلیط پارک تهیه شود. این زمان نباید تجاوز شود. یعنی شما نباید بیشتر از زمانی که روی بلیط پارک نوشته شده است، در آنجا پارک کنید.</div>',0,'Die auf dem Parkschein angegebene Parkzeit darf nicht überschritten werden',1,1,''),
(699,'1.4.42-111','Der Parkschein muss für Kontrollen gut lesbar ausgelegt sein','The parking ticket must be put in a place so it can be easily read when controlled','بلیط پارک باید برای بازرسی‌ها به وضوح قابل خواندن باشد','<div dir=\'rtl\'>برای اینکه پلیس بتواند بررسی کند که آیا زمان پارک پرداخت شده رعایت شده و بیشتر از حد مجاز پارک نشده است، بلیط پارک باید به وضوح قابل مشاهده باشد. معمولاً آن را پشت شیشه جلو قرار می‌دهند.</div>',0,'Der Parkschein muss für Kontrollen gut lesbar ausgelegt sein',1,1,''),
(700,'1.4.42-111','Parkschein und Parkscheibe sind gleichgestellt','Parking ticket and parking disc rank equal','بلیط پارک و دیسک پارک هم‌ارز هستند','<div dir=\'rtl\'>اگر بلیط پارک (پارک‌شاین) الزامی باشد، دیسک پارک (پارک‌شایبه) کافی نیست.</div>',0,'Parkschein und Parkscheibe sind gleichgestellt',1,0,''),
(701,'1.4.42-112','Fahrzeuge bis 2,8 t zulässiger Gesamtmasse','Vehicles with a permissible total mass of up to 2.8 t','وسایل نقلیه تا حداکثر وزن مجاز ۲.۸ تن','<div dir=\'rtl\'>این تابلو راهنمایی و رانندگی شامل وسایل نقلیه با حداکثر وزن مجاز بیش از ۳.۵ تن نمی‌شود. بنابراین، این وسایل نقلیه مجاز به پارک در اینجا نیستند.</div>',0,'Fahrzeuge bis 2,8 t zulässiger Gesamtmasse',1,1,''),
(702,'1.4.42-112','Motorräder','Motorcycles','موتورسیکلت‌ها','<div dir=\'rtl\'>موتورسیکلت‌ها مجاز به پارک در اینجا هستند.</div>',0,'Motorräder',1,1,''),
(703,'1.4.42-112','Fahrzeuge über 3,5 t zulässiger Gesamtmasse','Vehicles with a permissible total mass of more than 3.5 t','وسایل نقلیه با حداکثر وزن مجاز بیش از ۳.۵ تن','<div dir=\'rtl\'>این تابلو راهنمایی و رانندگی شامل وسایل نقلیه با حداکثر وزن مجاز بیش از ۳.۵ تن نمی‌شود. بنابراین، این وسایل نقلیه مجاز به پارک در اینجا نیستند.</div>',0,'Fahrzeuge über 3,5 t zulässiger Gesamtmasse',1,0,''),
(704,'1.4.42-116','61 km/h','61 km/h','۶۱ کیلومتر بر ساعت','<div dir=\'rtl\'>این تابلو راهنمایی و رانندگی نشان‌دهنده شروع یک جاده مخصوص وسایل نقلیه موتوری است. فقط وسایل نقلیه‌ای مجاز به استفاده از آن هستند که حداکثر سرعت طراحی شده آن‌ها حداقل ۶۱ کیلومتر بر ساعت باشد.</div>',0,'61 km/h',1,1,''),
(705,'1.4.42-116','51 km/h','51 km/h','۵۱ کیلومتر بر ساعت','<div dir=\'rtl\'>اگر یک وسیله نقلیه موتوری به دلیل طراحی خود فقط می‌تواند حداکثر ۵۱ کیلومتر بر ساعت حرکت کند، برای این جاده مجاز نیست، زیرا از حداقل سرعت ۶۱ کیلومتر بر ساعت کمتر است.</div>',0,'51 km/h',1,0,''),
(706,'1.4.42-116','81 km/h','81 km/h','۸۱ کیلومتر بر ساعت','<div dir=\'rtl\'>برای استفاده از این جاده، حداکثر سرعت طراحی شده ۶۱ کیلومتر بر ساعت لازم است. این حداقل سرعت برای مجاز بودن رانندگی در این جاده است. اگر یک خودرو به دلیل طراحی خود حداکثر ۸۱ کیلومتر بر ساعت حرکت می‌کند، البته که می‌تواند از این جاده نیز استفاده کند.</div>',0,'81 km/h',1,0,''),
(707,'1.4.42-119','Auf eine Sackgasse','A cul-de-sac','به یک کوچه بن‌بست','<div dir=\'rtl\'>تابلوی راهنمایی و رانندگی نمایش داده شده، نماد StVO برای یک کوچه بن‌بست است.</div>',0,'Auf eine Sackgasse',1,1,''),
(708,'1.4.42-119','Auf eine Unterführung','An underpass','به یک زیرگذر','<div dir=\'rtl\'>یک تابلوی راهنمایی و رانندگی برای زیرگذر عابران پیاده وجود دارد، به تصویر مراجعه کنید.</div>',0,'Auf eine Unterführung',1,0,''),
(709,'1.4.42-119','Auf eine für den Fahrzeugverkehr gesperrte Straße','A road closed to vehicle traffic','به یک خیابان مسدود برای تردد وسایل نقلیه','<div dir=\'rtl\'>تابلوی راهنمایی و رانندگی برای خیابان مسدود برای تردد وسایل نقلیه، یک دایره قرمز روی زمینه سفید است.</div>',0,'Auf eine für den Fahrzeugverkehr gesperrte Straße',1,0,''),
(710,'1.4.42-120','Auf eine Erste-Hilfe-Station','A first aid station','به یک ایستگاه کمک‌های اولیه','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی به یک ایستگاه کمک‌های اولیه اشاره دارد.</div>',0,'Auf eine Erste-Hilfe-Station',1,1,''),
(711,'1.4.42-120','Auf eine Kreuzung','A crossroads','به یک تقاطع','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی یک ایستگاه کمک‌های اولیه را اعلام می‌کند، نه یک تقاطع را.</div>',0,'Auf eine Kreuzung',1,0,''),
(712,'1.4.42-120','Auf eine Gefahrstelle','A danger spot','به یک نقطه خطرناک','<div dir=\'rtl\'>تابلوی راهنمایی و رانندگی «نقطه خطرناک» متفاوت است.</div>',0,'Auf eine Gefahrstelle',1,0,''),
(713,'1.4.42-125','Die Straßenbeleuchtung brennt nicht die ganze Nacht','Street lighting does not stay on all night','روشنایی خیابان تمام شب روشن نمی‌ماند.','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی به این معنی است که چراغ خیابان تمام شب روشن نمی‌ماند.</div>',0,'Die Straßenbeleuchtung brennt nicht die ganze Nacht',1,1,''),
(714,'1.4.42-125','Fahrzeuge dürfen hier ohne Beleuchtung die ganze Nacht geparkt werden','Vehicles may be parked here all night without lights','وسایل نقلیه می‌توانند تمام شب بدون چراغ در اینجا پارک شوند.','<div dir=\'rtl\'>وسایل نقلیه‌ای که در کنار خیابان، جایی که این تابلو نصب شده است، پارک می‌کنند، باید حداقل چراغ پارک را روشن کنند یا وسیله نقلیه خود را به روشی دیگر به اندازه کافی قابل تشخیص کنند.</div>',0,'Fahrzeuge dürfen hier ohne Beleuchtung die ganze Nacht geparkt werden',1,0,''),
(715,'1.4.42-125','Fahrzeuge dürfen hier nicht geparkt werden','Vehicles may not be parked here','وسایل نقلیه اجازه پارک در اینجا را ندارند.','<div dir=\'rtl\'>وسایل نقلیه می‌توانند در اینجا پارک کنند. اما باید در هنگام غروب و در شب به اندازه کافی قابل تشخیص باشند. این کار می‌تواند با استفاده از چراغ پارک، چراغ‌های جانبی (چراغ کوچک) یا حتی تابلوهای هشدار پارک انجام شود.</div>',0,'Fahrzeuge dürfen hier nicht geparkt werden',1,0,''),
(716,'1.4.42-126','Auf eine Bundesstraße','A federal road (Bundesstraße)','به یک جاده فدرال (بوندس‌اشترسه)','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی شماره جاده فدرال را نشان می‌دهد.</div>',0,'Auf eine Bundesstraße',1,1,''),
(717,'1.4.42-126','Es darf nicht schneller als 35 km/h gefahren werden','Vehicles may not drive faster than 35 km/h','نباید سریع‌تر از ۳۵ کیلومتر بر ساعت رانندگی کرد','<div dir=\'rtl\'>تابلوی راهنمایی و رانندگی که سرعت را محدود می‌کند، یک عدد سیاه با دایره‌ای با حاشیه قرمز روی پس‌زمینه سفید است.</div>',0,'Es darf nicht schneller als 35 km/h gefahren werden',1,0,''),
(718,'1.4.42-126','Es muss mindestens 35 km/h gefahren werden','Vehicles must drive at least 35 km/h','باید حداقل ۳۵ کیلومتر بر ساعت رانندگی کرد','<div dir=\'rtl\'>تابلوی راهنمایی و رانندگی که حداقل سرعت را تعیین می‌کند، یک عدد سفید روی دایره آبی است.</div>',0,'Es muss mindestens 35 km/h gefahren werden',1,0,''),
(719,'1.4.42-128','Auf eine in der Regel weniger befahrene Autobahnstrecke','An autobahn section which is normally not used very much','به یک مسیر بزرگراهی که معمولاً کمتر شلوغ است.','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی که به عنوان «پیکان انحراف» شناخته می‌شود، به یک مسیر جایگزین کمتر شلوغ در یک بزرگراه دیگر اشاره دارد. با این حال، مسیر دیگر به همان مقصد منتهی می‌شود.</div>',0,'Auf eine in der Regel weniger befahrene Autobahnstrecke',1,1,''),
(720,'1.4.42-128','Auf eine Stelle, an der man die Autobahn verlassen muss','The place where the autobahn must be exited','به محلی که باید از بزرگراه خارج شد.','<div dir=\'rtl\'>هنگام مشاهده این تابلو، نیازی به خروج از بزرگراه نیست. این تابلو فقط یک امکان را برای رسیدن به همان مقصد از طریق یک مسیر جایگزین نشان می‌دهد. به همین دلیل، پیکان انحراف در تقاطع‌ها و سه‌راهی‌های بزرگراهی نصب می‌شود.</div>',0,'Auf eine Stelle, an der man die Autobahn verlassen muss',1,0,''),
(721,'1.4.42-128','Auf eine vorgeschriebene Umleitung für Fahrzeuge mit gefährlichen Gütern','An obligatory diversion for vehicles with dangerous goods','به یک مسیر انحرافی اجباری برای وسایل نقلیه حامل کالاهای خطرناک.','<div dir=\'rtl\'>رنگ‌بندی پیکان انحراف گیج‌کننده است: نارنجی همچنین رنگ تابلوهای هشداردهنده روی وسایل نقلیه حامل کالاهای خطرناک است. با این حال، این تابلوی راهنمایی و رانندگی به یک مسیر انحرافی اجباری برای حمل و نقل کالاهای خطرناک اشاره ندارد.</div>',0,'Auf eine vorgeschriebene Umleitung für Fahrzeuge mit gefährlichen Gütern',1,0,''),
(722,'1.4.42-132','Ich fahre mit Abblendlicht','Drive with dipped headlights','من با نور پایین رانندگی می‌کنم.','<div dir=\'rtl\'>در تونل همیشه باید نور پایین روشن باشد.</div>',0,'Ich fahre mit Abblendlicht',1,1,''),
(723,'1.4.42-132','Ich fahre ohne Licht','Drive without lights','من بدون چراغ رانندگی می‌کنم.','<div dir=\'rtl\'>این بسیار خطرناک خواهد بود. نور پایین را روشن کنید تا دید کافی داشته باشید و به اندازه کافی دیده شوید.</div>',0,'Ich fahre ohne Licht',1,0,''),
(724,'1.4.42-132','Ich fahre mit Tagfahrlicht','Drive with daytime running lights','من با نور روز رانندگی می‌کنم.','<div dir=\'rtl\'>نور روز برای اطمینان از دید کافی در تونل کافی نیست. شما باید نور پایین را روشن کنید.</div>',0,'Ich fahre mit Tagfahrlicht',1,0,''),
(725,'1.4.42-133','- eines verkehrsberuhigten Bereichs','- a traffic-calming zone','- یک منطقه آرام ترافیکی','<div dir=\'rtl\'>این تابلو نشان‌دهنده پایان یک منطقه آرام ترافیکی است.</div>',0,'- eines verkehrsberuhigten Bereichs',1,1,''),
(726,'1.4.42-133','- eines Fußgängerbereichs','- a pedestrian zone','- یک منطقه عابر پیاده','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی به پایان یک منطقه عابر پیاده اشاره ندارد.</div>',0,'- eines Fußgängerbereichs',1,0,''),
(727,'1.4.42-133','- eines Spielplatzes','- a children\'s playground','- یک زمین بازی','<div dir=\'rtl\'>هیچ تابلوی راهنمایی و رانندگی وجود ندارد که به پایان یک زمین بازی اشاره کند.</div>',0,'- eines Spielplatzes',1,0,''),
(728,'1.4.43-101','Auf einen Anhänger, der innerhalb einer geschlossenen Ortschaft auf der Fahrbahn abgestellt ist','A trailer parked on the roadway within a built-up area','به یک تریلر که در داخل یک منطقه مسکونی در جاده پارک شده است.','<div dir=\'rtl\'>تریلرهایی که در جاده پارک شده‌اند، باید در داخل مناطق مسکونی با تابلوهای هشداردهنده پارک با نوارهای قرمز-سفید ایمن شوند، زیرا در غیر این صورت به دلیل نداشتن منبع انرژی نمی‌توانند روشن شوند.</div>',0,'Auf einen Anhänger, der innerhalb einer geschlossenen Ortschaft auf der Fahrbahn abgestellt ist',1,1,''),
(729,'1.4.43-101','Auf ein Fahrzeug mit Überbreite','A vehicle with excessive width','به یک وسیله نقلیه با عرض بیش از حد.','<div dir=\'rtl\'>این تابلوهای هشداردهنده می‌توانند، از جمله، وسایل نقلیه با عرض بیش از حد را مشخص کنند. آنها از فاصله دور قابل تشخیص هستند و به این ترتیب سایر کاربران جاده را به موقع از ابعاد خاص وسیله نقلیه آگاه می‌کنند.</div>',0,'Auf ein Fahrzeug mit Überbreite',1,1,''),
(730,'1.4.43-101','Auf ein Gefahrgutfahrzeug','A vehicle transporting dangerous goods','به یک وسیله نقلیه حامل مواد خطرناک.','<div dir=\'rtl\'>روی تابلوهای هشداردهنده وسایل نقلیه حامل مواد خطرناک، از طریق تصاویر و پیکتوگرام‌ها به خطرات مواد حمل شده اشاره می‌شود. علاوه بر این، روی تابلوهای نارنجی اضافی دقیقاً مشخص می‌شود که وسیله نقلیه چه چیزی را بارگیری کرده است. تابلوهای هاشوردار قرمز-سفید در اینجا برای هشدار استفاده نمی‌شوند.</div>',0,'Auf ein Gefahrgutfahrzeug',1,0,''),
(731,'1.5.01-004','Der Kraftstoffverbrauch nimmt zu','Fuel consumption increases','مصرف سوخت افزایش می‌یابد','<div dir=\'rtl\'>هر کس که تا به حال با دوچرخه رانندگی کرده و باد لاستیک آن بسیار کم بوده، می‌داند که دوچرخه در آن صورت سنگین‌تر از معمول حرکت می‌کند. برای حرکت به جلو به نیروی بسیار بیشتری نیاز است. در خودرو نیز دقیقاً همین‌طور است؛ لاستیک سنگین‌تر می‌چرخد و در نتیجه برای حفظ همان سرعت، گاز بیشتری می‌دهیم. بدین ترتیب، مصرف سوخت افزایش می‌یابد.</div>',0,'Der Kraftstoffverbrauch nimmt zu',1,1,''),
(732,'1.5.01-004','Der Reifenabrieb nimmt zu','Tyre wear increases','سایش لاستیک افزایش می‌یابد','<div dir=\'rtl\'>اگر لاستیک باد کافی نداشته باشد، سنگین‌تر می‌چرخد. بنابراین باید بر مقاومت غلتشی بیشتری غلبه کنیم. اما این بدان معناست که باید نیروی بیشتری منتقل کنیم. هر چه نیروی منتقل شده به چرخ بیشتر باشد، لاستیک نیز بیشتر تحت فشار قرار می‌گیرد. سایش و در نتیجه فرسودگی لاستیک افزایش می‌یابد.</div>',0,'Der Reifenabrieb nimmt zu',1,1,''),
(733,'1.5.01-004','Der Schadstoffausstoß nimmt ab','Pollutant emission decreases','انتشار آلاینده‌ها کاهش می‌یابد','<div dir=\'rtl\'>اگر فشار باد لاستیک خیلی کم باشد، باید گاز بیشتری بدهیم تا سرعت را حفظ کنیم. بنابراین، سوخت بیشتری نیز مصرف می‌شود. هنگامی که مصرف سوخت افزایش می‌یابد، انتشار آلاینده‌ها نیز افزایش می‌یابد.</div>',0,'Der Schadstoffausstoß nimmt ab',1,0,''),
(734,'1.5.01-005','Wenn Sie in einem Verkehrsstau länger warten müssen','','هنگامی که مجبورید در ترافیک برای مدت طولانی‌تری منتظر بمانید','<div dir=\'rtl\'>اگر در ترافیکی با زمان انتظار طولانی‌تر قرار دارید، موتور باید خاموش شود تا محیط زیست بی‌مورد آلوده نشود. بنابراین، موتور باید خاموش شود.</div>',0,'Wenn Sie in einem Verkehrsstau länger warten müssen',1,1,''),
(735,'1.5.01-005','Wenn Sie vor Bahnübergängen oder Baustellen warten müssen','','هنگامی که مجبورید جلوی گذرگاه‌های راه‌آهن یا محل‌های ساخت و ساز منتظر بمانید','<div dir=\'rtl\'>جلوی گذرگاه‌های راه‌آهن یا محل‌های ساخت و ساز، موتور باید خاموش شود، زیرا مدت زمان انتظار قابل تخمین نیست و محیط زیست نباید بی‌مورد آلوده شود.</div>',0,'Wenn Sie vor Bahnübergängen oder Baustellen warten müssen',1,1,''),
(736,'1.5.01-005','Wenn Sie bei einem „STOP“-Schild anhalten','','هنگامی که در یک تابلوی «ایست» توقف می‌کنید','<div dir=\'rtl\'>در هر تابلوی ایست باید توقف کرد. اگر خیابان دارای حق تقدم آزاد باشد، می‌توانید بلافاصله پس از توقف حرکت کنید. در اینجا، روشن و خاموش کردن موتور مانع جریان ترافیک می‌شود. بنابراین، هنگام توقف در تابلوی ایست، موتور می‌تواند روشن بماند.</div>',0,'Wenn Sie bei einem „STOP“-Schild anhalten',1,0,''),
(737,'1.5.01-006','600 Liter','600 litres','۶۰۰ لیتر','<div dir=\'rtl\'>یک قطره کوچک روغن می‌تواند تا ۶۰۰ لیتر آب را غیرقابل شرب کند.</div>',0,'600 Liter',1,1,''),
(738,'1.5.01-006','50 Liter','50 litres','۵۰ لیتر','<div dir=\'rtl\'>یک قطره کوچک روغن می‌تواند بیش از ۵۰ لیتر آب را غیرقابل شرب کند.</div>',0,'50 Liter',1,0,''),
(739,'1.5.01-006','1 Liter','1 litre','۱ لیتر','<div dir=\'rtl\'>یک قطره کوچک روغن می‌تواند بیش از یک لیتر آب را غیرقابل شرب کند.</div>',0,'1 Liter',1,0,''),
(740,'1.5.01-007','Keine Kraftstoffdämpfe einatmen','Do not breath in any fuel fumes','بخارات سوخت را استنشاق نکنید.','<div dir=\'rtl\'>استنشاق بخارات سوخت ممکن است منجر به آسیب‌های سلامتی یا اختلال در پردازش اطلاعات در مغز شود. بنابراین، بهتر است از آن خودداری کنید.</div>',0,'Keine Kraftstoffdämpfe einatmen',1,1,''),
(741,'1.5.01-007','Nicht nachtanken, wenn der Tank voll ist und die Zapfpistole abgeschaltet hat','Do not refuel when the tank is full and the nozzle has switched off','پس از پر شدن باک و قطع شدن نازل سوخت، دوباره سوخت‌گیری نکنید.','<div dir=\'rtl\'>سوخت با دمای ۶ تا ۸ درجه سانتی‌گراد از مخزن خارج می‌شود و متناسب با این دما حجم مشخصی دارد. اگر دمای بیرون بالاتر باشد، سوخت در باک بلافاصله شروع به گرم شدن می‌کند. در نتیجه، حجم آن افزایش می‌یابد. هنگامی که نازل سوخت قطع می‌شود، هنوز هوای کافی در باک وجود دارد که می‌تواند هنگام انبساط سوخت خارج شود. اگر باک را کاملاً پر کنم، این فضای هوایی از بین می‌رود. سوخت منبسط می‌شود و قسمتی که دیگر در باک جا نمی‌گیرد، بیرون می‌ریزد. این با مقررات حفاظت از محیط زیست و آتش‌سوزی مطابقت ندارد. بنابراین، باید از سوخت‌گیری مجدد خودداری کرد.</div>',0,'Nicht nachtanken, wenn der Tank voll ist und die Zapfpistole abgeschaltet hat',1,1,''),
(742,'1.5.01-007','Möglichst randvoll tanken','Fill up to the brim if possible','تا حد امکان باک را کاملاً پر کنید.','<div dir=\'rtl\'>سوخت با دمای ۶ تا ۸ درجه سانتی‌گراد از مخزن خارج می‌شود و متناسب با این دما حجم مشخصی دارد. اگر دمای بیرون بالاتر باشد، سوخت در باک بلافاصله شروع به گرم شدن می‌کند. در نتیجه، حجم آن افزایش می‌یابد. هنگامی که نازل سوخت قطع می‌شود، هنوز هوای کافی در باک وجود دارد که می‌تواند هنگام انبساط سوخت خارج شود. اگر باک را کاملاً پر کنم، این فضای هوایی از بین می‌رود. سوخت منبسط می‌شود و قسمتی که دیگر در باک جا نمی‌گیرد، بیرون می‌ریزد.</div>',0,'Möglichst randvoll tanken',1,0,''),
(743,'1.5.01-110','Rechtzeitig Gas wegnehmen und Schwung ausnutzen, wenn die nächste Ampel „Rot“ zeigt','Decelerate in good time and use the momentum of the car when the next traffic light is on red','هنگامی که چراغ راهنمایی بعدی «قرمز» است، به موقع پا را از روی گاز بردارید و از شتاب (اینرسی) استفاده کنید.','<div dir=\'rtl\'>اگر زودتر پا را از روی گاز بردارید، خودرو به حرکت خود ادامه می‌دهد. بنابراین، از شتاب باقیمانده و اینرسی جرم استفاده می‌کنید. این کار باعث کاهش شدید مصرف سوخت و حفظ ترمزها می‌شود.</div>',0,'Rechtzeitig Gas wegnehmen und Schwung ausnutzen, wenn die nächste Ampel „Rot“ zeigt',1,1,''),
(744,'1.5.01-110','Unnötiges Beschleunigen und unnötiges Abbremsen vermeiden','Avoid unnecessary acceleration and unnecessary braking','از شتاب‌گیری و ترمزگیری غیرضروری خودداری کنید.','<div dir=\'rtl\'>هر شتاب‌گیری هزینه سوخت دارد. ترمزگیری غیرضروری هزینه سوخت ندارد، اما پس از آن باید دوباره شتاب بگیرید و در نتیجه سوخت مصرف می‌کنید.</div>',0,'Unnötiges Beschleunigen und unnötiges Abbremsen vermeiden',1,1,''),
(745,'1.5.01-110','Bei „Grün“ immer voll beschleunigen','Always accelerate to the maximum when the traffic light changes to green','هنگام «سبز» شدن چراغ، همیشه با تمام قدرت شتاب بگیرید.','<div dir=\'rtl\'>هرچه با شدت بیشتری شتاب بگیرید، سوخت سریع‌تر و بیشتر مصرف می‌شود. این کار باعث آلودگی بیشتر محیط زیست نیز می‌شود.</div>',0,'Bei „Grün“ immer voll beschleunigen',1,0,''),
(746,'1.5.01-114','Schon beim Kauf eines Kraftfahrzeugs auf den Kraftstoffverbrauch achten','Paying attention to the fuel consumption of a motor vehicle when buying it','هنگام خرید وسیله نقلیه موتوری، به مصرف سوخت آن توجه کنید.','<div dir=\'rtl\'>اگر هنگام خرید خودرو، وسیله‌ای را انتخاب کنید که مصرف سوخت کمی دارد، در درازمدت در هزینه‌ها صرفه‌جویی کرده و آلودگی محیط زیست را کاهش می‌دهید.</div>',0,'Schon beim Kauf eines Kraftfahrzeugs auf den Kraftstoffverbrauch achten',1,1,''),
(747,'1.5.01-114','Durch vorausschauende Fahrweise zu einem gleichmäßigen Verkehrsfluss beitragen','Contributing to a constant flow of traffic by thinking ahead and driving correspondingly','با رانندگی پیش‌بینانه به جریان یکنواخت ترافیک کمک کنید.','<div dir=\'rtl\'>اگر با رانندگی پیش‌بینانه از ترمزگیری و شتاب‌گیری مکرر جلوگیری کنید، در مصرف سوخت صرفه‌جویی کرده و آلودگی محیط زیست را کاهش می‌دهید.</div>',0,'Durch vorausschauende Fahrweise zu einem gleichmäßigen Verkehrsfluss beitragen',1,1,''),
(748,'1.5.01-114','Nach Möglichkeit öffentliche Verkehrsmittel benutzen, mit dem Fahrrad fahren oder zu Fuß gehen','Using public transport, a bicycle or walking, wherever possible','در صورت امکان از وسایل حمل و نقل عمومی استفاده کنید، دوچرخه سواری کنید یا پیاده بروید.','<div dir=\'rtl\'>اگر استفاده از وسیله نقلیه را کاهش دهید، به طور طبیعی در مصرف سوخت صرفه‌جویی می‌شود. این کار برای محیط زیست نیز مفید است، زیرا گازهای خروجی کمتری وارد جو می‌شوند.</div>',0,'Nach Möglichkeit öffentliche Verkehrsmittel benutzen, mit dem Fahrrad fahren oder zu Fuß gehen',1,1,''),
(749,'1.5.01-115','- Kurzstreckenfahrten','- driving short distances','- سفرهای کوتاه','<div dir=\'rtl\'>مسافت‌های کوتاه را می‌توان پیاده، با دوچرخه یا وسایل حمل و نقل عمومی نیز طی کرد. به این ترتیب می‌توانید از محیط زیست محافظت کرده و علاوه بر آن در مصرف سوخت نیز صرفه‌جویی کنید.</div>',0,'- Kurzstreckenfahrten',1,1,''),
(750,'1.5.01-115','- Fahrten mit Vollgas','- driving at flat-out speed','- رانندگی با حداکثر سرعت (گاز کامل)','<div dir=\'rtl\'>رانندگی با حداکثر سرعت (گاز کامل) سوخت زیادی مصرف می‌کند و بی‌جهت محیط زیست را آلوده می‌کند.</div>',0,'- Fahrten mit Vollgas',1,1,''),
(751,'1.5.01-115','- Fahrten in überfüllte Innenstädte','- driving in crowded city centres','- رانندگی در مراکز شهرهای شلوغ','<div dir=\'rtl\'>در مراکز شهرهای شلوغ اغلب ترافیک «توقف و حرکت» وجود دارد. بنابراین، به دلیل حجم بالای ترافیک، باید مکرراً حرکت کرده و دوباره ترمز کنید که این کار سوخت زیادی مصرف کرده و محیط زیست را آلوده می‌کند.</div>',0,'- Fahrten in überfüllte Innenstädte',1,1,''),
(752,'1.7.01-003','Durch den Kurvenradius','','توسط شعاع پیچ','<div dir=\'rtl\'>نیروی گریز از مرکز هرچه پیچ تندتر باشد، قوی‌تر است. پیچ هرچه شعاع انحنای کوچکتر و سرعت خودروی در حال حرکت بیشتر باشد، تندتر است.</div>',0,'Durch den Kurvenradius',1,1,''),
(753,'1.7.01-003','Durch die Geschwindigkeit','','توسط سرعت','<div dir=\'rtl\'>اندازه نیروی گریز از مرکز در یک پیچ هم توسط سرعت و هم توسط شعاع انحنای پیچ تحت تأثیر قرار می‌گیرد. هرچه پیچ تندتر باشد، اندازه نیروی گریز از مرکز بیشتر است.</div>',0,'Durch die Geschwindigkeit',1,1,''),
(754,'1.7.01-003','Durch den Fahrtwind','','توسط باد ناشی از حرکت','<div dir=\'rtl\'>باد ناشی از حرکت بر اندازه نیروی گریز از مرکز تأثیری ندارد.</div>',0,'Durch den Fahrtwind',1,0,''),
(755,'2.1.01-004','Durch Kurvenschneiden','Cutting corners','با بریدن پیچ','<div dir=\'rtl\'>با بریدن پیچ، بخشی از خودرو در مسیر مقابل یا بسیار نزدیک به آن قرار می‌گیرد. به خصوص در پیچ‌ها، دید رانندگان از ترافیک مقابل محدود است. این می‌تواند منجر به تصادفات خطرناک شود.</div>',0,'Durch Kurvenschneiden',1,1,''),
(756,'2.1.01-004','Durch zu spätes Abblenden','Dipping your headlights too late','با دیر خاموش کردن نور بالا','<div dir=\'rtl\'>نور بالا رانندگان مقابل را خیره می‌کند. این می‌تواند منجر به موقعیت‌های ترافیکی خطرناک شود، زیرا رانندگان به دلیل خیرگی تنها می‌توانند وضعیت ترافیک را به طور محدود ارزیابی کنند.</div>',0,'Durch zu spätes Abblenden',1,1,''),
(757,'2.1.01-004','Durch zu großen Abstand nach vorn','Driving too far behind the vehicle in front','با فاصله زیاد از خودروی جلویی','<div dir=\'rtl\'>این کار ایمنی را افزایش می‌دهد و خطری ایجاد نمی‌کند.</div>',0,'Durch zu großen Abstand nach vorn',1,0,''),
(758,'2.1.01-102','In der Nähe solcher Fahrzeuge verlieren Blinde die Orientierung','Blind people lose their orientation when they are near the car','در نزدیکی چنین وسایل نقلیه‌ای، افراد نابینا جهت‌یابی خود را از دست می‌دهند.','<div dir=\'rtl\'>حس شنوایی در افراد نابینا قوی‌تر از افراد بینا است. موسیقی بلند نشانه‌های صوتی محیط را که افراد نابینا با کمک آن‌ها جهت‌یابی می‌کنند، تحت‌الشعاع قرار می‌دهد.</div>',0,'In der Nähe solcher Fahrzeuge verlieren Blinde die Orientierung',1,1,''),
(759,'2.1.01-102','Die Aufmerksamkeit des Fahrers wird erheblich beeinträchtigt','The driver’s attention is significantly impaired','توجه راننده به طور قابل توجهی مختل می‌شود.','<div dir=\'rtl\'>موسیقی بسیار بلند، راننده را از رانندگی متمرکز منحرف می‌کند.</div>',0,'Die Aufmerksamkeit des Fahrers wird erheblich beeinträchtigt',1,1,''),
(760,'2.1.01-102','Blinde erkennen dadurch leichter den Verlauf der Fahrbahn','It makes it easier for blind people to recognise where the road is','افراد نابینا به این ترتیب مسیر جاده را راحت‌تر تشخیص می‌دهند.','<div dir=\'rtl\'>افراد نابینا ممکن است به این دلیل جهت‌یابی خود را از دست بدهند.</div>',0,'Blinde erkennen dadurch leichter den Verlauf der Fahrbahn',1,0,''),
(761,'2.1.03-015','Hohe Geschwindigkeit','High speed','سرعت بالا','<div dir=\'rtl\'>هرچه سرعت بیشتر باشد، خطر آب‌سواری بیشتر است. در سرعت‌های پایین، آب می‌تواند توسط لاستیک‌ها به کنار رانده شود، اما در سرعت‌های بالاتر، این زمان وجود ندارد و خودرو روی لایه آب سر می‌خورد.</div>',0,'Hohe Geschwindigkeit',1,1,''),
(762,'2.1.03-015','Abgefahrene Reifen','Worn tyres','لاستیک‌های فرسوده','<div dir=\'rtl\'>هرچه عمق آج لاستیک بیشتر باشد، فضای بیشتری در شیارهای آج برای چسبیدن به سطح جاده، با وجود لایه آب، وجود دارد.</div>',0,'Abgefahrene Reifen',1,1,''),
(763,'2.1.03-015','Spurrillen in der Fahrbahn','Grooves in the roadway','شیارهای چرخ در جاده','<div dir=\'rtl\'>در جاده‌های فرسوده، آب در شیارهای چرخ جمع می‌شود، در حالی که در جاده‌های هموار، آب در کل سطح جاده پخش می‌شود. بنابراین، در اینجا سطح آب بالاتر است و خودروها به دلیل آب‌سواری راحت‌تر دچار لغزش می‌شوند.</div>',0,'Spurrillen in der Fahrbahn',1,1,''),
(764,'2.1.03-025','Zu Schleuder- und Rutschgefahr','Danger of sliding and skidding','به خطر لغزش و سر خوردن','<div dir=\'rtl\'>به دلیل بدتر شدن وضعیت سطح جاده، چسبندگی لاستیک‌ها به زمین نیز می‌تواند کاهش یابد. بنابراین، یک وسیله نقلیه بیشتر در معرض سر خوردن یا لغزش قرار می‌گیرد.</div>',0,'Zu Schleuder- und Rutschgefahr',1,1,''),
(765,'2.1.03-025','Zu veränderten Reifengeräuschen','Changes in tyre noise','به تغییر صداهای لاستیک','<div dir=\'rtl\'>صدای غلتش لاستیک‌ها به کیفیت سطح جاده بستگی دارد. بنابراین، این صدا نیز بسته به وضعیت سطح جاده تغییر می‌کند.</div>',0,'Zu veränderten Reifengeräuschen',1,1,''),
(766,'2.1.03-025','Zu längerem Reaktionsweg','Longer reaction distance','به مسافت واکنش طولانی‌تر','<div dir=\'rtl\'>زمان واکنش شما تغییری نمی‌کند. تشخیص یک مانع یا خطر ربطی به کیفیت سطح جاده ندارد.</div>',0,'Zu längerem Reaktionsweg',1,0,''),
(767,'2.1.03-101','In Fahrbahnsenken','In dips in the roadway','در فرورفتگی‌های سطح جاده','<div dir=\'rtl\'>در اینجا آب به‌ویژه به‌راحتی جمع می‌شود که می‌تواند منجر به آب‌لغزش شود.</div>',0,'In Fahrbahnsenken',1,1,''),
(768,'2.1.03-101','Bei Spurrillen in der Fahrbahn','Where there are grooves in the roadway','در شیارهای چرخ در سطح جاده','<div dir=\'rtl\'>شیارهای چرخ، فرورفتگی‌هایی در سطح جاده هستند که در اثر فرسودگی جاده ایجاد شده‌اند. در اینجا احتمال آب‌لغزش بیشتر است تا در سطوح صاف.</div>',0,'Bei Spurrillen in der Fahrbahn',1,1,''),
(769,'2.1.03-101','An Bahnübergängen','At level crossings','در گذرگاه‌های راه‌آهن','<div dir=\'rtl\'>در اینجا نباید انتظار خطر افزایش‌یافته آب‌لغزش را داشت.</div>',0,'An Bahnübergängen',1,0,''),
(770,'2.1.03-103','Auf eine gefährliche Schmierschicht auf der Fahrbahn','A dangerous greasy film on the surface of the road','یک لایه لغزنده خطرناک روی سطح جاده','<div dir=\'rtl\'>کثیفی و سایر رسوبات در صورت عدم بارندگی روی سطح جاده باقی می‌مانند. به محض شروع بارندگی، ممکن است این رسوبات یک لایه لغزنده و لغزنده ایجاد کنند.</div>',0,'Auf eine gefährliche Schmierschicht auf der Fahrbahn',1,1,''),
(771,'2.1.03-103','Auf schlechtere Sicht gleich nach Einschalten der Scheibenwischer','Bad visibility immediately upon switching the windscreen wipers on','کاهش دید بلافاصله پس از روشن کردن برف‌پاک‌کن‌ها','<div dir=\'rtl\'>اگر برف‌پاک‌کن‌ها برای مدت طولانی استفاده نشده باشند، رسوباتی روی آن‌ها جمع می‌شود که در ابتدای استفاده مجدد می‌توانند رگه‌هایی روی شیشه باقی بگذارند.</div>',0,'Auf schlechtere Sicht gleich nach Einschalten der Scheibenwischer',1,1,''),
(772,'2.1.03-103','Auf einen kürzeren Bremsweg','Shorter braking distance','مسافت ترمز کوتاه‌تر','<div dir=\'rtl\'>هنگامی که شرایط سطح جاده بدتر می‌شود، مسافت ترمز بیشتر طولانی می‌شود تا اینکه کوتاه شود.</div>',0,'Auf einen kürzeren Bremsweg',1,0,''),
(773,'2.1.03-104','Weil sich ein Schmierfilm bilden kann, der den Bremsweg verlängert','Because a greasy film may form which increases the braking distance','زیرا ممکن است یک لایه چرب تشکیل شود که مسافت ترمز را طولانی‌تر می‌کند.','<div dir=\'rtl\'>به دلیل لایه چرب، چسبندگی لاستیک‌ها به سطح جاده کاهش یافته و مسافت ترمز طولانی‌تر می‌شود.</div>',0,'Weil sich ein Schmierfilm bilden kann, der den Bremsweg verlängert',1,1,''),
(774,'2.1.03-104','Weil die Sicht schlechter werden kann und die Scheibenwischer nicht sofort ein klares Sichtfeld schaffen','Because visibility may become worse and the windscreen wipers do not immediately provide a clear field of vision','زیرا دید ممکن است بدتر شود و برف‌پاک‌کن‌ها بلافاصله یک میدان دید واضح ایجاد نمی‌کنند.','<div dir=\'rtl\'>معمولاً برف‌پاک‌کن‌ها باید چند بار حرکت کنند تا دید واضح شود. بنابراین، دید ممکن است برای مدت کوتاهی بدتر شود.</div>',0,'Weil die Sicht schlechter werden kann und die Scheibenwischer nicht sofort ein klares Sichtfeld schaffen',1,1,''),
(775,'2.1.03-104','Weil die Bremsen schneller ansprechen','Because the brakes react more quickly','زیرا ترمزها سریع‌تر عمل می‌کنند.','<div dir=\'rtl\'>ترمزها در شرایط رانندگی نامساعد، بهتر عمل نمی‌کنند.</div>',0,'Weil die Bremsen schneller ansprechen',1,0,''),
(776,'2.1.03-105','Nein, weil der Gegenverkehr gefährdet werden kann','No, because it could represent a danger to oncoming traffic','خیر، زیرا ترافیک روبرو می‌تواند به خطر بیفتد.','<div dir=\'rtl\'>شما هرگز نباید دائماً روی خط ممتد رانندگی کنید. به خصوص زمانی که دید ضعیف است، مانند شرایط مه غلیظ. وسایل نقلیه روبرو ممکن است دیر تشخیص داده شوند.</div>',0,'Nein, weil der Gegenverkehr gefährdet werden kann',1,1,''),
(777,'2.1.03-105','Ja, wenn Nebelscheinwerfer und Nebelschlussleuchte eingeschaltet sind','Yes, if fog headlamps and rear fog lamps are switched on','بله، اگر چراغ‌های مه‌شکن جلو و چراغ مه‌شکن عقب روشن باشند.','<div dir=\'rtl\'>شما مجاز نیستید در اینجا از خط ممتد عبور کنید.</div>',0,'Ja, wenn Nebelscheinwerfer und Nebelschlussleuchte eingeschaltet sind',1,0,''),
(778,'2.1.03-105','Ja, weil man weniger in Gefahr gerät, von der Fahrbahn abzukommen','Yes, because it reduces the risk of running off the road','بله، زیرا کمتر در معرض خطر انحراف از جاده قرار می‌گیرید.','<div dir=\'rtl\'>شما باید در مسیر خود بمانید، زیرا به دلیل مه غلیظ، وسایل نقلیه روبرو را دیر تشخیص می‌دهید.</div>',0,'Ja, weil man weniger in Gefahr gerät, von der Fahrbahn abzukommen',1,0,''),
(779,'2.1.03-106','Geschwindigkeit sofort den Sichtverhältnissen anpassen','Adapt speed immediately to visibility conditions','سرعت را بلافاصله با توجه به شرایط دید تنظیم کنید.','<div dir=\'rtl\'>مه دید را مختل می‌کند. بنابراین باید فوراً سرعت را تنظیم کنید تا کسی را به خطر نیندازید.</div>',0,'Geschwindigkeit sofort den Sichtverhältnissen anpassen',1,1,''),
(780,'2.1.03-106','Abblendlicht einschalten','Switch on dipped headlights','چراغ نور پایین را روشن کنید.','<div dir=\'rtl\'>برای اینکه توسط سایر کاربران جاده بهتر دیده شوید و همچنین خودتان بهتر ببینید، باید چراغ نور پایین را روشن کنید.</div>',0,'Abblendlicht einschalten',1,1,''),
(781,'2.1.03-106','Nur Standlicht einschalten','Only switch on parking lights','فقط چراغ کوچک (پارک) را روشن کنید.','<div dir=\'rtl\'>چراغ کوچک (پارک) کافی نیست. شما باید چراغ نور پایین را روشن کنید.</div>',0,'Nur Standlicht einschalten',1,0,''),
(782,'2.1.03-107','Bei Nebel den Scheibenwischer von Zeit zu Zeit einschalten','Switch on the windscreen wipers from time to time when it is foggy','در مه، برف پاک کن را هر از گاهی روشن کنید','<div dir=\'rtl\'>مه از قطرات ریز آب تشکیل شده است که به مرور زمان می توانند روی شیشه جلو نیز جمع شوند. بنابراین، هر از گاهی برف پاک کن را روشن کنید تا دید را بهبود بخشید.</div>',0,'Bei Nebel den Scheibenwischer von Zeit zu Zeit einschalten',1,1,''),
(783,'2.1.03-107','Bei Schneematsch die Scheibenwischer schon einschalten, bevor Ihnen andere Fahrzeuge Matsch auf die Scheibe schleudern','When there is slush, switch on the windscreen wipers already before slush is thrown onto your windscreen by other vehicles','در برف و گل، برف پاک کن ها را از قبل روشن کنید، قبل از اینکه وسایل نقلیه دیگر گل و لای را روی شیشه شما بپاشند','<div dir=\'rtl\'>به این ترتیب گل و لای بلافاصله پاک می شود، به محض اینکه روی شیشه قرار گیرد و دید شما برای مدت کمتری محدود خواهد بود.</div>',0,'Bei Schneematsch die Scheibenwischer schon einschalten, bevor Ihnen andere Fahrzeuge Matsch auf die Scheibe schleudern',1,1,''),
(784,'2.1.03-107','Bei innen beschlagener Scheibe Lüftung ausschalten und Fenster geschlossen halten','When the windscreen is steamed up, switch the ventilator off and keep the windows closed','هنگام بخار گرفتن شیشه از داخل، تهویه را خاموش کرده و پنجره ها را بسته نگه دارید','<div dir=\'rtl\'>برعکس. هنگام بخار گرفتن شیشه از داخل، باید تهویه را روشن کرده و پنجره ها را باز کنید.</div>',0,'Bei innen beschlagener Scheibe Lüftung ausschalten und Fenster geschlossen halten',1,0,''),
(785,'2.1.04-002','Sofort abblenden','Immediately dip your headlights','بلافاصله نور پایین بزنید','<div dir=\'rtl\'>حیوان وحشی در پرتو نور می‌ایستد. بنابراین باید نور پایین زده شود تا حیوان وحشی وضعیت را خطرناک درک کند.</div>',0,'Sofort abblenden',1,1,''),
(786,'2.1.04-002','Hupen und bremsen','Sound the horn and brake','بوق بزنید و ترمز کنید','<div dir=\'rtl\'>در مواقع اضطراری باید آماده توقف باشید تا حیوان وحشی بتواند از جاده عبور کند، بدون اینکه کسی به خطر بیفتد.</div>',0,'Hupen und bremsen',1,1,''),
(787,'2.1.04-002','Mit Fernlicht unverändert weiterfahren','Proceed on full beam','با نور بالا بدون تغییر به رانندگی ادامه دهید','<div dir=\'rtl\'>باید نور پایین بزنید، زیرا در غیر این صورت حیوان وحشی در پرتو نور می‌ایستد.</div>',0,'Mit Fernlicht unverändert weiterfahren',1,0,''),
(788,'2.1.04-102','Durch Spiegelung auf der nassen Fahrbahn können Sie geblendet werden','You can be dazzled by reflections on the wet road','ممکن است به دلیل بازتاب نور روی سطح خیس جاده خیره شوید','<div dir=\'rtl\'>چراغ‌های وسایل نقلیه می‌توانند روی سطح خیس جاده منعکس شوند. اگر به شدت خیره شدید، خود را با لبه سمت راست جاده هماهنگ کنید. در صورت لزوم سرعت خود را کاهش دهید.</div>',0,'Durch Spiegelung auf der nassen Fahrbahn können Sie geblendet werden',1,1,''),
(789,'2.1.04-102','Durch Schlieren auf der Windschutzscheibe verschlechtert sich die Sicht','Your wet windscreen can result in your being dazzled','دید به دلیل لکه‌ها روی شیشه جلو بدتر می‌شود','<div dir=\'rtl\'>نحوه رانندگی خود را با شرایط دید تطبیق دهید.</div>',0,'Durch Schlieren auf der Windschutzscheibe verschlechtert sich die Sicht',1,1,''),
(790,'2.1.04-102','Durch Einschalten von Fernlicht können Sie eine Blendung vermeiden','You can avoid possible dazzle by switching on full beam','با روشن کردن نور بالا می‌توانید از خیرگی جلوگیری کنید','<div dir=\'rtl\'>نور بالا باعث خیرگی وسایل نقلیه روبرو می‌شود و شرایط دید را بهبود نمی‌بخشد.</div>',0,'Durch Einschalten von Fernlicht können Sie eine Blendung vermeiden',1,0,''),
(791,'2.1.05-002','Das Gefühl für die Geschwindigkeit lässt nach','You lose your feel for speed','حس سرعت کاهش می‌یابد','<div dir=\'rtl\'>فرد به سرعت عادت می‌کند. در نتیجه، این خطر وجود دارد که در موقعیت‌های خطرناک با تأخیر واکنش نشان دهد.</div>',0,'Das Gefühl für die Geschwindigkeit lässt nach',1,1,''),
(792,'2.1.05-002','Es wird zu dicht aufgefahren','You drive too close to vehicles in front','فاصله بیش از حد نزدیک می‌شود','<div dir=\'rtl\'>سرعت بالا دیگر به عنوان سرعت بالا درک نمی‌شود و در نتیجه، فاصله‌ها بزرگ‌تر از آنچه واقعاً هستند تخمین زده می‌شوند.</div>',0,'Es wird zu dicht aufgefahren',1,1,''),
(793,'2.1.05-002','Die Reaktionsbereitschaft nimmt zu','Your reactions improve','آمادگی واکنش افزایش می‌یابد','<div dir=\'rtl\'>آمادگی واکنش در رانندگی طولانی‌مدت کاهش می‌یابد.</div>',0,'Die Reaktionsbereitschaft nimmt zu',1,0,''),
(794,'2.1.05-101','Das gleichzeitige Abschätzen des Seitenabstands zu den Bäumen und zum Gegenverkehr','To estimate the lateral distance to the trees and oncoming traffic simultaneously','تخمین همزمان فاصله جانبی تا درختان و تا ترافیک روبرو','<div dir=\'rtl\'>این برای عبور ایمن از کنار هر دو ضروری است. در صورت تردید، ترجیحاً آهسته‌تر برانید.</div>',0,'Das gleichzeitige Abschätzen des Seitenabstands zu den Bäumen und zum Gegenverkehr',1,1,''),
(795,'2.1.05-101','Dass bei einem entgegenkommenden breiten Fahrzeug unter Umständen in der halben übersehbaren Strecke angehalten werden muss','It may be necessary to stop within half the visible distance when a wide vehicle is coming from the opposite direction','اینکه در صورت مواجهه با یک وسیله نقلیه پهن روبرو، ممکن است لازم باشد در نیمی از مسافت قابل دید توقف کنید.','<div dir=\'rtl\'>به این ترتیب، شما و آن وسیله نقلیه زمان کافی برای کاهش سرعت و همچنین عبور ایمن و بدون ایجاد خطر از کنار یکدیگر خواهید داشت.</div>',0,'Dass bei einem entgegenkommenden breiten Fahrzeug unter Umständen in der halben übersehbaren Strecke angehalten werden muss',1,1,''),
(796,'2.1.05-101','Die schnell wechselnden Lichtverhältnisse erleichtern das Abschätzen der seitlichen Abstände','Rapidly changing light conditions make it easier to estimate lateral distances','شرایط نوری که به سرعت تغییر می‌کنند، تخمین فاصله‌های جانبی را آسان می‌کنند.','<div dir=\'rtl\'>تغییر سریع نور و سایه به دلیل درختان، تخمین فاصله‌های جانبی را آسان نمی‌کند، بلکه دشوارتر می‌سازد. چشم‌ها باید هر بار دوباره به شرایط نوری عادت کنند.</div>',0,'Die schnell wechselnden Lichtverhältnisse erleichtern das Abschätzen der seitlichen Abstände',1,0,''),
(797,'2.1.07-101','Wenn er plötzlich von starkem Seitenwind erfasst wird','It is suddenly hit by a gust of strong side wind','هنگامی که ناگهان در معرض باد شدید جانبی قرار گیرد','<div dir=\'rtl\'>به دلیل باد شدید جانبی، ممکن است یک خودروی سواری به پهلو منحرف شود.</div>',0,'Wenn er plötzlich von starkem Seitenwind erfasst wird',1,1,''),
(798,'2.1.07-101','Wenn ein Reifen platzt','A burst tyre','هنگامی که یک تایر می‌ترکد','<div dir=\'rtl\'>در صورت ترکیدن تایر، دیگر بارگذاری یکنواختی وجود ندارد. ممکن است، به خصوص در سرعت‌های بالا، خودرو به پهلو منحرف شود.</div>',0,'Wenn ein Reifen platzt',1,1,''),
(799,'2.1.07-101','Wenn plötzlich Gegenwind auftritt','Sudden headwind','هنگامی که ناگهان باد مخالف می‌وزد','<div dir=\'rtl\'>باد مخالف می‌تواند سرعت شما را کاهش دهد، اما از آنجایی که از روبرو می‌آید، عامل انحراف جانبی نیست.</div>',0,'Wenn plötzlich Gegenwind auftritt',1,0,''),
(800,'2.1.07-102','Das Beobachten der Kolonne durch die Scheiben der Vorausfahrenden','Watching the queue through the windows of the vehicles travelling in front','مشاهده ستون خودروها از طریق شیشه‌های خودروهای جلویی','<div dir=\'rtl\'>اینگونه می‌توانی خود را زودتر با تغییرات وفق دهی.</div>',0,'Das Beobachten der Kolonne durch die Scheiben der Vorausfahrenden',1,1,''),
(801,'2.1.07-102','Leicht versetztes Fahren im eigenen Fahrstreifen','Driving in a slightly staggered position in your own lane','رانندگی کمی جابجا شده در خط عبور خود','<div dir=\'rtl\'>اینگونه بهتر می‌بینی که چه اتفاقی در جلوی تو می‌افتد و می‌توانی زودتر به آن واکنش نشان دهی.</div>',0,'Leicht versetztes Fahren im eigenen Fahrstreifen',1,1,''),
(802,'2.1.07-102','Fahren mit ständig eingeschaltetem Warnblinklicht','Keeping your hazard warning lights switched on when driving','رانندگی با چراغ‌های هشداردهنده (فلاشر) همیشه روشن','<div dir=\'rtl\'>این در این مورد مجاز نیست، زیرا در اینجا نیازی به هشدار دادن به کسی نداری.</div>',0,'Fahren mit ständig eingeschaltetem Warnblinklicht',1,0,''),
(803,'2.1.07-106','Gas wegnehmen, wenn nötig gegenlenken und vorsichtig abbremsen','Throttle down, if necessary, steer against and brake cautiously','گاز را رها کنید، در صورت لزوم فرمان را به سمت مخالف بچرخانید و با احتیاط ترمز کنید.','<div dir=\'rtl\'>در مرحله بعد، باید خودرو را به شانه راه هدایت کنید تا مانع ادامه جریان ترافیک نشوید. سرعت را کاهش دهید و از مانورهای خطرناک خودداری کنید.</div>',0,'Gas wegnehmen, wenn nötig gegenlenken und vorsichtig abbremsen',1,1,''),
(804,'2.1.07-106','Möglichst auf dem Seitenstreifen anhalten, Warnblinklicht einschalten und Warndreieck aufstellen','Stop, if possible, on the hard shoulder, switch on hazard warning lights and place the warning triangle','در صورت امکان در شانه راه توقف کنید، چراغ‌های هشداردهنده (فلاشر) را روشن کرده و مثلث هشدار را قرار دهید.','<div dir=\'rtl\'>شما باید خودرو را در اسرع وقت از مسیر حرکت خارج کنید. سپس فراموش نکنید که قبل از پیاده شدن از خودرو، جلیقه ایمنی خود را بپوشید. پس از ایمن‌سازی محل خرابی، باید با خدمات امداد خودرو تماس بگیرید.</div>',0,'Möglichst auf dem Seitenstreifen anhalten, Warnblinklicht einschalten und Warndreieck aufstellen',1,1,''),
(805,'2.1.07-106','Sofort Vollbremsung durchführen, anschließend auf den Seitenstreifen wechseln','Immediately apply the brakes fully and move over onto the hard shoulder','بلافاصله ترمز کامل بگیرید، سپس به شانه راه بروید.','<div dir=\'rtl\'>از ترمز کامل با لاستیک ترکیده باید خودداری کرد، زیرا احتمالاً بلافاصله دچار لغزش خواهید شد.</div>',0,'Sofort Vollbremsung durchführen, anschließend auf den Seitenstreifen wechseln',1,0,''),
(806,'2.1.08-005-B','Mit einem Fahrstreifenwechsel des Vorausfahrenden','The vehicle in front changing lanes','با تغییر خط حرکت خودروی جلویی','<div dir=\'rtl\'>یک تابلو نشان می‌دهد که در فاصله ۲۰۰ متری، خط سمت چپ با خط سمت راست ادغام می‌شود. بنابراین خط سمت چپ حذف می‌شود. به همین دلیل، خودروی جلویی به خط شما تغییر مسیر خواهد داد.</div>',0,'Mit einem Fahrstreifenwechsel des Vorausfahrenden',1,1,''),
(807,'2.1.08-005-B','Mit einer Verdichtung des Verkehrs hinter der Unterführung','Denser traffic beyond the underpass','با متراکم شدن ترافیک پشت زیرگذر','<div dir=\'rtl\'>زیرا در اینجا جاده تک‌مسیره می‌شود، ترافیک پس از ادغام خطوط حرکت می‌تواند متراکم شود.</div>',0,'Mit einer Verdichtung des Verkehrs hinter der Unterführung',1,1,''),
(808,'2.1.08-005-B','Mit dem Ende des rechten Fahrstreifens','The right-hand lane coming to an end','با پایان یافتن خط حرکت سمت راست','<div dir=\'rtl\'>خط حرکت سمت چپ به پایان می‌رسد.</div>',0,'Mit dem Ende des rechten Fahrstreifens',1,0,''),
(809,'2.1.08-008-B','Möglichst Warnblinklicht einschalten, um nachfolgende Fahrzeuge zu warnen','If possible, switch on hazard warning lights to warn vehicles following behind','تا حد امکان چراغ‌های هشداردهنده (فلاشر) را روشن کنید تا وسایل نقلیه پشت سر را هشدار دهید.','<div dir=\'rtl\'>به این ترتیب ترافیک پشت سر می‌تواند به موقع به آن واکنش نشان دهد.</div>',0,'Möglichst Warnblinklicht einschalten, um nachfolgende Fahrzeuge zu warnen',1,1,''),
(810,'2.1.08-008-B','So weit rechts wie möglich fahren, um links Platz für eine Gasse zu machen','Drive as far as possible to the right in order to leave room for a channel on the left','تا حد امکان به سمت راست برانید تا در سمت چپ فضایی برای یک مسیر اضطراری (Rettungsgasse) ایجاد کنید.','<div dir=\'rtl\'>مسیر اضطراری (Rettungsgasse) باید بین خط عبور سمت چپ و خط عبور میانی ایجاد شود.</div>',0,'So weit rechts wie möglich fahren, um links Platz für eine Gasse zu machen',1,1,''),
(811,'2.1.08-008-B','So weit links wie möglich fahren, um rechts Platz für eine Gasse zu machen','Drive as far as possible to the left in order to leave room for a channel on the right','تا حد امکان به سمت چپ برانید تا در سمت راست فضایی برای یک مسیر اضطراری (Rettungsgasse) ایجاد کنید.','<div dir=\'rtl\'>مسیر اضطراری (Rettungsgasse) باید بین خط عبور سمت چپ و خط عبور میانی ایجاد شود.</div>',0,'So weit links wie möglich fahren, um rechts Platz für eine Gasse zu machen',1,0,''),
(812,'2.1.10-002','Rechtzeitige und ausreichende Pausen','By well-timed and sufficient stops for rests','استراحت‌های به موقع و کافی','<div dir=\'rtl\'>هنگام رانندگی، تمرکز مداوم ضروری است. برای حفظ این تمرکز در یک سفر طولانی، باید در فواصل زمانی مشخص، استراحت‌های طولانی‌تری داشته باشید که در آن‌ها در هوای آزاد حرکت کنید.</div>',0,'Rechtzeitige und ausreichende Pausen',1,1,''),
(813,'2.1.10-002','Gymnastische Übungen während der Pausen','Gymnastic exercises during stops','تمرینات ژیمناستیک در طول استراحت','<div dir=\'rtl\'>حرکت در طول استراحت برای مقابله با خستگی در سفرهای طولانی ضروری است. این کار گردش خون را تحریک کرده و مغز شما را با اکسیژن کافی تامین می‌کند تا بتوانید دوباره با تمرکز به رانندگی ادامه دهید.</div>',0,'Gymnastische Übungen während der Pausen',1,1,''),
(814,'2.1.10-002','Kaffeetrinken statt Pausen','Drink coffee and make no stops','نوشیدن قهوه به جای استراحت','<div dir=\'rtl\'>قهوه حاوی کافئین است و می‌تواند شما را برای مدت کوتاهی بیدارتر کند، اما برای مقابله با خستگی طولانی‌مدت در رانندگی، تنها از طریق استراحت‌های طولانی، هوای تازه و حرکت می‌توانید اقدام کنید.</div>',0,'Kaffeetrinken statt Pausen',1,0,''),
(815,'2.1.10-101','Starke Emotionen (z. B. Freude, Ärger, Ungeduld)','Strong emotions (e.g. delight, annoyance, impatience)','احساسات شدید (مانند شادی، عصبانیت، بی‌صبری)','<div dir=\'rtl\'>احساسات می‌توانند بر سبک رانندگی شما تأثیر بگذارند. اگر از نظر احساسی به شدت آشفته هستید، باید استراحت کنید تا بتوانید دوباره با تمرکز به رانندگی ادامه دهید.</div>',0,'Starke Emotionen (z. B. Freude, Ärger, Ungeduld)',1,1,''),
(816,'2.1.10-101','Lebhafte Unterhaltung','Animated conversation','گفتگوی پر جنب و جوش','<div dir=\'rtl\'>این کار از رانندگی متمرکز منحرف می‌کند.</div>',0,'Lebhafte Unterhaltung',1,1,''),
(817,'2.1.10-101','Spannende Sendungen im Autoradio','Engrossing programs on the car radio','برنامه‌های هیجان‌انگیز در رادیو خودرو','<div dir=\'rtl\'>از این طریق توجه به برنامه رادیویی معطوف می‌شود که برای رانندگی متمرکز ضروری است.</div>',0,'Spannende Sendungen im Autoradio',1,1,''),
(818,'2.1.10-102','Telefonieren','Telephoning','تلفن صحبت کردن','<div dir=\'rtl\'>در اینجا، علاوه بر رانندگی، روی مکالمه تمرکز می‌کنید. این باعث حواس‌پرتی می‌شود.</div>',0,'Telefonieren',1,1,''),
(819,'2.1.10-102','Anzünden einer Zigarette','Lighting a cigarette','روشن کردن سیگار','<div dir=\'rtl\'>هنگام روشن کردن سیگار، برای مدت کوتاهی نمی‌توانید به جاده نگاه کنید. این شما را از رانندگی ایمن منحرف می‌کند.</div>',0,'Anzünden einer Zigarette',1,1,''),
(820,'2.1.10-102','Quengelnde Kinder auf den Rücksitzen','Nagging children on the backseats','بچه‌های نق‌نقو در صندلی‌های عقب','<div dir=\'rtl\'>در صورت وجود، سرنشین جلو باید به این موضوع رسیدگی کند تا راننده بتواند روی ترافیک تمرکز کند.</div>',0,'Quengelnde Kinder auf den Rücksitzen',1,1,''),
(821,'2.2.02-006','Den mittleren','The middle lane','خط میانی','<div dir=\'rtl\'>در این حالت، شما مجاز به استفاده مداوم از خط میانی هستید، زیرا به طور مداوم در حال سبقت گرفتن هستید.</div>',0,'Den mittleren',1,1,''),
(822,'2.2.02-006','Den linken','The left-hand lane','خط سمت چپ','<div dir=\'rtl\'>شما مجاز به استفاده از خط سمت چپ فقط برای سبقت گرفتن از وسایل نقلیه در خط میانی هستید. از آنجایی که هیچ کس در خط میانی رانندگی نمی‌کند، شما مجاز به استفاده از خط سمت چپ نیز نیستید.</div>',0,'Den linken',1,0,''),
