(833,'2.2.03-016','12,5 m','12.5 m','۱۲.۵ متر','<div dir=\'rtl\'>با اعمال فرمول، نتیجه به دست می‌آید: [(۵۰:۱۰) × (۵۰:۱۰)] : ۲ = ۱۲.۵ متر</div>',0,'12,5 m',1,1,''),
(834,'2.2.03-016','11,0 m','11.0 m','۱۱.۰ متر','<div dir=\'rtl\'>این پاسخ اشتباه است.</div>',0,'11,0 m',1,0,''),
(835,'2.2.03-016','9,5 m','9.5 m','۹.۵ متر','<div dir=\'rtl\'>این پاسخ صحیح نیست. مسافت ترمز در اینجا ۱۲.۵ متر است.</div>',0,'9,5 m',1,0,''),
