(838,'2.2.04-001','Einen „Zwei-Sekunden-Abstand“','A \\\"distance of 2 seconds\\\"','فاصله «دو ثانیه»','<div dir=\'rtl\'>این کافی نیست. باید یک «فاصله دو ثانیه» رعایت شود.</div>',0,'Einen „Zwei-Sekunden-Abstand“',1,1,''),
(839,'2.2.04-001','Einen „Ein-Sekunden-Abstand“','A \\\"distance of 1 second\\\"','فاصله «یک ثانیه»','<div dir=\'rtl\'>این کافی نیست. باید یک «فاصله دو ثانیه» رعایت شود.</div>',0,'Einen „Ein-Sekunden-Abstand“',1,0,''),
(840,'2.2.04-001','Einen Abstand von 15 Metern','A distance of 15 metres','فاصله ۱۵ متری','<div dir=\'rtl\'>فاصله ایمنی به سرعت رانندگی بستگی دارد.</div>',0,'Einen Abstand von 15 Metern',1,0,''),
(841,'2.2.04-002','15 m entsprechend etwa 3 Pkw-Längen','15 m or approximately 3 car lengths','۱۵ متر، معادل تقریباً ۳ طول خودروی سواری','<div dir=\'rtl\'>این فاصله ایمنی کافی نیست.</div>',0,'15 m entsprechend etwa 3 Pkw-Längen',1,1,''),
(842,'2.2.04-002','10 m entsprechend etwa 2 Pkw-Längen','10 m or approximately 2 car lengths','۱۰ متر، معادل تقریباً ۲ طول خودروی سواری','<div dir=\'rtl\'>این فاصله ایمنی کافی نیست.</div>',0,'10 m entsprechend etwa 2 Pkw-Längen',1,0,''),
(843,'2.2.04-002','5 m entsprechend etwa 1 Pkw-Länge','5 m or approximately 1 car length','۵ متر، معادل تقریباً ۱ طول خودروی سواری','<div dir=\'rtl\'>این فاصله ایمنی کافی نیست.</div>',0,'5 m entsprechend etwa 1 Pkw-Länge',1,0,''),
