INSERT INTO `questions` VALUES
(1,'1.1.01-001','','','',NULL,'',4,1,1,0,',49,','','Was versteht man unter defensivem Fahren?','منظور از رانندگی تدافعی چیست؟','What should you understand by defensive driving?','<p>رانندگی تدافعی به معنای رانندگی با احتیاط است، نه لزوماً پافشاری بر حق تقدم خود.<br>مشارکت در ترافیک جاده‌ای مستلزم احتیاط مداوم و احترام متقابل است. بنابراین، رانندگان تدافعی انتظار دارند که سایر کاربران جاده اشتباه کنند. علاوه بر این، رانندگان تدافعی آماده‌اند تا برای حل موقعیت‌های خطرناک، بر حقوق خود پافشاری نکنند.</p>',0),
(2,'1.1.01-002','','4.1',NULL,NULL,'',4,1,1,0,',49,','','Was kann zu Auffahrunfällen führen?','چه چیزی می تواند منجر به تصادف از عقب شود؟','What can be the causes of rear-end collisions?','<p>بی‌توجهی منجر به این می‌شود که واکنش سایر کاربران جاده دیر تشخیص داده شود یا اصلاً تشخیص داده نشود. رانندگی با فاصله خیلی کم، زمان موجود برای واکنش به رفتار وسیله نقلیه جلویی را کاهش می‌دهد.</p><p>فاصله تا وسیله نقلیه جلویی معمولاً باید به اندازه کافی زیاد باشد تا حتی در صورت ترمز ناگهانی، وسیله نقلیه بتواند در پشت آن متوقف شود.</p><p>راننده جلویی نباید بدون دلیل قانع کننده ترمز شدید بگیرد.</p>',0),
(3,'1.1.01-101','','','Der Vorausfahrende','راننده جلویی','The driver in front',3,1,0,0,',49,','','Sie fahren innerorts hinter einem Fahrzeug mit ortsfremdem Kennzeichen. Was könnte geschehen?','شما در یک منطقه مسکونی پشت سر وسیله نقلیه ای با پلاک خارج از شهر رانندگی می کنید. چه اتفاقی ممکن است بیفتد؟','You are driving in a built-up area behind a vehicle with number plates that are not local. What could happen?','<p>با توجه به پلاک خارج از شهر، نمی‌توان این احتمال را رد کرد که راننده جلویی هیچ شناخت محلی ندارد و در نتیجه تصمیمات غیرمنتظره‌ای می‌گیرد. ممکن است وسیله نقلیه جلویی به طور غیرمنتظره ترمز کند. ممکن است دیر راهنما بزند. همچنین می‌تواند به طور غیرمنتظره‌ای متوقف شود.</p>',0),
(4,'1.1.01-102','','1.2; 3.2',NULL,NULL,'',3,1,0,0,',49,','','Was sind vermeidbare Behinderungen im fließenden Verkehr?','موانع قابل اجتناب در جریان ترافیک کدامند؟','What can cause unnecessary obstructions?','<p>یعنی مشکلاتب&nbsp;<span style=\"background-color: initial;\">که در تردد با خوردو می توان جلوی آن ها را گرفت.</span></p><p>مو<span style=\"background-color: initial;\">انع قابل اجتناب، تمام مواردی هستند که صرفاً به دلیل سوء رفتار یا برنامه‌ریزی ناکافی ایجاد می‌شوند. جمله دوم از قانون اساسی در بخش ۱ مقررات راهنمایی و رانندگی آلمان (StVO) بیان می‌کند: هر کسی که در ترافیک شرکت می‌کند باید به گونه‌ای رفتار کند که هیچ شخص دیگری بیش از آنچه که تحت شرایط اجتناب‌ناپذیر است، آسیب نبیند، در معرض خطر قرار نگیرد یا دچار انسداد یا ناراحتی نشود.</span></p><p>وسایل نقلیه موتوری نباید بدون دلیل موجه آنقدر آهسته برانند که مانع جریان ترافیک شوند. با بررسی منظم سطح سوخت می‌توان از خرابی‌های ناشی از کمبود سوخت جلوگیری کرد.</p><p>با تمرین استارت زدن می‌توان از خاموش شدن موتور جلوگیری کرد.</p>',0),
(5,'1.1.01-103','','3.2',NULL,NULL,'',3,1,0,0,',49,','','Warum darf man nicht unnötig langsam fahren?','چرا نباید بی دلیل آهسته رانندگی کرد؟','Why must you not drive extra slowly for no good reason?','<p>وسایل نقلیه موتوری نباید بدون دلیل موجه آنقدر آهسته برانند که مانع جریان ترافیک شوند. رانندگی آهسته خطر تصادف از عقب را افزایش می‌دهد. همچنین می‌تواند رانندگان پشت سر را به سبقت گرفتن تشویق کند.</p>',0),
(6,'1.1.01-107','','',NULL,NULL,'',4,1,0,0,',49,','','Welche Anzeichen warnen während der Fahrt vor aufkommender Müdigkeit?','چه علائمی از خستگی قریب الوقوع هنگام رانندگی هشدار می دهند؟','How can you tell that you are getting tired while you are driving?','<p>سنگینی پلک‌ها و خمیازه کشیدن مکرر، هر دو از نشانه‌های بارز خستگی مفرط هستند. در نتیجه خستگی، زمان واکنش ممکن است طولانی تر شود و در نتیجه خطر تصادفات افزایش یابد</p><p><img src=\"/storage/answers/info/img_69f9855b0ce968.34313858.jpg\" style=\"width: 50%;\"></p><p><br></p>',0),
(7,'1.1.01-108','','',NULL,NULL,'',4,1,0,0,',49,','','Welche Folgen kann die Missachtung von Müdigkeitsanzeichen nach sich ziehen?','نادیده گرفتن علائم خستگی چه عواقبی دارد؟','What can happen if you ignore signs of tiredness?','<p>خستگی اثرات منفی متنوعی بر راننده دارد. این خطر وجود دارد که آنها پشت فرمان به خواب بروند و در نتیجه کنترل وسیله نقلیه خود را از دست بدهند.</p><p>همچنین خطر عدم تمرکز وجود دارد که خطاهای رانندگی را افزایش می‌دهد.</p>',0),
(8,'1.1.01-109','','',NULL,NULL,'',4,1,0,0,',49,','','Was ist zu tun, wenn Sie während der Fahrt Anzeichen von Müdigkeit spüren?','اگر هنگام رانندگی علائم خستگی را احساس کردید، چه باید بکنید؟','What should you do if you start feeling tired while driving?','<p>استراحت به بدن کمک می‌کند تا خود را بازسازی کند و بنابراین می‌تواند به رفع خستگی کمک کند. ورزش در هوای تازه گردش خون را بهبود می‌بخشد و عملکردهای حیاتی را فعال می‌کند</p>',0),
(9,'1.1.01-110','','',NULL,NULL,'',4,1,0,0,',49,','','Wie wirkt sich Müdigkeit beim Fahren aus?','خستگی چگونه رانندگی را تحت تأثیر قرار می دهد؟','How does tiredness affect your driving?','<p>خستگی می‌تواند به طرق مختلفی بر رانندگان تأثیر بگذارد. این می‌تواند منجر به کاهش توجه، اختلال در درک ترافیک و تأخیر در واکنش‌ها شود.</p>',0),
(10,'1.1.01-112','','','','','',4,1,0,0,',49,','','Was kann zum Abkommen von der Fahrbahn führen?','چه چیزی می تواند باعث شود که جاده را ترک کنید؟','What could cause the vehicle to leave the road?','',0),
(11,'1.1.02-005','','','','','',5,1,1,0,',77,','','Mit welchem Verhalten von Kindern müssen Sie an Zebrastreifen rechnen?','چه نوع رفتاری باید از کودکان در خط عابر پیاده انتظار داشته باشید؟','What conduct must you expect of children at zebra crossings?','',0),
(12,'1.1.02-022','','','Dass die Kinder','که بچه ها','That the children',4,1,1,0,',77,','','Womit ist zu rechnen, wenn Kinder an einer Ampel warten?','اگر کودکان پشت چراغ راهنمایی منتظر بمانند چه انتظاری باید داشته باشیم؟','What do you have to reckon with when children are waiting at traffic lights?','',0),
(13,'1.1.02-027','','','','','',4,1,1,0,',77,','','Womit müssen Sie rechnen, wenn ältere Personen mit Gehhilfe die Fahrbahn überqueren?','وقتی افراد مسن برای عبور از جاده از وسایل کمکی پیاده روی (مثلا عصا یا واکر )استفاده می کنند چه انتظاری باید داشته باشید؟','What do you have to reckon with when elderly persons using walking frames cross the road?','',0),
(14,'1.1.02-028','','','','','',4,1,0,0,',77,','','Trotz vorhandenen Gehweges auf der rechten Straßenseite fährt eine Person im Rollstuhl auf der Straße. Wie verhalten Sie sich?','با&nbsp; وجود پیاده رو در سمت راست خیابان، فردی با ویلچر در حال راندن در خیابان است. چگونه رفتار می کنید؟','A person in a wheelchair is travelling along the road although there is a pavement on the right. What do you do?','',0),
(15,'1.1.02-029','','','','','',4,1,0,0,',77,','','Eine Person im Rollstuhl schafft es nach dem Überqueren der Straße nicht, mit dem Rollstuhl den Bordstein zu überwinden, um den Gehweg zu erreichen. Wie verhalten Sie sich?','پس از عبور از خیابان، فردی که روی ویلچر می‌نشیند، نمی‌تواند از حاشیه عبور کند تا به پیاده‌رو برسد. چگونه رفتار می کنید؟','Having crossed the road, a person in a wheelchair cannot get up the curb and onto the pavement. What do you do?','',0),
(16,'1.1.02-032','1.1.02-032.jpg','','','','',4,1,1,0,',77,','','Bei welcher Person müssen Sie mit einer schweren Sehbehinderung rechnen?','با کدام فرد باید انتظار اختلال بینایی شدید داشته باشد؟','Who has a severe visual handicap?','<div dir=\'rtl\'>افراد کم بینا و نابینا را می توان با عصای سفید، سگ راهنما یا بازوبند زرد با سه نقطه سیاه شناسایی کرد.</div>',0),
(17,'1.1.02-039-M','1.1.02-039-M.jpg','','','','',4,1,1,1,',77,','','Wie verhalten Sie sich?','چگونه رفتار می کنید؟','How do you behave?','',0),
(18,'1.1.02-041-M','1.1.02-041-M.jpg','','','','',5,1,1,1,',77,','','Mit welchen Gefahren müssen Sie rechnen?','چه خطراتی را باید انتظار داشت؟','What risks must you be aware of?','',0),
(19,'1.1.02-042-M','1.1.02-042-M.jpg','','','','',5,1,1,1,',77,','','Wie sollten Sie sich verhalten?','چگونه باید رفتار کرد؟','How should you behave?','<div dir=\"rtl\">طبق بخش 3 بند 2 a StVO: \"رانندگان وسایل نقلیه باید با کودکان، کسانی که به کمک نیاز دارند و افراد مسن تر، به ویژه با کاهش سرعت و آمادگی برای ترمز رفتار کنند، به گونه ای که خطری این کاربران جاده را تهدید نکند.\"</div>',0),
(20,'1.1.02-043-M','1.1.02-043-M.jpg','','','','',5,1,1,1,',77,','','Wie müssen Sie sich verhalten?','چگونه باید رفتار کرد؟','How must you behave?','',0),
(21,'1.1.02-108-B','1.1.02-108-B.jpg','20.4','Sie d&uuml;rfen','ما اجازه داریم','You may',4,1,0,0,',77,','','Was müssen Sie in dieser Situation beachten?<pcaption>(Warnblinklicht an)</pcaption>','در این شرایط باید به چه چیزی توجه کنید؟<pcaption>(چراغ های خطر روشن)</pcaption>','What must you heed in this situation?<pcaption>(Hazard warning lights on)</pcaption>','',0),
(22,'1.1.02-110-B','1.1.02-110-B.jpg','','','','',4,1,0,0,',77,','','Was ist in dieser Situation richtig?<pcaption>(Warnblinklicht an)</pcaption>','در این وضعیت چه چیزی صحیح است؟<pcaption>(چراغ‌های هشداردهنده روشن است)</pcaption>','','',1),
(23,'1.1.02-116','1.1.02-116.jpg','20.1; 20.2','Ein- oder aussteigende Fahrg&auml;ste','مسافرانی که سوار یا پیاده می شوند','Passengers boarding or alighting',4,1,1,0,',77,','','Die Straßenbahn ist an der Haltestelle gerade zum Stehen gekommen. Welches Verhalten ist richtig?','تراموا به تازگی در ایستگاه توقف کرده است. کدام رفتار صحیح است؟','The tram has just become stationary at the stop. What is the right course of action?','',0),
(24,'1.1.03-001','','','','','',3,1,1,0,',35,','','Wo müssen Sie besonders mit starker Fahrbahnverschmutzung und Rutschgefahr rechnen?','کجا باید به طور ویژه انتظار آلودگی شدید سطح جاده و خطر لغزش را داشته باشید؟','Where must you particularly reckon with dirt on the roadway and therefore danger of skidding?','',0),
(25,'1.1.03-003','','','','','',4,1,1,0,',35,','','Wo müssen Sie besonders mit Fahrbahnvereisung rechnen?','در کجا باید به طور ویژه انتظار یخ‌زدگی سطح جاده را داشته باشید؟','Where must you especially reckon with ice on the roadway?','',0),
(26,'1.1.03-102-B','1.1.03-102-B.jpg','','','','',4,1,0,0,',35,','','Warum müssen Sie auf dieser Straße besonders aufmerksam fahren?','چرا باید در این جاده با دقت ویژه‌ای رانندگی کنید؟','Why does driving on this stretch of road require greater alertness on the part of the motorist?','',0),
(27,'1.1.03-104','','','','','',4,1,0,0,',35,','','Die Straße ist auf einem kurzen Stück vereist. Was sollen Sie hier möglichst vermeiden?','جاده در یک قسمت کوتاه یخ‌زده است. در اینجا تا حد امکان از چه چیزی باید اجتناب کنید؟','The road is icy for a short distance. What should you avoid here, if possible?','',0),
(28,'1.1.03-105','','','','','',4,1,0,0,',35,','','Wie können Sie beim Fahren gefahrlos feststellen, ob die Fahrbahn vereist ist?','چگونه می توانید هنگام رانندگی با خیال راحت تشخیص دهید که آیا سطح جاده یخ زده است؟','While driving, how can you safely check whether the road is icy?','',0),
(29,'1.1.03-108-B','1.1.03-108-B.jpg','','','','',3,1,0,0,',35,','','Warum müssen Sie hier besonders vorsichtig fahren?','چرا باید در اینجا با احتیاط ویژه رانندگی کنید؟','Why must you drive with particular caution here?','<div dir=\'rtl\'>ماده ۳ قانون راهنمایی و رانندگی (StVO) بیان می‌کند: \"(...) (۱) راننده وسیله نقلیه فقط باید با سرعتی رانندگی کند که بتواند وسیله نقلیه خود را همیشه کنترل کند. او باید سرعت خود را به ویژه با شرایط جاده، ترافیک، دید و آب و هوا، و همچنین با توانایی‌های شخصی خود و ویژگی‌های وسیله نقلیه و بار آن تطبیق دهد. اگر دید به دلیل مه، بارش برف یا باران کمتر از ۵۰ متر باشد، او نباید سریع‌تر از ۵۰ کیلومتر در ساعت رانندگی کند، مگر اینکه سرعت کمتری لازم باشد. او فقط باید با سرعتی رانندگی کند که بتواند در طول مسیر قابل مشاهده توقف کند. اما در مسیرهایی که آنقدر باریک هستند که ممکن است وسایل نقلیه روبرو به خطر بیفتند، او باید آنقدر آهسته رانندگی کند که بتواند حداقل در نیمی از مسیر قابل مشاهده توقف کند. (...)\"</div>',0),
(30,'1.1.03-109','','','','','',3,1,0,0,',35,','','Wo müssen Sie besonders mit plötzlich auftretendem Nebel rechnen?','در کجا باید به طور ویژه انتظار مه ناگهانی را داشته باشید؟','Where must you be prepared to encounter sudden fog?','',0),
(31,'1.1.03-110','','3.1','','','',4,1,0,0,',35,','','Was müssen Sie tun, wenn vor Ihnen ein Nebelfeld die Sicht stark behindert?','اگر یک میدان مه دید شما را به شدت مختل کند، چه کاری باید انجام دهید؟','What do you do if visibility is drastically reduced by fog?','',0),
(32,'1.1.03-114-M','1.1.03-114-M.jpg','','','','',4,1,0,1,',35,','','Warum müssen Sie hier besonders aufmerksam sein?','چرا باید در اینجا توجه ویژه‌ای داشته باشید؟','Why do you have to pay particular attention here?','',0),
(33,'1.1.04-103-B','1.1.04-103-B.jpg','17.2','','','',4,1,0,0,',29,','','Was müssen Sie hier tun, wenn Sie geblendet werden?','در اینجا، اگر خیره شدید، چه کاری باید انجام دهید؟','What must you do in this situation when you are dazzled?','',0),
(34,'1.1.04-107','1.1.04-107.jpg','','','','',4,1,0,0,',29,','','Womit müssen Sie hier rechnen?','در اینجا باید انتظار چه چیزی را داشته باشید؟','What must you be aware of here?','',0),
(35,'1.1.05-001','','','','','',4,1,1,0,',45,','','Wo führt schnelles Fahren häufig zu Unfällen?','رانندگی سریع اغلب در کجا منجر به تصادف می‌شود؟','Where does driving fast often lead to accidents?','',0),
(36,'1.1.05-002','','','','','',4,1,1,0,',45,','','Wo ist zu schnelles Fahren besonders gefährlich?','رانندگی با سرعت زیاد در کجا به خصوص خطرناک است؟','Where is fast driving particularly dangerous?','<div dir=\'rtl\'>ماده ۳ بند ۱ قانون راهنمایی و رانندگی (StVO) مقرر می‌دارد: «راننده وسیله نقلیه فقط باید با سرعتی رانندگی کند که بتواند وسیله نقلیه خود را همیشه کنترل کند. او باید سرعت خود را به ویژه با شرایط جاده، ترافیک، دید و آب و هوا [...] تطبیق دهد.»</div>',0),
(37,'1.1.05-003','','','','','',4,1,1,0,',45,','','Wie durchfahren Sie enge Kurven?','چگونه از پیچ‌های تند عبور می‌کنید؟','How do you take tight bends?','',0),
(38,'1.1.06-002','','5.3','','','',5,1,1,0,',68,','','Ist es leichtsinnig, noch kurz vor einer Kreuzung einen Lastzug zu überholen?','آیا سبقت گرفتن از یک کامیون درست قبل از یک تقاطع بی‌احتیاطی است؟','Is it irresponsible to overtake a truck and trailer a short distance before a crossroads?','',0),
(39,'1.1.06-104','','5.6','Wenn der Eingeholte','اگر وسیله نقلیه سبقت‌گرفته‌شده','When the road user being overtaken',5,1,0,0,',68,','','Wann wird ein Überholender gefährdet?','چه زمانی یک سبقت‌گیرنده به خطر می‌افتد؟','When are you in danger when overtaking?','<div dir=\'rtl\'>ماده ۵ آیین‌نامه راهنمایی و رانندگی: سبقت گرفتن (۱) سبقت گرفتن باید از سمت چپ انجام شود. (۲) سبقت گرفتن تنها زمانی مجاز است که راننده بتواند اطمینان حاصل کند که در طول کل فرآیند سبقت، هیچ مانعی برای ترافیک مقابل ایجاد نمی‌شود. همچنین، سبقت گرفتن تنها زمانی مجاز است که راننده با سرعتی به مراتب بیشتر از وسیله نقلیه‌ای که از آن سبقت گرفته می‌شود، حرکت کند. (۳) سبقت گرفتن در موارد زیر ممنوع است: ۱. در وضعیت ترافیکی نامشخص یا ۲. زمانی که توسط یک تابلوی راهنمایی و رانندگی (تابلوهای ۲۷۶، ۲۷۷) ممنوع شده باشد. (۳ الف) راننده‌ای که وسیله نقلیه موتوری با وزن کلی مجاز بیش از ۷.۵ تن را هدایت می‌کند، صرف‌نظر از سایر ممنوعیت‌های سبقت، نباید سبقت بگیرد اگر دید به دلیل مه، بارش برف یا باران کمتر از ۵۰ متر باشد. (۴) کسی که قصد سبقت گرفتن و خارج شدن از مسیر را دارد، باید به گونه‌ای رفتار کند که هیچ خطری برای ترافیک پشت سر ایجاد نشود. هنگام سبقت گرفتن، باید فاصله جانبی کافی با سایر کاربران جاده، به ویژه عابران پیاده و دوچرخه‌سواران، حفظ شود. کسی که سبقت می‌گیرد، باید در اسرع وقت دوباره به سمت راست برگردد. کسی که سبقت می‌گیرد، نباید مانع از حرکت وسیله نقلیه‌ای شود که از آن سبقت گرفته می‌شود. (۴ الف) خارج شدن برای سبقت و بازگشت به مسیر باید به موقع و واضح اعلام شود؛ در این حالت باید از چراغ‌های راهنما استفاده شود. (۵) خارج از مناطق مسکونی، سبقت گرفتن می‌تواند با علائم صوتی کوتاه یا نوری اعلام شود. اگر از نور بالا برای علامت دادن استفاده شود، نباید رانندگان وسایل نقلیه مقابل را خیره کرد. (۶) کسی که از او سبقت گرفته می‌شود، نباید سرعت خود را افزایش دهد. راننده‌ای که وسیله نقلیه کندتری را هدایت می‌کند، باید در محل مناسب سرعت خود را کاهش دهد و در صورت لزوم توقف کند، اگر تنها از این طریق چندین وسیله نقلیه پشت سر هم بتوانند سبقت بگیرند. برای این منظور می‌توان از شانه‌های مناسب جاده نیز استفاده کرد؛ این مورد در بزرگراه‌ها صدق نمی‌کند. (۷) کسی که قصد خود را برای گردش به چپ اعلام کرده و در مسیر قرار گرفته است، باید از سمت راست از او سبقت گرفته شود. از وسایل نقلیه ریلی باید از سمت راست سبقت گرفته شود. تنها کسی که نمی‌تواند این کار را انجام دهد، زیرا ریل‌ها بیش از حد به سمت راست قرار دارند، مجاز است از سمت چپ سبقت بگیرد. در مسیرهای یک‌طرفه، از وسایل نقلیه ریلی می‌توان از سمت چپ نیز سبقت گرفت. (۸) در صورت وجود فضای کافی، دوچرخه‌سواران و موتورسواران موپد مجازند از وسایل نقلیه‌ای که در خط عبور سمت راست منتظر هستند، با سرعت متوسط و احتیاط ویژه از سمت راست سبقت بگیرند.</div>',0),
(40,'1.1.06-105','','5.2; 5.6','','','',5,1,0,0,',68,','','In welchen Fällen muss das Überholen abgebrochen werden?','در چه مواردی باید از سبقت گرفتن صرف نظر کرد؟','In which cases must you abandon overtaking?','',0),
(41,'1.1.06-106','','5.2; 5.3','','','',4,1,0,0,',68,','','Wann ist das Überholen verboten?','چه زمانی سبقت گرفتن ممنوع است؟','When is overtaking forbidden?','<div dir=\'rtl\'>ماده ۵ قانون راهنمایی و رانندگی (StVO) - سبقت گرفتن (۱) سبقت گرفتن باید از سمت چپ انجام شود. (۲) سبقت گرفتن تنها زمانی مجاز است که راننده بتواند اطمینان حاصل کند که در طول کل فرآیند سبقت، هیچ مانعی برای ترافیک روبرو ایجاد نخواهد شد. همچنین، سبقت گرفتن تنها زمانی مجاز است که راننده با سرعتی به مراتب بیشتر از وسیله نقلیه مورد سبقت حرکت کند. (۳) سبقت گرفتن در موارد زیر غیرمجاز است: ۱. در شرایط ترافیکی نامشخص یا ۲. زمانی که توسط یک تابلوی راهنمایی و رانندگی مشخص (تابلوهای ۲۷۶، ۲۷۷) ممنوع شده باشد. (۳ الف) راننده‌ای که وسیله نقلیه موتوری با وزن کلی مجاز بیش از ۷.۵ تن را هدایت می‌کند، بدون در نظر گرفتن سایر ممنوعیت‌های سبقت، نباید سبقت بگیرد اگر دید به دلیل مه، بارش برف یا باران کمتر از ۵۰ متر باشد. (۴) کسی که قصد سبقت گرفتن دارد، باید به گونه‌ای رفتار کند که هیچ خطری برای ترافیک پشت سر ایجاد نشود. هنگام سبقت گرفتن، باید فاصله جانبی کافی با سایر شرکت‌کنندگان در ترافیک، به ویژه عابران پیاده و دوچرخه‌سواران، حفظ شود. کسی که سبقت می‌گیرد، باید در اسرع وقت به سمت راست بازگردد. کسی که سبقت می‌گیرد، نباید مانع از حرکت وسیله نقلیه‌ای شود که از آن سبقت گرفته می‌شود. (۴ الف) تغییر مسیر برای سبقت گرفتن و بازگشت به مسیر باید به موقع و به وضوح اعلام شود؛ در این حالت باید از چراغ‌های راهنما استفاده شود. (۵) خارج از مناطق مسکونی، سبقت گرفتن را می‌توان با علائم صوتی کوتاه یا نوری اعلام کرد. در صورت استفاده از نور بالا برای علامت دادن، رانندگان وسایل نقلیه روبرو نباید خیره شوند. (۶) کسی که از او سبقت گرفته می‌شود، نباید سرعت خود را افزایش دهد. کسی که وسیله نقلیه کندتری را هدایت می‌کند، باید در محل مناسب سرعت خود را کاهش دهد و در صورت لزوم صبر کند، اگر تنها از این طریق چندین وسیله نقلیه پشت سر هم بتوانند سبقت بگیرند. برای این منظور می‌توان از شانه‌های راه مناسب نیز استفاده کرد؛ این مورد در بزرگراه‌ها صدق نمی‌کند. (۷) کسی که قصد خود را برای گردش به چپ اعلام کرده و در مسیر قرار گرفته است، باید از سمت راست از او سبقت گرفته شود. وسایل نقلیه ریلی باید از سمت راست سبقت گرفته شوند. تنها کسی که نمی‌تواند این کار را انجام دهد، به دلیل اینکه ریل‌ها بیش از حد به سمت راست قرار دارند، مجاز است از سمت چپ سبقت بگیرد. در مسیرهای یک‌طرفه، وسایل نقلیه ریلی را می‌توان از سمت چپ نیز سبقت گرفت.</div>',0),
(42,'1.1.07-001','','','Er wird','او خواهد','The truck will',3,1,1,0,',26,','','Womit müssen Sie rechnen, wenn vor Ihnen ein Lastzug in eine enge Straße nach rechts abbiegen will?','هنگامی که یک کامیون (کشنده با تریلر) جلوی شما قصد دارد به یک خیابان باریک به سمت راست بپیچد، چه چیزی را باید در نظر بگیرید؟','What must you be prepared for when a truck in front of you wishes to turn right into a narrow street?','',0),
(43,'1.1.07-002','','','','','',3,1,1,0,',26,','','Worauf müssen Sie innerorts an Kreuzungen und Einmündungen besonders achten?','در داخل شهر، در تقاطع‌ها و محل‌های اتصال جاده‌ها، به چه چیزی باید به طور ویژه توجه کنید؟','What do you have to particularly remember at crossroads and junctions in a built-up area?','',0),
(44,'1.1.07-006-B','1.1.07-006-B.jpg','','','','',3,1,1,0,',26,','','Warum müssen Sie hier besonders vorsichtig sein?','چرا باید در اینجا به ویژه محتاط باشید؟','Why must you be particularly careful here?','',0),
(45,'1.1.07-009','','','Dass Kinder','که کودکان','That children',5,1,1,0,',26,','','Sie nähern sich einer Schule. Kinder verlassen das Schulgelände. Womit müssen Sie rechnen?','شما به یک مدرسه نزدیک می‌شوید. کودکان در حال ترک محوطه مدرسه هستند. چه چیزی را باید پیش‌بینی کنید؟','You are approaching a school. Children are leaving the school grounds. What must you reckon with?','',0),
(46,'1.1.07-010','','16.2','','','',4,1,1,0,',26,','','Worauf kann Warnblinklicht hinweisen?','چراغ هشداردهنده می‌تواند نشان‌دهنده چه چیزی باشد؟','What do hazard warning lights draw your attention to?','',0),
(47,'1.1.07-011','','','Der M&auml;hdrescher','کمباین','The combine harvester',4,1,1,0,',26,','','Vor Ihnen will ein großer Mähdrescher nach rechts abbiegen. Was ist richtig?','یک کمباین بزرگ در جلوی شما می‌خواهد به راست بپیچد. چه چیزی صحیح است؟','A big combine harvester in front of you wishes to turn right. What is correct?','',0),
(48,'1.1.07-013','','','','','',4,1,1,0,',26,1008,','','Sie fahren hinter einem landwirtschaftlichen Fahrzeug mit hoch beladenem Anhänger. Womit müssen Sie rechnen?','شما پشت یک وسیله نقلیه کشاورزی با یک تریلر (یدک‌کش) با بار زیاد رانندگی می‌کنید. چه چیزی را باید انتظار داشته باشید؟','You are driving behind a farm vehicle with a trailer carrying a high load. What must you reckon with?','<p><span style=\"font-family: system-ui, -apple-system, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, &quot;Noto Sans&quot;, &quot;Liberation Sans&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;, &quot;Noto Color Emoji&quot;;\">یک وسیله نقلیه کشاورزی با یک تریلر (یدک‌کش) با بار زیاد</span><img src=\"/storage/answers/info/ai_gemini_69f263aea1f332.67554107.jpg\" style=\"width: 300px;\"></p>',0),
(49,'1.1.07-015-M','1.1.07-015-M.jpg','','','','',4,1,1,1,',26,','','Wie verhalten Sie sich in dieser Situation?','در این وضعیت چگونه رفتار می‌کنید؟','What should you do in this situation?','',0),
(50,'1.1.07-101','','','','','',4,1,0,0,',26,','','Sie wollen eine landwirtschaftliche Zugmaschine mit nach hinten herausragendem Anbaugerät überholen. Was ist zu beachten?','شما می‌خواهید از یک تراکتور کشاورزی با تجهیزات متصل که به سمت عقب بیرون زده است، سبقت بگیرید. به چه نکاتی باید توجه کرد؟','You wish to overtake a farm tractor with a mounted implement extending beyond its back. What must you remember?','<p><span style=\"font-family: system-ui, -apple-system, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, &quot;Noto Sans&quot;, &quot;Liberation Sans&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;, &quot;Noto Color Emoji&quot;;\">تراکتور کشاورزی با تجهیزات متصل که به سمت عقب بیرون زده است</span></p><p><img src=\"/storage/answers/info/img_69f265a5383649.59296140.jpeg\" style=\"width: 315.238px;\"><span style=\"font-family: system-ui, -apple-system, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, &quot;Noto Sans&quot;, &quot;Liberation Sans&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;, &quot;Noto Color Emoji&quot;;\"><br></span></p>',0),
(51,'1.1.07-103-M','1.1.07-103-M.jpg','','','','',3,1,0,1,',26,','','Womit müssen Sie hinter dieser Straßenkuppe rechnen?','پشت این برآمدگی جاده باید انتظار چه چیزی را داشته باشید؟','What must you anticipate on the other side of this crest in the road?','<div dir=\'rtl\'>از آنجایی که دید به ادامه مسیر جاده به دلیل برآمدگی امکان‌پذیر نیست، باید خود را برای هرگونه مانع احتمالی آماده کنید. به همین دلیل باید آهسته و با احتیاط رانندگی کنید.</div>',0),
(52,'1.1.07-107-B','1.1.07-107-B.jpg','','','','',3,1,0,0,',26,','','Worauf müssen Sie sich einstellen?','چه انتظاری باید داشته باشید؟','What must you be prepared for in this situation?','',0),
(53,'1.1.07-111','','','Sie m&uuml;ssen','شما باید','',4,1,0,0,',26,','','Sie warten an einer Ampel und wollen nach rechts abbiegen. Worauf müssen Sie achten?','شما در یک چراغ راهنمایی منتظر هستید و می‌خواهید به راست بپیچید. به چه چیزی باید توجه کنید؟','','',1),
(54,'1.1.07-113','','','','','',3,1,0,0,',26,','','Sie fahren auf einer neu angelegten Straße durch bewaldetes Gebiet. Womit müssen Sie rechnen?','شما در یک جاده تازه احداث شده از میان منطقه‌ای جنگلی رانندگی می‌کنید. چه چیزی را باید انتظار داشته باشید؟','You are driving on a new road through a woodland area. What must you reckon with?','<p><span style=\"font-family: system-ui, -apple-system, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, &quot;Noto Sans&quot;, &quot;Liberation Sans&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;, &quot;Noto Color Emoji&quot;;\">یک جاده تازه احداث شده از میان منطقه‌ای جنگلی</span><span style=\"background-color: rgb(211, 245, 218); color: rgb(33, 37, 41); font-family: system-ui, -apple-system, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, &quot;Noto Sans&quot;, &quot;Liberation Sans&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;, &quot;Noto Color Emoji&quot;; font-size: 1rem; font-weight: 700;\">&nbsp;</span><img src=\"/storage/answers/info/ai_gemini_69f266c9f03316.49736238.jpg\" style=\"color: rgb(33, 37, 41); font-family: system-ui, -apple-system, &quot;Segoe UI&quot;, Roboto, &quot;Helvetica Neue&quot;, &quot;Noto Sans&quot;, &quot;Liberation Sans&quot;, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;, &quot;Noto Color Emoji&quot;; font-size: 1rem; font-weight: 700; width: 300px;\"></p>',0),
(55,'1.1.07-117','','','','','',3,1,0,0,',26,','','Zu welcher Tageszeit ist mit verstärktem Wildwechsel zu rechnen?','در چه زمان از روز احتمال عبور حیوانات وحشی بیشتر است؟','At which time of the day do you have to reckon with increased wild animals crossing?','',0),
(56,'1.1.07-118','','','','','',4,1,0,0,',26,','','Mit welchen Gefahren müssen Sie vor allem in ländlichen Gebieten rechnen?','در مناطق روستایی، به خصوص باید انتظار چه خطراتی را داشته باشید؟','Which dangers must you reckon with above all in rural areas?','',0),
(57,'1.1.07-119','','','','','',4,1,0,0,',26,1008,','','In der Dämmerung kommt Ihnen eine landwirtschaftliche Zugmaschine mit eingeschalteter Beleuchtung entgegen. Womit müssen Sie rechnen?','در گرگ و میش (هنگام غروب)، یک تراکتور کشاورزی با چراغ‌های روشن از روبرو به سمت شما می‌آید. چه چیزی را باید انتظار داشته باشید؟','A farm tractor is approaching you at dawn with its headlights switched on. What must you reckon with?','',0),
(58,'1.1.07-120','','','','','',4,1,0,0,',26,','','Was müssen Sie beachten, bevor Sie in einen Tunnel einfahren?','قبل از ورود به تونل، به چه نکاتی باید توجه کنید؟','What must you observe when you enter a tunnel?','<div dir=\'rtl\'>ماده ۱۷ آیین‌نامه راهنمایی و رانندگی (StVO) بیان می‌کند: «(۱) در هنگام گرگ و میش، تاریکی یا زمانی که شرایط دید ایجاب می‌کند، باید از تجهیزات روشنایی مقرر استفاده شود. تجهیزات روشنایی نباید پوشانده یا کثیف باشند. (...) (۳) اگر مه، بارش برف یا باران به طور قابل توجهی دید را مختل کند، حتی در روز نیز باید با نور پایین رانندگی کرد. فقط در چنین شرایط آب و هوایی می‌توان چراغ‌های مه‌شکن را روشن کرد (...).»</div>',0),
(59,'1.1.07-121','','','','','',4,1,0,0,',26,','','Wie müssen Sie sich bei einem Stau im Tunnel verhalten?','در صورت ترافیک (راهبندان) در تونل، چگونه باید رفتار کنید؟','What must you do in case of a traffic jam in a tunnel?','',0),
(60,'1.1.07-122','','','','','',4,1,0,0,',26,','','Wodurch kann die Aufmerksamkeit bei einer Tunneldurchfahrt beeinträchtigt werden?','چه عواملی می‌توانند تمرکز را هنگام عبور از تونل مختل کنند؟','What can impair your attention when driving through a tunnel?','',0),
(61,'1.1.07-125','','','','','',4,1,0,0,',26,','','Welche grundlegenden Verhaltensregeln müssen Sie im Tunnel beachten?','چه قوانین رفتاری اساسی را باید در تونل رعایت کنید؟','Which basic code of conduct must you observe in a tunnel?','',0),
(62,'1.1.09-004','','','','','',4,1,1,0,',14,','','Wodurch kann die Fahrtüchtigkeit herabgesetzt werden?','چه عواملی می‌توانند توانایی رانندگی را کاهش دهند؟','What can impair fitness to drive?','',0),
(63,'1.1.09-006','','','','','',4,1,1,0,',14,','','Wie lange dauert es im Allgemeinen, bis 1,0 Promille Alkohol im Blut abgebaut ist?','به طور کلی چقدر طول می‌کشد تا ۱.۰ پرومیل الکل در خون تجزیه شود؟','In general, how long does it take before an alcohol level of 1.0 per mille (100 mg/100 ml) is cleared from the blood stream?','',0),
(64,'1.1.09-008','','','','','',4,1,1,0,',14,','','Wozu können bereits geringe Mengen Alkohol führen?','مقادیر کم الکل می‌تواند به چه پیامدهایی منجر شود؟','What can be the effects of even small quantities of alcohol?','',0),
(65,'1.1.09-015','','','','','',4,1,1,0,',14,','','Wie wird der berauschende Wirkstoff von Haschisch im Körper abgebaut?','ماده فعال مست‌کننده حشیش چگونه در بدن تجزیه می‌شود؟','How is the intoxicating substance in hashish broken down by the body?','',0),
(66,'1.1.09-017','','','','','',4,1,1,0,',14,','','Welche Folgen kann es haben, wenn man unter Einwirkung von Drogen (wie z. B. Haschisch, Heroin, Kokain) ein Kraftfahrzeug führt?','چه عواقبی می‌تواند داشته باشد اگر فردی تحت تأثیر مواد مخدر (مانند حشیش، هروئین، کوکائین) وسیله نقلیه موتوری رانندگی کند؟','What are the consequences for a person driving a motor vehicle under the influence of drugs (e.g. hashish, heroin, cocaine)?','',0),
(67,'1.1.09-018','','','','','',4,1,1,0,',14,','','Was kann Haschischkonsum bewirken?','مصرف حشیش چه تأثیری می‌تواند داشته باشد؟','What are the possible effects of hashish consumption?','<div dir=\'rtl\'>حشیش بر سیستم عصبی مرکزی تأثیر می‌گذارد. اثرات آن از فردی به فرد دیگر متفاوت است. حتی تأثیر آن در یک فرد نیز می‌تواند بسته به وضعیت جسمی و روحی و همچنین مقدار مصرفی، متفاوت باشد.</div>',0),
(68,'1.1.09-019','','','','','',4,1,1,0,',14,','','Welche Auswirkungen kann Haschischkonsum haben?','مصرف حشیش چه عواقبی می‌تواند داشته باشد؟','What are the possible effects of hashish consumption?','<div dir=\'rtl\'>اثرات حشیش می‌تواند بسیار متفاوت باشد. بسته به مقدار و نوع مصرف حشیش، تغییرات متفاوتی (و با شدت‌های متفاوت) در آگاهی فرد ممکن است رخ دهد. از آنجایی که حشیش بر آگاهی تأثیر می‌گذارد، بسته به وضعیت روحی لحظه‌ای، اثرات متفاوتی در یک فرد می‌تواند ظاهر شود. این اثرات از سرخوشی، توهمات حسی، ادراکات انتخابی گرفته تا حالات روان‌پریشی یا اضطراب و افسردگی متغیر است.</div>',0),
(69,'1.1.09-021','','','','','',4,1,0,0,',14,','','Für wen besteht ein Alkoholverbot beim Führen von Kraftfahrzeugen?','ممنوعیت مصرف الکل هنگام رانندگی با وسایل نقلیه موتوری برای چه کسانی اعمال می‌شود؟','Who is not allowed to drink alcohol when driving motor vehicles?','',0),
(70,'1.1.09-022','','','','','',4,1,0,0,',14,','','Dürfen Kraftfahrer beim Führen von Kraftfahrzeugen während der Probezeit unter der Wirkung alkoholischer Getränke stehen?','آیا رانندگان وسایل نقلیه موتوری در طول دوره آزمایشی مجاز به رانندگی تحت تأثیر نوشیدنی‌های الکلی هستند؟','Are drivers during their probation period allowed to be under the influence of alcohol when driving motor vehicles?','',0),
(71,'1.2.01-001','','1','Sie m&uuml;ssen','شما باید','',4,1,1,0,',51,','','Die Teilnahme am Straßenverkehr erfordert ständige Vorsicht und gegenseitige Rücksicht. Was bedeutet das für Sie?','مشارکت در ترافیک جاده‌ای نیازمند احتیاط دائمی و ملاحظه متقابل است. این برای شما چه معنایی دارد؟','','',1),
(72,'1.2.02-101-B','1.2.02-101-B.jpg','','','','',3,1,0,0,',66,','','Wozu darf der rechte Seitenstreifen benutzt werden?','شانه راست برای چه مواردی قابل استفاده است؟','When may you use the right-hand hard shoulder?','',0),
(73,'1.2.03-001','','','','','',4,1,1,0,',46,1008,','','Was verlängert den Bremsweg?','چه چیزی مسافت توقف را افزایش می‌دهد؟','Which factors lengthen your braking distance?','',0),
(74,'1.2.03-002','','','Vom Zustand der','به وضعیت','The condition of the',3,1,1,0,',46,','','Wovon ist der Bremsweg abhängig?','فاصله ترمز به چه چیزی بستگی دارد؟','What does the braking distance depend on?','',0),
(75,'1.2.03-101','','','Antwort:','پاسخ:','Answer:',3,1,0,0,',46,1003,','','Welche zulässige Höchstgeschwindigkeit gilt allgemein innerhalb geschlossener Ortschaften?','حداکثر سرعت مجاز در مناطق مسکونی (شهری) به طور کلی چقدر است؟','What is the permissible top speed generally in built-up areas?','<div dir=\'rtl\'>حداکثر سرعت مجاز در مناطق مسکونی (شهری) طبق قانون ۵۰ کیلومتر بر ساعت تعیین شده است.</div>',0),
(76,'1.2.03-102','','','Antwort: Er wird','پاسخ: آن می‌شود','Answer: It is',4,1,0,0,',46,1005,','','Sie verdoppeln Ihre Geschwindigkeit. Wie verändert sich der Bremsweg?','شما سرعت خود را دو برابر می‌کنید. مسافت ترمز چگونه تغییر می‌کند؟','You double the speed at which you are travelling. How does this affect the braking distance?','<div dir=\'rtl\'>از آنجایی که سرعت به صورت توان دوم (مربع)، یعنی دو بار، در فرمول مسافت ترمز وارد می‌شود، با دو برابر شدن سرعت، مسافت ترمز ۴ برابر می‌شود، زیرا ۲² = ۴</div>',0),
(77,'1.2.03-103','','','','','',4,1,0,0,',46,','','Was müssen Sie bei der Wahl Ihrer Geschwindigkeit berücksichtigen?','هنگام انتخاب سرعت خود باید به چه نکاتی توجه کنید؟','What must you take into consideration when selecting your speed?','',0),
(78,'1.2.03-104','','','','','',2,1,0,0,',46,1005,','','Nach welcher Faustformel kann man aus der Geschwindigkeit den Weg in Metern ermitteln, den ein Fahrzeug in einer Sekunde zurücklegt?','برای تعیین مسافتی که یک وسیله نقلیه در یک ثانیه طی می کند بر حسب سرعت، از چه قانون کلی می توان استفاده کرد؟','By which rule of thumb can you determine from the speed the distance in metres a motor vehicle travels in one second?','',0),
(79,'1.2.03-105','','','','','',2,1,0,0,',46,1005,','','Nach welcher Faustformel kann man aus der Geschwindigkeit den Bremsweg in Metern bei einer normalen Bremsung berechnen?','با استفاده از کدام فرمول سرانگشتی می‌توان مسافت ترمز را بر حسب متر از سرعت در یک ترمز عادی محاسبه کرد؟','By which rule of thumb can you determine the braking distance in metres from speed when braking normally?','',0),
(80,'1.2.03-106','','','','','',4,1,0,0,',46,1005,','','Sie fahren mit 30 km/h. Dabei beträgt der Bremsweg bei einer normalen Bremsung 9 Meter nach der Faustformel. Wie lang ist der Bremsweg unter gleichen Bedingungen bei 60 km/h?','شما با سرعت 30 کیلومتر در ساعت رانندگی می کنید. مسافت ترمزگیری برای ترمز معمولی طبق قاعده کلی 9 متر است. مسافت ترمز در سرعت 60 کیلومتر در ساعت در شرایط مشابه چقدر است؟','You are travelling at 30 km/h. According to the rule of thumb, the braking distance is 9 metres when braking normally. How long is the braking distance under the same conditions when travelling at 60 km/h?','',0),
(81,'1.2.04-101','','4-1','','','',5,1,0,0,',9,','','Wovon hängt der einzuhaltende Abstand zum vorausfahrenden Fahrzeug ab?','فاصله ایمنی که باید با خودروی جلویی حفظ شود، به چه عواملی بستگی دارد؟','What does the distance to be maintained from the vehicle ahead depend on?','',0),
(82,'1.2.05-101','','','','','',4,1,0,0,',69,','','Wo ist das Überholen verboten?','سبقت گرفتن در کجا ممنوع است؟','Where is overtaking prohibited?','',0),
(83,'1.2.05-103','','5.2; 5.4','','','',4,1,0,0,',69,','','Was ist Voraussetzung für das Ausscheren zum Überholen?','چه چیزی پیش‌نیاز برای خارج شدن از مسیر جهت سبقت گرفتن است؟','What is the correct procedure for pulling out to overtake?','<div dir=\'rtl\'>بند ۵ قانون راهنمایی و رانندگی (StVO) مقرر می‌دارد: (۲) سبقت گرفتن تنها برای کسی مجاز است که بتواند اطمینان حاصل کند که در طول کل فرآیند سبقت، هیچ مانعی برای ترافیک روبرو ایجاد نخواهد شد (...). (۴) هر کس که می‌خواهد برای سبقت گرفتن از مسیر خارج شود، باید طوری رفتار کند که هیچ خطری برای ترافیک پشت سر ایجاد نشود (...).</div>',0),
(84,'1.2.05-104','','5.4; 5.4a','','','',3,1,0,0,',69,','','Wie müssen Sie einen Überholvorgang beenden?','چگونه باید یک سبقت را به پایان برسانید؟','What must you do to end an overtaking manoeuvre?','<div dir=\'rtl\'>ماده ۵ آیین‌نامه راهنمایی و رانندگی (StVO) مقرر می‌دارد: (۴) هر کس که قصد سبقت گرفتن دارد، باید به گونه‌ای رفتار کند که هیچ خطری برای ترافیک پشت سر وجود نداشته باشد. هنگام سبقت گرفتن، باید فاصله جانبی کافی با سایر کاربران جاده، به ویژه عابران پیاده و دوچرخه‌سواران، حفظ شود. سبقت‌گیرنده باید در اسرع وقت دوباره به سمت راست برگردد. او نباید در این حین مانع خودروی سبقت‌گرفته‌شده شود. (۴ الف) خروج برای سبقت و بازگشت به مسیر باید به موقع و به وضوح اعلام شود؛ در این حین باید از چراغ‌های راهنما استفاده شود.</div>',0),
(85,'1.2.05-105','','3.3; 5.2; ','','','',4,1,0,0,',69,','','Was ist über die Geschwindigkeit beim Überholvorgang vorgeschrieben?','در مورد سرعت هنگام سبقت گرفتن چه چیزی الزامی است؟','What are the regulations governing speed when overtaking?','',0),
(86,'1.2.05-106','','2.2; 5.6','','','',4,1,0,0,',69,','','Wie müssen Sie sich verhalten, wenn Sie überholt werden?','هنگامی که از شما سبقت گرفته می‌شود، چگونه باید رفتار کنید؟','What must you do when you are being overtaken?','',0),
(87,'1.2.05-107','','5.7','','','',3,1,0,0,',69,','','Auf welcher Seite ist eine Straßenbahn zu überholen, die in der Mitte der Fahrbahn fährt (keine Einbahnstraße)?','از کدام سمت باید از تراموایی که در وسط خط حرکت می‌کند (نه در خیابان یک‌طرفه) سبقت گرفت؟','On which side must you overtake a tram which is travelling in the middle of the roadway (not a one-way street)?','',0),
(88,'1.2.05-108','','5.7','','','',3,1,0,0,',69,','','In welchen Fällen dürfen Sie eine Straßenbahn links überholen?','در چه مواردی مجاز به سبقت گرفتن از تراموا از سمت چپ هستید؟','When may a tram be overtaken on the left?','<div dir=\'rtl\'>در بند ۷ ماده ۵ قانون راهنمایی و رانندگی (StVO) آمده است: «کسی که قصد خود را برای گردش به چپ اعلام کرده و در مسیر خود قرار گرفته است، باید از سمت راست از او سبقت گرفته شود. از وسایل نقلیه ریلی باید از سمت راست سبقت گرفته شود. اگر ریل‌ها بیش از حد به سمت راست قرار گرفته باشند و در نتیجه سبقت گرفتن از سمت راست را غیرممکن سازند، می‌توان از سمت چپ سبقت گرفت. در مسیرهای یک‌طرفه نیز می‌توان از تراموا از سمت چپ سبقت گرفت.» خیابان یک‌طرفه نیز یک مسیر فقط برای یک جهت است.</div>',0),
(89,'1.2.05-109','','5.4','','','',4,1,0,0,',69,','','Welche Fahrzeuge dürfen nur mit besonders großem Seitenabstand überholt werden?','کدام وسایل نقلیه را فقط باید با فاصله جانبی بسیار زیاد سبقت گرفت؟','Which vehicles may be overtaken only by maintaining a specially great lateral distance?','',0),
(90,'1.2.05-110','','5.4a; 6','','','',3,1,0,0,',69,','','In welchen Fällen müssen Sie blinken?','در چه مواردی باید راهنما بزنید؟','When must you signal?','',0),
(91,'1.2.06-001','','6','','','',3,1,1,0,',82,','','Welches Fahrzeug muss warten, wenn eine Baustelle die halbe Fahrbahn blockiert?','کدام وسیله نقلیه باید منتظر بماند، اگر یک کارگاه ساختمانی نیمی از خط عبور را مسدود کرده باشد؟','Which vehicle must wait when half the roadway is closed because of roadworks?','<div dir=\'rtl\'>بند ۶ قانون راهنمایی و رانندگی (StVO) مقرر می‌دارد: «هر کس بخواهد از کنار یک وسیله نقلیه متوقف، یک مانع یا هر مانع دیگری در سمت چپ خط عبور عبور کند، باید به وسایل نقلیه روبرو اجازه عبور دهد.»</div>',0),
(92,'1.2.07-001','','7.5','','','',4,1,1,0,',23,','','Was müssen Sie tun, wenn Sie den Fahrstreifen wechseln wollen?','هنگام تغییر خط رانندگی چه کاری باید انجام دهید؟','What must you remember when you want to change lanes?','',0),
(93,'1.2.07-104','','','','','',4,1,0,0,',23,','','Wie verhalten Sie sich in einem Tunnel mit Gegenverkehr?','در یک تونل با ترافیک روبرو چگونه رفتار می‌کنید؟','','',1),
(94,'1.2.09-101','','','','','',4,1,0,0,',3,','','Was kann bei mehrspurigem Abbiegen zu besonders gefährlichen Situationen führen?','چه چیزی می‌تواند هنگام گردش در مسیرهای چندگانه به موقعیت‌های به خصوص خطرناک منجر شود؟','What can give rise to particularly dangerous situations where several lanes turn off?','',0),
(95,'1.2.09-103-B','1.2.09-103-B.jpg','9.1','','','',3,1,0,0,',3,','','Alle drei Fahrzeuge wollen links abbiegen. Wer hat sich richtig eingeordnet?','هر سه وسیله نقلیه می‌خواهند به چپ بپیچند. کدام یک به درستی در مسیر قرار گرفته است؟','All three vehicles want to turn left. Which is in the correct lane?','',0),
(96,'1.2.09-104-B','1.2.09-104-B.jpg','','Wie der','مانند','Like',3,1,0,0,',3,','','Nach dem Linksabbiegen wollen Sie sofort rechts abbiegen. Wie ordnen Sie sich ein?','پس از گردش به چپ، می‌خواهید بلافاصله به راست بپیچید. چگونه باید خود را در مسیر قرار دهید؟','After turning left, you want to turn immediately right. How should you position your vehicle?','',0),
(97,'1.2.09-107-B','1.2.09-107-B.jpg','9.1','','','',3,1,0,0,',3,','','Wer muss die Fahrtrichtungsänderung anzeigen?','چه کسی باید تغییر جهت حرکت را نشان دهد؟','Who must signal a change of direction here?','',0),
(98,'1.2.09-109','','8.1a; 9.1','','','',3,1,0,0,',3,','','Sie befinden sich im Kreisverkehr. Was ist zu beachten?','شما در میدان (فلکه) هستید. چه نکاتی را باید رعایت کرد؟','You are on a roundabout. What should you remember?','<div dir=\'rtl\'>بند ۱ از ماده ۹ قانون راهنمایی و رانندگی (StVO) مقرر می‌دارد: «پیچیدن، دور زدن و دنده عقب رفتن. (۱) هر کس قصد پیچیدن دارد، باید این موضوع را به موقع و به وضوح اعلام کند؛ در این حین باید از چراغ راهنما استفاده شود. ...» ماده ۹a قانون راهنمایی و رانندگی (StVO) مقرر می‌دارد: «میدان (فلکه). (۱) اگر در ورودی یک میدان، تابلوی ۲۱۵ (میدان) زیر تابلوی ۲۰۵ (حق تقدم را واگذار کنید!) قرار گرفته باشد، ترافیک در مسیر دایره‌ای میدان حق تقدم دارد. هنگام ورود به چنین میدانی، استفاده از چراغ راهنما مجاز نیست. توقف در مسیر حرکت در داخل میدان ممنوع است. (۲) عبور از روی جزیره مرکزی میدان مجاز نیست. استثنا از این قاعده، وسایل نقلیه‌ای هستند که به دلیل ابعادشان، عبور از میدان برایشان به شکل دیگری ممکن نیست. این وسایل نقلیه می‌توانند از روی جزیره مرکزی عبور کنند، به شرطی که خطری برای سایر شرکت‌کنندگان در ترافیک ایجاد نشود.»</div>',0),
(99,'1.2.09-113-M','1.2.09-113-M.jpg','','','','',3,1,0,1,',3,','','Wer muss hier die Fahrtrichtungsänderung anzeigen?','چه کسی باید در اینجا تغییر جهت حرکت را نشان دهد؟','Who is required to indicate a change of driving direction here?','<div dir=\'rtl\'>تغییر جهت حرکت همیشه باید نشان داده شود.</div>',0),
(100,'1.2.09-117','','','','','',4,1,1,0,',3,','','In welchen Fällen müssen Sie eine Änderung der Fahrtrichtung anzeigen?','در چه مواردی باید تغییر جهت حرکت را نشان دهید؟','When do have you to indicate a change in direction?','<div dir=\'rtl\'>هر شرکت‌کننده در ترافیک باید هرگونه تغییر جهت حرکت را نشان دهد.</div>',0),
(101,'1.2.10-005','','10','','','',4,1,1,0,',32,','','Sie kommen aus einer Straße mit abgesenktem Bordstein und wollen in eine andere Straße einbiegen. Von links kommt ein Pkw. Was gilt hier?','شما از یک خیابان با جدول پایین‌آورده شده خارج می‌شوید و می‌خواهید وارد خیابان دیگری شوید. یک خودروی سواری از سمت چپ می‌آید. در اینجا چه قانونی اعمال می‌شود؟','You want to turn out of a road with a sunken kerbstone into another road. A car is coming from the left. What applies here?','<div dir=\'rtl\'>ماده ۱۰ قانون راهنمایی و رانندگی (StVO) مقرر می‌دارد: «ورود به مسیر و شروع حرکت. هر کس که بخواهد ... از روی یک جدول پایین‌آورده شده وارد مسیر حرکت شود یا از کنار جاده شروع به حرکت کند، باید طوری رفتار کند که خطر برای سایر کاربران ترافیک منتفی باشد؛ در صورت لزوم، باید از راهنمایی دیگران استفاده کند. او باید قصد خود را به موقع و واضح اعلام کند؛ در این حین باید از چراغ‌های راهنما استفاده شود. ...»</div>',0),
(102,'1.2.10-101','','10','','','',4,1,0,0,',32,','','Wie verhalten Sie sich beim Anfahren vom Fahrbahnrand?','هنگام حرکت از کنار جاده چگونه رفتار می‌کنید؟','What must you do when leaving the edge of the roadway?','<div dir=\'rtl\'>ماده ۱۰ قانون راهنمایی و رانندگی (StVO) مقرر می‌دارد: «ورود به جریان ترافیک و حرکت از کنار جاده: هر کس که می‌خواهد ... از کنار جاده حرکت کند، باید طوری رفتار کند که هیچ خطری برای سایر شرکت‌کنندگان در ترافیک ایجاد نشود؛ در صورت لزوم، باید از راهنمایی دیگران استفاده کند. او باید قصد خود را به موقع و واضح اعلام کند؛ در این راستا باید از چراغ‌های راهنما استفاده شود. ...»</div>',0),
(103,'1.2.11-003','','11.1; 19.3','','','',4,1,1,0,',25,','','Bei stockendem Verkehr müssen bestimmte Bereiche freigehalten werden. Welche sind dies?','در ترافیک متوقف، باید مناطق خاصی را باز نگه داشت. این مناطق کدامند؟','Which are the areas you must not drive into when there is traffic congestion?','',0),
