(816,'1.2.12-124','','12.4','','','',2,1,0,0,',52,','','Welche Fahrzeuge dürfen auf Fahrbahnen in zweiter Reihe halten?','کدام وسایل نقلیه مجاز به توقف در ردیف دوم در مسیرهای رانندگی هستند؟','What vehicles may be parked alongside other parked cars on the roadway?','',0),
(817,'1.2.19-116','','','','','',3,1,0,0,',19,','','Wo müssen Sie mit technisch ungesicherten Bahnübergängen rechnen?','در کجا باید انتظار گذرگاه‌های ریلی (تقاطع راه‌آهن) بدون ایمنی فنی را داشته باشید؟','Where do you have to anticipate encountering rail crossings with no technical safeguards?','<div dir=\'rtl\'>«بدون ایمنی فنی» به این معنی است که گذرگاه ریلی فقط با صلیب آندریاس (Andreaskreuz) یا تابلوهای مشابه تجهیز شده است، اما نه با موانع (راهبند) یا چراغ‌های هشداردهنده.</div>',0),
(818,'1.2.37-019','','','','','',2,1,1,0,',87,','','Unter welchen Umständen dürfen Sie an einer Kreuzung eine rote Ampel überfahren?','تحت چه شرایطی مجاز به عبور از چراغ قرمز در یک تقاطع هستید؟','Under what circumstances may you cross a junction during a red light?','',0),
(819,'1.3.01-034-M','1.3.01-034-M.jpg','','','','',5,1,1,1,',97,1002,','','Wie verhalten Sie sich hier richtig?','در اینجا رفتار صحیح شما چیست؟','What is the right course of action here?','',0),
(820,'1.4.40-147','1440147.png','','','','',3,1,0,0,',42,1001,','','Worauf weist dieses Verkehrszeichen hin?','این تابلوی راهنمایی و رانندگی به چه چیزی اشاره دارد؟','What does this traffic sign indicate?','<div dir=\'rtl\'>این تابلوی خطر، یک مثلث قرمز با زمینه سفید، در مورد یک نقطه خطر هشدار می‌دهد. در این مورد، در مورد اسب‌ها هشدار می‌دهد.</div>',0),
(821,'1.4.40-148','1440148.png','','','','',3,1,0,0,',42,1001,','','Worauf weist dieses Verkehrszeichen hin?','این تابلوی راهنمایی و رانندگی به چه چیزی اشاره دارد؟','What does this traffic sign indicate?','<div dir=\'rtl\'>این تابلوی خطر، در مورد لغزندگی ناشی از یخ‌زدگی و برف در جاده هشدار می‌دهد.</div>',0),
(822,'1.4.40-149','1440149.png','','','','',3,1,0,0,',42,1001,','','Womit müssen Sie bei diesem Verkehrszeichen rechnen?','با این تابلوی راهنمایی و رانندگی باید انتظار چه چیزی را داشته باشید؟','What must you anticipate with this road sign?','<div dir=\'rtl\'>این تابلوی خطر نشان می‌دهد که در نزدیکی آن احتمال عبور و مرور دام وجود دارد.</div>',0),
(823,'1.4.40-150','1440150.png','','Ich sollte','من باید','I should',3,1,0,0,',42,1001,','','Wie sollten Sie sich bei einer so gekennzeichneten Gefahrstelle verhalten?','در مواجهه با یک نقطه خطرناک که به این شکل علامت‌گذاری شده است، چگونه باید رفتار کنید؟','How should you act at a point of danger indicated by this sign?','<div dir=\'rtl\'>این علامت خطر در مورد شن و ماسه (سنگریزه) و جاده‌های ناهموار، یعنی سطح جاده‌ای که آسفالت نشده است، هشدار می‌دهد.</div>',0),
(824,'1.4.40-151','1440151.png','','','','',2,1,0,0,',42,1001,','','Worauf weist dieses Verkehrszeichen hin?','این تابلوی راهنمایی و رانندگی به چه چیزی اشاره دارد؟','What does this traffic sign indicate?','<div dir=\'rtl\'>این تابلوی خطر، در مورد یک پل متحرک هشدار می‌دهد. پل‌های متحرک معمولاً علاوه بر این، مجهز به چراغ‌های راهنمایی و موانع (راهبند) هستند.</div>',0),
(825,'1.4.40-152','1440152.png','','','','',2,1,0,0,',42,1001,','','Was haben Sie bei diesem Verkehrszeichen zu beachten?','هنگام مشاهده این تابلوی راهنمایی و رانندگی، به چه نکاتی باید توجه داشته باشید؟','What must you be aware of when you see this road traffic sign?','<div dir=\'rtl\'>این تابلوی راهنمایی و رانندگی در مورد یک ساحل یا کناره (رودخانه/دریاچه) ناامن یا بدون حفاظ در نزدیکی هشدار می‌دهد. به عنوان مثال، در اسکله‌های کشتی‌رانی یا کنار دریاچه‌ها و رودخانه‌ها قرار می‌گیرد.</div>',0),
(826,'1.4.40-153','1440153.png','','','','',3,1,0,0,',42,1001,','','Was haben Sie bei diesem Verkehrszeichen zu beachten?','در مورد این تابلوی راهنمایی و رانندگی به چه نکاتی باید توجه کنید؟','What must you be aware of when you see this road traffic sign?','<div dir=\'rtl\'>این تابلوی خطر، در مورد ریزش سنگ هشدار می‌دهد. اغلب در مسیرهای شیب‌دار و تپه‌ای که بسیار نزدیک به دیواره‌های سنگی هستند، یافت می‌شود.</div>',0),
(827,'1.4.40-154','1440154.png','','','','',2,1,0,0,',42,1001,','','Womit müssen Sie bei diesem Verkehrszeichen rechnen?','با این علامت ترافیکی باید انتظار چه چیزی را داشته باشید؟','What must you anticipate with this road sign?','<div dir=\'rtl\'>این علامت خطر در مورد عملیات پروازی در نزدیکی هشدار می‌دهد.</div>',0),
(828,'2.1.03-033','2.1.03-033.m4v','','','','',4,0,0,0,',36,1000,',',15,1,16,2,17,3,19,6,8,10,11,','Wie verhalten Sie sich jetzt richtig?','اکنون چگونه باید درست عمل کنید؟','What is the right course of action now?','<div dir=\'rtl\'>خودروی روبرو تازه لیز خورده و وارد خط شما شده است. به نظر می‌رسد جاده لغزنده است.</div>',0),
(829,'2.1.03-117','2.1.03-117.m4v','3.1; 17.3','Ich darf','من مجاز هستم','I may',5,0,0,0,',36,1000,',',19,6,7,8,10,11,','Sie fahren auf der Autobahn. Was ist in dieser Situation richtig?','شما در اتوبان رانندگی می‌کنید. در این وضعیت چه چیزی صحیح است؟','You are driving on the autobahn. What is the correct thing to do in this situation?','<div dir=\'rtl\'>دید به دلیل مه بسیار محدود است و کمتر از ۵۰ متر می‌باشد.</div>',0),
