(22,'1.1.02-116','1.1.02-116.jpg','20.1; 20.2','Ein- oder aussteigende Fahrg&auml;ste',4,1,1,0,',77,','','Die Straßenbahn ist an der Haltestelle gerade zum Stehen gekommen. Welches Verhalten ist richtig?'),
(23,'1.1.03-001','','','',3,1,1,0,',35,','','Wo müssen Sie besonders mit starker Fahrbahnverschmutzung und Rutschgefahr rechnen?'),
(24,'1.1.03-003','','','',4,1,1,0,',35,','','Wo müssen Sie besonders mit Fahrbahnvereisung rechnen?'),
(25,'1.1.03-102-B','1.1.03-102-B.jpg','','',4,1,0,0,',35,','','Warum müssen Sie auf dieser Straße besonders aufmerksam fahren?'),
(26,'1.1.03-104','','','',4,1,0,0,',35,','','Die Straße ist auf einem kurzen Stück vereist. Was sollen Sie hier möglichst vermeiden?'),
(27,'1.1.03-105','','','',4,1,0,0,',35,','','Wie können Sie beim Fahren gefahrlos feststellen, ob die Fahrbahn vereist ist?'),
(28,'1.1.03-108-B','1.1.03-108-B.jpg','','',3,1,0,0,',35,','','Warum müssen Sie hier besonders vorsichtig fahren?'),
(29,'1.1.03-109','','','',3,1,0,0,',35,','','Wo müssen Sie besonders mit plötzlich auftretendem Nebel rechnen?'),
(30,'1.1.03-110','','3.1','',4,1,0,0,',35,','','Was müssen Sie tun, wenn vor Ihnen ein Nebelfeld die Sicht stark behindert?'),
(31,'1.1.03-114-M','1.1.03-114-M.jpg','','',4,1,0,1,',35,','','Warum müssen Sie hier besonders aufmerksam sein?'),
(32,'1.1.04-103-B','1.1.04-103-B.jpg','17.2','',4,1,0,0,',29,','','Was müssen Sie hier tun, wenn Sie geblendet werden?'),
(33,'1.1.04-107','1.1.04-107.jpg','','',4,1,0,0,',29,','','Womit müssen Sie hier rechnen?'),
(34,'1.1.05-001','','','',4,1,1,0,',45,','','Wo führt schnelles Fahren häufig zu Unfällen?'),
(35,'1.1.05-002','','','',4,1,1,0,',45,','','Wo ist zu schnelles Fahren besonders gefährlich?'),
